// Function to export a GPIO pin
int export_gpio(int pin) {
    char path[64];
    FILE *fp;

    snprintf(path, sizeof(path), "%s/export", GPIO_PATH);
    fp = fopen(path, "w");
    if (fp == NULL) {
        perror("Failed to open GPIO export file");
        return -1;
    }

    fprintf(fp, "%d", pin);
    fclose(fp);
    return 0;
}

// Function to unexport a GPIO pin
int unexport_gpio(int pin) {
    char path[64];
    FILE *fp;

    snprintf(path, sizeof(path), "%s/unexport", GPIO_PATH);
    fp = fopen(path, "w");
    if (fp == NULL) {
        perror("Failed to open GPIO unexport file");
        return -1;
    }

    fprintf(fp, "%d", pin);
    fclose(fp);
    return 0;
}

// Function to set the direction of a GPIO pin (in or out)
int set_gpio_direction(int pin, const char *direction) {
    char path[64];
    FILE *fp;

    snprintf(path, sizeof(path), "%s/gpio%d/direction", GPIO_PATH, pin);
    fp = fopen(path, "w");
    if (fp == NULL) {
        perror("Failed to open GPIO direction file");
        return -1;
    }

    fprintf(fp, "%s", direction);
    fclose(fp);
    return 0;
}

// Function to read the value of a GPIO pin
int read_gpio_value(int pin) {
    char path[64];
    FILE *fp;
    char value_str[3];

    snprintf(path, sizeof(path), "%s/gpio%d/value", GPIO_PATH, pin);
    fp = fopen(path, "r");
    if (fp == NULL) {
        perror("Failed to open GPIO value file");
        return -1;
    }

    if (fread(value_str, 1, 3, fp) == 0) {
        perror("Failed to read GPIO value");
        fclose(fp);
        return -1;
    }

    fclose(fp);
    return atoi(value_str);
}

// Cleanup function to unexport GPIO pins
void cleanup() {
    printf("Cleaning up and exiting...\n");
    unexport_gpio(GPIO_PIN_1);
    unexport_gpio(GPIO_PIN_2);
}

// Signal handler to catch Ctrl+C and exit gracefully
void signal_handler(int signal) {
    program_running = 0;
    printf("Caught signal %d, exiting...\n", signal);
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <unistd.h>
#include <linux/i2c-dev.h>
#include <sys/ioctl.h>
#include <fcntl.h>
#include <time.h>
#include <signal.h>
#include <string.h>

// TMAG5170 I2C address
#define TMAG5170_ADDR 0x0E

// Register addresses
#define MAG_X_REG_L 0x08
#define MAG_X_REG_H 0x09
#define MAG_Y_REG_L 0x0A
#define MAG_Y_REG_H 0x0B
#define MAG_Z_REG_L 0x0C
#define MAG_Z_REG_H 0x0D

// I2C file descriptor
int i2c_fd;

// Flag to handle Ctrl+C
volatile sig_atomic_t stop_flag = 0;

// Signal handler
void sigint_handler(int signo) {
    stop_flag = 1;
    printf("\nCaught signal %d, exiting gracefully.\n", signo);
}

// Function to initialize I2C
int init_i2c(const char *device) {
    int fd = open(device, O_RDWR);
    if (fd < 0) {
        perror("Error opening I2C device");
        return -1;
    }

    if (ioctl(fd, I2C_SLAVE, TMAG5170_ADDR) < 0) {
        perror("Error setting I2C slave address");
        close(fd);
        return -1;
    }

    return fd;
}

// Function to read a 16-bit value from the sensor
int16_t read_sensor_value(int fd, uint8_t reg_l, uint8_t reg_h) {
    uint8_t buffer[2];
    int16_t value;

    // Read low byte
    buffer[0] = reg_l;
    if (write(fd, buffer, 1) != 1) {
        perror("Error writing to I2C device (low byte)");
        return 0; // Or some error value
    }
    if (read(fd, buffer, 1) != 1) {
        perror("Error reading from I2C device (low byte)");
        return 0;
    }
    uint8_t low_byte = buffer[0];

    // Read high byte
    buffer[0] = reg_h;
    if (write(fd, buffer, 1) != 1) {
        perror("Error writing to I2C device (high byte)");
        return 0;
    }
    if (read(fd, buffer, 1) != 1) {
        perror("Error reading from I2C device (high byte)");
        return 0;
    }
    uint8_t high_byte = buffer[0];

    // Combine the bytes
    value = (int16_t)((high_byte << 8) | low_byte);
    return value;
}

// Function to log the data
void log_data(int16_t x, int16_t y, int16_t z) {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[20];

    time(&rawtime);
    timeinfo = localtime(&rawtime);
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    printf("%s - X: %d, Y: %d, Z: %d\n", timestamp, x, y, z);
}

int main() {
    // Install signal handler
    if (signal(SIGINT, sigint_handler) == SIG_ERR) {
        perror("Error installing signal handler");
        return 1;
    }

    // Initialize I2C
    i2c_fd = init_i2c("/dev/i2c-1");
    if (i2c_fd < 0) {
        return 1;
    }

    // Main loop
    while (!stop_flag) {
        // Read sensor values
        int16_t x = read_sensor_value(i2c_fd, MAG_X_REG_L, MAG_X_REG_H);
        int16_t y = read_sensor_value(i2c_fd, MAG_Y_REG_L, MAG_Y_REG_H);
        int16_t z = read_sensor_value(i2c_fd, MAG_Z_REG_L, MAG_Z_REG_H);

        // Log the data
        log_data(x, y, z);

        // Sleep for 250ms
        usleep(250000);
    }

    // Close I2C device
    close(i2c_fd);

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
