// Define SPI pins
#define SPI_CE0 RPI_GPIO_P1_24 // Chip Enable (CE0)
#define SPI_MOSI RPI_GPIO_P1_19 // Master Out Slave In (MOSI)
#define SPI_MISO RPI_GPIO_P1_21 // Master In Slave Out (MISO)
#define SPI_CLK RPI_GPIO_P1_23  // Clock (CLK)

// MCP3008 channel connected to MLX90822
#define ADC_CHANNEL 0

// Function prototypes
int init_spi();
int read_adc(int channel);
void log_data(int adc_value);
void cleanup();
void sigint_handler(int sig);

// Global variables
volatile sig_atomic_t stop_flag = 0;

struct sensor_config {
    int read_interval_ms;
    float vref;
};

struct sensor_config config = {
    .read_interval_ms = 1000, // Read every 1 second
    .vref = 3.3             // Reference voltage of MCP3008
};

int main(int argc, char **argv) {
    // Setup signal handler for Ctrl+C
    signal(SIGINT, sigint_handler);

    // Initialize BCM2835 library
    if (!bcm2835_init()) {
        fprintf(stderr, "bcm2835_init failed. Are you running as root?\n");
        return 1;
    }

    // Initialize SPI
    if (init_spi() != 0) {
        fprintf(stderr, "SPI initialization failed.\n");
        bcm2835_close();
        return 1;
    }

    printf("Pressure sensor data logging started. Press Ctrl+C to exit.\n");

    while (!stop_flag) {
        // Read ADC value
        int adc_value = read_adc(ADC_CHANNEL);

        // Log the data
        if (adc_value >= 0) {
            log_data(adc_value);
        } else {
            fprintf(stderr, "Failed to read ADC value.\n");
        }

        // Wait for the specified interval
        bcm2835_delay(config.read_interval_ms);
    }

    // Cleanup and exit
    cleanup();
    printf("\nExiting.\n");
    return 0;
}

// Initialize SPI
int init_spi() {
    bcm2835_spi_begin();
    bcm2835_spi_setBitOrder(BCM2835_SPI_BIT_ORDER_MSBFIRST);
    bcm2835_spi_setDataMode(BCM2835_SPI_MODE0);
    bcm2835_spi_setClockDivider(BCM2835_SPI_CLOCK_DIVIDER_64); // Adjust divider as needed
    bcm2835_spi_chipSelect(BCM2835_SPI_CS0);                  // Chip select 0
    bcm2835_spi_setChipSelectPolarity(BCM2835_SPI_CS0, LOW);  // Chip select active low
    return 0;
}

// Read from MCP3008 ADC
int read_adc(int channel) {
    unsigned char txbuf[3];
    unsigned char rxbuf[3];

    txbuf[0] = 0x01;                           // Start bit
    txbuf[1] = (0x08 | channel) << 4;           // Single-ended mode, channel selection
    txbuf[2] = 0x00;                           // Don't care

    bcm2835_spi_transfernb(txbuf, rxbuf, 3);

    int adc_value = ((rxbuf[1] & 0x03) << 8) + rxbuf[2]; // Extract 10-bit value

    return adc_value;
}

// Log data with timestamp
void log_data(int adc_value) {
    struct timeval tv;
    gettimeofday(&tv, NULL);
    struct tm *tm = localtime(&tv.tv_sec);
    char timestamp[64];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", tm);
    snprintf(timestamp + strlen(timestamp), sizeof(timestamp) - strlen(timestamp), ".%06d", tv.tv_usec);

    // Calculate voltage (optional, for debugging/calibration)
    float voltage = (float)adc_value / 1023.0 * config.vref;

    printf("%s ADC Value: %d, Voltage: %.3fV\n", timestamp, adc_value, voltage);
}

// Cleanup resources
void cleanup() {
    bcm2835_spi_end();
    bcm2835_close();
}

// Signal handler for Ctrl+C
void sigint_handler(int sig) {
    stop_flag = 1;
}

#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <unistd.h>
#include <pigpio.h>

// Si1120 I2C address
#define SI1120_ADDR 0x60

// Si1120 Register Addresses
#define REG_PART_ID 0x00
#define REG_REV_ID 0x01
#define REG_SEQ_ID 0x02
#define REG_INT_CFG 0x03
#define REG_IRQ_EN  0x04
#define REG_IRQ_MODE1 0x05
#define REG_IRQ_MODE2 0x06
#define REG_HW_KEY    0x07
#define REG_MEAS_RATE0 0x08
#define REG_MEAS_RATE1 0x09
#define REG_ALS_RATE  0x0A
#define REG_ALS_FORCE 0x0B
#define REG_PS_RATE   0x0C
#define REG_PS_FORCE  0x0D
#define REG_PS1_ADCMUX 0x10
#define REG_PS2_ADCMUX 0x11
#define REG_PS3_ADCMUX 0x12
#define REG_LED1_A     0x13
#define REG_LED2_A     0x14
#define REG_LED3_A     0x15
#define REG_PS1_ABC     0x16
#define REG_PS2_ABC     0x17
#define REG_PS3_ABC     0x18
#define REG_PS_LED2SEL  0x19
#define REG_PS_LED3SEL  0x1A
#define REG_PS1_DATA0   0x22
#define REG_PS1_DATA1   0x23
#define REG_ALS_DATA0   0x24
#define REG_ALS_DATA1   0x25
#define REG_PARAM_WR    0x30
#define REG_COMMAND     0x31
#define REG_RESPONSE0   0x32
#define REG_RESPONSE1   0x33
#define REG_RESPONSE2   0x34

// Commands
#define CMD_RESET       0x01
#define CMD_ALS_START   0x02
#define CMD_PS_START    0x03
#define CMD_ALS_PAUSE   0x04
#define CMD_PS_PAUSE    0x05

static int i2c_handle;
static volatile sig_atomic_t terminate = 0;

// Signal handler for graceful termination
static void sigint_handler(int signal) {
    terminate = 1;
}

// Function to write a register in Si1120
int si1120_write_reg(int handle, uint8_t reg, uint8_t value) {
    return i2cWriteByteData(handle, reg, value);
}

// Function to read a register in Si1120
int si1120_read_reg(int handle, uint8_t reg) {
    return i2cReadByteData(handle, reg);
}

// Function to initialize the Si1120 sensor
int si1120_init(int handle) {
    // Reset the device
    if (si1120_write_reg(handle, REG_COMMAND, CMD_RESET) < 0) {
        fprintf(stderr, "Error: Failed to reset Si1120.\n");
        return -1;
    }
    gpioDelay(10); // Wait for reset to complete

    // Configure the sensor for ALS and proximity sensing
    if (si1120_write_reg(handle, REG_MEAS_RATE0, 0x01) < 0) { // Measurement rate divisor = 1
        fprintf(stderr, "Error: Failed to set measurement rate.\n");
        return -1;
    }
    if (si1120_write_reg(handle, REG_ALS_RATE, 0x40) < 0) { // ALS rate divisor = 64
        fprintf(stderr, "Error: Failed to set ALS rate.\n");
        return -1;
    }
    if (si1120_write_reg(handle, REG_PS_RATE, 0x40) < 0) { // PS rate divisor = 64
        fprintf(stderr, "Error: Failed to set PS rate.\n");
        return -1;
    }
    if (si1120_write_reg(handle, REG_PS1_ADCMUX, 0x05) < 0) { // PS1 ADC MUX
        fprintf(stderr, "Error: Failed to set PS1 ADC MUX.\n");
        return -1;
    }
    if (si1120_write_reg(handle, REG_LED1_A, 0x3F) < 0) { // LED1 current
        fprintf(stderr, "Error: Failed to set LED1 current.\n");
        return -1;
    }

    // Start ALS and PS measurements
    if (si1120_write_reg(handle, REG_COMMAND, CMD_ALS_START) < 0) {
        fprintf(stderr, "Error: Failed to start ALS.\n");
        return -1;
    }
    if (si1120_write_reg(handle, REG_COMMAND, CMD_PS_START) < 0) {
        fprintf(stderr, "Error: Failed to start PS.\n");
        return -1;
    }

    return 0;
}

// Function to read ambient light data
float si1120_read_als(int handle) {
    unsigned char data[2];
    if (i2cReadI2CBlockData(handle, REG_ALS_DATA0, (char *)data, 2) != 2) {
        fprintf(stderr, "Error: Failed to read ALS data.\n");
        return -1.0f;
    }

    unsigned int als_data = (data[1] << 8) | data[0];
    // Simple lux calculation (adjust as needed based on calibration)
    float lux = (float)als_data / 10.0f; // Example conversion
    return lux;
}

// Function to read proximity data
int si1120_read_proximity(int handle) {
    unsigned char data[2];
    if (i2cReadI2CBlockData(handle, REG_PS1_DATA0, (char *)data, 2) != 2) {
        fprintf(stderr, "Error: Failed to read proximity data.\n");
        return -1;
    }

    return (data[1] << 8) | data[0];
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "Error: pigpio initialisation failed\n");
        return 1;
    }

    // Open I2C connection
    i2c_handle = i2cOpen(1, SI1120_ADDR, 0); // I2C bus 1
    if (i2c_handle < 0) {
        fprintf(stderr, "Error: Could not open I2C connection\n");
        gpioTerminate();
        return 1;
    }

    // Initialize Si1120 sensor
    if (si1120_init(i2c_handle) < 0) {
        fprintf(stderr, "Error: Si1120 initialisation failed\n");
        i2cClose(i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Set up signal handler for Ctrl+C
    signal(SIGINT, sigint_handler);

    // Main loop
    while (!terminate) {
        // Read ambient light data
        float lux = si1120_read_als(i2c_handle);

        // Read proximity data
        int proximity = si1120_read_proximity(i2c_handle);

        // Print the data
        if (lux >= 0.0f && proximity >= 0) {
            printf("Ambient Light: %.2f lux, Proximity: %d\n", lux, proximity);
        } else {
            fprintf(stderr, "Error reading sensor data.\n");
        }

        // Wait 500ms
        gpioDelay(500000); // 500ms
    }

    // Close I2C connection
    i2cClose(i2c_handle);

    // Terminate pigpio
    gpioTerminate();

    printf("Program terminated.\n");
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <signal.h>
#include <pigpio.h>

// Define sensor I2C address
#define SDP810_ADDR 0x25

// Define trigger command for single measurement (pressure and temperature)
#define MEASURE_CMD 0x362F

// Define scale factors (replace with actual values from sensor datasheet)
#define SCALE_FACTOR_PRESSURE 0.1  // Example value, adjust based on datasheet
#define SCALE_FACTOR_TEMPERATURE 0.01 // Example value, adjust based on datasheet

// Global variables for pigpio handle and I2C handle
int i2c_handle;
int terminate = 0;

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("Caught signal %d, terminating...
", signal);
    terminate = 1;
}

// Function to initialize pigpio and I2C
int initialize() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return -1;
    }

    i2c_handle = i2cOpen(1, SDP810_ADDR, 0); // Bus 1, address, flags
    if (i2c_handle < 0) {
        fprintf(stderr, "Failed to open I2C device: %d\n", i2c_handle);
        gpioTerminate();
        return -1;
    }

    return 0;
}

// Function to read data from the sensor
int read_sensor(float *pressure, float *temperature) {
    char cmd[2] = {(MEASURE_CMD >> 8) & 0xFF, MEASURE_CMD & 0xFF};
    char buffer[6];
    int raw_pressure, raw_temperature;
    int status;

    // Send measurement command
    if (i2cWriteDevice(i2c_handle, cmd, 2) != 2) {
        fprintf(stderr, "Failed to write measurement command\n");
        return -1;
    }

    // Wait for conversion (at least 10ms)
    gpioDelay(10000); // 10ms

    // Read 6 bytes of data
    if (i2cReadDevice(i2c_handle, buffer, 6) != 6) {
        fprintf(stderr, "Failed to read sensor data\n");
        return -1;
    }

    // Extract raw values (MSB first)
    raw_pressure = (buffer[0] << 8) | buffer[1];
    raw_temperature = (buffer[2] << 8) | buffer[3];
    status = (buffer[4] << 8) | buffer[5];

    // Convert to float using scale factors
    *pressure = raw_pressure * SCALE_FACTOR_PRESSURE;
    *temperature = raw_temperature * SCALE_FACTOR_TEMPERATURE;

    return 0;
}

int main() {
    float pressure, temperature;

    // Register signal handlers
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Initialize pigpio and I2C
    if (initialize() < 0) {
        return 1;
    }

    printf("SDP810 Sensor Reading Program\n");

    // Main loop
    while (!terminate) {
        if (read_sensor(&pressure, &temperature) == 0) {
            printf("Pressure: %.2f Pa, Temperature: %.2f °C\n", pressure, temperature);
        } else {
            fprintf(stderr, "Failed to read sensor data\n");
        }

        gpioDelay(500000); // 500ms delay
    }

    // Close I2C connection and terminate pigpio
    i2cClose(i2c_handle);
    gpioTerminate();

    printf("Program terminated successfully.\n");
    return 0;
}

