#define ADXL345_ADDRESS 0x53
#define PWR_MGMT_2 0x2D
#define DATAX0 0x32
#define SCALING_FACTOR 0.0039

int fd;
volatile sig_atomic_t program_running = 1;

void signal_handler(int sig) {
    program_running = 0;
    printf("\nExiting program...\n");
}

int adxl345_init() {
    int result = wiringPiI2CWriteReg8(fd, PWR_MGMT_2, 0x08); // Set measurement mode
    if (result < 0) {
        fprintf(stderr, "Error initializing ADXL345: %d\n", result);
        return -1;
    }
    return 0;
}

int read_acceleration(float *x, float *y, float *z) {
    int16_t x_raw, y_raw, z_raw;
    int result;

    result = wiringPiI2CReadReg8(fd, DATAX0); // Read X
    if (result < 0) {
        fprintf(stderr, "Error reading X0 register: %d\n", result);
        return -1;
    }
    x_raw = (int16_t)result;

    result = wiringPiI2CReadReg8(fd, DATAX0 + 1); // Read X
    if (result < 0) {
        fprintf(stderr, "Error reading X1 register: %d\n", result);
        return -1;
    }
    x_raw |= ((int16_t)result) << 8;

    result = wiringPiI2CReadReg8(fd, DATAX0 + 2); // Read Y
    if (result < 0) {
        fprintf(stderr, "Error reading Y0 register: %d\n", result);
        return -1;
    }
    y_raw = (int16_t)result;

    result = wiringPiI2CReadReg8(fd, DATAX0 + 3); // Read Y
    if (result < 0) {
        fprintf(stderr, "Error reading Y1 register: %d\n", result);
        return -1;
    }
    y_raw |= ((int16_t)result) << 8;

    result = wiringPiI2CReadReg8(fd, DATAX0 + 4); // Read Z
    if (result < 0) {
        fprintf(stderr, "Error reading Z0 register: %d\n", result);
        return -1;
    }
    z_raw = (int16_t)result;

    result = wiringPiI2CReadReg8(fd, DATAX0 + 5); // Read Z
    if (result < 0) {
        fprintf(stderr, "Error reading Z1 register: %d\n", result);
        return -1;
    }
    z_raw |= ((int16_t)result) << 8;


    *x = (float)x_raw * SCALING_FACTOR;
    *y = (float)y_raw * SCALING_FACTOR;
    *z = (float)z_raw * SCALING_FACTOR;

    return 0;
}

int main() {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[20];
    float x, y, z;

    signal(SIGINT, signal_handler);

    wiringPiSetup();

    fd = wiringPiI2CSetup(ADXL345_ADDRESS);
    if (fd == -1) {
        fprintf(stderr, "Error opening I2C device!\n");
        return 1;
    }

    if (adxl345_init() != 0) {
        wiringPiI2CClose(fd);
        return 1;
    }

    printf("timestamp,X,Y,Z\n");

    while (program_running) {
        if (read_acceleration(&x, &y, &z) == 0) {
            time(&rawtime);
            timeinfo = localtime(&rawtime);
            strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);
            printf("%s,%.4f,%.4f,%.4f\n", timestamp, x, y, z);
        } else {
            fprintf(stderr, "Error reading acceleration data.\n");
        }

        usleep(100000); // 100ms
    }

    wiringPiI2CClose(fd);
    return 0;
}

#include <stdio.h>
