// Define I2C bus and address
#define I2C_BUS "/dev/i2c-1"
#define IMP23ABSU_ADDR 0x6B // Example address, verify with datasheet

// Register definitions (Example, check datasheet for correct values)
#define CTRL_REG1 0x20
#define OUT_X_L 0x28
#define OUT_X_H 0x29

// Structure for configuration
typedef struct {
    int i2c_fd;
    char *log_file;
} Config;

// Global flag for signal handling
volatile sig_atomic_t keep_running = 1;

// Signal handler
void signal_handler(int signum) {
    if (signum == SIGINT) {
        printf("\nExiting gracefully...\n");
        keep_running = 0;
    }
}

// Function to initialize I2C
int init_i2c(const char *bus, int addr) {
    int fd = open(bus, O_RDWR);
    if (fd < 0) {
        perror("Error opening I2C device");
        return -1;
    }

    if (ioctl(fd, I2C_SLAVE, addr) < 0) {
        perror("Error setting I2C slave address");
        close(fd);
        return -1;
    }

    return fd;
}

// Function to write a byte to a register
int write_reg(int fd, uint8_t reg, uint8_t value) {
    uint8_t buf[2];
    buf[0] = reg;
    buf[1] = value;

    if (write(fd, buf, 2) != 2) {
        perror("Error writing to I2C");
        return -1;
    }

    return 0;
}

// Function to read a byte from a register
int read_reg(int fd, uint8_t reg, uint8_t *value) {
    if (write(fd, &reg, 1) != 1) {
        perror("Error writing register address for read");
        return -1;
    }

    if (read(fd, value, 1) != 1) {
        perror("Error reading from I2C");
        return -1;
    }

    return 0;
}

// Function to read accelerometer data
int read_sensor_data(int fd, int16_t *x) {
    uint8_t x_l, x_h;

    if (read_reg(fd, OUT_X_L, &x_l) < 0) return -1;
    if (read_reg(fd, OUT_X_H, &x_h) < 0) return -1;

    *x = (int16_t)((x_h << 8) | x_l);

    return 0;
}

// Function to log data to a file
void log_data(const char *log_file, int16_t x) {
    FILE *fp = fopen(log_file, "a");
    if (fp == NULL) {
        perror("Error opening log file");
        return;
    }

    time_t t = time(NULL);
    struct tm tm = *localtime(&t);
    fprintf(fp, "%d-%02d-%02d %02d:%02d:%02d, X: %d\n", tm.tm_year + 1900, tm.tm_mon + 1, tm.tm_mday, tm.tm_hour, tm.tm_min, tm.tm_sec, x);
    fclose(fp);
}

int setup(Config *config) {
    config->i2c_fd = init_i2c(I2C_BUS, IMP23ABSU_ADDR);
    if (config->i2c_fd < 0) {
        fprintf(stderr, "I2C initialization failed.\n");
        return -1;
    }

    // Initialize the sensor (example: set ODR and enable X axis)
    if (write_reg(config->i2c_fd, CTRL_REG1, 0x77) < 0) { // Example value, consult datasheet
        fprintf(stderr, "Sensor initialization failed.\n");
        close(config->i2c_fd);
        return -1;
    }

    return 0;
}

int main() {
    Config config = {
        .i2c_fd = -1,
        .log_file = "biometric_data.log"
    };

    signal(SIGINT, signal_handler);

    if (setup(&config) != 0) {
        return 1;
    }

    int16_t x_accel;

    while (keep_running) {
        if (read_sensor_data(config.i2c_fd, &x_accel) == 0) {
            log_data(config.log_file, x_accel);
            printf("X-axis acceleration: %d\n", x_accel);
        } else {
            fprintf(stderr, "Failed to read sensor data.\n");
        }

        sleep(1); // Adjust sleep duration as needed
    }

    close(config.i2c_fd);
    return 0;
}

