// LSM9DS1 I2C addresses
#define LSM9DS1_GYRO_ACCEL_ADDR 0x6B // Gyro and Accelerometer address
#define LSM9DS1_MAG_ADDR 0x1D       // Magnetometer address

// LSM9DS1 register addresses (Gyro/Accel)
#define CTRL_REG1_G 0x10
#define CTRL_REG2_G 0x11
#define CTRL_REG3_G 0x12
#define CTRL_REG4_G 0x13
#define CTRL_REG5_G 0x14
#define OUT_X_L_G   0x18
#define OUT_X_H_G   0x19
#define OUT_Y_L_G   0x1A
#define OUT_Y_H_G   0x1B
#define OUT_Z_L_G   0x1C
#define OUT_Z_H_G   0x1D
#define OUT_X_L_A   0x28
#define OUT_X_H_A   0x29
#define OUT_Y_L_A   0x2A
#define OUT_Y_H_A   0x2B
#define OUT_Z_L_A   0x2C
#define OUT_Z_H_A   0x2D

// LSM9DS1 register addresses (Magnetometer)
#define CTRL_REG1_XM 0x20
#define CTRL_REG2_XM 0x21
#define CTRL_REG3_XM 0x22
#define CTRL_REG4_XM 0x23
#define CTRL_REG5_XM 0x24
#define OUT_X_L_M   0x28
#define OUT_X_H_M   0x29
#define OUT_Y_L_M   0x2A
#define OUT_Y_H_M   0x2B
#define OUT_Z_L_M   0x2C
#define OUT_Z_H_M   0x2D

// I2C file descriptors
int gyro_accel_fd;
int mag_fd;

// Signal handler for Ctrl+C
void signal_handler(int sig) {
    printf("\nExiting...\n");
    if (gyro_accel_fd >= 0) close(gyro_accel_fd);
    if (mag_fd >= 0) close(mag_fd);
    exit(0);
}

// Function to read a 16-bit value from the LSM9DS1
int16_t read_sensor_data(int fd, uint8_t low_reg, uint8_t high_reg) {
    int16_t value;
    int8_t low, high;
    int retries = 3; // Number of retries

    while (retries > 0) {
        low = wiringPiI2CReadReg8(fd, low_reg);
        if (low < 0) {
            fprintf(stderr, "Error reading register 0x%02X (low): %s\n", low_reg, strerror(errno));
            retries--;
            delay(10); // Wait before retrying
            continue; // Retry
        }

        high = wiringPiI2CReadReg8(fd, high_reg);
        if (high < 0) {
            fprintf(stderr, "Error reading register 0x%02X (high): %s\n", high_reg, strerror(errno));
            retries--;
            delay(10); // Wait before retrying
            continue; // Retry
        }

        value = (high << 8) | low;
        return value;
    }

    fprintf(stderr, "Failed to read sensor data after multiple retries.\n");
    return 0; // Return 0 as a default value in case of failure
}

int main() {
    // Register the signal handler
    signal(SIGINT, signal_handler);

    // Initialize wiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "wiringPiSetup failed: %s\n", strerror(errno));
        return 1;
    }

    // Initialize I2C for Gyro/Accel
    gyro_accel_fd = wiringPiI2CSetup(LSM9DS1_GYRO_ACCEL_ADDR);
    if (gyro_accel_fd == -1) {
        fprintf(stderr, "wiringPiI2CSetup failed (Gyro/Accel): %s\n", strerror(errno));
        return 1;
    }

    // Initialize I2C for Magnetometer
    mag_fd = wiringPiI2CSetup(LSM9DS1_MAG_ADDR);
    if (mag_fd == -1) {
        fprintf(stderr, "wiringPiI2CSetup failed (Magnetometer): %s\n", strerror(errno));
        return 1;
    }

    // Initialize Gyro/Accel (Example configuration - adjust as needed)
    wiringPiI2CWriteReg8(gyro_accel_fd, CTRL_REG1_G, 0x60); // 119 Hz, 245 dps
    wiringPiI2CWriteReg8(gyro_accel_fd, CTRL_REG2_G, 0x00);
    wiringPiI2CWriteReg8(gyro_accel_fd, CTRL_REG3_G, 0x00);
    wiringPiI2CWriteReg8(gyro_accel_fd, CTRL_REG4_G, 0x38); // Enable X, Y, Z
    wiringPiI2CWriteReg8(gyro_accel_fd, CTRL_REG5_G, 0x00);

    wiringPiI2CWriteReg8(gyro_accel_fd, CTRL_REG1_XM, 0x67); //119 HZ, +-2g
    wiringPiI2CWriteReg8(gyro_accel_fd, CTRL_REG2_XM, 0x00);
    wiringPiI2CWriteReg8(gyro_accel_fd, CTRL_REG3_XM, 0x00);
    wiringPiI2CWriteReg8(gyro_accel_fd, CTRL_REG4_XM, 0x08); //Continous update, enable z,y,x
    wiringPiI2CWriteReg8(gyro_accel_fd, CTRL_REG5_XM, 0x00);

    // Initialize Magnetometer (Example configuration - adjust as needed)
    wiringPiI2CWriteReg8(mag_fd, CTRL_REG1_XM, 0x14); // Temp sensor enable, 80 Hz ODR
    wiringPiI2CWriteReg8(mag_fd, CTRL_REG2_XM, 0x20); // +-4 gauss
    wiringPiI2CWriteReg8(mag_fd, CTRL_REG3_XM, 0x00); // Continuous conversion mode
    wiringPiI2CWriteReg8(mag_fd, CTRL_REG4_XM, 0x00); // Enable X, Y, Z
    wiringPiI2CWriteReg8(mag_fd, CTRL_REG5_XM, 0x40);

    // Main loop
    while (1) {
        // Read accelerometer data
        int16_t acc_x = read_sensor_data(gyro_accel_fd, OUT_X_L_A, OUT_X_H_A);
        int16_t acc_y = read_sensor_data(gyro_accel_fd, OUT_Y_L_A, OUT_Y_H_A);
        int16_t acc_z = read_sensor_data(gyro_accel_fd, OUT_Z_L_A, OUT_Z_H_A);

        // Read gyroscope data
        int16_t gyro_x = read_sensor_data(gyro_accel_fd, OUT_X_L_G, OUT_X_H_G);
        int16_t gyro_y = read_sensor_data(gyro_accel_fd, OUT_Y_L_G, OUT_Y_H_G);
        int16_t gyro_z = read_sensor_data(gyro_accel_fd, OUT_Z_L_G, OUT_Z_H_G);

        // Read magnetometer data
        int16_t mag_x = read_sensor_data(mag_fd, OUT_X_L_M, OUT_X_H_M);
        int16_t mag_y = read_sensor_data(mag_fd, OUT_Y_L_M, OUT_Y_H_M);
        int16_t mag_z = read_sensor_data(mag_fd, OUT_Z_L_M, OUT_Z_H_M);

        // Print the sensor data
        printf("AccX: %6d, AccY: %6d, AccZ: %6d, GyroX: %6d, GyroY: %6d, GyroZ: %6d, MagX: %6d, MagY: %6d, MagZ: %6d\n",
               acc_x, acc_y, acc_z, gyro_x, gyro_y, gyro_z, mag_x, mag_y, mag_z);

        delay(200); // Wait 200ms
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <unistd.h>
#include <signal.h>
#include <time.h>

// Constants
#define I2C_BUS 1
#define SDP800_ADDRESS 0x25
#define MEASUREMENT_COMMAND 0x2400
#define MEASUREMENT_DELAY_US 20000 // 20ms
#define SAMPLE_DELAY_MS 100

// Global variables
int i2c_handle;
bool running = true;

// Function prototypes
int trigger_measurement(int handle);
int read_measurement(int handle, uint8_t *data);
float convert_pressure(uint8_t msb, uint8_t lsb);
float convert_temperature(uint8_t temp_raw);
int crc8(const uint8_t *data, int len);

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("\nCaught signal %d, exiting gracefully...\n", signal);
    running = false;
}

int main() {
    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Open I2C connection
    i2c_handle = i2cOpen(I2C_BUS, SDP800_ADDRESS, 0);
    if (i2c_handle < 0) {
        fprintf(stderr, "Failed to open I2C device: %d\n", i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Register signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    printf("SDP800 Sensor Interface\n");

    // Main loop
    while (running) {
        uint8_t data[3];
        float pressure, temperature;

        // Trigger measurement
        if (trigger_measurement(i2c_handle) != 0) {
            fprintf(stderr, "Failed to trigger measurement. Re-initializing I2C.\n");
            i2cClose(i2c_handle);
            i2c_handle = i2cOpen(I2C_BUS, SDP800_ADDRESS, 0);
            if(i2c_handle < 0){
                fprintf(stderr, "Failed to re-open I2C device: %d\n", i2c_handle);
                running = false; //Exit loop if re-init fails
                continue;
            }
            gpioDelay(100000); // Wait 100ms before retrying
            continue; // Skip to the next iteration
        }

        // Read measurement data
        if (read_measurement(i2c_handle, data) != 0) {
            fprintf(stderr, "Failed to read measurement. Re-initializing I2C.\n");
            i2cClose(i2c_handle);
            i2c_handle = i2cOpen(I2C_BUS, SDP800_ADDRESS, 0);
            if(i2c_handle < 0){
                fprintf(stderr, "Failed to re-open I2C device: %d\n", i2c_handle);
                running = false; //Exit loop if re-init fails
                continue;
            }
            gpioDelay(100000); // Wait 100ms before retrying
            continue; // Skip to the next iteration
        }

        // Convert data
        pressure = convert_pressure(data[0], data[1]);
        temperature = convert_temperature(data[2]);

        // Print data
        printf("Pressure: %.2f Pa, Temperature: %.2f °C\n", pressure, temperature);

        // Delay before next measurement
        gpioDelay(SAMPLE_DELAY_MS * 1000); // Convert ms to us
    }

    // Close I2C connection and terminate pigpio
    i2cClose(i2c_handle);
    gpioTerminate();

    return 0;
}

// Function to trigger a single measurement
int trigger_measurement(int handle) {
    uint8_t command[2];
    command[0] = (MEASUREMENT_COMMAND >> 8) & 0xFF; // MSB
    command[1] = MEASUREMENT_COMMAND & 0xFF;      // LSB

    int result = i2cWriteDevice(handle, command, 2);
    if (result != 0) {
        fprintf(stderr, "Error writing to I2C device: %d\n", result);
        return -1;
    }

    gpioDelay(MEASUREMENT_DELAY_US); // Wait for measurement
    return 0;
}

// Function to read measurement data
int read_measurement(int handle, uint8_t *data) {
    int result = i2cReadDevice(handle, data, 3);
    if (result != 3) {
        fprintf(stderr, "Error reading from I2C device: %d\n", result);
        return -1;
    }
    return 0;
}

// Function to convert raw pressure data to Pascals
float convert_pressure(uint8_t msb, uint8_t lsb) {
    int16_t pressure_raw = (msb << 8) | lsb;
    return (float)pressure_raw / 10.0; // Scaling factor from datasheet
}

// Function to convert raw temperature data to degrees Celsius
float convert_temperature(uint8_t temp_raw) {
    return (float)temp_raw / 10.0; // Scaling factor from datasheet
}

// CRC-8 calculation (simplified, assumes data is 1 byte and CRC is next byte)
int crc8(const uint8_t *data, int len) {
    const uint8_t POLY = 0x31; // CRC-8 polynomial
    uint8_t crc = 0xFF;

    for (int i = 0; i < len; i++) {
        crc ^= data[i];
        for (int j = 0; j < 8; j++) {
            if (crc & 0x80) {
                crc = (crc << 1) ^ POLY;
            } else {
                crc <<= 1;
            }
        }
    }
    return crc;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdint.h>
#include <unistd.h>
#include <fcntl.h>
#include <termios.h>
#include <errno.h>
#include <wiringPi.h>
#include <time.h>
#include <sys/time.h>
#include <signal.h>

// Define GPIO pins (BCM numbering)
#define RESET_PIN 17
#define ENABLE_PIN 18

// UART configuration
#define UART_DEVICE "/dev/ttyS0" // or /dev/ttyAMA0
#define BAUD_RATE B921600

// Sensor data structure (example)
typedef struct {
    uint16_t range;
    uint16_t velocity;
    uint16_t signal_strength;
} SensorData;

// Global variables
volatile sig_atomic_t keep_running = 1;
int uart_fd;

// Function prototypes
int setup_gpio();
int setup_uart();
int read_sensor_data(SensorData *data);
void log_data(const SensorData *data);
void cleanup();
void signal_handler(int signal);

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    keep_running = 0;
    printf("\nCaught signal %d, exiting gracefully.\n", signal);
}

// Setup GPIO pins
int setup_gpio() {
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "WiringPi setup failed: %s\n", strerror(errno));
        return -1;
    }

    pinMode(RESET_PIN, OUTPUT);
    pinMode(ENABLE_PIN, OUTPUT);

    // Initialize pins (example: enable sensor)
    digitalWrite(ENABLE_PIN, HIGH);
    digitalWrite(RESET_PIN, HIGH);
    delay(100); // Small delay
    digitalWrite(RESET_PIN, LOW);
    delay(100); // Small delay
    digitalWrite(RESET_PIN, HIGH);
    delay(100); // Small delay

    return 0;
}

// Setup UART communication
int setup_uart() {
    uart_fd = open(UART_DEVICE, O_RDWR | O_NOCTTY | O_NDELAY);
    if (uart_fd == -1) {
        fprintf(stderr, "Error opening UART: %s\n", strerror(errno));
        return -1;
    }

    struct termios options;
    tcgetattr(uart_fd, &options);
    options.c_cflag = BAUD_RATE | CS8 | CLOCAL | CREAD;
    options.c_iflag = IGNPAR;
    options.c_oflag = 0;
    options.c_lflag = 0; // Non-canonical mode
    tcflush(uart_fd, TCIFLUSH);
    tcsetattr(uart_fd, TCSANOW, &options);

    return 0;
}

// Read sensor data from UART
int read_sensor_data(SensorData *data) {
    // Example: Read a fixed number of bytes
    unsigned char buffer[6]; // Assuming 6 bytes for range, velocity, signal strength
    ssize_t bytes_read = read(uart_fd, buffer, sizeof(buffer));

    if (bytes_read == sizeof(buffer)) {
        // Parse data from buffer
        data->range = (buffer[0] << 8) | buffer[1];
        data->velocity = (buffer[2] << 8) | buffer[3];
        data->signal_strength = (buffer[4] << 8) | buffer[5];
        return 0; // Success
    } else if (bytes_read > 0) {
        fprintf(stderr, "Incomplete read: %zd bytes\n", bytes_read);
        return -1; // Error
    } else {
        if (errno != EAGAIN && errno != EWOULDBLOCK) {
            fprintf(stderr, "UART read error: %s\n", strerror(errno));
        }
        return -1; // Error
    }
}

// Log sensor data to console with timestamp
void log_data(const SensorData *data) {
    struct timeval tv;
    gettimeofday(&tv, NULL);
    time_t nowtime = tv.tv_sec;
    struct tm *nowtm = localtime(&nowtime);
    char tmbuf[64], buf[64];
    strftime(tmbuf, sizeof(tmbuf), "%Y-%m-%d %H:%M:%S", nowtm);
    snprintf(buf, sizeof(buf), "%s.%06ld", tmbuf, tv.tv_usec);

    printf("[%s] Range: %u, Velocity: %u, Signal: %u\n", buf, data->range, data->velocity, data->signal_strength);
}

// Cleanup resources
void cleanup() {
    if (uart_fd != -1) {
        close(uart_fd);
    }
    digitalWrite(ENABLE_PIN, LOW); // Disable sensor
}

int main() {
    // Install signal handler
    signal(SIGINT, signal_handler);

    if (setup_gpio() == -1) {
        return 1;
    }

    if (setup_uart() == -1) {
        return 1;
    }

    SensorData sensor_data;

    while (keep_running) {
        if (read_sensor_data(&sensor_data) == 0) {
            log_data(&sensor_data);
        } else {
            fprintf(stderr, "Failed to read sensor data.\n");
        }
        delay(100); // Read every 100ms
    }

    cleanup();
    return 0;
}

