}

// Function to read distance from the sensor
int read_distance(int fd, sensor_data_t *data) {
    uint8_t buf[4]; // Buffer to read 4 bytes (status + distance)

    // Read status and distance registers
    buf[0] = CH201_REG_STATUS; // Address of the status register
    if (write(fd, buf, 1) != 1) {
        perror("Error writing to I2C");
        return -1;
    }
    if (read(fd, buf, 1) != 1) {
        perror("Error reading status from I2C");
        return -1;
    }
    data->status = buf[0];

    buf[0] = CH201_REG_DISTANCE; // Address of the distance register
    if (write(fd, buf, 1) != 1) {
        perror("Error writing to I2C");
        return -1;
    }
    if (read(fd, buf, 2) != 2) {
        perror("Error reading distance from I2C");
        return -1;
    }
    data->distance = (buf[0] << 8) | buf[1]; // Combine high and low bytes
    time(&data->timestamp);

    return 0;
}

// Function to log sensor data
void log_data(const sensor_data_t *data) {
    char timestamp_str[32];
    struct tm *tm_info = localtime(&data->timestamp);
    strftime(timestamp_str, sizeof(timestamp_str), "%Y-%m-%d %H:%M:%S", tm_info);

    printf("[%s] Status: 0x%02X, Distance: %d mm\n", timestamp_str, data->status, data->distance);
}

// Signal handler for graceful shutdown
void signal_handler(int sig) {
    printf("\nCaught signal %d, exiting gracefully...\n", sig);
    stop_flag = 1;
}

int main() {
    // Setup signal handling
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Initialize I2C communication
    i2c_fd = i2c_setup(I2C_BUS, CH201_ADDR);
    if (i2c_fd < 0) {
        fprintf(stderr, "Failed to initialize I2C. Exiting.\n");
        return 1;
    }

    sensor_data_t sensor_data;

    // Main loop
    while (!stop_flag) {
        if (read_distance(i2c_fd, &sensor_data) == 0) {
            log_data(&sensor_data);
        } else {
            fprintf(stderr, "Error reading sensor data.\n");
        }
        sleep(1); // Read sensor every 1 second
    }

    // Clean up and close I2C device
    close(i2c_fd);
    printf("I2C connection closed.\n");

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <signal.h>
#include <unistd.h>
#include <pigpio.h>

// LSM6DS33 Registers
#define LSM6DS33_ADDR1 0x6A
#define LSM6DS33_ADDR2 0x6B
#define WHO_AM_I 0x0F
#define CTRL1_XL 0x10
#define CTRL2_G 0x11
#define OUTX_L_G 0x22
#define OUTX_L_XL 0x28

// Configuration values
#define ACCEL_CONFIG 0x80  // 104 Hz, +/- 2g
#define GYRO_CONFIG 0x80   // 104 Hz, +/- 250 dps

// Global variables
int i2c_handle;
int running = 1;
int lsm_address;

// Signal handler
void signal_handler(int signal)
{
    printf("Received signal %d, exiting...\n", signal);
    running = 0;
}

// Function to detect LSM6DS33 address
int detect_lsm_address()
{
    int handle1 = i2cOpen(1, LSM6DS33_ADDR1, 0);
    if (handle1 >= 0) {
        i2cClose(handle1);
        return LSM6DS33_ADDR1;
    }

    int handle2 = i2cOpen(1, LSM6DS33_ADDR2, 0);
    if (handle2 >= 0) {
        i2cClose(handle2);
        return LSM6DS33_ADDR2;
    }

    return -1; // No device found
}

// Function to initialize the LSM6DS33
int init_lsm6ds33()
{
    // Configure accelerometer
    if (i2cWriteByteData(i2c_handle, CTRL1_XL, ACCEL_CONFIG) != 0) {
        fprintf(stderr, "Error configuring accelerometer\n");
        return -1;
    }

    // Configure gyroscope
    if (i2cWriteByteData(i2c_handle, CTRL2_G, GYRO_CONFIG) != 0) {
        fprintf(stderr, "Error configuring gyroscope\n");
        return -1;
    }

    return 0;
}

// Function to read sensor data
int read_sensor_data(int16_t *accel_x, int16_t *accel_y, int16_t *accel_z, int16_t *gyro_x, int16_t *gyro_y, int16_t *gyro_z)
{
    char buffer[12];

    if (i2cReadI2CBlockData(i2c_handle, OUTX_L_G, buffer, 12) != 12) {
        fprintf(stderr, "Error reading sensor data\n");
        return -1;
    }

    *gyro_x = (int16_t)((buffer[1] << 8) | buffer[0]);
    *gyro_y = (int16_t)((buffer[3] << 8) | buffer[2]);
    *gyro_z = (int16_t)((buffer[5] << 8) | buffer[4]);
    *accel_x = (int16_t)((buffer[7] << 8) | buffer[6]);
    *accel_y = (int16_t)((buffer[9] << 8) | buffer[8]);
    *accel_z = (int16_t)((buffer[11] << 8) | buffer[10]);

    return 0;
}

int main()
{
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Detect LSM6DS33 address
    lsm_address = detect_lsm_address();
    if (lsm_address == -1) {
        fprintf(stderr, "LSM6DS33 not found\n");
        gpioTerminate();
        return 1;
    }

    // Open I2C device
    i2c_handle = i2cOpen(1, lsm_address, 0);
    if (i2c_handle < 0) {
        fprintf(stderr, "Error opening I2C device\n");
        gpioTerminate();
        return 1;
    }

    // Initialize LSM6DS33
    if (init_lsm6ds33() != 0) {
        i2cClose(i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Set up signal handling
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Read and print sensor data
    int16_t accel_x, accel_y, accel_z, gyro_x, gyro_y, gyro_z;
    while (running) {
        if (read_sensor_data(&accel_x, &accel_y, &accel_z, &gyro_x, &gyro_y, &gyro_z) == 0) {
            printf("%d,%d,%d,%d,%d,%d\n", accel_x, accel_y, accel_z, gyro_x, gyro_y, gyro_z);
        }
        gpioDelay(100); // 100 ms delay
    }

    // Close I2C device and terminate pigpio
    i2cClose(i2c_handle);
    gpioTerminate();

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <fcntl.h>
#include <unistd.h>
#include <sys/ioctl.h>
#include <linux/i2c-dev.h>
#include <time.h>
#include <signal.h>
#include <string.h>

// LSM9DS1 I2C addresses
#define LSM9DS1_MAG_ADDRESS 0x1E // Magnetometer address
#define LSM9DS1_XG_ADDRESS 0x6B  // Accelerometer/Gyroscope address

// LSM9DS1 register addresses (Magnetometer)
#define LSM9DS1_MAG_WHO_AM_I 0x0F
#define LSM9DS1_MAG_CTRL_REG1_M 0x20
#define LSM9DS1_MAG_CTRL_REG2_M 0x21
#define LSM9DS1_MAG_CTRL_REG3_M 0x22
#define LSM9DS1_MAG_OUT_X_L_M 0x28

// LSM9DS1 register addresses (Accelerometer/Gyroscope)
#define LSM9DS1_XG_WHO_AM_I 0x0F
#define LSM9DS1_XG_CTRL_REG1_G 0x10
#define LSM9DS1_XG_CTRL_REG2_G 0x11
#define LSM9DS1_XG_CTRL_REG4_XL 0x20
#define LSM9DS1_XG_CTRL_REG5_XL 0x24
#define LSM9DS1_XG_OUT_X_L_G 0x18
#define LSM9DS1_XG_OUT_X_L_XL 0x28

//Global variables
int i2c_fd;
FILE *log_file;
volatile sig_atomic_t stop_flag = 0;

// Structure to hold sensor data
typedef struct {
    float mag_x, mag_y, mag_z;
    float gyro_x, gyro_y, gyro_z;
    float acc_x, acc_y, acc_z;
    time_t timestamp;
} sensor_data_t;

// Function prototypes
int i2c_setup(int address);
int lsm9ds1_mag_init();
int lsm9ds1_xg_init();
int lsm9ds1_read_mag(sensor_data_t *data);
int lsm9ds1_read_xg(sensor_data_t *data);
void log_sensor_data(const sensor_data_t *data);
void signal_handler(int sig);

// Helper function to read a single byte from an I2C register
int i2c_read_reg(int i2c_fd, uint8_t reg_address, uint8_t *data)
{
    if (write(i2c_fd, &reg_address, 1) != 1) {
        perror("I2C write (register address) failed");
        return -1;
    }
    if (read(i2c_fd, data, 1) != 1) {
        perror("I2C read failed");
        return -1;
    }
    return 0;
}

// Helper function to write a single byte to an I2C register
int i2c_write_reg(int i2c_fd, uint8_t reg_address, uint8_t value)
{
    uint8_t buffer[2];
    buffer[0] = reg_address;
    buffer[1] = value;
    if (write(i2c_fd, buffer, 2) != 2) {
        perror("I2C write failed");
        return -1;
    }
    return 0;
}

int main() {
    sensor_data_t sensor_data;
    // Set up signal handler for graceful shutdown
    signal(SIGINT, signal_handler);

    // Open I2C bus
    i2c_fd = open("/dev/i2c-1", O_RDWR);
    if (i2c_fd < 0) {
        perror("Error opening I2C bus");
        return 1;
    }

    // Initialize magnetometer and accelerometer/gyroscope
    if (lsm9ds1_mag_init() != 0) {
        fprintf(stderr, "Magnetometer initialization failed.\n");
        close(i2c_fd);
        return 1;
    }

    if (lsm9ds1_xg_init() != 0) {
        fprintf(stderr, "Accelerometer/Gyroscope initialization failed.\n");
        close(i2c_fd);
        return 1;
    }

    // Open log file
    log_file = fopen("sensor_data.log", "a");
    if (log_file == NULL) {
        perror("Error opening log file");
        close(i2c_fd);
        return 1;
    }

    // Main loop
    while (!stop_flag) {
        // Read sensor data
        if (lsm9ds1_read_mag(&sensor_data) != 0) {
            fprintf(stderr, "Error reading magnetometer data.\n");
        }
        if (lsm9ds1_read_xg(&sensor_data) != 0) {
            fprintf(stderr, "Error reading accelerometer/gyroscope data.\n");
        }

        // Get timestamp
        time(&sensor_data.timestamp);

        // Log sensor data
        log_sensor_data(&sensor_data);

        // Sleep for a short period
        sleep(1);
    }

    // Clean up
    fclose(log_file);
    close(i2c_fd);

    printf("Program terminated gracefully.\n");
    return 0;
}

// Function to set up I2C communication with a specific device address
int i2c_setup(int address) {
    if (ioctl(i2c_fd, I2C_SLAVE, address) < 0) {
        perror("Error acquiring I2C bus access or setting slave address");
        return -1;
    }
    return 0;
}

// Function to initialize the LSM9DS1 magnetometer
int lsm9ds1_mag_init() {
    if (i2c_setup(LSM9DS1_MAG_ADDRESS) != 0) {
        return -1;
    }

    uint8_t who_am_i;
    if (i2c_read_reg(i2c_fd, LSM9DS1_MAG_WHO_AM_I, &who_am_i) != 0) {
        return -1;
    }
    if (who_am_i != 0x3D) {
        fprintf(stderr, "Error: Magnetometer WHO_AM_I returned 0x%x, expected 0x3D\n", who_am_i);
        return -1;
    }

    // Set magnetometer to continuous mode, 80 Hz output data rate
    if (i2c_write_reg(i2c_fd, LSM9DS1_MAG_CTRL_REG1_M, 0x70) != 0) {
        return -1;
    }
    // Set gain to +/- 4 gauss
    if (i2c_write_reg(i2c_fd, LSM9DS1_MAG_CTRL_REG2_M, 0x00) != 0) {
        return -1;
    }
    // Enable temperature compensation
    if (i2c_write_reg(i2c_fd, LSM9DS1_MAG_CTRL_REG3_M, 0x00) != 0) {
        return -1;
    }

    return 0;
}

// Function to initialize the LSM9DS1 accelerometer and gyroscope
int lsm9ds1_xg_init() {
    if (i2c_setup(LSM9DS1_XG_ADDRESS) != 0) {
        return -1;
    }

    uint8_t who_am_i;
    if (i2c_read_reg(i2c_fd, LSM9DS1_XG_WHO_AM_I, &who_am_i) != 0) {
        return -1;
    }
    if (who_am_i != 0x68) {
        fprintf(stderr, "Error: Accelerometer/Gyroscope WHO_AM_I returned 0x%x, expected 0x68\n", who_am_i);
        return -1;
    }

    // Set gyroscope to 238 Hz, 245 dps
    if (i2c_write_reg(i2c_fd, LSM9DS1_XG_CTRL_REG1_G, 0x78) != 0) {
        return -1;
    }
    // Enable high-pass filter
    if (i2c_write_reg(i2c_fd, LSM9DS1_XG_CTRL_REG2_G, 0x00) != 0) {
        return -1;
    }
    // Set accelerometer to 119 Hz, +/- 2g
    if (i2c_write_reg(i2c_fd, LSM9DS1_XG_CTRL_REG4_XL, 0x68) != 0) {
        return -1;
    }
    // Enable accelerometer low-pass filter
    if (i2c_write_reg(i2c_fd, LSM9DS1_XG_CTRL_REG5_XL, 0x00) != 0) {
        return -1;
    }

    return 0;
}

// Function to read data from the LSM9DS1 magnetometer
int lsm9ds1_read_mag(sensor_data_t *data) {
    uint8_t buffer[6];
    int16_t raw_x, raw_y, raw_z;

    if (i2c_setup(LSM9DS1_MAG_ADDRESS) != 0) {
        return -1;
    }

    if (write(i2c_fd, (uint8_t[ ]){LSM9DS1_MAG_OUT_X_L_M}, 1) != 1) {
        perror("I2C write (register address) failed");
        return -1;
    }
    if (read(i2c_fd, buffer, 6) != 6) {
        perror("I2C read failed");
        return -1;
    }

    raw_x = (int16_t)((buffer[1] << 8) | buffer[0]);
    raw_y = (int16_t)((buffer[3] << 8) | buffer[2]);
    raw_z = (int16_t)((buffer[5] << 8) | buffer[4]);

    data->mag_x = (float)raw_x;
    data->mag_y = (float)raw_y;
    data->mag_z = (float)raw_z;

    return 0;
}

// Function to read data from the LSM9DS1 accelerometer and gyroscope
int lsm9ds1_read_xg(sensor_data_t *data) {
    uint8_t buffer[12];
    int16_t raw_gyro_x, raw_gyro_y, raw_gyro_z;
    int16_t raw_acc_x, raw_acc_y, raw_acc_z;

    if (i2c_setup(LSM9DS1_XG_ADDRESS) != 0) {
        return -1;
    }

    if (write(i2c_fd, (uint8_t[ ]){LSM9DS1_XG_OUT_X_L_G}, 1) != 1) {
        perror("I2C write (register address) failed");
        return -1;
    }
    if (read(i2c_fd, buffer, 6) != 6) {
        perror("I2C read failed (gyro)");
        return -1;
    }

    raw_gyro_x = (int16_t)((buffer[1] << 8) | buffer[0]);
    raw_gyro_y = (int16_t)((buffer[3] << 8) | buffer[2]);
    raw_gyro_z = (int16_t)((buffer[5] << 8) | buffer[4]);

    if (write(i2c_fd, (uint8_t[ ]){LSM9DS1_XG_OUT_X_L_XL}, 1) != 1) {
        perror("I2C write (register address) failed");
        return -1;
    }
    if (read(i2c_fd, buffer, 6) != 6) {
        perror("I2C read failed (accel)");
        return -1;
    }

    raw_acc_x = (int16_t)((buffer[1] << 8) | buffer[0]);
    raw_acc_y = (int16_t)((buffer[3] << 8) | buffer[2]);
    raw_acc_z = (int16_t)((buffer[5] << 8) | buffer[4]);

    data->gyro_x = (float)raw_gyro_x;
    data->gyro_y = (float)raw_gyro_y;
    data->gyro_z = (float)raw_gyro_z;
    data->acc_x = (float)raw_acc_x;
    data->acc_y = (float)raw_acc_y;
    data->acc_z = (float)raw_acc_z;

    return 0;
}

// Function to log sensor data to a file
void log_sensor_data(const sensor_data_t *data) {
    char timestamp_str[30];
    strftime(timestamp_str, sizeof(timestamp_str), "%Y-%m-%d %H:%M:%S", localtime(&data->timestamp));

    fprintf(log_file, "%s, %.2f, %.2f, %.2f, %.2f, %.2f, %.2f, %.2f, %.2f, %.2f\n",
            timestamp_str,
            data->mag_x, data->mag_y, data->mag_z,
            data->gyro_x, data->gyro_y, data->gyro_z,
            data->acc_x, data->acc_y, data->acc_z);
    fflush(log_file); // Ensure data is written to file immediately
}

// Signal handler to catch Ctrl+C and exit gracefully
void signal_handler(int sig) {
    stop_flag = 1;
    printf("Ctrl+C detected, stopping...\n");
}

#include <stdio.h>
