#define GPIO17 17
#define GPIO27 27

// Structure to hold GPIO configuration
typedef struct {
    int gpio_num;
    char gpio_str[3]; // String representation of GPIO number
    char gpio_path[64]; // Path to GPIO value file
} gpio_config_t;

// Global flag for graceful shutdown
volatile sig_atomic_t program_running = 1;

// Signal handler for SIGINT (Ctrl+C)
void sigint_handler(int sig) {
    (void)sig; // Suppress unused parameter warning
    program_running = 0;
    printf("\nExiting gracefully...\n");
}

// Function to export a GPIO pin
int gpio_export(int gpio) {
    char buffer[3];
    ssize_t bytes_written;
    int fd;

    fd = open("/sys/class/gpio/export", O_WRONLY);
    if (fd == -1) {
        fprintf(stderr, "Failed to open export for writing!\n");
        return -1;
    }

    snprintf(buffer, sizeof(buffer), "%d", gpio);
    bytes_written = write(fd, buffer, strlen(buffer));
    close(fd);
    if (bytes_written < 0) {
        fprintf(stderr, "Failed to export GPIO %d\n", gpio);
        return -1;
    }
    return 0;
}

// Function to unexport a GPIO pin
int gpio_unexport(int gpio) {
    char buffer[3];
    ssize_t bytes_written;
    int fd;

    fd = open("/sys/class/gpio/unexport", O_WRONLY);
    if (fd == -1) {
        fprintf(stderr, "Failed to open unexport for writing!\n");
        return -1;
    }

    snprintf(buffer, sizeof(buffer), "%d", gpio);
    bytes_written = write(fd, buffer, strlen(buffer));
    close(fd);
    if (bytes_written < 0) {
        fprintf(stderr, "Failed to unexport GPIO %d\n", gpio);
        return -1;
    }
    return 0;
}

// Function to set GPIO direction (in or out)
int gpio_set_direction(int gpio, const char *direction) {
    char path[64];
    int fd;

    snprintf(path, sizeof(path), "/sys/class/gpio/gpio%d/direction", gpio);
    fd = open(path, O_WRONLY);
    if (fd == -1) {
        fprintf(stderr, "Failed to open gpio%d direction for writing!\n", gpio);
        return -1;
    }

    if (write(fd, direction, strlen(direction)) < 0) {
        fprintf(stderr, "Failed to set direction for gpio%d\n", gpio);
        close(fd);
        return -1;
    }

    close(fd);
    return 0;
}

// Function to read the value of a GPIO pin
int gpio_read(int gpio) {
    char path[64];
    char value_str[3];
    int fd;

    snprintf(path, sizeof(path), "/sys/class/gpio/gpio%d/value", gpio);
    fd = open(path, O_RDONLY);
    if (fd == -1) {
        fprintf(stderr, "Failed to open gpio%d value for reading!\n", gpio);
        return -1;
    }

    if (read(fd, value_str, 3) < 0) {
        fprintf(stderr, "Failed to read value for gpio%d\n", gpio);
        close(fd);
        return -1;
    }

    close(fd);
    return (atoi(value_str));
}

int main() {
    gpio_config_t sensor17, sensor27;
    sensor17.gpio_num = GPIO17;
    sensor27.gpio_num = GPIO27;

    snprintf(sensor17.gpio_str, sizeof(sensor17.gpio_str), "%d", sensor17.gpio_num);
    snprintf(sensor27.gpio_str, sizeof(sensor27.gpio_str), "%d", sensor27.gpio_num);

    snprintf(sensor17.gpio_path, sizeof(sensor17.gpio_path), "/sys/class/gpio/gpio%d/value", sensor17.gpio_num);
    snprintf(sensor27.gpio_path, sizeof(sensor27.gpio_path), "/sys/class/gpio/gpio%d/value", sensor27.gpio_num);

    // Register signal handler for Ctrl+C
    signal(SIGINT, sigint_handler);

    // Export GPIO pins
    if (gpio_export(sensor17.gpio_num) == -1 || gpio_export(sensor27.gpio_num) == -1) {
        fprintf(stderr, "Failed to export GPIO pins. Exiting.\n");
        return 1;
    }

    // Set GPIO direction to input
    if (gpio_set_direction(sensor17.gpio_num, "in") == -1 || gpio_set_direction(sensor27.gpio_num, "in") == -1) {
        fprintf(stderr, "Failed to set GPIO direction. Exiting.\n");
        gpio_unexport(sensor17.gpio_num);
        gpio_unexport(sensor27.gpio_num);
        return 1;
    }

    printf("IR Obstacle Detection Started (Ctrl+C to exit)\n");

    while (program_running) {
        int value17 = gpio_read(sensor17.gpio_num);
        int value27 = gpio_read(sensor27.gpio_num);

        if (value17 == -1 || value27 == -1) {
            fprintf(stderr, "Error reading sensor values.\n");
        } else {
            printf("Sensor 17: %s\n", (value17 == 0) ? "Obstacle Detected" : "No Obstacle");
            printf("Sensor 27: %s\n", (value27 == 0) ? "Obstacle Detected" : "No Obstacle");
        }

        usleep(500000); // Sleep for 500ms
    }

    // Unexport GPIO pins before exiting
    gpio_unexport(sensor17.gpio_num);
    gpio_unexport(sensor27.gpio_num);

    printf("IR Obstacle Detection Stopped\n");

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
