/*
 * Omron D7S Vibration Sensor Interface
 * Raspberry Pi 5
 * I2C Communication using pigpio library
 *
 * Sensor Connection:
 * SDA - Pin 3 (GPIO2)
 * SCL - Pin 5 (GPIO3)
 * VCC - 3.3V
 * GND - GND
 */

#define I2C_ADDR 0x19
#define ACCEL_XOUT_L 0x28
#define ACCEL_XOUT_H 0x29
#define ACCEL_YOUT_L 0x2A
#define ACCEL_YOUT_H 0x2B
#define ACCEL_ZOUT_L 0x2C
#define ACCEL_ZOUT_H 0x2D

#define NUM_REGISTERS 6 // Number of registers to read for X, Y, and Z acceleration data

#define ZERO_G_OFFSET_X 0   // Experimentally determined zero-g offset for X axis
#define ZERO_G_OFFSET_Y 0   // Experimentally determined zero-g offset for Y axis
#define ZERO_G_OFFSET_Z 0   // Experimentally determined zero-g offset for Z axis

#define VIBRATION_THRESHOLD 0.5 // Vibration threshold in g

int i2c_handle;
volatile sig_atomic_t terminate = 0;

void signal_handler(int sig) {
    terminate = 1;
    printf("Signal received, exiting gracefully.\n");
}

// Function to read raw acceleration data from the sensor
int read_acceleration_data(int16_t *x, int16_t *y, int16_t *z) {
    char buffer[NUM_REGISTERS];
    int result = i2cReadI2CBlockData(i2c_handle, ACCEL_XOUT_L, buffer, NUM_REGISTERS);

    if (result != NUM_REGISTERS) {
        fprintf(stderr, "Error reading acceleration data: %d\n", result);
        return -1;
    }

    *x = (int16_t)((buffer[1] << 8) | buffer[0]);
    *y = (int16_t)((buffer[3] << 8) | buffer[2]);
    *z = (int16_t)((buffer[5] << 8) | buffer[4]);

    return 0;
}

// Function to log vibration data to a file
void log_vibration_data(int16_t x, int16_t y, int16_t z) {
    FILE *fp = fopen("vibration_log.txt", "a");
    if (fp == NULL) {
        fprintf(stderr, "Error opening log file!\n");
        return;
    }

    time_t t = time(NULL);
    struct tm *tm = localtime(&t);
    char s[64];
    strftime(s, sizeof(s), "%Y-%m-%d %H:%M:%S", tm);

    fprintf(fp, "%s, X: %d, Y: %d, Z: %d\n", s, x, y, z);
    fclose(fp);
}

int main() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    i2c_handle = i2cOpen(1, I2C_ADDR, 0); // Bus 1, address 0x19, no flags
    if (i2c_handle < 0) {
        fprintf(stderr, "Error opening I2C device: %d\n", i2c_handle);
        gpioTerminate();
        return 1;
    }

    signal(SIGINT, signal_handler);

    printf("Vibration data logging started. Press Ctrl+C to exit.\n");

    while (!terminate) {
        int16_t raw_x, raw_y, raw_z;

        if (read_acceleration_data(&raw_x, &raw_y, &raw_z) == 0) {
            // Calibrate the raw data
            int16_t calibrated_x = raw_x - ZERO_G_OFFSET_X;
            int16_t calibrated_y = raw_y - ZERO_G_OFFSET_Y;
            int16_t calibrated_z = raw_z - ZERO_G_OFFSET_Z;

            // Calculate vibration magnitude (in arbitrary units, needs scaling for g)
            float magnitude = sqrt(pow(calibrated_x, 2) + pow(calibrated_y, 2) + pow(calibrated_z, 2));

            // Scale magnitude to g (adjust scale factor as needed based on sensor sensitivity)
            float magnitude_g = magnitude / 16384.0; // Example scaling for +/- 2g range

            if (magnitude_g > VIBRATION_THRESHOLD) {
                log_vibration_data(calibrated_x, calibrated_y, calibrated_z);
                printf("Vibration detected! Magnitude: %.2f g\n", magnitude_g);
            }
        } else {
            fprintf(stderr, "Failed to read sensor data. Retrying...\n");
        }

        gpioDelay(100); // Check every 100ms
    }

    i2cClose(i2c_handle);
    gpioTerminate();
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <pigpio.h>
#include <time.h>
#include <signal.h>
#include <unistd.h>

// Default I2C address of the SHT40 sensor
#define DEFAULT_I2C_ADDRESS 0x44

// Measurement command (high precision)
#define MEASURE_HIGH_PRECISION 0xFD

// Structure to hold sensor data
typedef struct {
    float temperature;
    float humidity;
} SensorData;

int i2c_handle;
int i2c_address = DEFAULT_I2C_ADDRESS;

// Function prototypes
unsigned char crc8(const unsigned char *data, int len);
SensorData read_sht40(int i2c_handle);
void signal_handler(int signal);
int initialize_pigpio();
int open_i2c_connection(int address);
void terminate_pigpio();

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("\nReceived signal %d, shutting down...\n", signal);
    terminate_pigpio();
    exit(0);
}

// CRC-8 calculation function
unsigned char crc8(const unsigned char *data, int len) {
    const unsigned char polynomial = 0x31; // Standard CRC-8 polynomial
    unsigned char crc = 0xFF;

    for (int i = 0; i < len; i++) {
        crc ^= data[i];
        for (int j = 0; j < 8; j++) {
            if (crc & 0x80) {
                crc = (crc << 1) ^ polynomial;
            } else {
                crc <<= 1;
            }
        }
    }
    return crc;
}

// Function to read temperature and humidity from SHT40
SensorData read_sht40(int i2c_handle) {
    unsigned char data[6];
    SensorData sensor_data;
    int result;

    // Send measurement command
    result = i2cWriteByteData(i2c_handle, MEASURE_HIGH_PRECISION, 0x00);
    if (result != 0) {
        fprintf(stderr, "Error writing to I2C: %d\n", result);
        sensor_data.temperature = NAN; // Not a Number
        sensor_data.humidity = NAN;
        return sensor_data;
    }

    // Wait for measurement to complete (datasheet recommends 10ms)
    gpioDelay(10);

    // Read 6 bytes of data
    result = i2cReadDevice(i2c_handle, data, 6);
    if (result != 6) {
        fprintf(stderr, "Error reading from I2C: %d\n", result);
        sensor_data.temperature = NAN;
        sensor_data.humidity = NAN;
        return sensor_data;
    }

    // Extract temperature and humidity values
    uint16_t temperature_raw = (data[0] << 8) | data[1];
    uint16_t humidity_raw = (data[3] << 8) | data[4];

    // CRC validation
    if (crc8(data, 2) != data[2] || crc8(data + 3, 2) != data[5]) {
        fprintf(stderr, "CRC check failed\n");
        sensor_data.temperature = NAN;
        sensor_data.humidity = NAN;
        return sensor_data;
    }

    // Convert raw values to temperature and humidity (from datasheet)
    float temperature = -45.0 + 175.0 * (float)temperature_raw / 65535.0;
    float humidity = 100.0 * (float)humidity_raw / 65535.0;

    sensor_data.temperature = temperature;
    sensor_data.humidity = humidity;

    return sensor_data;
}

// Function to initialize the pigpio library
int initialize_pigpio() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return -1;
    }
    return 0;
}

// Function to open an I2C connection
int open_i2c_connection(int address) {
    int handle = i2cOpen(1, address, 0); // Bus 1, address, no flags
    if (handle < 0) {
        fprintf(stderr, "Error opening I2C: %d\n", handle);
        return -1;
    }
    return handle;
}

// Function to terminate the pigpio library
void terminate_pigpio() {
    i2cClose(i2c_handle);
    gpioTerminate();
}

int main(int argc, char *argv[]) {
    // Register signal handlers for graceful shutdown
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Parse command-line arguments for I2C address
    if (argc > 1) {
        i2c_address = strtol(argv[1], NULL, 0); // Convert string to integer
        printf("Using I2C address: 0x%02X\n", i2c_address);
    } else {
        printf("Using default I2C address: 0x%02X\n", DEFAULT_I2C_ADDRESS);
    }

    // Initialize pigpio
    if (initialize_pigpio() != 0) {
        return 1;
    }

    // Open I2C connection
    i2c_handle = open_i2c_connection(i2c_address);
    if (i2c_handle < 0) {
        terminate_pigpio();
        return 1;
    }

    // Main loop
    while (1) {
        SensorData data = read_sht40(i2c_handle);

        if (!isnan(data.temperature) && !isnan(data.humidity)) {
            // Get current timestamp
            time_t now = time(NULL);
            struct tm *t = localtime(&now);
            char timestamp[30];
            strftime(timestamp, sizeof(timestamp)-1, "%Y-%m-%d %H:%M:%S", t);

            // Print temperature and humidity
            printf("%s - Temperature: %.2f °C, Humidity: %.2f %%\n", timestamp, data.temperature, data.humidity);
        } else {
            fprintf(stderr, "Failed to read sensor data.\n");
        }

        gpioDelay(5000); // Wait 5 seconds
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <wiringPiI2C.h>
#include <unistd.h>
#include <time.h>
#include <signal.h>

// SCD30 I2C address
#define SCD30_I2C_ADDR 0x61

// SCD30 commands
#define SCD30_CMD_MEASURE 0x0010
#define SCD30_CMD_GET_DATA 0x0300
#define SCD30_CMD_SET_MEASUREMENT_INTERVAL 0x4600
#define SCD30_CMD_GET_STATUS 0xF493

// Global variable for I2C file descriptor
int fd;

// Structure to hold sensor data
typedef struct {
    float co2;
    float temperature;
    float humidity;
} sensor_data_t;

// Function prototypes
int init_scd30();
int read_scd30_data(sensor_data_t *data);
void log_data(sensor_data_t data);
void set_measurement_interval(int interval);

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("\nExiting program.\n");
    exit(0);
}

// Function to initialize the SCD30 sensor
int init_scd30() {
    fd = wiringPiI2CSetup(SCD30_I2C_ADDR);
    if (fd == -1) {
        perror("wiringPiI2CSetup failed");
        return -1;
    }

    // Set measurement interval to 2 seconds
    set_measurement_interval(2);

    return 0;
}

// Function to set the measurement interval
void set_measurement_interval(int interval) {
    uint16_t cmd = SCD30_CMD_SET_MEASUREMENT_INTERVAL;
    uint16_t interval_val = interval;

    wiringPiI2CWriteReg16(fd, cmd, interval_val);
    usleep(10000); // Wait for the command to complete
}

// Function to read data from the SCD30 sensor
int read_scd30_data(sensor_data_t *data) {
    uint16_t cmd = SCD30_CMD_GET_DATA;
    uint8_t buffer[18];
    uint32_t raw_data[3];
    float *float_data = (float *)raw_data;

    // Start measurement
    wiringPiI2CWriteReg16(fd, SCD30_CMD_MEASURE, 0); // Ambient pressure = 0
    usleep(3000); // Wait for measurement to start

    // Wait for data ready status (polling)
    int ready = 0;
    for (int i = 0; i < 10; i++) {
        uint16_t status = wiringPiI2CReadReg16(fd, SCD30_CMD_GET_STATUS);
        if ((status & 0x01) != 0) {
            ready = 1;
            break;
        }
        usleep(100000); // Wait 100ms
    }

    if (!ready) {
        fprintf(stderr, "Data not ready after multiple retries.\n");
        return -1;
    }

    // Read data
    for (int i = 0; i < 18; i++) {
        buffer[i] = wiringPiI2CReadReg8(fd, cmd + i);
    }

    // Convert bytes to float values
    raw_data[0] = (uint32_t)buffer[0] << 24 | (uint32_t)buffer[1] << 16 | (uint32_t)buffer[3] << 8 | (uint32_t)buffer[4];
    raw_data[1] = (uint32_t)buffer[6] << 24 | (uint32_t)buffer[7] << 16 | (uint32_t)buffer[9] << 8 | (uint32_t)buffer[10];
    raw_data[2] = (uint32_t)buffer[12] << 24 | (uint32_t)buffer[13] << 16 | (uint32_t)buffer[15] << 8 | (uint32_t)buffer[16];

    data->co2 = float_data[0];
    data->temperature = float_data[1];
    data->humidity = float_data[2];

    return 0;
}

// Function to log the sensor data to the console
void log_data(sensor_data_t data) {
    time_t rawtime;
    struct tm *timeinfo;

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    char timestamp[20];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    printf("%s - CO2: %.2f ppm, Temperature: %.2f °C, Humidity: %.2f %%\n",
           timestamp, data.co2, data.temperature, data.humidity);
}

int main() {
    // Set up signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Initialize the SCD30 sensor
    if (init_scd30() == -1) {
        fprintf(stderr, "SCD30 initialization failed. Exiting.\n");
        return 1;
    }

    sensor_data_t sensor_data;

    // Main loop to read and log data periodically
    while (1) {
        if (read_scd30_data(&sensor_data) == 0) {
            log_data(sensor_data);
        } else {
            fprintf(stderr, "Failed to read sensor data.\n");
        }

        sleep(2); // Wait for 2 seconds
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <unistd.h>
#include <signal.h>
#include <time.h>
#include <sys/time.h>
#include <bcm2835.h>

// Define GPIO pins for CLK and DATA
#define CLK_PIN RPI_GPIO_23
#define DATA_PIN RPI_GPIO_24

// Define sampling interval (10ms)
#define SAMPLE_INTERVAL_US 10000

// Global flag for graceful shutdown
volatile sig_atomic_t terminate = 0;

// Structure for runtime configuration
typedef struct {
    uint8_t clk_pin;
    uint8_t data_pin;
    uint32_t sample_interval_us;
} config_t;

// Signal handler for SIGINT (Ctrl+C)
void sigint_handler(int signal) {
    printf("\nCaught signal %d, terminating gracefully...\n", signal);
    terminate = 1;
}

// Initialize GPIO using bcm2835 library
int setup_gpio(config_t *config) {
    if (!bcm2835_init()) {
        fprintf(stderr, "bcm2835_init failed. Are you running as root?\n");
        return -1;
    }

    bcm2835_gpio_fsel(config->clk_pin, BCM2835_GPIO_FSEL_INPUT); // Clock as input
    bcm2835_gpio_fsel(config->data_pin, BCM2835_GPIO_FSEL_INPUT); // Data as input

    // Set pull-up/down resistor (optional, depends on your setup)
    // bcm2835_gpio_set_pud(DATA_PIN, BCM2835_GPIO_PUD_UP);

    return 0;
}

// Read a single bit from the microphone
int read_bit(config_t *config) {
    // Wait for clock to go high
    while (bcm2835_gpio_lev(config->clk_pin) == LOW && !terminate) {
        // Optionally add a timeout here to prevent infinite loops
    }
    if(terminate) return -1;

    // Wait for clock to go low
    while (bcm2835_gpio_lev(config->clk_pin) == HIGH && !terminate) {
        // Optionally add a timeout here to prevent infinite loops
    }
    if(terminate) return -1;

    // Read data bit
    return bcm2835_gpio_lev(config->data_pin);
}

// Read a single PCM sample (assuming 16-bit PCM)
int16_t read_sample(config_t *config) {
    int16_t sample = 0;
    for (int i = 0; i < 16; ++i) {
        int bit = read_bit(config);
        if(bit == -1) return 0; //Return 0 to avoid problems
        sample |= (bit << i);
    }
    return sample;
}

// Log PCM data to the console
void log_data(int16_t pcm_value) {
    struct timeval tv;
    gettimeofday(&tv, NULL);
    unsigned long milliseconds = (tv.tv_sec * 1000) + (tv.tv_usec / 1000);
    printf("[%lu] PCM: %d\n", milliseconds, pcm_value);
}

int main(int argc, char **argv) {
    // Install signal handler for graceful shutdown
    signal(SIGINT, sigint_handler);

    // Configuration
    config_t config = {
        .clk_pin = CLK_PIN,
        .data_pin = DATA_PIN,
        .sample_interval_us = SAMPLE_INTERVAL_US
    };

    // Initialize GPIO
    if (setup_gpio(&config) != 0) {
        fprintf(stderr, "GPIO initialization failed.\n");
        return 1;
    }

    printf("Audio sampling started. Press Ctrl+C to terminate.\n");

    // Main loop
    while (!terminate) {
        // Read PCM sample
        int16_t pcm_value = read_sample(&config);

        // Log data
        log_data(pcm_value);

        // Wait for the next sample interval
        usleep(config.sample_interval_us);
    }

    // Clean up GPIO
    bcm2835_close();

    printf("Audio sampling terminated.\n");

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <unistd.h>
#include <pigpio.h>

// Define the I2C bus and address
#define I2C_BUS 1
#define TMP102_ADDR 0x48
#define TEMP_REG 0x00

int i2c_handle;

// Signal handler function
void signal_handler(int signal) {
    printf("Received signal %d, closing I2C and terminating pigpio...\n", signal);
    i2cClose(i2c_handle);
    gpioTerminate();
    exit(0);
}

int main() {
    // Register signal handlers for SIGINT and SIGTERM
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Initialize the pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Open the I2C bus
    i2c_handle = i2cOpen(I2C_BUS, TMP102_ADDR, 0);
    if (i2c_handle < 0) {
        fprintf(stderr, "Failed to open I2C device: %d\n", i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Main loop to read and print temperature data
    while (1) {
        // Read the temperature register
        int raw_value = i2cReadWordData(i2c_handle, TEMP_REG);
        if (raw_value < 0) {
            fprintf(stderr, "Failed to read temperature data: %d\n", raw_value);
            // Attempt to recover; continue to next iteration
            sleep(1); // Wait before retrying
            continue;
        }

        // Convert the raw value to Celsius
        float temperature_celsius = (float)raw_value * 0.0625;

        // Print the temperature to the console
        printf("Temperature: %.2f °C\n", temperature_celsius);

        // Wait for 5 seconds
        sleep(5);
    }

    // The program should never reach here, but include cleanup for safety
    i2cClose(i2c_handle);
    gpioTerminate();
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <unistd.h>
#include <signal.h>
#include <wiringPiI2C.h>

// Define the I2C address of the SDP33 sensor
#define SDP33_I2C_ADDR 0x21

// Define the trigger measurement command
#define TRIGGER_MEASUREMENT_COMMAND_1 0x36
#define TRIGGER_MEASUREMENT_COMMAND_2 0x2F

// Define the scaling factor for pressure calculation
#define PRESSURE_SCALING_FACTOR 60.0

// Global variable to store the I2C file descriptor
int fd;

// Signal handler for Ctrl+C
void signal_handler(int sig) {
    printf("\nExiting program...");
    close(fd); // Close the I2C device
    exit(0);  // Exit the program
}

// Function to initialize the I2C interface
int init_i2c(int devId) {
    fd = wiringPiI2CSetup(devId);
    if (fd == -1) {
        fprintf(stderr, "Error: Failed to initialize I2C interface.\n");
        return -1;
    }
    printf("I2C interface initialized successfully.\n");
    return fd;
}

// Function to read the sensor data
int read_sensor_data(int fd, int *pressure_raw, int *temperature_raw, int *status_word) {
    // Send the trigger measurement command
    if (wiringPiI2CWriteReg8(fd, TRIGGER_MEASUREMENT_COMMAND_1, TRIGGER_MEASUREMENT_COMMAND_2) == -1) {
        fprintf(stderr, "Error: Failed to send trigger measurement command.\n");
        return -1;
    }

    delay(500); // Wait for 500ms

    // Read the sensor data (6 bytes)
    unsigned char data[6];
    for (int i = 0; i < 6; i++) {
        int result = wiringPiI2CRead(fd);
        if (result == -1) {
            fprintf(stderr, "Error: Failed to read byte %d from sensor.\n", i);
            return -1;
        }
        data[i] = (unsigned char)result;
    }

    // Combine the bytes into 16-bit words
    *pressure_raw = (data[0] << 8) | data[1];
    *temperature_raw = (data[2] << 8) | data[3];
    *status_word = (data[4] << 8) | data[5];

    return 0;
}

// Function to calculate the differential pressure in Pascals
float calculate_pressure(int pressure_raw) {
    return (float)pressure_raw / PRESSURE_SCALING_FACTOR;
}

int main() {
    // Register the signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Initialize the I2C interface
    if (init_i2c(SDP33_I2C_ADDR) == -1) {
        return 1;
    }

    int pressure_raw, temperature_raw, status_word;
    float pressure;

    // Main loop
    while (1) {
        // Read the sensor data
        if (read_sensor_data(fd, &pressure_raw, &temperature_raw, &status_word) == -1) {
            fprintf(stderr, "Error: Failed to read sensor data. Retrying in 500ms.\n");
            delay(500);
            continue; // Retry the loop
        }

        // Calculate the differential pressure
        pressure = calculate_pressure(pressure_raw);

        // Print the pressure to the console
        printf("Pressure: %.2f Pa\n", pressure);

        delay(500); // Wait for 500ms
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <wiringPiI2C.h>
#include <wiringPi.h>
#include <unistd.h>
#include <signal.h>

// ADXL345 I2C address
#define ADXL345_ADDRESS 0x53

// ADXL345 register addresses
#define ADXL345_POWER_CTL 0x2D
#define ADXL345_DATAX0 0x32

// Global variable for I2C file descriptor
int fd;

// Structure to hold accelerometer data
typedef struct {
    int16_t x;
    int16_t y;
    int16_t z;
} accelerometer_data_t;

// Function to handle Ctrl+C signal (graceful exit)
void signal_handler(int signum) {
    printf("\nExiting gracefully.\n");
    close(fd);
    exit(0);
}

// Function to initialize the ADXL345 accelerometer
int initialize_accelerometer() {
    // Initialize wiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "wiringPiSetup failed\n");
        return -1;
    }

    // Open I2C device
    fd = wiringPiI2CSetup(ADXL345_ADDRESS);
    if (fd == -1) {
        fprintf(stderr, "wiringPiI2CSetup failed\n");
        return -1;
    }

    // Set POWER_CTL register to start measurement
    wiringPiI2CWriteReg8(fd, ADXL345_POWER_CTL, 0x08); // Enable measurement
    delay(100); // Short delay after initialization

    return 0;
}

// Function to read accelerometer data
int read_accelerometer_data(accelerometer_data_t *data) {
    int16_t x, y, z;

    // Read X, Y, and Z axis data (6 bytes)
    x = wiringPiI2CReadReg16(fd, ADXL345_DATAX0);
    y = wiringPiI2CReadReg16(fd, ADXL345_DATAX0 + 2);
    z = wiringPiI2CReadReg16(fd, ADXL345_DATAX0 + 4);

    if (x == -1 || y == -1 || z == -1) {
        fprintf(stderr, "Error reading accelerometer data\n");
        return -1;
    }

    data->x = x;
    data->y = y;
    data->z = z;

    return 0;
}

// Function to print accelerometer data
void print_accelerometer_data(accelerometer_data_t data) {
    printf("X: %6d, Y: %6d, Z: %6d\n", data.x, data.y, data.z);
}

int main() {
    // Register signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Initialize accelerometer
    if (initialize_accelerometer() == -1) {
        return 1;
    }

    accelerometer_data_t data;

    // Main loop
    while (1) {
        // Read accelerometer data
        if (read_accelerometer_data(&data) == 0) {
            // Print accelerometer data
            print_accelerometer_data(data);
        } else {
            fprintf(stderr, "Failed to read data, retrying...\n");
        }

        // Delay for 200ms
        delay(200);
    }

    return 0;
}

#include <stdio.h>
