// Define UART port
#define UART_PORT "/dev/ttyS0" // or /dev/ttyAMA0

// Define baud rate
#define BAUD_RATE B115200

// Define data structure for radar readings
typedef struct {
    float range;
    float velocity;
} RadarData;

// Global variable for UART file descriptor
int uart_fd = -1;

// Signal handler for graceful shutdown
void signal_handler(int signum) {
    printf("\nCaught signal %d, exiting gracefully...\n", signum);
    if (uart_fd != -1) {
        close(uart_fd);
    }
    exit(0);
}

// Function to initialize UART
int init_uart(const char *port, speed_t baud_rate) {
    int fd = open(port, O_RDWR | O_NOCTTY | O_SYNC);
    if (fd == -1) {
        perror("Error opening UART port");
        return -1;
    }

    struct termios tty;
    if (tcgetattr(fd, &tty) != 0) {
        perror("Error getting termios attributes");
        close(fd);
        return -1;
    }

    tty.c_cflag = (tty.c_cflag & ~CSIZE) | CS8;     // 8-bit chars
    tty.c_iflag &= ~IGNBRK;         // disable break processing
    tty.c_lflag = 0;                // no signaling chars, no echo, no canonical processing
    tty.c_oflag = 0;                // no remapping, no delays
    tty.c_cc[VMIN]  = 0;            // read doesn't block
    tty.c_cc[VTIME] = 5;            // 0.5 seconds read timeout

    tty.c_iflag &= ~(IXON | IXOFF | IXANY); // shut off xon/xoff ctrl

    tty.c_cflag |= (CLOCAL | CREAD);// ignore modem controls, enable reading
    tty.c_cflag &= ~(PARENB | PARODD);      // shut off parity
    tty.c_cflag &= ~CSTOPB;
    tty.c_cflag &= ~CRTSCTS;

    if (cfsetospeed(&tty, baud_rate) != 0 || cfsetispeed(&tty, baud_rate) != 0) {
        perror("Error setting baud rate");
        close(fd);
        return -1;
    }

    if (tcsetattr(fd, TCSANOW, &tty) != 0) {
        perror("Error setting termios attributes");
        close(fd);
        return -1;
    }

    return fd;
}

// Function to read radar data from UART
int read_radar_data(int fd, RadarData *data) {
    // Implement your radar data parsing logic here
    // This is a placeholder; replace with actual data reception and parsing
    // based on the IWR1443's UART output format.

    // Example: Assume data is received as two floats separated by a comma and newline
    char buffer[64];
    ssize_t bytes_read = read(fd, buffer, sizeof(buffer) - 1);

    if (bytes_read > 0) {
        buffer[bytes_read] = '\0';
        //printf("Received: %s", buffer);
        if (sscanf(buffer, "%f,%f", &data->range, &data->velocity) == 2) {
            return 0; // Success
        } else {
            fprintf(stderr, "Error parsing radar data: %s", buffer);
            return -1; // Parsing error
        }
    } else if (bytes_read == 0) {
        fprintf(stderr, "Timeout reading from UART\n");
        return -1; // Timeout
    } else {
        perror("Error reading from UART");
        return -1; // Read error
    }
}

// Function to log radar data with timestamp
void log_radar_data(const RadarData *data) {
    struct timeval tv;
    gettimeofday(&tv, NULL);
    time_t nowtime = tv.tv_sec;
    struct tm *nowtm = localtime(&nowtime);
    char tmbuf[64], buf[64];
    strftime(tmbuf, sizeof(tmbuf), "%Y-%m-%d %H:%M:%S", nowtm);
    snprintf(buf, sizeof(buf), "%s.%06ld", tmbuf, tv.tv_usec);

    printf("[%s] Range: %.2f m, Velocity: %.2f m/s\n", buf, data->range, data->velocity);
}

int main() {
    // Install signal handler
    signal(SIGINT, signal_handler);

    // Initialize UART
    uart_fd = init_uart(UART_PORT, BAUD_RATE);
    if (uart_fd == -1) {
        return EXIT_FAILURE;
    }

    RadarData radar_data;

    // Main loop
    while (1) {
        if (read_radar_data(uart_fd, &radar_data) == 0) {
            log_radar_data(&radar_data);
        } else {
            fprintf(stderr, "Failed to read radar data. Retrying...\n");
        }

        sleep(1); // Read data every 1 second
    }

    // Cleanup (should not reach here normally due to the signal handler)
    close(uart_fd);
    return EXIT_SUCCESS;
}

