// Define the I2C address of the Si1120 sensor
#define SI1120_ADDR 0x60

// Define register addresses
#define REG_ALS_VIS_DATA0 0x22
#define REG_PS1_DATA0     0x24

// Error handling macro
#define CHECK_ERROR(ret, msg) \
    if (ret < 0) { \
        fprintf(stderr, "%s error: %s\n", msg, strerror(errno)); \
        close(i2c_fd); \
        return 1; \
    }

// Function to read a register from the Si1120 sensor
int read_register(int i2c_fd, uint8_t reg_addr, uint8_t *data) {
    int ret;

    // Write the register address to the sensor
    ret = write(i2c_fd, &reg_addr, 1);
    if (ret != 1) {
        return -1;
    }

    // Read the data from the sensor
    ret = read(i2c_fd, data, 1);
    if (ret != 1) {
        return -1;
    }

    return 0;
}

// Function to read a 16-bit value from the Si1120 sensor
uint16_t read_16bit_register(int i2c_fd, uint8_t reg_addr) {
    uint8_t data[2];
    read_register(i2c_fd, reg_addr, &data[0]);
    read_register(i2c_fd, reg_addr + 1, &data[1]);
    return (uint16_t)data[0] | ((uint16_t)data[1] << 8);
}

int main() {
    int i2c_fd;
    int ret;
    uint16_t als_vis;
    uint16_t ps1;
    struct timespec sleep_time = {0, 500000000}; // 500ms

    // Open the I2C device
    i2c_fd = open("/dev/i2c-1", O_RDWR);
    if (i2c_fd < 0) {
        perror("Error opening I2C device");
        return 1;
    }

    // Specify the address of the slave device
    ret = ioctl(i2c_fd, I2C_SLAVE, SI1120_ADDR);
    CHECK_ERROR(ret, "ioctl I2C_SLAVE");

    /* Main loop */
    while (1) {
        als_vis = read_16bit_register(i2c_fd, REG_ALS_VIS_DATA0);
        ps1 = read_16bit_register(i2c_fd, REG_PS1_DATA0);

        // Print the sensor data
        printf("ALS Visible: %u, Proximity: %u\n", als_vis, ps1);

        nanosleep(&sleep_time, NULL);
    }

    close(i2c_fd);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <unistd.h>
#include <signal.h>

// Define the I2C bus and address
#define I2C_BUS 1
#define SI1120_ADDR 0x60

// Define Si1120 register addresses (consult datasheet for accurate values)
#define REG_PART_ID 0x00
#define REG_RST_CMD 0x07
#define REG_MEAS_RATE 0x03
#define REG_ALS_RATE 0x04
#define REG_PS_RATE 0x05
#define REG_ALS_DATA 0x22 // Example address, verify from datasheet
#define REG_PS_DATA 0x24  // Example address, verify from datasheet
#define REG_PS_LED21_SELECT 0x1E
#define REG_PS_LED_DRIVE 0x0F
#define REG_PS_ADC_MUX_SETTINGS 0x0E

int i2c_handle;

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("\nCaught signal %d, cleaning up...\n", signal);
    i2cClose(i2c_handle);
    gpioTerminate();
    exit(0);
}

// Function to write a single byte to a Si1120 register
int si1120_write_register(int handle, int reg, int value) {
    int result = i2cWriteByteData(handle, reg, value);
    if (result != 0) {
        fprintf(stderr, "Error writing to register 0x%02X: %d\n", reg, result);
        return -1;
    }
    return 0;
}

// Function to read a single byte from a Si1120 register
int si1120_read_register(int handle, int reg) {
    int result = i2cReadByteData(handle, reg);
    if (result < 0) {
        fprintf(stderr, "Error reading from register 0x%02X: %d\n", reg, result);
        return -1;
    }
    return result;
}

// Function to initialize the Si1120 sensor
int si1120_init(int handle) {
    // Reset the Si1120
    if (si1120_write_register(handle, REG_RST_CMD, 0x00) != 0) {
        return -1;
    }
    gpioDelay(10); // Wait for reset to complete

    // Configure measurement rates
    if (si1120_write_register(handle, REG_MEAS_RATE, 8) != 0) { // 8 measurements per second
        return -1;
    }
    if (si1120_write_register(handle, REG_ALS_RATE, 8) != 0) {
        return -1;
    }
    if (si1120_write_register(handle, REG_PS_RATE, 8) != 0) {
        return -1;
    }

    // Configure proximity sensor parameters (example values, adjust as needed)
    if (si1120_write_register(handle, REG_PS_LED21_SELECT, 0x01) != 0) { // Use LED1
        return -1;
    }
    if (si1120_write_register(handle, REG_PS_LED_DRIVE, 0x20) != 0) { // LED drive strength
        return -1;
    }
    if (si1120_write_register(handle, REG_PS_ADC_MUX_SETTINGS, 0x03) != 0) { //Proximity channel
        return -1;
    }

    // Start measurements (consult datasheet for the correct command)
    if (si1120_write_register(handle, REG_RST_CMD, 0x01) != 0) { // Start
        return -1;
    }

    return 0;
}

// Function to read ambient light and proximity data
int si1120_read_data(int handle, int *ambient_light, int *proximity) {
    int als_low, als_high, ps_low, ps_high;

    // Read ambient light data
    als_low = si1120_read_register(handle, REG_ALS_DATA);
    if (als_low < 0) return -1;
    als_high = si1120_read_register(handle, REG_ALS_DATA + 1);
    if (als_high < 0) return -1;
    *ambient_light = (als_high << 8) | als_low;

    // Read proximity data
    ps_low = si1120_read_register(handle, REG_PS_DATA);
    if (ps_low < 0) return -1;
    ps_high = si1120_read_register(handle, REG_PS_DATA + 1);
    if (ps_high < 0) return -1;
    *proximity = (ps_high << 8) | ps_low;

    return 0;
}

int main() {
    // Register signal handlers for graceful shutdown
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Initialize the pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set sampling rate
    gpioCfgClock(5, 1, 0); // 5us sampling rate

    // Open the I2C device
    i2c_handle = i2cOpen(I2C_BUS, SI1120_ADDR, 0);
    if (i2c_handle < 0) {
        fprintf(stderr, "Error opening I2C device: %d\n", i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Initialize the Si1120 sensor
    if (si1120_init(i2c_handle) != 0) {
        fprintf(stderr, "Si1120 initialisation failed\n");
        i2cClose(i2c_handle);
        gpioTerminate();
        return 1;
    }

    int ambient_light, proximity;

    // Continuously read and display sensor data
    while (1) {
        if (si1120_read_data(i2c_handle, &ambient_light, &proximity) == 0) {
            printf("Ambient Light: %d, Proximity: %d\n", ambient_light, proximity);
        } else {
            fprintf(stderr, "Error reading sensor data\n");
        }

        gpioDelay(100); // 100ms delay
    }

    // The following lines will never be reached in normal execution
    // because the while(1) loop runs indefinitely.  However, they
    // are included for completeness.
    i2cClose(i2c_handle);
    gpioTerminate();
    return 0;
}

