// Define sensor address and register addresses
#define SI1182_ADDR 0x49
#define SI1182_ALS_VIS_DATA0 0x14

// Global variable for I2C file descriptor
int i2c_fd;

// Function to handle Ctrl+C signal
void signal_handler(int sig) {
    printf("\nExiting program.\n");
    close(i2c_fd);
    exit(0);
}

// Function to initialize I2C communication
int init_i2c(const char *device) {
    int fd = open(device, O_RDWR);
    if (fd < 0) {
        perror("Error opening I2C device");
        return -1;
    }

    if (ioctl(fd, I2C_SLAVE, SI1182_ADDR) < 0) {
        perror("Error setting I2C slave address");
        close(fd);
        return -1;
    }

    return fd;
}

// Function to read data from the sensor
int16_t read_sensor_data() {
    uint8_t buf[2];

    // Read two bytes from the sensor
    if (read(i2c_fd, buf, 2) != 2) {
        perror("Error reading sensor data");
        return -1;
    }

    // Combine the two bytes into a 16-bit value
    return (int16_t)((buf[1] << 8) | buf[0]);
}

int write_register(uint8_t reg, uint8_t value) {
    uint8_t buf[2];
    buf[0] = reg;
    buf[1] = value;

    if (write(i2c_fd, buf, 2) != 2) {
        perror("Error writing to register");
        return -1;
    }
    return 0;
}

int main() {
    // Register signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Initialize I2C
    i2c_fd = init_i2c("/dev/i2c-1");
    if (i2c_fd < 0) {
        return 1;
    }

    // Initialize sensor (example initialization sequence)
    if (write_register(0x18, 0x0F) < 0) {
        fprintf(stderr, "Error initializing sensor\n");
        close(i2c_fd);
        return 1;
    }
    if (write_register(0x17, 0x00) < 0) {
        fprintf(stderr, "Error initializing sensor\n");
        close(i2c_fd);
        return 1;
    }
    if (write_register(0x03, 0x01) < 0) {
        fprintf(stderr, "Error initializing sensor\n");
        close(i2c_fd);
        return 1;
    }

    // Main loop
    while (1) {
        // Set register to read from
        uint8_t reg = SI1182_ALS_VIS_DATA0;
        if (write(i2c_fd, &reg, 1) != 1) {
            perror("Error setting register address");
            sleep(1); // Wait before retrying
            continue;
        }

        // Read sensor data
        int16_t proximity_data = read_sensor_data();

        // Check for errors
        if (proximity_data < 0) {
            fprintf(stderr, "Error reading proximity data\n");
        } else {
            // Print the sensor data
            printf("Proximity Data: %d\n", proximity_data);
        }

        // Wait for 500ms
        usleep(500000);
    }

    // Close I2C device (never reached in normal execution)
    close(i2c_fd);
    return 0;
}

#include <stdio.h>
