// Configuration
#define SPI_DEVICE "/dev/spidev0.0" // SPI device
#define SPI_MODE SPI_MODE_0
#define SPI_BITS_PER_WORD 8
#define SPI_SPEED 1000000 // 1 MHz
#define MCP3008_CHANNEL 0 // CO sensor connected to channel 0
#define READ_INTERVAL_SEC 5

// Global Variables
static int spi_fd; // SPI file descriptor
static volatile sig_atomic_t keep_running = 1; // Flag to control the main loop

// Structure for storing sensor data
typedef struct {
    time_t timestamp;
    float co_ppm;
} sensor_data_t;

// Function Prototypes
int spi_setup(const char *device);
int spi_transfer(int spi_fd, unsigned char *data, int len);
int read_mcp3008(int spi_fd, int channel);
float adc_to_ppm(int adc_value);
void log_data(sensor_data_t data);
void signal_handler(int signal);

// Function to handle Ctrl+C signal
void signal_handler(int signal) {
    keep_running = 0;
    printf("\nExiting gracefully...\n");
}

// Function to set up the SPI interface
int spi_setup(const char *device) {
    int fd;
    // Open SPI device
    if ((fd = open(device, O_RDWR)) < 0) {
        perror("Error opening SPI device");
        return -1;
    }

    // Set SPI mode
    uint8_t mode = SPI_MODE;
    if (ioctl(fd, SPI_IOC_WR_MODE, &mode) < 0) {
        perror("Error setting SPI mode");
        close(fd);
        return -1;
    }

    // Set bits per word
    uint8_t bits = SPI_BITS_PER_WORD;
    if (ioctl(fd, SPI_IOC_WR_BITS_PER_WORD, &bits) < 0) {
        perror("Error setting bits per word");
        close(fd);
        return -1;
    }

    // Set SPI speed
    uint32_t speed = SPI_SPEED;
    if (ioctl(fd, SPI_IOC_WR_MAX_SPEED_HZ, &speed) < 0) {
        perror("Error setting SPI speed");
        close(fd);
        return -1;
    }

    return fd;
}

// Function to transfer data over SPI
int spi_transfer(int spi_fd, unsigned char *data, int len) {
    struct spi_ioc_transfer tr = {
        .tx_buf = (unsigned long)data,
        .rx_buf = (unsigned long)data,
        .len = len,
        .delay_usecs = 0,
        .speed_hz = SPI_SPEED,
        .bits_per_word = SPI_BITS_PER_WORD,
    };

    if (ioctl(spi_fd, SPI_IOC_MESSAGE(1), &tr) < 0) {
        perror("Error sending SPI message");
        return -1;
    }
    return 0;
}

// Function to read data from MCP3008 ADC
int read_mcp3008(int spi_fd, int channel) {
    unsigned char data[3];

    data[0] = 1; // Start bit
    data[1] = (0x08 | channel) << 4; // Single-ended mode, channel selection
    data[2] = 0; // Dummy byte

    if (spi_transfer(spi_fd, data, 3) < 0) {
        fprintf(stderr, "SPI transfer failed\n");
        return -1;
    }

    // Extract ADC value
    int adc_value = ((data[1] & 0x03) << 8) + data[2];
    return adc_value;
}

// Function to convert ADC value to CO concentration (ppm)
float adc_to_ppm(int adc_value) {
    // This is a placeholder.  Calibration is necessary to map ADC values to actual PPM.
    // You'll need to calibrate the sensor and determine the correct formula.
    // For example, assuming a linear relationship:
    // float ppm = (float)adc_value / 1023.0 * MAX_PPM; // MAX_PPM would need to be determined
    // Replace with your calibrated formula.
    return (float)adc_value / 1023.0 * 100.0; // Placeholder - replace with actual calibration
}

// Function to log sensor data to the console
void log_data(sensor_data_t data) {
    char timestamp_str[30];
    struct tm *tm_info = localtime(&data.timestamp);
    strftime(timestamp_str, sizeof(timestamp_str), "%Y-%m-%d %H:%M:%S", tm_info);

    printf("[%s] CO Concentration: %.2f ppm\n", timestamp_str, data.co_ppm);
}

int main() {
    // Install signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Initialize SPI
    spi_fd = spi_setup(SPI_DEVICE);
    if (spi_fd < 0) {
        fprintf(stderr, "SPI setup failed\n");
        return 1;
    }

    printf("CO Sensor Monitoring Started (Ctrl+C to exit)\n");

    while (keep_running) {
        // Read CO concentration
        int adc_value = read_mcp3008(spi_fd, MCP3008_CHANNEL);
        if (adc_value < 0) {
            fprintf(stderr, "Failed to read CO concentration. Retrying in %d seconds.\n", READ_INTERVAL_SEC);
            sleep(READ_INTERVAL_SEC);
            continue;
        }

        // Convert ADC value to PPM
        float co_ppm = adc_to_ppm(adc_value);

        // Get current timestamp
        time_t now = time(NULL);

        // Store sensor data
        sensor_data_t data = {
            .timestamp = now,
            .co_ppm = co_ppm
        };

        // Log the data
        log_data(data);

        // Wait for the next reading
        sleep(READ_INTERVAL_SEC);
    }

    // Close SPI device
    close(spi_fd);

    return 0;
}

