// Define the SHT31-DIS-B sensor I2C address (can be 0x44 or 0x45)
#define SHT31_ADDR_DEFAULT 0x44

// Define the measurement command (High Repeatability Mode)
#define SHT31_MEASURE_CMD 0x2C06

// Global variables
int i2c_handle;
int i2c_bus;
int i2c_address;

// Function to calculate CRC-8 checksum
uint8_t crc8(const uint8_t *data, int len) {
    uint8_t crc = 0xFF;
    for (int i = 0; i < len; i++) {
        crc ^= data[i];
        for (int j = 0; j < 8; j++) {
            if (crc & 0x80) {
                crc = (crc << 1) ^ 0x31; // Polynomial 0x31
            } else {
                crc <<= 1;
            }
        }
    }
    return crc;
}

// Function to read temperature and humidity from the sensor
int read_sht31(float *temperature, float *humidity) {
    uint8_t write_data[2];
    uint8_t read_data[6];

    // Send measurement command
    write_data[0] = (SHT31_MEASURE_CMD >> 8) & 0xFF;
    write_data[1] = SHT31_MEASURE_CMD & 0xFF;

    int w = i2cWriteDevice(i2c_handle, (char *)write_data, 2);
    if (w != 2) {
        fprintf(stderr, "Error writing to I2C device: %d\n", w);
        return -1;
    }

    // Wait for measurement to complete (typical time is 10ms for high repeatability)
    gpioDelay(20000); // 20 ms

    // Read 6 bytes of data (T_MSB, T_LSB, T_CRC, H_MSB, H_LSB, H_CRC)
    int r = i2cReadDevice(i2c_handle, (char *)read_data, 6);
    if (r != 6) {
        fprintf(stderr, "Error reading from I2C device: %d\n", r);
        return -1;
    }

    // CRC check for temperature
    if (crc8(read_data, 2) != read_data[2]) {
        fprintf(stderr, "Temperature CRC check failed!\n");
        return -1;
    }

    // CRC check for humidity
    if (crc8(read_data + 3, 2) != read_data[5]) {
        fprintf(stderr, "Humidity CRC check failed!\n");
        return -1;
    }

    // Convert raw data to temperature (degrees Celsius)
    uint16_t raw_temperature = (read_data[0] << 8) | read_data[1];
    *temperature = -45.0 + (175.0 * (float)raw_temperature / 65535.0);

    // Convert raw data to humidity (%RH)
    uint16_t raw_humidity = (read_data[3] << 8) | read_data[4];
    *humidity = 100.0 * (float)raw_humidity / 65535.0;

    return 0;
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("Received signal %d, closing I2C and terminating pigpio...\n", signal);
    i2cClose(i2c_handle);
    gpioTerminate();
    exit(0);
}

int main(int argc, char *argv[]) {
    // Parse command-line arguments
    if (argc != 3) {
        fprintf(stderr, "Usage: %s <i2c_bus> <i2c_address>\n", argv[0]);
        return 1;
    }

    i2c_bus = atoi(argv[1]);
    i2c_address = strtol(argv[2], NULL, 0); // Allow hex or decimal

    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Open I2C connection
    i2c_handle = i2cOpen(i2c_bus, i2c_address, 0);
    if (i2c_handle < 0) {
        fprintf(stderr, "Error opening I2C device: %d\n", i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Register signal handlers
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Main loop
    float temperature, humidity;
    while (1) {
        // Read temperature and humidity
        if (read_sht31(&temperature, &humidity) == 0) {
            // Get current timestamp
            time_t now = time(NULL);
            struct tm *t = localtime(&now);
            char timestamp[30];
            strftime(timestamp, sizeof(timestamp)-1, "%Y-%m-%d %H:%M:%S", t);

            // Log data to console
            printf("%s - Temperature: %.2f °C, Humidity: %.2f %%\n", timestamp, temperature, humidity);
        } else {
            fprintf(stderr, "Failed to read sensor data. Retrying in 5 seconds...\n");
        }

        // Wait 5 seconds
        gpioDelay(5000000); // 5 seconds
    }

    // The following lines will never be reached due to the infinite loop, but are included for completeness.
    i2cClose(i2c_handle);
    gpioTerminate();
    return 0;
}

