int spi_read(int fd, uint8_t *data, int len) {
    struct spi_ioc_transfer transfer = {
        .tx_buf = (unsigned long)NULL, // Read only
        .rx_buf = (unsigned long)data,
        .len = len,
        .speed_hz = SPI_MAX_SPEED,
        .bits_per_word = SPI_BITS_PER_WORD,
    };

    int status = ioctl(fd, SPI_IOC_MESSAGE(1), &transfer);
    if (status < 0) {
        perror("Error during SPI transfer");
        return -1;
    }

    return 0;
}

// Function to read flow sensor data
double read_flow_sensor(int fd, const sensor_config_t *config) {
    uint8_t rx_data[2]; // Assuming 2 bytes of data from the sensor

    // Read data from SPI
    if (spi_read(fd, rx_data, sizeof(rx_data)) != 0) {
        fprintf(stderr, "Error reading flow sensor data\n");
        return -1.0; // Indicate error
    }

    // Combine the bytes into a 16-bit value
    uint16_t raw_value = (rx_data[0] << 8) | rx_data[1];

    // Convert raw value to flow rate (example conversion, adjust as needed)
    double flow_rate = (double)raw_value / config->sensor_resolution * config->sensor_voltage;

    return flow_rate;
}

// Function to log the flow rate data
void log_data(double flow_rate) {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[80];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    printf("[%s] Flow Rate: %.2f L/min\n", timestamp, flow_rate);
}

int main() {
    // Register signal handler for graceful termination
    signal(SIGINT, sigint_handler);

    // Sensor configuration
    sensor_config_t config = {
        .spi_device = SPI_DEVICE,
        .spi_mode = SPI_MODE,
        .spi_bits_per_word = SPI_BITS_PER_WORD,
        .spi_max_speed = SPI_MAX_SPEED,
        .sensor_resolution = FLOW_SENSOR_RESOLUTION,
        .sensor_voltage = FLOW_SENSOR_VOLTAGE
    };

    // Initialize SPI
    int spi_fd = spi_init(config.spi_device);
    if (spi_fd < 0) {
        return EXIT_FAILURE;
    }

    // Main loop
    while (!terminate) {
        // Read flow sensor data
        double flow_rate = read_flow_sensor(spi_fd, &config);

        if (flow_rate >= 0.0) {
            // Log the data
            log_data(flow_rate);
        } else {
            fprintf(stderr, "Failed to read flow rate. Retrying...\n");
        }

        // Wait for a short interval (adjust as needed)
        sleep(1);
    }

    // Close SPI device
    close(spi_fd);

    return EXIT_SUCCESS;
}

