// MPU6050 Register Map
#define MPU6050_ADDR 0x68
#define MPU6050_PWR_MGMT_1 0x6B
#define MPU6050_ACCEL_XOUT_H 0x3B
#define MPU6050_GYRO_XOUT_H 0x43

// Configuration Structure
typedef struct {
    int i2c_fd;
    char *i2c_device;
    bool running;
} mpu6050_config_t;

// Function Prototypes
int mpu6050_init(mpu6050_config_t *config);
int16_t read_raw_data(int fd, uint8_t addr);
void read_sensor_data(int fd, float *accel_x, float *accel_y, float *accel_z, float *gyro_x, float *gyro_y, float *gyro_z);
void log_data(float accel_x, float accel_y, float accel_z, float gyro_x, float gyro_y, float gyro_z);
void signal_handler(int signal);

mpu6050_config_t config = { .running = true };

int main() {
    config.i2c_device = "/dev/i2c-1";

    if (mpu6050_init(&config) != 0) {
        fprintf(stderr, "MPU6050 initialization failed.\n");
        return 1;
    }

    signal(SIGINT, signal_handler);

    float accel_x, accel_y, accel_z, gyro_x, gyro_y, gyro_z;

    while (config.running) {
        read_sensor_data(config.i2c_fd, &accel_x, &accel_y, &accel_z, &gyro_x, &gyro_y, &gyro_z);
        log_data(accel_x, accel_y, accel_z, gyro_x, gyro_y, gyro_z);
        usleep(50000); // 50ms delay
    }

    close(config.i2c_fd);
    printf("Program terminated.\n");
    return 0;
}

// Initialize the MPU6050 sensor
int mpu6050_init(mpu6050_config_t *config) {
    config->i2c_fd = open(config->i2c_device, O_RDWR);
    if (config->i2c_fd < 0) {
        perror("Failed to open I2C device");
        return -1;
    }

    if (ioctl(config->i2c_fd, I2C_SLAVE, MPU6050_ADDR) < 0) {
        perror("Failed to acquire bus access and/or talk to slave");
        close(config->i2c_fd);
        return -1;
    }

    // Wake up the MPU6050
    uint8_t wake_up_data[2] = {MPU6050_PWR_MGMT_1, 0x00};
    if (write(config->i2c_fd, wake_up_data, 2) != 2) {
        perror("Failed to write to I2C device");
        close(config->i2c_fd);
        return -1;
    }

    return 0;
}

// Read raw sensor data from a specific register
int16_t read_raw_data(int fd, uint8_t addr) {
    uint8_t data[2];
    if (write(fd, &addr, 1) != 1) {
        perror("Failed to write address to I2C device");
        return 0; //Return 0 on error, handle it in caller function
    }

    if (read(fd, data, 2) != 2) {
        perror("Failed to read data from I2C device");
        return 0; //Return 0 on error, handle it in caller function
    }

    return (int16_t)((data[0] << 8) | data[1]);
}

// Read and process sensor data
void read_sensor_data(int fd, float *accel_x, float *accel_y, float *accel_z, float *gyro_x, float *gyro_y, float *gyro_z) {
    *accel_x = (float)read_raw_data(fd, MPU6050_ACCEL_XOUT_H) / 16384.0;
    *accel_y = (float)read_raw_data(fd, MPU6050_ACCEL_XOUT_H + 2) / 16384.0;
    *accel_z = (float)read_raw_data(fd, MPU6050_ACCEL_XOUT_H + 4) / 16384.0;
    *gyro_x = (float)read_raw_data(fd, MPU6050_GYRO_XOUT_H) / 131.0;
    *gyro_y = (float)read_raw_data(fd, MPU6050_GYRO_XOUT_H + 2) / 131.0;
    *gyro_z = (float)read_raw_data(fd, MPU6050_GYRO_XOUT_H + 4) / 131.0;
}

// Log sensor data to the console
void log_data(float accel_x, float accel_y, float accel_z, float gyro_x, float gyro_y, float gyro_z) {
    printf("Accel: X=%.2f, Y=%.2f, Z=%.2f | Gyro: X=%.2f, Y=%.2f, Z=%.2f\n",
           accel_x, accel_y, accel_z, gyro_x, gyro_y, gyro_z);
}

// Signal handler to gracefully exit the program
void signal_handler(int signal) {
    if (signal == SIGINT) {
        printf("SIGINT received, exiting...\n");
        config.running = false;
    }
}

#include <stdio.h>
