// Define the I2C address of the SDP810 sensor.
#define SDP810_I2C_ADDR 0x25

// Define commands for the SDP810 sensor.
#define TRIGGER_MEASUREMENT 0x362F // Trigger measurement without averaging

// Define a structure to hold the sensor data.
typedef struct {
    int16_t differential_pressure;
    int16_t temperature;
    uint16_t status;
} sdp810_data_t;

// Global variable to control the main loop.
volatile sig_atomic_t running = 1;

// Signal handler for graceful shutdown.
void sigint_handler(int signal) {
    running = 0;
    printf("\nExiting gracefully...\n");
}

// Function to initialize the I2C bus.
int i2c_init(const char *device) {
    int fd = open(device, O_RDWR);
    if (fd < 0) {
        fprintf(stderr, "Error opening I2C device: %s\n", strerror(errno));
        return -1;
    }

    if (ioctl(fd, I2C_SLAVE, SDP810_I2C_ADDR) < 0) {
        fprintf(stderr, "Error setting I2C slave address: %s\n", strerror(errno));
        close(fd);
        return -1;
    }

    return fd;
}

// Function to read data from the SDP810 sensor.
int read_sdp810_data(int fd, sdp810_data_t *data) {
    uint8_t buffer[9];
    int16_t temp;

    // Send the trigger measurement command.
    uint8_t command[2] = {(TRIGGER_MEASUREMENT >> 8) & 0xFF, TRIGGER_MEASUREMENT & 0xFF};
    if (write(fd, command, 2) != 2) {
        fprintf(stderr, "Error writing to I2C device: %s\n", strerror(errno));
        return -1;
    }

    // Wait for the measurement to complete (adjust as needed).
    usleep(100000); // 100 ms

    // Read the data from the sensor.
    if (read(fd, buffer, 9) != 9) {
        fprintf(stderr, "Error reading from I2C device: %s\n", strerror(errno));
        return -1;
    }

    // Parse the data.
    data->differential_pressure = (buffer[0] << 8) | buffer[1];
    data->temperature = (buffer[3] << 8) | buffer[4];
    data->status = (buffer[6] << 8) | buffer[7];

    return 0;
}

// Function to log the sensor data to the console.
void log_data(const sdp810_data_t *data) {
    struct timeval tv;
    gettimeofday(&tv, NULL);
    time_t nowtime = tv.tv_sec;
    struct tm *nowtm = localtime(&nowtime);
    char tmbuf[64], buf[64];
    strftime(tmbuf, sizeof(tmbuf), "%Y-%m-%d %H:%M:%S", nowtm);
    snprintf(buf, sizeof(buf), "%s.%06ld", tmbuf, tv.tv_usec);

    printf("%s, Differential Pressure: %d Pa, Temperature: %d (raw), Status: 0x%04X\n",
           buf, data->differential_pressure, data->temperature, data->status);
}

int main() {
    int fd;
    sdp810_data_t sensor_data;

    // Install signal handler for graceful shutdown.
    signal(SIGINT, sigint_handler);

    // Initialize the I2C bus.
    fd = i2c_init("/dev/i2c-1");
    if (fd < 0) {
        return 1;
    }

    // Main loop to read and log sensor data.
    while (running) {
        if (read_sdp810_data(fd, &sensor_data) == 0) {
            log_data(&sensor_data);
        } else {
            fprintf(stderr, "Error reading sensor data.\n");
        }

        sleep(1); // Read data every 1 second.
    }

    // Close the I2C device.
    close(fd);

    return 0;
}

#include <stdio.h>
