// Define the GPIO pins connected to the touch sensor channels
#define NUM_CHANNELS 8
const int touch_pins[NUM_CHANNELS] = {4, 17, 18, 27, 22, 23, 24, 25}; // Example GPIO pins

// Structure to hold sensor data
typedef struct {
    int channel;
    int value;
    struct timespec timestamp;
} SensorData;

// Global flag to signal program termination
volatile sig_atomic_t terminate = 0;

// Signal handler for graceful shutdown
void signal_handler(int signum) {
    terminate = 1;
    printf("\nCaught signal %d, terminating...\n", signum);
}

// Function to initialize GPIO pins using wiringPi
int setup_gpio() {
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "Error initializing wiringPi: %s\n", strerror(errno));
        return -1;
    }

    for (int i = 0; i < NUM_CHANNELS; i++) {
        pinMode(touch_pins[i], INPUT);
        pullUpDnControl(touch_pins[i], PUD_DOWN); // Enable pull-down resistor
    }

    return 0;
}

// Function to read the sensor data for a given channel
int read_sensor(int channel) {
    return digitalRead(touch_pins[channel]);
}

// Function to get the current timestamp
struct timespec get_timestamp() {
    struct timespec ts;
    clock_gettime(CLOCK_REALTIME, &ts);
    return ts;
}

// Function to log the sensor data to the console
void log_data(SensorData data) {
    char timestamp_str[30];
    strftime(timestamp_str, sizeof(timestamp_str), "%Y-%m-%d %H:%M:%S", localtime(&data.timestamp.tv_sec));
    printf("%s.%09ld Channel %d: %s\n", timestamp_str, data.timestamp.tv_nsec, data.channel, data.value ? "HIGH" : "LOW");
}

int main() {
    // Install signal handler
    signal(SIGINT, signal_handler);

    // Initialize GPIO
    if (setup_gpio() == -1) {
        return 1;
    }

    printf("Touch sensor data logger started. Press Ctrl+C to exit.\n");

    // Main loop
    while (!terminate) {
        for (int i = 0; i < NUM_CHANNELS; i++) {
            SensorData data;
            data.channel = i;
            data.value = read_sensor(i);
            data.timestamp = get_timestamp();
            log_data(data);
        }
        nanosleep((const struct timespec[]){{0, 100000000L}}, NULL); // Sleep for 100ms
    }

    printf("Exiting cleanly.\n");
    return 0;
}

#include <stdio.h>
