// Configuration
#define SPI_DEVICE "/dev/spidev0.0"
#define SPI_MODE SPI_MODE_0
#define SPI_BITS_PER_WORD 8
#define SPI_MAX_SPEED_HZ 1000000 // 1 MHz
#define MCP3008_CHANNEL 0       // ADC channel connected to flow sensor

// Global variables
static int spi_fd; // SPI file descriptor
static volatile sig_atomic_t terminate = 0;

// Structure for grouping SPI configurations
typedef struct {
    const char *device;
    uint8_t mode;
    uint8_t bits_per_word;
    uint32_t max_speed_hz;
} spi_config_t;

// Function prototypes
int spi_setup(const spi_config_t *config);
int spi_transfer(uint8_t tx_data[], uint8_t rx_data[], int length);
int read_mcp3008(int channel);
float convert_to_flowrate(int adc_value);
void log_data(float flow_rate);
void signal_handler(int sig);

// Signal handler for graceful shutdown
void signal_handler(int sig) {
    terminate = 1;
    printf("\nReceived signal %d, terminating...\n", sig);
}

// SPI setup function
int spi_setup(const spi_config_t *config) {
    int ret = 0;

    spi_fd = open(config->device, O_RDWR);
    if (spi_fd < 0) {
        perror("Error opening SPI device");
        return -1;
    }

    ret = ioctl(spi_fd, SPI_IOC_WR_MODE, &config->mode);
    if (ret == -1) {
        perror("Error setting SPI mode");
        return -1;
    }

    ret = ioctl(spi_fd, SPI_IOC_RD_MODE, &config->mode);
    if (ret == -1) {
        perror("Error getting SPI mode");
        return -1;
    }

    ret = ioctl(spi_fd, SPI_IOC_WR_BITS_PER_WORD, &config->bits_per_word);
    if (ret == -1) {
        perror("Error setting bits per word");
        return -1;
    }

    ret = ioctl(spi_fd, SPI_IOC_RD_BITS_PER_WORD, &config->bits_per_word);
    if (ret == -1) {
        perror("Error getting bits per word");
        return -1;
    }

    ret = ioctl(spi_fd, SPI_IOC_WR_MAX_SPEED_HZ, &config->max_speed_hz);
    if (ret == -1) {
        perror("Error setting max speed hz");
        return -1;
    }

    ret = ioctl(spi_fd, SPI_IOC_RD_MAX_SPEED_HZ, &config->max_speed_hz);
    if (ret == -1) {
        perror("Error getting max speed hz");
        return -1;
    }

    printf("SPI device %s configured: mode=%d, bits=%d, max_speed=%d Hz\n",
           config->device, config->mode, config->bits_per_word, config->max_speed_hz);

    return 0;
}

// SPI transfer function
int spi_transfer(uint8_t tx_data[], uint8_t rx_data[], int length) {
    struct spi_ioc_transfer transfer = {
        .tx_buf = (unsigned long)tx_data,
        .rx_buf = (unsigned long)rx_data,
        .len = length,
        .speed_hz = SPI_MAX_SPEED_HZ,
        .bits_per_word = SPI_BITS_PER_WORD,
    };

    int ret = ioctl(spi_fd, SPI_IOC_MESSAGE(1), &transfer);
    if (ret < 1) {
        perror("Error during SPI transfer");
        return -1;
    }
    return 0;
}

// Function to read from MCP3008 ADC
int read_mcp3008(int channel) {
    uint8_t tx_buffer[3];
    uint8_t rx_buffer[3];

    // Construct SPI message
    tx_buffer[0] = 0x01;                           // Start bit
    tx_buffer[1] = ((0x08 | channel) << 4);        // Single-ended mode, channel select
    tx_buffer[2] = 0x00;                           // Don't care

    if (spi_transfer(tx_buffer, rx_buffer, 3) != 0) {
        fprintf(stderr, "SPI transfer failed\n");
        return -1;
    }

    // Extract ADC value (10 bits)
    int adc_value = ((rx_buffer[1] & 0x03) << 8) + rx_buffer[2];
    return adc_value;
}

// Function to convert ADC value to flow rate (example calibration)
float convert_to_flowrate(int adc_value) {
    // Simple linear conversion (replace with actual calibration data)
    float flow_rate = (float)adc_value / 1023.0 * 10.0; // Assuming 0-10 corresponds to 0-10 ml/s
    return flow_rate;
}

// Function to log the flow rate
void log_data(float flow_rate) {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[20];

    time(&rawtime);
    timeinfo = localtime(&rawtime);
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    printf("%s - Flow Rate: %.2f ml/s\n", timestamp, flow_rate);
}

int main() {
    // SPI configuration
    const spi_config_t spi_config = {
        .device = SPI_DEVICE,
        .mode = SPI_MODE,
        .bits_per_word = SPI_BITS_PER_WORD,
        .max_speed_hz = SPI_MAX_SPEED_HZ
    };

    // Setup signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Initialize SPI
    if (spi_setup(&spi_config) != 0) {
        fprintf(stderr, "SPI initialization failed\n");
        return EXIT_FAILURE;
    }

    printf("Starting flow rate monitoring...\n");

    while (!terminate) {
        // Read ADC value
        int adc_value = read_mcp3008(MCP3008_CHANNEL);
        if (adc_value < 0) {
            fprintf(stderr, "Failed to read ADC value, retrying...\n");
            sleep(1); // Retry after 1 second
            continue;
        }

        // Convert to flow rate
        float flow_rate = convert_to_flowrate(adc_value);

        // Log the data
        log_data(flow_rate);

        // Wait for 1 second
        sleep(1);
    }

    // Close SPI device
    close(spi_fd);
    printf("Flow rate monitoring stopped.\n");

    return EXIT_SUCCESS;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <unistd.h>
#include <fcntl.h>
#include <sys/ioctl.h>
#include <linux/spi/spidev.h>
#include <time.h>
#include <string.h>
#include <errno.h>
#include <signal.h>

// Configuration
#define SPI_BUS 0
#define SPI_DEVICE 0
#define SPI_MODE SPI_MODE_0
#define SPI_BITS_PER_WORD 8
#define SPI_SPEED 1000000 // 1 MHz
#define MCP3008_CHANNEL 0 // Channel connected to MLX91204
#define SLEEP_DURATION_MS 500

// Global variables
int spi_fd;
bool running = true;

// Structure for sensor configuration
typedef struct {
    float sensitivity; // mV/A
    float offset;
} sensor_config_t;

// Sensor configuration (example values)
sensor_config_t sensor_config = {20.0, 2.5}; // 20mV/A, 2.5V offset

// Function prototypes
int spi_setup();
int read_adc(int channel);
float convert_to_current(int adc_value, sensor_config_t config);
void log_data(float current);
void cleanup();
void signal_handler(int signal);

int main() {
    // Register signal handler for graceful shutdown
    signal(SIGINT, signal_handler);

    // Initialize SPI
    if (spi_setup() < 0) {
        fprintf(stderr, "Failed to initialize SPI. Exiting.\n");
        return 1;
    }

    // Main loop
    while (running) {
        int adc_value = read_adc(MCP3008_CHANNEL);
        if (adc_value < 0) {
            fprintf(stderr, "Failed to read ADC value. Retrying.\n");
            usleep(100000); // 10ms delay before retry
            continue;
        }

        float current = convert_to_current(adc_value, sensor_config);
        log_data(current);

        usleep(SLEEP_DURATION_MS * 1000); // Sleep for 500ms
    }

    // Cleanup before exiting
    cleanup();

    return 0;
}

// SPI setup function
int spi_setup() {
    spi_fd = open("/dev/spidev0.0", O_RDWR);
    if (spi_fd < 0) {
        perror("Error opening SPI device");
        return -1;
    }

    // Configure SPI mode
    int mode = SPI_MODE;
    if (ioctl(spi_fd, SPI_IOC_WR_MODE, &mode) < 0) {
        perror("Error setting SPI mode");
        close(spi_fd);
        return -1;
    }

    // Configure SPI bits per word
    int bits = SPI_BITS_PER_WORD;
    if (ioctl(spi_fd, SPI_IOC_WR_BITS_PER_WORD, &bits) < 0) {
        perror("Error setting SPI bits per word");
        close(spi_fd);
        return -1;
    }

    // Configure SPI speed
    int speed = SPI_SPEED;
    if (ioctl(spi_fd, SPI_IOC_WR_MAX_SPEED_HZ, &speed) < 0) {
        perror("Error setting SPI speed");
        close(spi_fd);
        return -1;
    }

    return 0;
}

// Function to read ADC value from MCP3008
int read_adc(int channel) {
    uint8_t tx_buf[3];
    uint8_t rx_buf[3];
    struct spi_ioc_transfer tr;

    // MCP3008 command to read a single channel
    tx_buf[0] = 0x01; // Start bit
    tx_buf[1] = (0x08 | channel) << 4; // Single-ended mode, channel selection
    tx_buf[2] = 0x00;

    memset(&tr, 0, sizeof(tr));
    tr.tx_buf = (unsigned long)tx_buf;
    tr.rx_buf = (unsigned long)rx_buf;
    tr.len = 3;
    tr.speed_hz = SPI_SPEED;
    tr.bits_per_word = SPI_BITS_PER_WORD;

    if (ioctl(spi_fd, SPI_IOC_MESSAGE(1), &tr) < 0) {
        perror("Error sending SPI message");
        return -1;
    }

    // Extract ADC value (10 bits)
    int adc_value = ((rx_buf[1] & 0x03) << 8) + rx_buf[2];
    return adc_value;
}

// Function to convert ADC value to current
float convert_to_current(int adc_value, sensor_config_t config) {
    float voltage = (float)adc_value / 1023.0 * 3.3; // Assuming 3.3V reference
    return (voltage - config.offset) / config.sensitivity;
}

// Function to log current data
void log_data(float current) {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[20];

    time(&rawtime);
    timeinfo = localtime(&rawtime);
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    printf("[%s] Current: %.3f A\n", timestamp, current);
}

// Cleanup function
void cleanup() {
    close(spi_fd);
    printf("SPI closed. Exiting.\n");
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    running = false;
