}

#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
#include <time.h>
#include <signal.h>
#include <unistd.h>

// Define GPIO pins for the sensors (adjust these based on your wiring)
#define SENSOR_LEFT 0   // WiringPi pin 0 (GPIO 17)
#define SENSOR_RIGHT 2  // WiringPi pin 2 (GPIO 27)

// Structure to hold sensor data and configuration
typedef struct {
    int left_pin;
    int right_pin;
    int running;
} SensorConfig;

SensorConfig config = {SENSOR_LEFT, SENSOR_RIGHT, 1};

// Function to initialize GPIO using wiringPi
int setup_gpio() {
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "GPIO initialization failed!\n");
        return -1;
    }

    pinMode(config.left_pin, INPUT);
    pinMode(config.right_pin, INPUT);

    return 0;
}

// Function to read sensor data
int read_sensor(int pin) {
    int value = digitalRead(pin);
    return value;
}

// Function to log sensor data to the console
void log_data(int left_value, int right_value) {
    time_t rawtime;
    struct tm *timeinfo;
    time(&rawtime);
    timeinfo = localtime(&rawtime);

    printf("[%s] Left: %s, Right: %s\n", asctime(timeinfo), 
           left_value == 0 ? "Obstacle" : "Clear",
           right_value == 0 ? "Obstacle" : "Clear");
}

// Signal handler for graceful shutdown
void signal_handler(int signum) {
    config.running = 0;
    printf("Exiting gracefully...\n");
    exit(0);
}

int main() {
    // Register signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Initialize GPIO
    if (setup_gpio() == -1) {
        return 1;
    }

    printf("Sensor monitoring started. Press Ctrl+C to exit.\n");

    // Main loop to read and log sensor data
    while (config.running) {
        int left_value = -1;
        int right_value = -1;

        // Read left sensor with retry
        for (int i = 0; i < 3; ++i) {
            left_value = read_sensor(config.left_pin);
            if (left_value != -1) break; // Exit retry loop on success
            delay(10); // Small delay before retry
        }

        // Read right sensor with retry
        for (int i = 0; i < 3; ++i) {
            right_value = read_sensor(config.right_pin);
            if (right_value != -1) break; // Exit retry loop on success
            delay(10); // Small delay before retry
        }

        // Log the data if read was successful
        if (left_value != -1 && right_value != -1) {
            log_data(left_value, right_value);
        } else {
            fprintf(stderr, "Error reading sensor data.\n");
        }

        delay(200); // Delay between readings
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <pigpio.h>

// Define GPIO pins
#define ADC_CS 8
#define ADC_MISO 9
#define ADC_CLK 11

// Global variables
volatile sig_atomic_t program_running = 1;

// Function prototypes
int read_adc();
void signal_handler(int signal);

// Structure for ADC configuration (optional, but good practice)
typedef struct {
    int cs_pin;
    int miso_pin;
    int clk_pin;
} adc_config_t;

adc_config_t adc_config = {ADC_CS, ADC_MISO, ADC_CLK};

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    fprintf(stderr, "\nCaught signal %d, cleaning up...\n", signal);
    program_running = 0;
    gpioWrite(adc_config.cs_pin, 1); // Deselect ADC
    gpioTerminate(); // Terminate pigpio
    exit(0); // Exit the program
}

// Function to read ADC value using SPI
int read_adc() {
    int adc_value = -1; // Initialize to an invalid value for error checking
    unsigned char buffer[2];

    gpioWrite(adc_config.cs_pin, 0); // Select ADC
    gpioDelay(1); // Small delay after CS goes low

    // Transfer data (dummy byte out, ADC data in)
    spiXfer_t spi;
    spi.txBuf = NULL; // No data to transmit
    spi.rxBuf = buffer;
    spi.count = 2;       // Receive 2 bytes (10-bit ADC value)
    spi.bits = 8;        // 8 bits per word
    spi.delay = 0;       // No delay between bits

    if (gpioSpiXfer(0, &spi) >= 0) {
        // Combine the received bytes into a 10-bit integer
        adc_value = ((buffer[0] & 0x03) << 8) | buffer[1];
    } else {
        fprintf(stderr, "Error: SPI communication failed.\n");
    }

    gpioWrite(adc_config.cs_pin, 1); // Deselect ADC
    gpioDelay(1); // Small delay after CS goes high

    return adc_value;
}

int main() {
    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "Error: pigpio initialization failed.\n");
        return 1;
    }

    // Configure GPIO8 as output for ADC CS
    gpioSetMode(adc_config.cs_pin, PI_OUTPUT);
    gpioWrite(adc_config.cs_pin, 1); // Set CS high (inactive)

    // Configure SPI (using default SPI channel 0)
    // Mode 0: CPOL = 0, CPHA = 0
    // Bit rate: 1MHz (adjust as needed for your ADC)
    int spi_flags = 0; // SPI mode 0
    int spi_handle = spiOpen(0, 1000000, spi_flags); // Open SPI channel 0
    if (spi_handle < 0) {
        fprintf(stderr, "Error: SPI open failed (error code %d).\n", spi_handle);
        gpioTerminate(); // Clean up
        return 1;
    }

    // Set up signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Main loop
    while (program_running) {
        int adc_value = read_adc();

        if (adc_value >= 0) {
            printf("ADC Value: %d\n", adc_value);
        } else {
            fprintf(stderr, "Error: Failed to read ADC value.\n");
        }

        gpioDelay(100000); // Pause for 100 milliseconds
    }

    spiClose(spi_handle);
    gpioTerminate(); // Clean up
    return 0;
}

