#include <stdio.h>
#include <stdlib.h>
#include <bcm2835.h>
#include <unistd.h>
#include <time.h>
#include <signal.h>

// MLX75031 I2C address
#define MLX75031_ADDR 0x4C

// Register addresses (example, adjust based on datasheet)
#define MLX75031_DISTANCE_REG_LOW  0x00
#define MLX75031_DISTANCE_REG_HIGH 0x01

// Define a structure for sensor data
typedef struct {
    uint16_t distance;
    time_t timestamp;
} sensor_data_t;

// Global flag for graceful shutdown
volatile sig_atomic_t terminate = 0;

// Signal handler for Ctrl+C
void sigint_handler(int signal) {
    terminate = 1;
    printf("\nCaught signal %d, terminating gracefully...\n", signal);
}

// Function to initialize the bcm2835 library and I2C
int initialize() {
    if (!bcm2835_init()) {
        fprintf(stderr, "bcm2835_init failed. Are you running as root?\n");
        return 1;
    }

    bcm2835_i2c_begin();
    bcm2835_i2c_setSlaveAddress(MLX75031_ADDR);
    bcm2835_i2c_setClockDivider(BCM2835_I2C_CLOCK_DIVIDER_626); // 100kHz

    return 0;
}

// Function to read distance data from the sensor
int read_distance(uint16_t *distance) {
    char reg_low = MLX75031_DISTANCE_REG_LOW;
    char reg_high = MLX75031_DISTANCE_REG_HIGH;
    char read_buffer[2];

    // Read low byte
    bcm2835_i2c_write(&reg_low, 1);
    bcm2835_i2c_read(read_buffer, 1);
    uint8_t low_byte = read_buffer[0];

    // Read high byte
    bcm2835_i2c_write(&reg_high, 1);
    bcm2835_i2c_read(read_buffer, 1);
    uint8_t high_byte = read_buffer[0];

    *distance = (high_byte << 8) | low_byte;

    return 0;
}

// Function to log the sensor data
void log_data(sensor_data_t data) {
    struct tm *timeinfo;
    char timestamp[20];

    timeinfo = localtime(&data.timestamp);
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    printf("[%s] Distance: %u\n", timestamp, data.distance);
}

int main(int argc, char **argv) {
    // Set up signal handling for Ctrl+C
    signal(SIGINT, sigint_handler);

    if (initialize() != 0) {
        return 1;
    }

    printf("MLX75031 Data Logger started. Press Ctrl+C to exit.\n");

    while (!terminate) {
        sensor_data_t data;

        // Read the distance
        if (read_distance(&data.distance) != 0) {
            fprintf(stderr, "Error reading distance data.\n");
            continue; // Skip to the next iteration
        }

        // Get the current timestamp
        time(&data.timestamp);

        // Log the data
        log_data(data);

        // Wait for a specified period (e.g., 1 second)
        sleep(1);
    }

    bcm2835_i2c_end();
    bcm2835_close();

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <stdbool.h>
#include <wiringPiI2C.h>
#include <unistd.h>
#include <time.h>
#include <sys/time.h>
#include <signal.h>

// LSM9DS1 I2C addresses
#define LSM9DS1_MAG_ADDRESS 0x1E // Magnetometer address
#define LSM9DS1_XM_ADDRESS 0x6B  // Accelerometer/Gyroscope address

// LSM9DS1 register addresses (Magnetometer)
#define LSM9DS1_MAG_WHO_AM_I 0x0F
#define LSM9DS1_MAG_CTRL_REG1_M 0x20
#define LSM9DS1_MAG_CTRL_REG2_M 0x21
#define LSM9DS1_MAG_CTRL_REG3_M 0x22
#define LSM9DS1_MAG_OUT_X_L_M 0x28

// LSM9DS1 register addresses (Accelerometer/Gyroscope)
#define LSM9DS1_XM_WHO_AM_I 0x0F
#define LSM9DS1_CTRL_REG1_G 0x10
#define LSM9DS1_CTRL_REG2_G 0x11
#define LSM9DS1_CTRL_REG3_G 0x12
#define LSM9DS1_OUT_X_L_G 0x18
#define LSM9DS1_CTRL_REG1_XM 0x20
#define LSM9DS1_CTRL_REG2_XM 0x21
#define LSM9DS1_CTRL_REG3_XM 0x22
#define LSM9DS1_OUT_X_L_XL 0x28

// Structure to hold sensor data
typedef struct {
    int16_t gyro_x, gyro_y, gyro_z;
    int16_t accel_x, accel_y, accel_z;
    int16_t mag_x, mag_y, mag_z;
} sensor_data_t;

// Global variable for I2C file descriptors
int mag_fd, xm_fd;
bool running = true;

// Function prototypes
int init_lsm9ds1();
sensor_data_t read_sensor_data();
void log_sensor_data(sensor_data_t data);
void cleanup();
void signal_handler(int signal);

// Helper function to read a 16-bit value from I2C
int16_t read_i2c_word(int fd, uint8_t reg) {
    int16_t low = wiringPiI2CReadReg8(fd, reg);
    int16_t high = wiringPiI2CReadReg8(fd, reg + 1);
    return (high << 8) | low;
}

int main() {
    // Register signal handler for graceful shutdown
    signal(SIGINT, signal_handler);

    // Initialize the LSM9DS1
    if (init_lsm9ds1() != 0) {
        fprintf(stderr, "Failed to initialize LSM9DS1. Exiting.\n");
        return 1;
    }

    // Main loop to read and log sensor data
    while (running) {
        sensor_data_t data = read_sensor_data();
        log_sensor_data(data);
        usleep(200000); // 200ms
    }

    // Cleanup before exiting
    cleanup();
    return 0;
}

// Initializes the LSM9DS1 IMU
int init_lsm9ds1() {
    // Initialize WiringPi I2C for magnetometer
    mag_fd = wiringPiI2CSetup(LSM9DS1_MAG_ADDRESS);
    if (mag_fd == -1) {
        fprintf(stderr, "Failed to initialize I2C for magnetometer.\n");
        return -1;
    }

    // Initialize WiringPi I2C for accelerometer/gyroscope
    xm_fd = wiringPiI2CSetup(LSM9DS1_XM_ADDRESS);
    if (xm_fd == -1) {
        fprintf(stderr, "Failed to initialize I2C for accelerometer/gyroscope.\n");
        return -1;
    }

    // Verify magnetometer connection
    int who_am_i_mag = wiringPiI2CReadReg8(mag_fd, LSM9DS1_MAG_WHO_AM_I);
    if (who_am_i_mag != 0x3D) {
        fprintf(stderr, "Magnetometer WHO_AM_I returned: 0x%02X (Expected 0x3D)\n", who_am_i_mag);
        return -1;
    }

    // Verify accelerometer/gyroscope connection
    int who_am_i_xm = wiringPiI2CReadReg8(xm_fd, LSM9DS1_XM_WHO_AM_I);
    if (who_am_i_xm != 0x68) {
        fprintf(stderr, "Accelerometer/Gyroscope WHO_AM_I returned: 0x%02X (Expected 0x68)\n", who_am_i_xm);
        return -1;
    }

    // Magnetometer configuration
    wiringPiI2CWriteReg8(mag_fd, LSM9DS1_MAG_CTRL_REG1_M, 0x70); // Temp sensor enable, ODR = 80 Hz
    wiringPiI2CWriteReg8(mag_fd, LSM9DS1_MAG_CTRL_REG2_M, 0x00); // Gain +/- 4 gauss
    wiringPiI2CWriteReg8(mag_fd, LSM9DS1_MAG_CTRL_REG3_M, 0x00); // Continuous conversion mode

    // Gyroscope configuration
    wiringPiI2CWriteReg8(xm_fd, LSM9DS1_CTRL_REG1_G, 0x60); // ODR = 119 Hz, 245 dps
    wiringPiI2CWriteReg8(xm_fd, LSM9DS1_CTRL_REG2_G, 0x00); // Normal mode
    wiringPiI2CWriteReg8(xm_fd, LSM9DS1_CTRL_REG3_G, 0x00); // No interrupt

    // Accelerometer configuration
    wiringPiI2CWriteReg8(xm_fd, LSM9DS1_CTRL_REG1_XM, 0x60); // ODR = 119 Hz, +/- 2g
    wiringPiI2CWriteReg8(xm_fd, LSM9DS1_CTRL_REG2_XM, 0x00); // Normal mode
    wiringPiI2CWriteReg8(xm_fd, LSM9DS1_CTRL_REG3_XM, 0x00); // No interrupt

    return 0;
}

// Reads sensor data from the LSM9DS1
sensor_data_t read_sensor_data() {
    sensor_data_t data;

    // Read gyroscope data
    data.gyro_x = read_i2c_word(xm_fd, LSM9DS1_OUT_X_L_G);
    data.gyro_y = read_i2c_word(xm_fd, LSM9DS1_OUT_X_L_G + 2);
    data.gyro_z = read_i2c_word(xm_fd, LSM9DS1_OUT_X_L_G + 4);

    // Read accelerometer data
    data.accel_x = read_i2c_word(xm_fd, LSM9DS1_OUT_X_L_XL);
    data.accel_y = read_i2c_word(xm_fd, LSM9DS1_OUT_X_L_XL + 2);
    data.accel_z = read_i2c_word(xm_fd, LSM9DS1_OUT_X_L_XL + 4);

    // Read magnetometer data
    data.mag_x = read_i2c_word(mag_fd, LSM9DS1_MAG_OUT_X_L_M);
    data.mag_y = read_i2c_word(mag_fd, LSM9DS1_MAG_OUT_X_L_M + 2);
    data.mag_z = read_i2c_word(mag_fd, LSM9DS1_MAG_OUT_X_L_M + 4);

    return data;
}

// Logs sensor data to the console
void log_sensor_data(sensor_data_t data) {
    struct timeval tv;
    gettimeofday(&tv, NULL);
    unsigned long long milliseconds = (unsigned long long)(tv.tv_sec) * 1000 + (unsigned long long)(tv.tv_usec) / 1000;

    printf("%llu, Gyro: %6d %6d %6d, Accel: %6d %6d %6d, Mag: %6d %6d %6d\n",
           milliseconds,
           data.gyro_x, data.gyro_y, data.gyro_z,
           data.accel_x, data.accel_y, data.accel_z,
           data.mag_x, data.mag_y, data.mag_z);
}

// Cleanup function to close I2C connections
void cleanup() {
    close(mag_fd);
    close(xm_fd);
    printf("Cleanup complete. Exiting.\n");
}

// Signal handler to catch Ctrl+C and exit gracefully
void signal_handler(int signal) {
    running = false;
    printf("Caught signal %d, exiting gracefully.\n", signal);
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <unistd.h>
#include <fcntl.h>
#include <sys/ioctl.h>
#include <linux/i2c-dev.h>
#include <time.h>
#include <signal.h>
#include <string.h>

// Define sensor and I2C parameters
#define FXOS8700_ADDR 0x1F
#define FXOS8700_REGISTER_WHO_AM_I 0x0D
#define FXOS8700_REGISTER_XYZ_DATA_CFG 0x0E
#define FXOS8700_REGISTER_CTRL_REG1 0x2A
#define FXOS8700_REGISTER_STATUS 0x00
#define FXOS8700_REGISTER_ACCEL_DATA_X_MSB 0x01
#define FXOS8700_REGISTER_MAG_DATA_X_MSB 0x33

// Scale factors for accelerometer and magnetometer
#define ACCEL_MG_LSB_2G (0.000244F)
#define MAG_UT_LSB (0.1F)

// Global I2C file descriptor
int i2c_fd;

// Structure to hold sensor data
typedef struct {
    float accel_x, accel_y, accel_z;
    float mag_x, mag_y, mag_z;
} sensor_data_t;

// Structure to hold program state
typedef struct {
    int running;
    FILE *log_file;
} program_state_t;

program_state_t state = {1, NULL};

// Function prototypes
int i2c_setup(int address);
uint8_t read_register(int fd, uint8_t reg);
int write_register(int fd, uint8_t reg, uint8_t value);
sensor_data_t read_sensor_data(int fd);
void log_sensor_data(FILE *fp, sensor_data_t data);
void signal_handler(int signal);

// I2C setup function
int i2c_setup(int address) {
    int fd = open("/dev/i2c-1", O_RDWR);
    if (fd < 0) {
        perror("Error opening I2C device");
        return -1;
    }
    if (ioctl(fd, I2C_SLAVE, address) < 0) {
        perror("Error setting I2C slave address");
        close(fd);
        return -1;
    }
    return fd;
}

// Function to read a single register
uint8_t read_register(int fd, uint8_t reg) {
    uint8_t buf[1];
    buf[0] = reg;
    if (write(fd, buf, 1) != 1) {
        perror("Error writing register address");
        return 0; // Return 0 on error
    }
    if (read(fd, buf, 1) != 1) {
        perror("Error reading register value");
        return 0; // Return 0 on error
    }
    return buf[0];
}

// Function to write a single register
int write_register(int fd, uint8_t reg, uint8_t value) {
    uint8_t buf[2];
    buf[0] = reg;
    buf[1] = value;
    if (write(fd, buf, 2) != 2) {
        perror("Error writing to register");
        return -1;
    }
    return 0;
}

// Function to read sensor data
sensor_data_t read_sensor_data(int fd) {
    sensor_data_t data;
    uint8_t raw_data[14];

    // Read all 14 bytes of accelerometer and magnetometer data at once
    if (write_register(fd, FXOS8700_REGISTER_STATUS, 0) < 0) { // Dummy write to set register address
        fprintf(stderr, "Error setting register for multi-read.\n");
        data.accel_x = data.accel_y = data.accel_z = 0.0f;
        data.mag_x = data.mag_y = data.mag_z = 0.0f;
        return data;
    }

    if (read(fd, raw_data, 14) != 14) {
        fprintf(stderr, "Error reading sensor data.\n");
        data.accel_x = data.accel_y = data.accel_z = 0.0f;
        data.mag_x = data.mag_y = data.mag_z = 0.0f;
        return data;
    }

    // Combine MSB and LSB for 14-bit accelerometer data and convert to mg
    int16_t accel_x = ((int16_t)raw_data[1] << 6) | (raw_data[2] >> 2);
    int16_t accel_y = ((int16_t)raw_data[3] << 6) | (raw_data[4] >> 2);
    int16_t accel_z = ((int16_t)raw_data[5] << 6) | (raw_data[6] >> 2);

    data.accel_x = (float)accel_x * ACCEL_MG_LSB_2G * 9.81f; // Convert to m/s^2
    data.accel_y = (float)accel_y * ACCEL_MG_LSB_2G * 9.81f;
    data.accel_z = (float)accel_z * ACCEL_MG_LSB_2G * 9.81f;

    // Combine MSB and LSB for 16-bit magnetometer data and convert to uT
    int16_t mag_x = ((int16_t)raw_data[7] << 8) | raw_data[8];
    int16_t mag_y = ((int16_t)raw_data[9] << 8) | raw_data[10];
    int16_t mag_z = ((int16_t)raw_data[11] << 8) | raw_data[12];

    data.mag_x = (float)mag_x * MAG_UT_LSB; // Convert to uT
    data.mag_y = (float)mag_y * MAG_UT_LSB;
    data.mag_z = (float)mag_z * MAG_UT_LSB;

    return data;
}

// Function to log sensor data to a file
void log_sensor_data(FILE *fp, sensor_data_t data) {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[20];

    time(&rawtime);
    timeinfo = localtime(&rawtime);
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    fprintf(fp, "%s, %.3f, %.3f, %.3f, %.3f, %.3f, %.3f\n",
            timestamp, data.accel_x, data.accel_y, data.accel_z,
            data.mag_x, data.mag_y, data.mag_z);
    fflush(fp); // Ensure data is written to file immediately
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("Caught signal %d, exiting...\n", signal);
    state.running = 0;
    if (state.log_file != NULL) {
        fclose(state.log_file);
    }
    close(i2c_fd);
    exit(0);
}

int main() {
    // Register signal handler
    signal(SIGINT, signal_handler);

    // Initialize I2C communication
    i2c_fd = i2c_setup(FXOS8700_ADDR);
    if (i2c_fd < 0) {
        fprintf(stderr, "I2C setup failed. Exiting.\n");
        return 1;
    }

    // Verify sensor ID
    uint8_t who_am_i = read_register(i2c_fd, FXOS8700_REGISTER_WHO_AM_I);
    if (who_am_i != 0xC7) {
        fprintf(stderr, "Incorrect sensor ID: 0x%02X. Expected 0xC7. Exiting.\n", who_am_i);
        close(i2c_fd);
        return 1;
    }
    printf("Sensor ID verified: 0x%02X\n", who_am_i);

    // Configure sensor
    if (write_register(i2c_fd, FXOS8700_REGISTER_XYZ_DATA_CFG, 0x00) < 0) {
        fprintf(stderr, "Error configuring data range.\n");
        close(i2c_fd);
        return 1;
    }

    // Set to active mode, 100 Hz output data rate
    if (write_register(i2c_fd, FXOS8700_REGISTER_CTRL_REG1, 0x15) < 0) {
        fprintf(stderr, "Error setting active mode.\n");
        close(i2c_fd);
        return 1;
    }

    // Open log file
    state.log_file = fopen("sensor_data.csv", "a");
    if (state.log_file == NULL) {
        perror("Error opening log file");
        close(i2c_fd);
        return 1;
    }

    fprintf(state.log_file, "Timestamp, Accel_X (m/s^2), Accel_Y (m/s^2), Accel_Z (m/s^2), Mag_X (uT), Mag_Y (uT), Mag_Z (uT)\n");

    // Main loop
    while (state.running) {
        sensor_data_t data = read_sensor_data(i2c_fd);
        log_sensor_data(state.log_file, data);
        usleep(10000); // 10ms delay (100 Hz)
    }

    // Cleanup
    fclose(state.log_file);
    close(i2c_fd);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <stdbool.h>
#include <wiringPiI2C.h>
#include <wiringPi.h>
#include <unistd.h>
#include <time.h>
#include <sys/time.h>
#include <signal.h>

// Define SDP32 I2C address
#define SDP32_ADDR 0x21

// Define measurement command
#define MEASURE_COMMAND 0x362F

// Define scale factor
#define SCALE_FACTOR 60.0

// Global variable for I2C file descriptor
int fd;

// Structure to hold program state
typedef struct {
    bool running;
} ProgramState;

ProgramState state = {true};

// Signal handler for graceful shutdown
void signal_handler(int signum) {
    state.running = false;
    printf("\nExiting gracefully...\n");
}

// Function to initialize the SDP32 sensor
int initialize_sensor() {
    fd = wiringPiI2CSetup(SDP32_ADDR);
    if (fd == -1) {
        fprintf(stderr, "Error: Failed to initialize I2C communication.\n");
        return -1;
    }
    printf("I2C communication successfully initialized.\n");
    return 0;
}

// Function to read differential pressure from the SDP32 sensor
float read_differential_pressure() {
    // Send measurement command
    wiringPiI2CWriteReg16(fd, MEASURE_COMMAND >> 8, MEASURE_COMMAND & 0xFF);
    delay(50); // Wait for measurement

    // Read data (6 bytes: pressure, temperature, checksum)
    uint8_t data[6];
    for (int i = 0; i < 6; i++) {
        data[i] = wiringPiI2CRead(fd);
    }

    // Combine pressure data (first 2 bytes)
    int16_t raw_pressure = (data[0] << 8) | data[1];

    // Calculate differential pressure in Pa
    float pressure = (float)raw_pressure / SCALE_FACTOR;

    return pressure;
}

// Function to log the data with timestamp
void log_data(float pressure) {
    struct timeval tv;
    gettimeofday(&tv, NULL);
    time_t nowtime = tv.tv_sec;
    struct tm *nowtm = localtime(&nowtime);
    char tmbuf[64], buf[64];
    strftime(tmbuf, sizeof(tmbuf), "%Y-%m-%d %H:%M:%S", nowtm);
    snprintf(buf, sizeof(buf), "%s.%06ld", tmbuf, tv.tv_usec);

    printf("[%s] Differential Pressure: %.2f Pa\n", buf, pressure);
}

int main() {
    // Set up WiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "Error: Failed to set up WiringPi.\n");
        return 1;
    }

    // Register signal handler for graceful shutdown
    signal(SIGINT, signal_handler);

    // Initialize the sensor
    if (initialize_sensor() == -1) {
        return 1;
    }

    // Main loop
    while (state.running) {
        float pressure = 0.0;
        // Read differential pressure with retry
        for(int i = 0; i < 3; i++) {
            pressure = read_differential_pressure();
            if(pressure > -1000 && pressure < 1000) break; //Simple check if pressure is in a reasonable range
            fprintf(stderr, "Error: Failed to read pressure, retrying...\n");
            delay(100); //Small delay before retry
        }

        // Log the data
        log_data(pressure);

        // Wait for 1 second
        delay(1000);
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <signal.h>
#include <time.h>
#include <sys/time.h>
#include <wiringPi.h>

// Define the GPIO pin connected to the Hall sensor
#define HALL_SENSOR_PIN 17 // WiringPi pin number

// Structure to hold program state
typedef struct {
    volatile int pulse_count;
    unsigned long last_interrupt_time;
    FILE *log_file;
    int running;
} ProgramState;

ProgramState state = {0, 0, NULL, 1}; // Initialize global state

// Function prototypes
void setup();
void hall_interrupt_handler();
double calculate_speed();
void log_data(double speed);
void cleanup();
void signal_handler(int signum);

// Interrupt handler for the Hall sensor
void hall_interrupt_handler() {
    unsigned long current_time = millis();
    unsigned long time_diff = current_time - state.last_interrupt_time;

    // Debounce the signal (ignore interrupts that occur too quickly after each other)
    if (time_diff > 5) { // Adjust debounce time as needed
        state.pulse_count++;
        state.last_interrupt_time = current_time;
    }
}

// Function to calculate speed (pulses per second)
double calculate_speed() {
    unsigned long current_time = millis();
    unsigned long time_elapsed = current_time - state.last_interrupt_time;
    if(time_elapsed == 0) return 0.0;
    return ((double)state.pulse_count / (double)time_elapsed) * 1000.0; // pulses per second
}

// Function to log data to a file
void log_data(double speed) {
    struct timeval tv;
    gettimeofday(&tv, NULL);
    time_t nowtime = tv.tv_sec;
    struct tm *nowtm = localtime(&nowtime);
    char tmbuf[64], buf[64];
    strftime(tmbuf, sizeof(tmbuf), "%Y-%m-%d %H:%M:%S", nowtm);
    snprintf(buf, sizeof(buf), "%s.%06ld", tmbuf, tv.tv_usec);

    if (state.log_file != NULL) {
        fprintf(state.log_file, "%s, Speed: %.2f pulses/second, Pulse Count: %d\n", buf, speed, state.pulse_count);
        fflush(state.log_file); // Ensure data is written to disk immediately
    } else {
        printf("%s, Speed: %.2f pulses/second, Pulse Count: %d\n", buf, speed, state.pulse_count);
    }
}

// Setup function to initialize GPIO and logging
void setup() {
    wiringPiSetupGpio(); // Use Broadcom GPIO numbering

    // Set the Hall sensor pin as input with pull-up resistor
    pinMode(HALL_SENSOR_PIN, INPUT);
    pullUpDnControl(HALL_SENSOR_PIN, PUD_UP);

    // Initialize interrupt
    wiringPiISR(HALL_SENSOR_PIN, INT_EDGE_FALLING, hall_interrupt_handler);

    // Open the log file
    state.log_file = fopen("speed_log.txt", "a");
    if (state.log_file == NULL) {
        perror("Error opening log file");
        fprintf(stderr, "Logging to console instead.\n");
    }

    state.last_interrupt_time = millis();
}

// Cleanup function to close the log file and reset GPIO
void cleanup() {
    printf("Cleaning up and exiting...\n");
    if (state.log_file != NULL) {
        fclose(state.log_file);
    }
    // No need to reset GPIO in wiringPi, but good practice in general
}

// Signal handler for Ctrl+C
void signal_handler(int signum) {
    state.running = 0;
}

int main() {
    // Register signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    setup();

    printf("Hall sensor speed monitor started. Press Ctrl+C to exit.\n");

    while (state.running) {
        delay(1000); // Check speed every second
        double current_speed = calculate_speed();
        log_data(current_speed);
        state.pulse_count = 0; // Reset pulse count for the next interval
        state.last_interrupt_time = millis();
    }

    cleanup();
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <unistd.h>
#include <fcntl.h>
#include <sys/ioctl.h>
#include <linux/spi/spidev.h>
#include <time.h>
#include <sys/time.h>
#include <signal.h>
#include <string.h>

// Configuration
#define SPI_BUS 0
#define SPI_DEVICE 0
#define SPI_MODE SPI_MODE_0
#define SPI_BITS_PER_WORD 8
#define SPI_MAX_SPEED_HZ 1000000
#define MCP3008_CHANNEL 0 // Connected to Channel 0
#define CURRENT_SENSITIVITY 0.040 // 40mV/A
#define SLEEP_DURATION_SEC 1

// Global variables
int spi_fd;
volatile sig_atomic_t terminate = 0;

// Structure for holding SPI configuration
typedef struct {
    uint8_t mode;
    uint8_t bits_per_word;
    uint32_t max_speed_hz;
} spi_config_t;

// Function prototypes
int spi_init(int bus, int device, spi_config_t config);
uint16_t read_mcp3008(int channel);
float convert_to_current(uint16_t adc_value);
void log_data(float current);
void signal_handler(int signal);

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    terminate = 1;
    printf("\nCaught signal %d, terminating...\n", signal);
}

// Initialize SPI
int spi_init(int bus, int device, spi_config_t config) {
    char spi_device_path[20];
    sprintf(spi_device_path, "/dev/spidev%d.%d", bus, device);

    spi_fd = open(spi_device_path, O_RDWR);
    if (spi_fd < 0) {
        perror("Error opening SPI device");
        return -1;
    }

    if (ioctl(spi_fd, SPI_IOC_WR_MODE, &config.mode) == -1) {
        perror("Error setting SPI mode");
        close(spi_fd);
        return -1;
    }

    if (ioctl(spi_fd, SPI_IOC_WR_BITS_PER_WORD, &config.bits_per_word) == -1) {
        perror("Error setting SPI bits per word");
        close(spi_fd);
        return -1;
    }

    if (ioctl(spi_fd, SPI_IOC_WR_MAX_SPEED_HZ, &config.max_speed_hz) == -1) {
        perror("Error setting SPI max speed Hz");
        close(spi_fd);
        return -1;
    }

    return 0;
}

// Read from MCP3008 ADC
uint16_t read_mcp3008(int channel) {
    uint8_t tx_buf[3];
    uint8_t rx_buf[3];
    struct spi_ioc_transfer transfer[1];

    // Construct SPI message for MCP3008
    tx_buf[0] = 0x01; // Start bit
    tx_buf[1] = (0x08 | channel) << 4; // Single-ended mode, channel selection
    tx_buf[2] = 0x00;

    memset(transfer, 0, sizeof(transfer));

    transfer[0].tx_buf = (unsigned long)tx_buf;
    transfer[0].rx_buf = (unsigned long)rx_buf;
    transfer[0].len = 3;
    transfer[0].delay_usecs = 0;
    transfer[0].speed_hz = SPI_MAX_SPEED_HZ;
    transfer[0].bits_per_word = SPI_BITS_PER_WORD;

    if (ioctl(spi_fd, SPI_IOC_MESSAGE(1), transfer) < 1) {
        perror("Error sending SPI message");
        return 0; // Return 0 on error
    }

    // Extract ADC value from response
    uint16_t adc_value = ((rx_buf[1] & 0x03) << 8) + rx_buf[2];
    return adc_value;
}

// Convert ADC value to current (Amperes)
float convert_to_current(uint16_t adc_value) {
    // Assuming Vref = 3.3V
    float voltage = (adc_value / 1023.0) * 3.3;
    float current = voltage / CURRENT_SENSITIVITY;
    return current;
}

// Log data with timestamp
void log_data(float current) {
    struct timeval tv;
    gettimeofday(&tv, NULL);
    time_t nowtime = tv.tv_sec;
    struct tm *nowtm = localtime(&nowtime);
    char tmbuf[64], buf[64];
    strftime(tmbuf, sizeof(tmbuf), "%Y-%m-%d %H:%M:%S", nowtm);
    snprintf(buf, sizeof(buf), "%s.%06ld", tmbuf, tv.tv_usec);
    printf("%s, Current: %.3f A\n", buf, current);
}

int main() {
    spi_config_t spi_config = {
        .mode = SPI_MODE,
        .bits_per_word = SPI_BITS_PER_WORD,
        .max_speed_hz = SPI_MAX_SPEED_HZ
    };

    // Setup signal handler
    signal(SIGINT, signal_handler);

    // Initialize SPI
    if (spi_init(SPI_BUS, SPI_DEVICE, spi_config) != 0) {
        fprintf(stderr, "SPI initialization failed.\n");
        return 1;
    }

    printf("SPI initialized successfully.\n");

    // Main loop
    while (!terminate) {
        uint16_t adc_value = read_mcp3008(MCP3008_CHANNEL);
        if (adc_value > 0) {
            float current = convert_to_current(adc_value);
            log_data(current);
        } else {
            fprintf(stderr, "Failed to read ADC value.\n");
        }
        sleep(SLEEP_DURATION_SEC);
    }

    // Cleanup
    close(spi_fd);
    printf("SPI closed.\n");

    return 0;
}

#include <stdio.h>
#include <stdint.h>
#include <stdbool.h>
#include <wiringPiI2C.h>
#include <unistd.h>
#include <time.h>
#include <signal.h>
#include <errno.h>

// Define the I2C address of the TMP117 sensor
#define TMP117_I2C_ADDR 0x48 // Default address, can be changed via ADDR0 and ADDR1 pins

// Register addresses for TMP117
#define TMP117_TEMP_RESULT_REG 0x00
#define TMP117_CONFIG_REG 0x01

// Configuration settings
#define TMP117_CONFIG_CONT_CONV 0x0200 // Continuous conversion mode
#define TMP117_CONFIG_AVG16 0x00C0      // 16 Averaged measurements

// Global variable to control the main loop
volatile sig_atomic_t keep_running = 1;

// Structure to hold the sensor data and configuration
typedef struct {
    int fd; // I2C file descriptor
    float temperature; // Last read temperature
    bool initialized; // Initialization status
} sensor_data_t;

// Signal handler for graceful shutdown
void intHandler(int dummy) {
    keep_running = 0;
}

// Function to initialize the TMP117 sensor
bool init_tmp117(sensor_data_t *sensor) {
    // Initialize wiringPi I2C
    sensor->fd = wiringPiI2CSetup(TMP117_I2C_ADDR);
    if (sensor->fd == -1) {
        perror("wiringPiI2CSetup failed");
        return false;
    }

    // Configure the sensor for continuous conversion mode and 16 averages
    int config_value = TMP117_CONFIG_CONT_CONV | TMP117_CONFIG_AVG16;
    if (wiringPiI2CWriteReg16(sensor->fd, TMP117_CONFIG_REG, config_value) == -1) {
        perror("Failed to write config register");
        return false;
    }

    sensor->initialized = true;
    return true;
}

// Function to read the temperature from the TMP117 sensor
float read_temperature(sensor_data_t *sensor) {
    if (!sensor->initialized) {
        fprintf(stderr, "Sensor not initialized.");
        return -273.15; // Return absolute zero if not initialized
    }

    int16_t raw_temp = wiringPiI2CReadReg16(sensor->fd, TMP117_TEMP_RESULT_REG);

    if (raw_temp == -1) {
        perror("Failed to read temperature register");
        return -273.15;
    }

    // Temperature is a signed 16-bit value, LSB is 7.8125 m°C
    float temperature = (float)raw_temp * 0.0078125;
    sensor->temperature = temperature;
    return temperature;
}

// Function to log the temperature data
void log_temperature(float temperature) {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[80];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    printf("[%s] Temperature: %.2f °C\n", timestamp, temperature);
}

int main() {
    // Set up signal handler for Ctrl+C
    signal(SIGINT, intHandler);

    sensor_data_t sensor;
    sensor.initialized = false;

    // Initialize the sensor
    if (!init_tmp117(&sensor)) {
        fprintf(stderr, "TMP117 initialization failed. Exiting.\n");
        return 1;
    }

    printf("TMP117 sensor initialized. Reading temperature every 5 seconds.\n");

    // Main loop
    while (keep_running) {
        float temperature = read_temperature(&sensor);
        if (temperature > -273.0) { // Basic sanity check
            log_temperature(temperature);
        } else {
            fprintf(stderr, "Error reading temperature.\n");
        }

        sleep(5);
    }

    printf("Exiting.\n");
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <unistd.h>
#include <fcntl.h>
#include <sys/ioctl.h>
#include <linux/i2c-dev.h>
#include <time.h>
#include <sys/time.h>
#include <signal.h>
#include <errno.h>

// Configuration
#define I2C_BUS_NUMBER 1
#define MLX90825_I2C_ADDRESS 0x40 // Replace with the actual I2C address
#define LOG_FILE "pressure_log.txt"
#define READ_INTERVAL_SEC 5

// Global variables
volatile sig_atomic_t program_running = 1;
int i2c_fd;
FILE *log_fp;

// Structure to hold sensor data
typedef struct {
    float pressure;
    struct timeval timestamp;
} sensor_data_t;

// Function prototypes
int setup_i2c();
int read_pressure(float *pressure);
int log_data(sensor_data_t data);
void signal_handler(int signal);
void cleanup();

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    program_running = 0;
    printf("Caught signal %d, exiting gracefully.\n", signal);
}

// I2C setup function
int setup_i2c() {
    char i2c_device[20];
    snprintf(i2c_device, sizeof(i2c_device), "/dev/i2c-%d", I2C_BUS_NUMBER);

    i2c_fd = open(i2c_device, O_RDWR);
    if (i2c_fd < 0) {
        perror("Error opening I2C device");
        return -1;
    }

    if (ioctl(i2c_fd, I2C_SLAVE, MLX90825_I2C_ADDRESS) < 0) {
        perror("Error setting I2C slave address");
        close(i2c_fd);
        return -1;
    }

    return 0;
}

// Function to read pressure from the sensor
int read_pressure(float *pressure) {
    uint8_t read_cmd = 0x10; // Example command, adjust as needed
    uint8_t buffer[2];
    int retries = 3;

    while (retries > 0) {
        if (write(i2c_fd, &read_cmd, 1) != 1) {
            perror("Error writing to I2C device");
            retries--;
            usleep(10000); // Wait before retrying
            continue;
        }

        if (read(i2c_fd, buffer, 2) != 2) {
            perror("Error reading from I2C device");
            retries--;
            usleep(10000); // Wait before retrying
            continue;
        }

        // Convert the received data to pressure (example)
        uint16_t raw_pressure = (buffer[0] << 8) | buffer[1];
        *pressure = (float)raw_pressure / 10.0; // Adjust scaling as needed
        return 0; // Success
    }

    fprintf(stderr, "Failed to read pressure after multiple retries.\n");
    return -1; // Failure after retries
}

// Function to log data to a file
int log_data(sensor_data_t data) {
    char timestamp_str[30];
    struct tm *tm_info;

    tm_info = localtime(&data.timestamp.tv_sec);
    strftime(timestamp_str, sizeof(timestamp_str), "%Y-%m-%d %H:%M:%S", tm_info);

    fprintf(log_fp, "%s.%06ld,%.2f\n", timestamp_str, data.timestamp.tv_usec, data.pressure);
    fflush(log_fp);

    return 0;
}

// Cleanup function to close resources
void cleanup() {
    if (i2c_fd >= 0) {
        close(i2c_fd);
    }
    if (log_fp != NULL) {
        fclose(log_fp);
    }
    printf("Cleanup complete.\n");
}

int main() {
    // Setup signal handling for Ctrl+C
    signal(SIGINT, signal_handler);

    // Initialize I2C
    if (setup_i2c() != 0) {
        fprintf(stderr, "I2C setup failed. Exiting.\n");
        return 1;
    }

    // Open the log file
    log_fp = fopen(LOG_FILE, "a");
    if (log_fp == NULL) {
        perror("Error opening log file");
        cleanup();
        return 1;
    }

    printf("Starting pressure sensor monitoring...\n");

    while (program_running) {
        sensor_data_t data;
        float pressure;

        // Read pressure from the sensor
        if (read_pressure(&pressure) == 0) {
            data.pressure = pressure;
            gettimeofday(&data.timestamp, NULL);

            // Log the data
            log_data(data);

            printf("Pressure: %.2f\n", pressure);
        } else {
            fprintf(stderr, "Failed to read pressure.\n");
        }

        sleep(READ_INTERVAL_SEC);
    }

    // Cleanup and exit
    cleanup();
    return 0;
}

