// Define the GPIO pin connected to the sensor's output
#define SENSOR_PIN 17

// Define a structure to hold sensor data and timestamp
typedef struct {
    time_t timestamp;
    int tilt_status; // 0 for no tilt, 1 for tilt detected
} SensorData;

// Global variable to control the main loop
volatile sig_atomic_t keep_running = 1;

// Signal handler for Ctrl+C
void sigint_handler(int signal) {
    keep_running = 0;
    printf("\nExiting gracefully...\n");
}

// Function to initialize the GPIO pin
int setup() {
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "WiringPi initialization failed: %s\n", strerror(errno));
        return -1;
    }

    pinMode(SENSOR_PIN, INPUT);
    pullUpDnControl(SENSOR_PIN, PUD_UP); // Enable pull-up resistor

    return 0;
}

// Function to read the sensor data
SensorData read_sensor() {
    SensorData data;
    data.timestamp = time(NULL);
    data.tilt_status = (digitalRead(SENSOR_PIN) == 0) ? 1 : 0; // Active low
    return data;
}

// Function to log the sensor data to a file
void log_data(SensorData data) {
    FILE *fp = fopen("tilt_sensor_log.txt", "a");
    if (fp == NULL) {
        fprintf(stderr, "Error opening log file: %s\n", strerror(errno));
        return;
    }

    char timestamp_str[30];
    strftime(timestamp_str, sizeof(timestamp_str), "%Y-%m-%d %H:%M:%S", localtime(&data.timestamp));

    fprintf(fp, "%s, %d\n", timestamp_str, data.tilt_status);
    fclose(fp);
}

// Function to print the sensor data to the console
void print_data(SensorData data) {
    char timestamp_str[30];
    strftime(timestamp_str, sizeof(timestamp_str), "%Y-%m-%d %H:%M:%S", localtime(&data.timestamp));

    printf("[%s] Tilt Status: %d\n", timestamp_str, data.tilt_status);
}

int main() {
    // Install signal handler for Ctrl+C
    signal(SIGINT, sigint_handler);

    // Initialize the GPIO
    if (setup() == -1) {
        return 1;
    }

    printf("Tilt sensor monitoring started. Press Ctrl+C to exit.\n");

    // Main loop
    while (keep_running) {
        SensorData data = read_sensor();
        print_data(data);
        log_data(data);
        sleep(1); // Check every 1 second
    }

    return 0;
}

#include <stdio.h>
