// I2C Addresses
#define ITG3200_ADDR 0x68
#define BMA180_ADDR 0x40

// ITG3200 Registers
#define ITG3200_X_OUT_H 0x1D

// BMA180 Registers
#define BMA180_CTRL_REG0 0x0D
#define BMA180_ACCX_H 0x02

// Sensitivity scales (adjust based on your specific sensor and configuration)
#define GYRO_SENSITIVITY 14.375 // degrees/sec per LSB
#define ACCEL_SENSITIVITY 0.0098 // m/s^2 per LSB (for +/- 1.5g range)

int i2c_handle_gyro;
int i2c_handle_accel;

volatile sig_atomic_t terminate = 0;

void signal_handler(int sig) {
    terminate = 1;
}

// Function to initialize the BMA180
int init_bma180() {
    // Set the range and enable accelerometer (example: +/- 1.5g range)
    char config_data = 0x03 << 4; // Range +/- 1.5g
    if (i2cWriteByteData(i2c_handle_accel, BMA180_CTRL_REG0, config_data) != 0) {
        fprintf(stderr, "Error writing to BMA180_CTRL_REG0: %s\n", gpioGetError( ));
        return -1;
    }
    gpioDelay(10000); // Wait 10ms

    // Set ee_w bit to allow writing to registers
    if (i2cWriteByteData(i2c_handle_accel, 0x08, 0x03) != 0) {
      fprintf(stderr, "Error writing to BMA180 register 0x08: %s\n", gpioGetError());
      return -1;
    }
    gpioDelay(10000);
    return 0;
}

// Function to read raw gyroscope data
int read_gyro_data(short *x, short *y, short *z) {
    char buf[6];
    if (i2cReadI2CBlockData(i2c_handle_gyro, ITG3200_X_OUT_H, buf, 6) != 6) {
        fprintf(stderr, "Error reading gyro data: %s\n", gpioGetError());
        return -1;
    }
    *x = (buf[0] << 8) | buf[1];
    *y = (buf[2] << 8) | buf[3];
    *z = (buf[4] << 8) | buf[5];
    return 0;
}

// Function to read raw accelerometer data
int read_accel_data(short *x, short *y, short *z) {
    char buf[6];
    if (i2cReadI2CBlockData(i2c_handle_accel, BMA180_ACCX_H, buf, 6) != 6) {
        fprintf(stderr, "Error reading accel data: %s\n", gpioGetError());
        return -1;
    }

    *x = (buf[0] << 8) | buf[1];
    *y = (buf[2] << 8) | buf[3];
    *z = (buf[4] << 8) | buf[5];
    return 0;
}

// Function to convert raw gyro data to angular velocities (degrees/sec)
void convert_gyro_data(short x, short y, short z, float *x_rate, float *y_rate, float *z_rate) {
    *x_rate = (float)x / GYRO_SENSITIVITY;
    *y_rate = (float)y / GYRO_SENSITIVITY;
    *z_rate = (float)z / GYRO_SENSITIVITY;
}

// Function to convert raw accelerometer data to accelerations (m/s^2)
void convert_accel_data(short x, short y, short z, float *x_accel, float *y_accel, float *z_accel) {
    *x_accel = (float)x * ACCEL_SENSITIVITY;
    *y_accel = (float)y * ACCEL_SENSITIVITY;
    *z_accel = (float)z * ACCEL_SENSITIVITY;
}

int main() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed: %s\n", gpioGetError());
        return 1;
    }

    gpioCfgClock(5, 1, 0); // 5us tick, DMA channel 1, off-peripheral (default, but explicit)

    i2c_handle_gyro = i2cOpen(1, ITG3200_ADDR, 0); // I2C bus 1, address 0x68, flags 0
    if (i2c_handle_gyro < 0) {
        fprintf(stderr, "Error opening I2C device for gyro: %s\n", gpioGetError());
        gpioTerminate();
        return 1;
    }

    i2c_handle_accel = i2cOpen(1, BMA180_ADDR, 0); // I2C bus 1, address 0x40, flags 0
    if (i2c_handle_accel < 0) {
        fprintf(stderr, "Error opening I2C device for accel: %s\n", gpioGetError());
        i2cClose(i2c_handle_gyro);
        gpioTerminate();
        return 1;
    }

    if (init_bma180() != 0) {
        fprintf(stderr, "Error initializing BMA180\n");
        i2cClose(i2c_handle_gyro);
        i2cClose(i2c_handle_accel);
        gpioTerminate();
        return 1;
    }

    signal(SIGINT, signal_handler);

    short gyro_x, gyro_y, gyro_z;
    short accel_x, accel_y, accel_z;
    float x_rate, y_rate, z_rate;
    float x_accel, y_accel, z_accel;

    while (!terminate) {
        if (read_gyro_data(&gyro_x, &gyro_y, &gyro_z) == 0 &&
            read_accel_data(&accel_x, &accel_y, &accel_z) == 0) {

            convert_gyro_data(gyro_x, gyro_y, gyro_z, &x_rate, &y_rate, &z_rate);
            convert_accel_data(accel_x, accel_y, accel_z, &x_accel, &y_accel, &z_accel);

            printf("Gyro: X=%.2f deg/s, Y=%.2f deg/s, Z=%.2f deg/s  ", x_rate, y_rate, z_rate);
            printf("Accel: X=%.2f m/s^2, Y=%.2f m/s^2, Z=%.2f m/s^2\n", x_accel, y_accel, z_accel);
        } else {
            fprintf(stderr, "Error reading sensor data\n");
        }
        gpioDelay(100000); // 0.1 second delay
    }

    i2cClose(i2c_handle_gyro);
    i2cClose(i2c_handle_accel);
    gpioTerminate();
    printf("Program terminated gracefully.\n");
    return 0;
}

