/*
 * Setup SPI communication
 */
int spi_setup(const char *device) {
    int fd;
    // Open SPI device
    if ((fd = open(device, O_RDWR)) < 0) {
        perror("Error opening SPI device");
        return -1;
    }

    // Set SPI mode
    uint8_t mode = SPI_MODE;
    if (ioctl(fd, SPI_IOC_WR_MODE, &mode) < 0) {
        perror("Error setting SPI mode");
        close(fd);
        return -1;
    }

    // Set bits per word
    uint8_t bits = SPI_BITS_PER_WORD;
    if (ioctl(fd, SPI_IOC_WR_BITS_PER_WORD, &bits) < 0) {
        perror("Error setting bits per word");
        close(fd);
        return -1;
    }

    // Set SPI speed
    uint32_t speed = SPI_SPEED;
    if (ioctl(fd, SPI_IOC_WR_MAX_SPEED_HZ, &speed) < 0) {
        perror("Error setting SPI speed");
        close(fd);
        return -1;
    }

    return fd;
}

/*
 * Read data from the SPI device
 */
uint16_t spi_read_data(int fd) {
    uint8_t tx_buf[2] = {0x00, 0x00}; // Transmit buffer (dummy data)
    uint8_t rx_buf[2] = {0x00, 0x00}; // Receive buffer
    struct spi_ioc_transfer transfer = {
        .tx_buf = (unsigned long)tx_buf,
        .rx_buf = (unsigned long)rx_buf,
        .len = 2, // 2 bytes
        .speed_hz = SPI_SPEED,
        .bits_per_word = SPI_BITS_PER_WORD,
    };

    if (ioctl(fd, SPI_IOC_MESSAGE(1), &transfer) < 0) {
        perror("Error sending SPI message");
        return 0; // Return 0 on error
    }

    // Combine the two bytes into a 16-bit value
    return (rx_buf[0] << 8) | rx_buf[1];
}

/*
 * Calculate flow rate from raw sensor data
 */
double calculate_flow_rate(uint16_t raw_data) {
    // Implement the flow rate calculation based on sensor datasheet
    // This is a placeholder; replace with the correct formula.
    double voltage = (raw_data / SENSOR_RESOLUTION) * SENSOR_VOLTAGE_RANGE;
    return voltage * 10.0; // Example conversion
}

/*
 * Log the sensor data to a file or terminal
 */
void log_data(sensor_data_t data) {
    char timestamp_str[32];
    struct tm *tm_info;

    tm_info = localtime(&data.timestamp);
    strftime(timestamp_str, sizeof(timestamp_str), "%Y-%m-%d %H:%M:%S", tm_info);

