        // Log the data
        log_data(sensor_data);

        // Sleep for a short interval
        sleep(1); // Adjust as needed
    }

    // Cleanup
    close(spi_fd);

    printf("Program terminated.\n");
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <fcntl.h>
#include <unistd.h>
#include <sys/ioctl.h>
#include <linux/i2c-dev.h>
#include <time.h>
#include <signal.h>

// Define sensor address and register addresses
#define SI1145_ADDR 0x60
#define SI1145_REG_PARTID 0x00
#define SI1145_REG_REVID 0x01
#define SI1145_REG_SEQID 0x02
#define SI1145_REG_INTCFG 0x03
#define SI1145_REG_IRQEN 0x04
#define SI1145_REG_ALSVISDATA0 0x22
#define SI1145_REG_ALSVISDATA1 0x23
#define SI1145_REG_ALSIRDATA0 0x24
#define SI1145_REG_ALSIRDATA1 0x25
#define SI1145_REG_ALSPROXDATA0 0x26
#define SI1145_REG_ALSPROXDATA1 0x27

// I2C file descriptor
int i2c_fd;

// Structure to hold sensor data
typedef struct {
    uint16_t visible;
    uint16_t ir;
    uint16_t prox;
} sensor_data_t;

// Function to write a byte to a register
int write_register(int fd, uint8_t reg, uint8_t value) {
    uint8_t buf[2] = {reg, value};
    if (write(fd, buf, 2) != 2) {
        perror("Failed to write to I2C device");
        return -1;
    }
    return 0;
}

// Function to read a byte from a register
int read_register(int fd, uint8_t reg, uint8_t *value) {
    if (write(fd, &reg, 1) != 1) {
        perror("Failed to write register address");
        return -1;
    }
    if (read(fd, value, 1) != 1) {
        perror("Failed to read register value");
        return -1;
    }
    return 0;
}

// Function to read a 16-bit value from two registers
int read_16bit(int fd, uint8_t reg, uint16_t *value) {
    uint8_t low, high;
    if (read_register(fd, reg, &low) < 0) return -1;
    if (read_register(fd, reg + 1, &high) < 0) return -1;
    *value = (uint16_t)high << 8 | (uint16_t)low;
    return 0;
}

// Function to read sensor data
int read_sensor_data(int fd, sensor_data_t *data) {
    if (read_16bit(fd, SI1145_REG_ALSVISDATA0, &data->visible) < 0) return -1;
    if (read_16bit(fd, SI1145_REG_ALSIRDATA0, &data->ir) < 0) return -1;
    if (read_16bit(fd, SI1145_REG_ALSPROXDATA0, &data->prox) < 0) return -1;
    return 0;
}

// Function to initialize the sensor
int init_sensor(int fd) {
    uint8_t part_id;
    if (read_register(fd, SI1145_REG_PARTID, &part_id) < 0) {
        fprintf(stderr, "Failed to read Part ID");
        return -1;
    }
    if (part_id != 0x45) {
        fprintf(stderr, "Incorrect Part ID: 0x%02x\n", part_id);
        return -1;
    }

    // Initialize sensor settings (example)
    write_register(fd, SI1145_REG_INTCFG, 0x00); // Disable interrupts
    write_register(fd, SI1145_REG_IRQEN, 0x00);  // Disable interrupt enable
    return 0;
}

// Signal handler for graceful shutdown
volatile sig_atomic_t keep_running = 1;
void sigint_handler(int signal) {
    (void)(signal);
    keep_running = 0;
}

int main() {
    // Open I2C device
    i2c_fd = open("/dev/i2c-1", O_RDWR);
    if (i2c_fd < 0) {
        perror("Failed to open I2C device");
        return 1;
    }

    // Specify slave address
    if (ioctl(i2c_fd, I2C_SLAVE, SI1145_ADDR) < 0) {
        perror("Failed to set I2C slave address");
        close(i2c_fd);
        return 1;
    }

    // Initialize the sensor
    if (init_sensor(i2c_fd) < 0) {
        fprintf(stderr, "Sensor initialization failed\n");
        close(i2c_fd);
        return 1;
    }

    sensor_data_t sensor_data;

    // Set up signal handler
    signal(SIGINT, sigint_handler);

    printf("Starting sensor data logging (press Ctrl+C to stop)...\n");

    while (keep_running) {
        // Read sensor data
        if (read_sensor_data(i2c_fd, &sensor_data) == 0) {
            // Log the data to the console
            printf("Visible: %5u, IR: %5u, Proximity: %5u\n", sensor_data.visible, sensor_data.ir, sensor_data.prox);
        } else {
            fprintf(stderr, "Failed to read sensor data\n");
        }

        // Wait for 500ms
        usleep(500000); // 500ms = 500000 microseconds
    }

    printf("Exiting...\n");

    // Close I2C device
    close(i2c_fd);

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <unistd.h>
#include <linux/i2c-dev.h>
#include <sys/ioctl.h>
#include <fcntl.h>
#include <time.h>
#include <signal.h>
#include <errno.h>

// Define MLX90615 I2C address
#define MLX90615_ADDR 0x5A

// Define register addresses
#define TOBJ1 0x07

// I2C bus
#define I2C_BUS "/dev/i2c-1"

// Global file descriptor for I2C
int i2c_fd;

// Structure for sensor data
typedef struct {
    float ambient_temp;
    float object_temp;
    time_t timestamp;
} sensor_data_t;

// Function to open the I2C bus
int open_i2c_bus(const char *bus) {
    int fd = open(bus, O_RDWR);
    if (fd < 0) {
        perror("Error opening I2C bus");
        return -1;
    }
    return fd;
}

// Function to set the I2C slave address
int set_i2c_slave(int fd, int addr) {
    if (ioctl(fd, I2C_SLAVE, addr) < 0) {
        perror("Error setting I2C slave address");
        return -1;
    }
    return 0;
}

// Function to read a 16-bit word from the sensor
int read_word(int fd, uint8_t reg_addr, uint16_t *value) {
    uint8_t buf[2];
    if (write(fd, &reg_addr, 1) != 1) {
        perror("Error writing register address");
        return -1;
    }
    if (read(fd, buf, 2) != 2) {
        perror("Error reading data");
        return -1;
    }
    *value = (buf[1] << 8) | buf[0];
    return 0;
}

// Function to read temperature from the sensor
int read_temperature(int fd, float *temperature) {
    uint16_t raw_temp;
    if (read_word(fd, TOBJ1, &raw_temp) < 0) {
        return -1;
    }
    // Temperature conversion (example, check datasheet for actual formula)
    *temperature = (float)raw_temp * 0.02 - 273.15; // Convert to Celsius
    return 0;
}

// Function to log sensor data
void log_data(sensor_data_t data) {
    char timestamp_str[30];
    struct tm *tm_info = localtime(&data.timestamp);
    strftime(timestamp_str, sizeof(timestamp_str), "%Y-%m-%d %H:%M:%S", tm_info);

    printf("[%s] Object Temperature: %.2f °C\n", timestamp_str, data.object_temp);
}

// Signal handler for graceful shutdown
volatile sig_atomic_t stop_flag = 0;
void signal_handler(int sig) {
    stop_flag = 1;
    printf("\nCtrl+C detected, exiting...\n");
}

int main() {
    // Register signal handler
    signal(SIGINT, signal_handler);

    // Open I2C bus
    i2c_fd = open_i2c_bus(I2C_BUS);
    if (i2c_fd < 0) {
        return 1;
    }

    // Set I2C slave address
    if (set_i2c_slave(i2c_fd, MLX90615_ADDR) < 0) {
        close(i2c_fd);
        return 1;
    }

    // Main loop
    while (!stop_flag) {
        sensor_data_t sensor_data;

        // Read object temperature
        if (read_temperature(i2c_fd, &sensor_data.object_temp) < 0) {
            fprintf(stderr, "Error reading temperature, retrying...\n");
            sleep(1); // Wait before retrying
            continue; // Skip to the next iteration
        }

        // Get current timestamp
        sensor_data.timestamp = time(NULL);

        // Log the data
        log_data(sensor_data);

        // Wait for a while
        sleep(2); // Check every 2 seconds
    }

    // Close I2C bus
    close(i2c_fd);

    return 0;
}

#include <stdio.h>
#include <pigpio.h>
#include <time.h>
#include <signal.h>
#include <stdlib.h>

// Define GPIO pins
#define TILT_SENSOR_PIN 17
#define LED_PIN 27

// Global variables for signal handling
volatile sig_atomic_t program_running = 1;

// Signal handler function
void signal_handler(int signal) {
    program_running = 0;
    printf("\nCaught signal %d, exiting gracefully...\n", signal);
}

// Function to log tilt events to a file
void log_tilt_event(const char *timestamp) {
    FILE *fp = fopen("tilt_log.txt", "a");
    if (fp == NULL) {
        perror("Error opening tilt_log.txt");
        return;
    }
    fprintf(fp, "%s Tilt detected\n", timestamp);
    fclose(fp);
}

int main() {
    // Register signal handlers for SIGINT and SIGTERM
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO pin modes
    gpioSetMode(TILT_SENSOR_PIN, PI_INPUT);
    gpioSetMode(LED_PIN, PI_OUTPUT);

    printf("Tilt sensor monitoring started. Press Ctrl+C to exit.\n");

    while (program_running) {
        // Debounce the tilt sensor input
        int high_count = 0;
        for (int i = 0; i < 3; ++i) {
            if (gpioRead(TILT_SENSOR_PIN) == 1) {
                high_count++;
            }
            gpioDelay(3); // 3ms delay
        }

        // If tilt is validated (3 consecutive HIGH readings)
        if (high_count == 3) {
            // Get current timestamp
            time_t rawtime;
            struct tm *timeinfo;
            char timestamp[80];

            time(&rawtime);
            timeinfo = localtime(&rawtime);
            strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

            // Log the tilt event
            log_tilt_event(timestamp);

            // Illuminate the LED
            gpioWrite(LED_PIN, 1);
            gpioDelay(500); // 500ms delay
            gpioWrite(LED_PIN, 0);

            gpioDelay(500); // Delay before next reading to prevent multiple triggers
        } else {
            gpioDelay(10); // Small delay to prevent busy-waiting
        }
    }

    // Clean up GPIO pins before exiting
    gpioWrite(LED_PIN, 0); // Ensure LED is off
    gpioTerminate();

    return 0;
}

#include <stdio.h>
