#include <sys/time.h>

// VEML6040 I2C address
#define VEML6040_ADDR 0x10

// VEML6040 register addresses
#define VEML6040_ALS_CONF_REG 0x00
#define VEML6040_ALS_RED_DATA 0x08
#define VEML6040_ALS_GREEN_DATA 0x0A
#define VEML6040_ALS_BLUE_DATA 0x0C
#define VEML6040_ALS_WHITE_DATA 0x0E

// Photoresistor ADC channel (MCP3008)
#define PHOTORESISTOR_CHANNEL 0

// WiringPi SPI channel (MCP3008)
#define SPI_CHANNEL 0

// MCP3008 SPI speed
#define SPI_SPEED 1000000 // 1MHz

// Reference voltage for ADC (V)
#define VREF 3.3

// Known resistance value in the voltage divider (ohms)
#define R_KNOWN 10000.0

// Function to read data from the MCP3008 ADC
int read_mcp3008(int spi_fd, int channel)
{
    unsigned char buffer[3];
    buffer[0] = 0x01;                  // Start bit
    buffer[1] = (0x08 | channel) << 4; // Single-ended mode, channel selection
    buffer[2] = 0x00;

    wiringPiSPIDataRW(SPI_CHANNEL, buffer, 3);

    int adc_value = ((buffer[1] & 0x03) << 8) + buffer[2];
    return adc_value;
}

// Function to initialize the VEML6040 sensor
int init_veml6040(int fd)
{
    // Recommended configuration: integration time = 128T, gain = 1/8
    int config = 0x00; // Integration time 100ms, Gain 1/8, Power Saving Mode: Disable

    if (wiringPiI2CWriteReg16(fd, VEML6040_ALS_CONF_REG, config) < 0) {
        fprintf(stderr, "Error writing to VEML6040 configuration register: %s\n", strerror(errno));
        return -1;
    }

    return 0;
}

// Function to read ambient light data from the VEML6040 sensor
int read_veml6040(int fd, int *red, int *green, int *blue, int *ambient)
{
    *red = wiringPiI2CReadReg16(fd, VEML6040_ALS_RED_DATA);
    *green = wiringPiI2CReadReg16(fd, VEML6040_ALS_GREEN_DATA);
    *blue = wiringPiI2CReadReg16(fd, VEML6040_ALS_BLUE_DATA);
    *ambient = wiringPiI2CReadReg16(fd, VEML6040_ALS_WHITE_DATA);

    if (*red < 0 || *green < 0 || *blue < 0 || *ambient < 0) {
        fprintf(stderr, "Error reading from VEML6040 data registers: %s\n", strerror(errno));
        return -1;
    }

    return 0;
}

// Function to calculate the resistance of the photoresistor
double calculate_photoresistor_resistance(int adc_value)
{
    double v_out = (double)adc_value * VREF / 1024.0;
    double r_photoresistor = R_KNOWN * (VREF - v_out) / v_out;
    return r_photoresistor;
}

int main()
{
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "Error initializing WiringPi: %s\n", strerror(errno));
        return 1;
    }

    // Initialize I2C for VEML6040
