            // Read photoresistor data
            adc_value = read_mcp3008(spi_fd, PHOTORESISTOR_CHANNEL);
            photoresistor_resistance = calculate_photoresistor_resistance(adc_value);

            // Get current timestamp
            gettimeofday(&tv, NULL);
            timeinfo = localtime(&tv.tv_sec);
