}

// Function to initialize UART
int init_uart(const char *port, int baud_rate) {
    int fd = open(port, O_RDWR | O_NOCTTY | O_SYNC);
    if (fd == -1) {
        perror("Error opening UART port");
        return -1;
    }

    struct termios tty;
    if (tcgetattr(fd, &tty) != 0) {
        perror("Error getting termios attributes");
        close(fd);
        return -1;
    }

    // Configure UART parameters
    tty.c_cflag = baud_rate | CS8 | CLOCAL | CREAD;  // 8-bit chars, enable receiver, ignore modem control lines
    tty.c_iflag = IGNPAR;                          // Ignore parity errors
    tty.c_oflag = 0;                               // Raw output
    tty.c_lflag = 0;                               // Non-canonical mode
    tty.c_cc[VMIN] = 0;                            // Read at least 0 characters
    tty.c_cc[VTIME] = 5;                           // Wait for 0.5 seconds

    if (tcsetattr(fd, TCSANOW, &tty) != 0) {
        perror("Error setting termios attributes");
        close(fd);
        return -1;
    }

    return fd;
}

