    if (bytes_read != sizeof(buffer)) {
        fprintf(stderr, "Error reading data from UART: %zd bytes read (expected %zu)\n", bytes_read, sizeof(buffer));
        return -1;
    }

    memcpy(&(data->range), buffer, 4);
    memcpy(&(data->velocity), buffer + 4, 4);

    return 0;
}

