    // Initialize UART
    uart_fd = init_uart(UART_PORT, BAUD_RATE);
    if (uart_fd == -1) {
        return EXIT_FAILURE;
    }

    printf("UART initialized successfully. Reading data...");

    // Main loop
    while (!terminate) {
        // Read radar data
