// SLF3S-1300F I2C address
#define SLF3S_ADDR 0x36

// SLF3S-1300F commands
#define MEASURE_LIQUID 0x3608
#define STOP_MEASUREMENT 0x3FF9

// Global variable to control program execution
volatile sig_atomic_t keep_running = 1;

// Structure to hold sensor data and I2C configuration
typedef struct {
    int i2c_fd;
    char *i2c_dev;
} sensor_config_t;

// Signal handler for graceful shutdown
void sigint_handler(int signal) {
    keep_running = 0;
    printf("\nExiting gracefully...\n");
}

// Function to initialize the I2C connection
int init_i2c(sensor_config_t *config) {
    config->i2c_fd = open(config->i2c_dev, O_RDWR);
    if (config->i2c_fd < 0) {
        perror("Error opening I2C device");
        return -1;
    }

    if (ioctl(config->i2c_fd, I2C_SLAVE, SLF3S_ADDR) < 0) {
        perror("Error setting I2C slave address");
        close(config->i2c_fd);
        return -1;
    }

    return 0;
}

// Function to send a command to the sensor
int send_command(int fd, uint16_t command) {
    uint8_t buf[2];
    buf[0] = (command >> 8) & 0xFF;
    buf[1] = command & 0xFF;

    if (write(fd, buf, 2) != 2) {
        perror("Error writing command to I2C");
        return -1;
    }

    return 0;
}

// Function to read flow rate from the sensor
int16_t read_flow_rate(int fd) {
    uint8_t buf[3];
    int16_t flow_rate;

    if (read(fd, buf, 3) != 3) {
        perror("Error reading data from I2C");
        return -1;
    }

    flow_rate = (buf[0] << 8) | buf[1];

    // CRC check (not implemented for brevity, but should be in a real application)
    return flow_rate;
}

// Function to stop measurement
int stop_measurement(int fd) {
    return send_command(fd, STOP_MEASUREMENT);
}

// Function to start measurement
int start_measurement(int fd) {
    return send_command(fd, MEASURE_LIQUID);
}

// Function to log the flow rate
void log_flow_rate(int16_t flow_rate) {
    // Scale the raw value to ml/min (example scaling, adjust based on sensor datasheet)
    float scaled_flow_rate = flow_rate / 1000.0f; // Example scaling
    printf("Flow Rate: %.3f ml/min\n", scaled_flow_rate);
}

int main() {
    sensor_config_t config;
    config.i2c_dev = "/dev/i2c-1"; // I2C device on Raspberry Pi

    // Install signal handler
    signal(SIGINT, sigint_handler);

    // Initialize I2C
    if (init_i2c(&config) < 0) {
        fprintf(stderr, "I2C initialization failed\n");
        return 1;
    }

    // Start measurement
    if (start_measurement(config.i2c_fd) < 0) {
        fprintf(stderr, "Failed to start measurement\n");
        close(config.i2c_fd);
        return 1;
    }

    // Main loop
    while (keep_running) {
        int16_t flow_rate = read_flow_rate(config.i2c_fd);
        if (flow_rate >= 0) {
            log_flow_rate(flow_rate);
        } else {
            fprintf(stderr, "Failed to read flow rate\n");
        }
        usleep(100000); // 100ms delay
    }

    // Stop measurement
    if (stop_measurement(config.i2c_fd) < 0) {
        fprintf(stderr, "Failed to stop measurement\n");
    }

    // Close I2C device
    close(config.i2c_fd);

    return 0;
}

