// Si1145 I2C address
#define SI1145_ADDR 0x60

// Register addresses
#define REG_PARTID 0x00
#define REG_REVID 0x01
#define REG_SEQID 0x02

#define REG_ALS_VIS_DATA0 0x22
#define REG_ALS_IR_DATA0 0x24

// Configuration registers (example)
#define REG_PS_LED21_SELECT 0x73
#define REG_PS_GAIN 0x77
#define REG_ALS_VIS_ADC_MUX 0x80


int fd; // I2C file descriptor
bool running = true;

// Function to handle Ctrl+C signal
void signal_handler(int signum) {
    running = false;
    printf("\nExiting gracefully...\n");
}

// Function to read a register
int read_register(int reg) {
    int result = wiringPiI2CReadReg8(fd, reg);
    if (result == -1) {
        fprintf(stderr, "Error reading register 0x%02X\n", reg);
        return -1;
    }
    return result;
}

// Function to write a register
int write_register(int reg, int value) {
    int result = wiringPiI2CWriteReg8(fd, reg, value);
    if (result == -1) {
        fprintf(stderr, "Error writing register 0x%02X with value 0x%02X\n", reg, value);
        return -1;
    }
    return 0;
}

// Function to read ambient light and IR data
int read_sensor_data(uint16_t *ambient_light, uint16_t *ir_light) {
    int als_vis_low, als_vis_high, als_ir_low, als_ir_high;

    als_vis_low = read_register(REG_ALS_VIS_DATA0);
    als_vis_high = read_register(REG_ALS_VIS_DATA0 + 1);
    als_ir_low = read_register(REG_ALS_IR_DATA0);
    als_ir_high = read_register(REG_ALS_IR_DATA0 + 1);

    if (als_vis_low == -1 || als_vis_high == -1 || als_ir_low == -1 || als_ir_high == -1) {
        return -1; // Indicate failure
    }

    *ambient_light = (uint16_t)((als_vis_high << 8) | als_vis_low);
    *ir_light = (uint16_t)((als_ir_high << 8) | als_ir_low);

    return 0;
}

// Function to initialize the Si1145 sensor
int initialize_sensor() {
    // Basic initialization (example, adjust as needed)
    if (write_register(REG_PS_LED21_SELECT, 0x03) == -1) return -1; // Enable LED
    if (write_register(REG_PS_GAIN, 0x00) == -1) return -1;       // Set gain
    if (write_register(REG_ALS_VIS_ADC_MUX, 0x20) == -1) return -1; // Set ALS mux
    return 0;
}

int main() {
    // Register signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Initialize wiringPi I2C
    fd = wiringPiI2CSetup(SI1145_ADDR);
    if (fd == -1) {
        fprintf(stderr, "Error initializing I2C communication.\n");
        return 1;
    }

    printf("I2C communication initialized successfully.\n");

    // Verify sensor connection (optional)
    int part_id = read_register(REG_PARTID);
    if (part_id != 0x46) {
        fprintf(stderr, "Error: Si1145 not found (Part ID: 0x%02X)\n", part_id);
        return 1;
    }

    printf("Si1145 sensor found. Initializing...\n");

    // Initialize the sensor
    if (initialize_sensor() == -1) {
        fprintf(stderr, "Error initializing Si1145 sensor.\n");
        return 1;
    }

    printf("Si1145 sensor initialized successfully.\n");

    uint16_t ambient_light, ir_light;
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[20];

    // Main loop
    while (running) {
        if (read_sensor_data(&ambient_light, &ir_light) == 0) {
            // Get current timestamp
            time(&rawtime);
            timeinfo = localtime(&rawtime);
            strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

            // Print the data with timestamp
            printf("[%s] Ambient Light: %u, IR Light: %u\n", timestamp, ambient_light, ir_light);
        } else {
            fprintf(stderr, "Error reading sensor data.\n");
        }

        sleep(1); // Read every 1 second
    }

    return 0;
}

#include <stdio.h>
