#include <pigpio.h>

// Define SPI parameters
#define SPI_CHANNEL 0
#define SPI_BAUD 1000000 // 1 MHz
#define MCP3008_CHANNEL 0 // Soil moisture sensor connected to channel 0

int spi_handle;

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("\nCaught signal %d, cleaning up...\n", signal);
    spiClose(spi_handle);
    gpioTerminate();
    exit(0);
}

// Function to read from MCP3008 ADC
int read_mcp3008(int channel) {
    unsigned char spi_tx_buf[3];
    unsigned char spi_rx_buf[3];

    // Construct SPI message
    spi_tx_buf[0] = 0x01;                  // Start bit
    spi_tx_buf[1] = 0x08 | (channel << 4); // Single-ended mode + channel number
    spi_tx_buf[2] = 0x00;                  // Don't care

    // Perform SPI transaction
    int spi_result = spiReadWrite(spi_handle, (char *)spi_tx_buf, (char *)spi_rx_buf, 3);

    if (spi_result != 3) {
        fprintf(stderr, "SPI read/write failed: %d\n", spi_result);
        return -1; // Indicate error
    }

    // Extract ADC value (10 bits from bits 11-2)
    int adc_value = ((spi_rx_buf[1] & 0x03) << 8) | spi_rx_buf[2];

    return adc_value;
}

int main() {
    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Open SPI channel
    spi_handle = spiOpen(SPI_CHANNEL, SPI_BAUD, 0); // SPI channel 0, 1 MHz, mode 0
    if (spi_handle < 0) {
        fprintf(stderr, "SPI open failed: %d\n", spi_handle);
        gpioTerminate();
        return 1;
    }

    // Register signal handler for graceful shutdown
    signal(SIGINT, signal_handler);

    // Main loop
    while (1) {
        // Read soil moisture sensor value
        int soil_moisture = read_mcp3008(MCP3008_CHANNEL);

        if (soil_moisture >= 0) {
            // Get current timestamp
            time_t current_time = time(NULL);
            char *time_string = ctime(&current_time);

            // Remove trailing newline from ctime()
            time_string[strcspn(time_string, "\n")] = 0;

            // Log sensor reading to the console
            printf("Timestamp: %s, Soil Moisture: %d\n", time_string, soil_moisture);
        } else {
            fprintf(stderr, "Failed to read soil moisture sensor\n");
        }

        // Delay for 5 seconds
        gpioSleep(PI_TIME_RELATIVE, 5, 0);
    }

    // The following lines will never be reached due to the infinite loop.
    spiClose(spi_handle);
    gpioTerminate();
    return 0;
}

