#include <unistd.h>
#include <sys/ioctl.h>
#include <linux/i2c-dev.h>
#include <time.h>
#include <signal.h>

// Configuration
#define I2C_BUS "/dev/i2c-1"  // I2C bus on Raspberry Pi
#define IMP23ABSU_ADDR 0x69    // I2C address of IMP23ABSU
#define DATA_REG_L 0x01          // Register address for lower byte of data
#define DATA_REG_H 0x02          // Register address for higher byte of data
#define SAMPLE_PERIOD_SEC 1      // Sample every 1 second

volatile sig_atomic_t program_running = 1;

// Structure to hold sensor data
typedef struct {
    int16_t data; // Signed 16-bit data
    time_t timestamp; // Timestamp of the reading
} sensor_data_t;

// Function prototypes
int i2c_setup(int addr);
int16_t read_sensor_data(int fd);
void log_data(sensor_data_t data);
void signal_handler(int signal);

// I2C file descriptor
int i2c_fd = -1;

// Setup I2C communication
int i2c_setup(int addr) {
    int fd = open(I2C_BUS, O_RDWR);
    if (fd < 0) {
        perror("Error opening I2C bus");
        return -1;
    }

    if (ioctl(fd, I2C_SLAVE, addr) < 0) {
        perror("Error setting I2C slave address");
        close(fd);
        return -1;
    }

    return fd;
}

// Read data from the sensor
int16_t read_sensor_data(int fd) {
    uint8_t data[2];

    // Read lower byte
    if (write(fd, &DATA_REG_L, 1) != 1) {
        perror("Error writing to I2C device (low byte register)");
        return -1;
    }
    if (read(fd, &data[0], 1) != 1) {
        perror("Error reading from I2C device (low byte)");
        return -1;
    }

    // Read higher byte
    if (write(fd, &DATA_REG_H, 1) != 1) {
        perror("Error writing to I2C device (high byte register)");
        return -1;
    }
    if (read(fd, &data[1], 1) != 1) {
        perror("Error reading from I2C device (high byte)");
        return -1;
    }

    // Combine the two bytes into a 16-bit signed integer
    int16_t combined_data = (int16_t)((data[1] << 8) | data[0]);

    return combined_data;
}

// Log the sensor data to the console
void log_data(sensor_data_t data) {
    struct tm *timeinfo;
    char timestamp_str[20];

    timeinfo = localtime(&data.timestamp);
    strftime(timestamp_str, sizeof(timestamp_str), "%Y-%m-%d %H:%M:%S", timeinfo);

    printf("[%s] Sensor Data: %d\n", timestamp_str, data.data);
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    program_running = 0;
    printf("\nExiting program...\n");
}

int main() {
    // Register signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Initialize I2C communication
    i2c_fd = i2c_setup(IMP23ABSU_ADDR);
    if (i2c_fd < 0) {
        fprintf(stderr, "Failed to initialize I2C communication. Exiting.\n");
        return 1;
    }

    printf("IMP23ABSU Data Logger started. Press Ctrl+C to exit.\n");

    // Main loop
    while (program_running) {
        sensor_data_t sensor_reading;

        // Read sensor data
        int16_t raw_data = read_sensor_data(i2c_fd);
        if (raw_data == -1) {
            fprintf(stderr, "Failed to read sensor data. Retrying in %d seconds.\n", SAMPLE_PERIOD_SEC);
        } else {
            // Store data and timestamp
            sensor_reading.data = raw_data;
            time(&sensor_reading.timestamp);

            // Log the data
            log_data(sensor_reading);
        }

        sleep(SAMPLE_PERIOD_SEC);
    }

    // Close I2C device
    close(i2c_fd);

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
#include <unistd.h>
#include <signal.h>

// Define GPIO pins for the sensors
#define SENSOR_1_PIN 17
#define SENSOR_2_PIN 27

// Function to handle program termination (Ctrl+C)
void cleanup_handler(int signal) {
    printf("\nCleaning up and exiting...\n");
    // No GPIO cleanup needed as wiringPiSetupGpio doesn't modify the physical pin mode permanently.
    exit(0);
}

int main() {
    // Set up signal handler for Ctrl+C
    signal(SIGINT, cleanup_handler);

    // Initialize wiringPi using GPIO numbering
    if (wiringPiSetupGpio() != 0) {
        fprintf(stderr, "Error initializing wiringPi using GPIO numbering!\n");
        return 1;
    }

    // Configure the sensor pins as input
    pinMode(SENSOR_1_PIN, INPUT);
    pinMode(SENSOR_2_PIN, INPUT);

    printf("Obstacle avoidance program started. Press Ctrl+C to exit.\n");

    // Main loop
    while (1) {
        int sensor1_value = digitalRead(SENSOR_1_PIN);
        int sensor2_value = digitalRead(SENSOR_2_PIN);

        if (sensor1_value == LOW) {
            printf("Obstacle detected on sensor 1 (GPIO 17)\n");
        }
        if (sensor2_value == LOW) {
            printf("Obstacle detected on sensor 2 (GPIO 27)\n");
        }
        if (sensor1_value == HIGH && sensor2_value == HIGH) {
            printf("No obstacles detected\n");
        }

        delay(500); // Wait for 500ms
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <unistd.h>
#include <pigpio.h>
#include <errno.h>
#include <time.h>

// BH1750 I2C address
#define BH1750_ADDR 0x23

// BH1750 command for high-resolution mode (continuous)
#define BH1750_CONTINUOUS_HIGH_RES_MODE 0x10

int i2c_handle;

// Signal handler to close I2C connection and terminate pigpio
void signal_handler(int signal) {
    printf("\nCaught signal %d, cleaning up...\n", signal);
    if (i2c_handle >= 0) {
        i2cClose(i2c_handle);
    }
    gpioTerminate();
    exit(0);
}

int main() {
    // Register signal handlers
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Open I2C bus
    i2c_handle = i2cOpen(1, BH1750_ADDR, 0);
    if (i2c_handle < 0) {
        fprintf(stderr, "Failed to open I2C device: %s\n", pigpio_error(i2c_handle));
        gpioTerminate();
        return 1;
    }

    // Set BH1750 to continuous high-resolution mode
    int write_result = i2cWriteByteData(i2c_handle, BH1750_CONTINUOUS_HIGH_RES_MODE);
    if (write_result < 0) {
        fprintf(stderr, "Failed to set mode: %s\n", pigpio_error(write_result));
        i2cClose(i2c_handle);
        gpioTerminate();
        return 1;
    }

    struct timespec sleep_time;
    sleep_time.tv_sec = 5;  // 5 seconds
    sleep_time.tv_nsec = 0; // 0 nanoseconds

    // Read data every 5 seconds
    while (1) {
        // Read 2 bytes of data (illuminance value)
        int reading = i2cReadWordData(i2c_handle);
        if (reading < 0) {
            fprintf(stderr, "Failed to read data: %s\n", pigpio_error(reading));
        } else {
            // Convert reading to lux
            float lux = (float)reading / 1.2;
            printf("Illuminance: %.1f lux\n", lux);
        }

        // Wait for 5 seconds
        if (nanosleep(&sleep_time, &sleep_time) != 0) {
            perror("nanosleep");
        }
    }

    // This part will not be reached due to the infinite loop
    i2cClose(i2c_handle);
    gpioTerminate();
    return 0;
}

#include <stdio.h>
#include <wiringPiI2C.h>
#include <wiringPi.h>
#include <time.h>
#include <errno.h>
#include <unistd.h>

#define MLX90615_ADDR 0x5A
#define TA_REG 0x06
#define TO_REG 0x07

int main(void) {
    int fd; // I2C file descriptor
    int raw_ambient, raw_object;
    float ambient_temp, object_temp;
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[20];

    if (wiringPiSetup() == -1) {
        fprintf(stderr, "wiringPiSetup failed: %s\n", strerror(errno));
        return 1;
    }

    fd = wiringPiI2CSetup(MLX90615_ADDR);
    if (fd == -1) {
        fprintf(stderr, "wiringPiI2CSetup failed: %s\n", strerror(errno));
        return 1;
    }

    while (1) {
        // Read ambient temperature
        raw_ambient = wiringPiI2CReadReg16(fd, TA_REG);
        if (raw_ambient < 0) {
            fprintf(stderr, "Error reading ambient temperature: %s\n", strerror(errno));
        } else {
            ambient_temp = (raw_ambient * 0.02) - 273.15;
        }

        // Read object temperature
        raw_object = wiringPiI2CReadReg16(fd, TO_REG);
        if (raw_object < 0) {
            fprintf(stderr, "Error reading object temperature: %s\n", strerror(errno));
        } else {
            object_temp = (raw_object * 0.02) - 273.15;
        }

        // Get current timestamp
        time(&rawtime);
        timeinfo = localtime(&rawtime);
        strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

        // Print the temperatures with timestamp
        if (raw_ambient >= 0 && raw_object >= 0) {
          printf("%s Ambient: %.2f C, Object: %.2f C\n", timestamp, ambient_temp, object_temp);
        }

        sleep(2);
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <time.h>
#include <signal.h>
#include <unistd.h>

#define GPIO_PIN 17
#define SAMPLE_INTERVAL_MS 500

// Structure to hold program state
typedef struct {
    int running;
    double last_tick;
    double rpm;
} AppState;

AppState app_state = {1, 0.0, 0.0};

// Function prototypes
void signal_handler(int signal);
void update_rpm(int gpio, int level, uint32_t tick);
int initialize_gpio();
void log_rpm();

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    app_state.running = 0;
    printf("\nExiting gracefully...\n");
}

// Callback function to update RPM
void update_rpm(int gpio, int level, uint32_t tick) {
    if (level == PI_HIGH) {
        double current_tick = tick;
        double diff = current_tick - app_state.last_tick;

        if (app_state.last_tick > 0 && diff > 0) {
            app_state.rpm = 60000000.0 / diff; // Convert to RPM
        }
        app_state.last_tick = current_tick;
    }
}

// Initialize GPIO
int initialize_gpio() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return -1;
    }

    if (gpioSetMode(GPIO_PIN, PI_INPUT) < 0) {
        fprintf(stderr, "Failed to set GPIO mode\n");
        gpioTerminate();
        return -1;
    }

    if (gpioSetPullUpDown(GPIO_PIN, PI_PUD_UP) < 0) {
        fprintf(stderr, "Failed to set pull-up resistor\n");
        gpioTerminate();
        return -1;
    }

    if (gpioSetAlertFunc(GPIO_PIN, update_rpm) < 0) {
        fprintf(stderr, "Failed to set alert function\n");
        gpioTerminate();
        return -1;
    }

    return 0;
}

// Log RPM with timestamp
void log_rpm() {
    time_t rawtime;
    struct tm * timeinfo;
    char timestamp[80];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    printf("[%s] RPM: %.2f\n", timestamp, app_state.rpm);
}

int main() {
    // Register signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Initialize GPIO
    if (initialize_gpio() != 0) {
        return 1;
    }

    printf("RPM measurement started. Press Ctrl+C to exit.\n");

    // Main loop
    while (app_state.running) {
        log_rpm();
        gpioDelay(SAMPLE_INTERVAL_MS * 1000); // pigpioDelay takes microseconds
    }

    // Clean up GPIO
    gpioTerminate();

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <fcntl.h>
#include <unistd.h>
#include <errno.h>
#include <signal.h>
#include <time.h>

// Define GPIO pins
#define GPIO17 17
#define GPIO27 27

// Define delay time in nanoseconds (500ms)
#define DELAY_NS 500000000L

// Global flag to handle program termination
volatile sig_atomic_t program_running = 1;

// Signal handler for SIGINT (Ctrl+C)
void signal_handler(int sig) {
    (void)sig; // Suppress unused parameter warning
    program_running = 0;
    printf("\nExiting program...\n");
}

// Function to read the value of a GPIO pin using sysfs
int read_gpio(int gpio) {
    char path[64];
    int fd;
    char value_str[3];
    int value;

    // Construct the path to the GPIO value file
    snprintf(path, sizeof(path), "/sys/class/gpio/gpio%d/value", gpio);

    // Open the GPIO value file for reading
    fd = open(path, O_RDONLY);
    if (fd < 0) {
        perror("Failed to open GPIO value file");
        return -1; // Indicate error
    }

    // Read the GPIO value
    if (read(fd, value_str, 3) < 0) {
        perror("Failed to read GPIO value");
        close(fd);
        return -1; // Indicate error
    }

    // Close the GPIO value file
    close(fd);

    // Convert the string value to an integer
    value = atoi(value_str);

    return value;
}

// Function to initialize a GPIO pin by exporting it and setting its direction to input
int initialize_gpio(int gpio) {
    int fd;
    char buf[64];

    // Export the GPIO pin
    fd = open("/sys/class/gpio/export", O_WRONLY);
    if (fd < 0) {
        perror("Failed to open /sys/class/gpio/export");
        return -1;
    }
    snprintf(buf, sizeof(buf), "%d", gpio);
    if (write(fd, buf, strlen(buf)) < 0) {
        perror("Failed to write to /sys/class/gpio/export");
        close(fd);
        return -1;
    }
    close(fd);

    // Set the GPIO direction to input
    snprintf(buf, sizeof(buf), "/sys/class/gpio/gpio%d/direction", gpio);
    fd = open(buf, O_WRONLY);
    if (fd < 0) {
        perror("Failed to open GPIO direction file");
        return -1;
    }
    if (write(fd, "in", 2) < 0) {
        perror("Failed to write to GPIO direction file");
        close(fd);
        return -1;
    }
    close(fd);

    return 0;
}

// Function to uninitialize a GPIO pin by unexporting it
int uninitialize_gpio(int gpio) {
    int fd;
    char buf[64];

    fd = open("/sys/class/gpio/unexport", O_WRONLY);
    if (fd < 0) {
        perror("Failed to open /sys/class/gpio/unexport");
        return -1;
    }
    snprintf(buf, sizeof(buf), "%d", gpio);
    if (write(fd, buf, strlen(buf)) < 0) {
        perror("Failed to write to /sys/class/gpio/unexport");
        close(fd);
        return -1;
    }
    close(fd);

    return 0;
}

int main() {
    // Structure for specifying nanosecond delays
    struct timespec req = {0};  // Initialize to zero
    req.tv_sec = 0; // Seconds
    req.tv_nsec = DELAY_NS; // Nanoseconds

    // Install signal handler for SIGINT
    signal(SIGINT, signal_handler);

    // Initialize GPIO pins
    if (initialize_gpio(GPIO17) < 0 || initialize_gpio(GPIO27) < 0) {
        fprintf(stderr, "GPIO initialization failed. Exiting.\n");
        return 1;
    }

    // Main loop to read sensor values and print them
    while (program_running) {
        int value17 = read_gpio(GPIO17);
        int value27 = read_gpio(GPIO27);

        if (value17 >= 0) {
            printf("GPIO %d: Sensor Reading = %d\n", GPIO17, value17);
        } else {
            fprintf(stderr, "Error reading GPIO %d\n", GPIO17);
        }

        if (value27 >= 0) {
            printf("GPIO %d: Sensor Reading = %d\n", GPIO27, value27);
        } else {
            fprintf(stderr, "Error reading GPIO %d\n", GPIO27);
        }

        // Delay for 500ms using nanosleep
        if(nanosleep(&req, (struct timespec *)NULL) < 0) {
            perror("nanosleep failed");
        }
    }

    // Uninitialize GPIO pins before exiting
    if (uninitialize_gpio(GPIO17) < 0 || uninitialize_gpio(GPIO27) < 0) {
        fprintf(stderr, "GPIO uninitialization failed.\n");
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <stdbool.h>
#include <unistd.h>
#include <time.h>
#include <wiringPiI2C.h>
#include <errno.h>
#include <string.h>

// Sensor-specific definitions
#define I2C_ADDR 0x28  // I2C address of the Honeywell Zephyr sensor
#define SENSOR_FULL_SCALE_PRESSURE 100.0 // in Pascals (Pa) for HAFBLF0100A2X3
#define SENSOR_MIN_OUTPUT 0x0800 // Minimum digital output
#define SENSOR_MAX_OUTPUT 0x3F00 // Maximum digital output

// Function to initialize the I2C connection
int setup_i2c(int *fd, int address) {
    *fd = wiringPiI2CSetup(address);
    if (*fd == -1) {
        fprintf(stderr, "wiringPiI2CSetup failed: %s\n", strerror(errno));
        return -1;
    }
    return 0;
}

// Function to read raw data from the sensor
int read_raw_data(int fd, int *raw_data) {
    uint8_t msb, lsb;
    int combined_data;

    msb = wiringPiI2CReadReg8(fd, 0x00); //dummy register to read
    lsb = wiringPiI2CReadReg8(fd, 0x00); //dummy register to read

    if (msb == -1 || lsb == -1) {
        fprintf(stderr, "I2C read failed: %s\n", strerror(errno));
        return -1;
    }

    combined_data = (msb << 8) | lsb;
    *raw_data = combined_data & 0x3FFF; // Mask out status bits

    return 0;
}

// Function to convert raw data to pressure in Pascals
float convert_to_pressure(int raw_data) {
    float pressure;
    pressure = (float)(raw_data - SENSOR_MIN_OUTPUT) * SENSOR_FULL_SCALE_PRESSURE / (SENSOR_MAX_OUTPUT - SENSOR_MIN_OUTPUT);
    return pressure;
}

// Function to log the pressure data
void log_data(float pressure) {
    time_t now = time(NULL);
    struct tm *tstruct = localtime(&now);
    char buf[80];
    strftime(buf, sizeof(buf), "%Y-%m-%d.%X", tstruct);

    printf("[%s] Pressure: %.2f Pa\n", buf, pressure);
}

int main() {
    int fd; // I2C file descriptor
    int raw_data;
    float pressure;

    // Initialize I2C
    if (setup_i2c(&fd, I2C_ADDR) == -1) {
        return 1;
    }

    // Main loop
    while (1) {
        // Read raw data from the sensor
        if (read_raw_data(fd, &raw_data) == -1) {
            fprintf(stderr, "Failed to read sensor data. Retrying...\n");
            usleep(200000); // Wait 200ms before retrying
            continue;
        }

        // Convert raw data to pressure
        pressure = convert_to_pressure(raw_data);

        // Log the data
        log_data(pressure);

        // Wait 200ms
        usleep(200000);
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <signal.h>
#include <pigpio.h>

// LIS3DH I2C address
#define LIS3DH_ADDR 0x18

// LIS3DH register addresses
#define LIS3DH_REG_CTRL1 0x20
#define LIS3DH_REG_CTRL4 0x23
#define LIS3DH_REG_OUT_X_L 0x28
#define LIS3DH_REG_OUT_X_H 0x29
#define LIS3DH_REG_OUT_Y_L 0x2A
#define LIS3DH_REG_OUT_Y_H 0x2B
#define LIS3DH_REG_OUT_Z_L 0x2C
#define LIS3DH_REG_OUT_Z_H 0x2D

// I2C bus
#define I2C_BUS 1

// Global variable for I2C handle
int i2c_handle;

// Signal handler function
void signal_handler(int signal) {
    printf("Caught signal %d, cleaning up...\n", signal);
    i2cClose(i2c_handle);
    gpioTerminate();
    exit(0);
}

// Function to initialize the LIS3DH accelerometer
int init_lis3dh() {
    // Configure CTRL1 register for 100Hz data rate and enable all axes
    char ctrl1_data = 0x77; // 0b01110111
    if (i2cWriteI2CBlockData(i2c_handle, LIS3DH_REG_CTRL1, &ctrl1_data, 1) != 1) {
        fprintf(stderr, "Error writing to CTRL1 register: %d\n", gpioGetError());
        return -1;
    }

    // Configure CTRL4 register for +/- 2g full scale and normal mode
    char ctrl4_data = 0x00; // 0b00000000
    if (i2cWriteI2CBlockData(i2c_handle, LIS3DH_REG_CTRL4, &ctrl4_data, 1) != 1) {
        fprintf(stderr, "Error writing to CTRL4 register: %d\n", gpioGetError());
        return -1;
    }

    return 0;
}

// Function to read accelerometer data
int read_accel_data(int16_t *x, int16_t *y, int16_t *z) {
    char buffer[6];

    // Read all six registers in one go
    if (i2cReadI2CBlockData(i2c_handle, LIS3DH_REG_OUT_X_L, buffer, 6) != 6) {
        fprintf(stderr, "Error reading accelerometer data: %d\n", gpioGetError());
        return -1;
    }

    // Combine low and high bytes for each axis
    *x = (int16_t)((buffer[1] << 8) | buffer[0]);
    *y = (int16_t)((buffer[3] << 8) | buffer[2]);
    *z = (int16_t)((buffer[5] << 8) | buffer[4]);

    return 0;
}

int main() {
    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed: %s\n", gpioGetErrorText(gpioInitialise()));
        return 1;
    }

    // Open I2C device
    i2c_handle = i2cOpen(I2C_BUS, LIS3DH_ADDR, 0);
    if (i2c_handle < 0) {
        fprintf(stderr, "Error opening I2C device: %d\n", gpioGetError());
        gpioTerminate();
        return 1;
    }

    // Initialize LIS3DH accelerometer
    if (init_lis3dh() < 0) {
        fprintf(stderr, "LIS3DH initialization failed.\n");
        i2cClose(i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Register signal handler for graceful shutdown
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Main loop
    while (1) {
        int16_t x, y, z;

        // Read accelerometer data
        if (read_accel_data(&x, &y, &z) == 0) {
            // Print accelerometer data
            printf("X: %6d, Y: %6d, Z: %6d\n", x, y, z);
        } else {
            fprintf(stderr, "Failed to read accelerometer data.\n");
        }

        // Delay for 100ms
        time_sleep(0.1);
    }

    return 0; // This line will never be reached due to the infinite loop
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <stdbool.h>
#include <unistd.h>
#include <wiringPiI2C.h>
#include <time.h>
#include <signal.h>

// SCD40 I2C address
#define SCD40_I2C_ADDR 0x62

// SCD40 commands
#define CMD_START_PERIODIC_MEASUREMENT 0x21b1
#define CMD_READ_MEASUREMENT 0xec05
#define CMD_STOP_PERIODIC_MEASUREMENT 0x3f86
#define CMD_REINIT 0x3646

// Global variable for I2C file descriptor
int fd;

// Structure to hold sensor data
typedef struct {
    uint16_t co2;
    float temperature;
    float humidity;
} sensor_data_t;

// Function prototypes
bool init_scd40(void);
sensor_data_t read_scd40_data(void);
void stop_scd40(void);
void log_data(sensor_data_t data);
void sigint_handler(int sig);

bool running = true;

void sigint_handler(int sig) {
    running = false;
    printf("\nExiting...\n");
    stop_scd40();
    exit(0);
}

// Function to initialize the SCD40 sensor
bool init_scd40(void) {
    // Stop periodic measurement before initialization
    stop_scd40();

    // Reinit the sensor
    wiringPiI2CWriteReg16(fd, CMD_REINIT >> 8, CMD_REINIT & 0xFF);
    usleep(20000); // Wait for reinit to complete

    // Start periodic measurement
    wiringPiI2CWriteReg16(fd, CMD_START_PERIODIC_MEASUREMENT >> 8, CMD_START_PERIODIC_MEASUREMENT & 0xFF);
    usleep(1000); // Wait briefly

    return true;
}

// Function to read data from the SCD40 sensor
sensor_data_t read_scd40_data(void) {
    sensor_data_t data = {0, 0.0f, 0.0f};
    uint8_t buffer[9];
    int i;

    // Read measurement command
    wiringPiI2CWriteReg16(fd, CMD_READ_MEASUREMENT >> 8, CMD_READ_MEASUREMENT & 0xFF);
    usleep(1000); // Wait for data to be ready

    // Read 9 bytes of data
    for (i = 0; i < 9; i++) {
        buffer[i] = wiringPiI2CRead(fd);
    }

    // Extract CO2, temperature, and humidity
    data.co2 = (buffer[0] << 8) | buffer[1];
    data.temperature = -45 + 175 * ((float)((buffer[3] << 8) | buffer[4])) / 65535.0f;
    data.humidity = 100 * ((float)((buffer[6] << 8) | buffer[7])) / 65535.0f;

    return data;
}

// Function to stop periodic measurement
void stop_scd40(void) {
    wiringPiI2CWriteReg16(fd, CMD_STOP_PERIODIC_MEASUREMENT >> 8, CMD_STOP_PERIODIC_MEASUREMENT & 0xFF);
    usleep(500); // Wait briefly
}

// Function to log data to the console
void log_data(sensor_data_t data) {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[20];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    printf("%s - CO2: %d ppm, Temperature: %.2f °C, Humidity: %.2f %%\n", timestamp, data.co2, data.temperature, data.humidity);
}

int main(void) {
    // Initialize WiringPi I2C
    fd = wiringPiI2CSetup(SCD40_I2C_ADDR);
    if (fd == -1) {
        fprintf(stderr, "Error: Unable to initialize I2C communication.\n");
        return 1;
    }

    // Initialize SCD40 sensor
    if (!init_scd40()) {
        fprintf(stderr, "Error: Unable to initialize SCD40 sensor.\n");
        return 1;
    }

    signal(SIGINT, sigint_handler);

    // Main loop
    while (running) {
        sensor_data_t data = read_scd40_data();
        log_data(data);
        sleep(5); // Read data every 5 seconds
    }

    return 0;
}

#include <stdio.h>
