#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <wiringPiI2C.h>
#include <unistd.h>
#include <time.h>
#include <signal.h>

// HIH7130 I2C address
#define HIH7130_ADDR 0x27

// Structure to hold sensor data
typedef struct {
    float temperature;
    float humidity;
} sensor_data_t;

// Global variable to control the main loop
volatile sig_atomic_t running = 1;

// Signal handler for graceful shutdown
void sigint_handler(int sig) {
    running = 0;
    printf("\nExiting gracefully...\n");
}

// Function to read raw data from the sensor
int read_raw_data(int fd, uint16_t *humidity, uint16_t *temperature) {
    unsigned char data[4];

    if (read(fd, data, 4) != 4) {
        fprintf(stderr, "Error reading data from sensor\n");
        return -1;
    }

    // Combine the bytes to form the humidity and temperature values
    *humidity = ((data[0] << 8) | data[1]) & 0x3FFF; // Mask out status bits
    *temperature = ((data[2] << 8) | data[3]) & 0x3FFF; // Mask out status bits

    return 0;
}

// Function to convert raw data to temperature and humidity
sensor_data_t convert_data(uint16_t raw_humidity, uint16_t raw_temperature) {
    sensor_data_t data;

    // Conversion formulas from datasheet
    data.humidity = ((float)raw_humidity / 16383) * 100;
    data.temperature = ((float)raw_temperature / 16383) * 165 - 40;

    return data;
}

// Function to log the sensor data
void log_data(sensor_data_t data) {
    time_t now = time(NULL);
    struct tm *tstruct = localtime(&now);
    char buf[80];
    strftime(buf, sizeof(buf), "%Y-%m-%d.%X", tstruct);

    printf("[%s] Temperature: %.2f °C, Humidity: %.2f %%\n", buf, data.temperature, data.humidity);
}

int main() {
    int fd;
    uint16_t raw_humidity, raw_temperature;
    sensor_data_t sensor_data;

    // Setup signal handler for Ctrl+C
    signal(SIGINT, sigint_handler);

    // Initialize wiringPi I2C
    if ((fd = wiringPiI2CSetup(HIH7130_ADDR)) < 0) {
        fprintf(stderr, "Unable to open I2C device: %s\n", strerror(errno));
        return 1;
    }

    printf("Starting temperature and humidity logging...\n");

    while (running) {
        // Trigger a measurement by writing any byte to the sensor
        if (wiringPiI2CWrite(fd, 0) < 0) {
            fprintf(stderr, "Error triggering measurement: %s\n", strerror(errno));
            sleep(5);
            continue;
        }

        // Wait for the measurement to complete (datasheet specifies 36.65ms max)
        usleep(50000); // 50ms

        // Read raw data from the sensor
        if (read_raw_data(fd, &raw_humidity, &raw_temperature) == 0) {
            // Convert raw data to temperature and humidity
            sensor_data = convert_data(raw_humidity, raw_temperature);

            // Log the data
            log_data(sensor_data);
        } else {
            fprintf(stderr, "Failed to read sensor data.\n");
        }

        // Wait 5 seconds
        sleep(5);
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>
#include <signal.h>
#include <unistd.h>
#include <pigpio.h>

// Define UART configuration
#define UART_TX_PIN 14
#define UART_RX_PIN 15
#define BAUD_RATE 115200
#define UART_FLAGS 0 // No parity, 1 stop bit

// Define data parsing constants
#define MAX_DATA_LENGTH 256
#define DELIMITER ","

// Global variables
int uart_fd;
volatile sig_atomic_t terminate = 0;

// Structure for storing radar data
typedef struct {
    float range;
    float velocity;
} RadarData;

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("Caught signal %d, terminating...
", signal);
    terminate = 1;
}

// Function to initialize UART
int init_uart() {
    // Set GPIO pins to ALT0 mode
    gpioSetMode(UART_TX_PIN, PI_ALT0);
    gpioSetMode(UART_RX_PIN, PI_ALT0);

    // Open UART
    uart_fd = serOpen("/dev/ttyS0", BAUD_RATE, UART_FLAGS);
    if (uart_fd < 0) {
        fprintf(stderr, "Error opening UART: %d\n", uart_fd);
        return -1;
    }

    printf("UART initialized successfully.\n");
    return 0;
}

// Function to read data from UART and parse it
int read_radar_data(RadarData *data) {
    char buffer[MAX_DATA_LENGTH];
    int bytes_read;
    char *token;
    int i = 0;

    // Read data from UART
    bytes_read = serRead(uart_fd, buffer, MAX_DATA_LENGTH - 1);
    if (bytes_read <= 0) {
        //printf("Error reading from UART: %d\n", bytes_read);
        return -1;
    }
    buffer[bytes_read] = '\0'; // Null-terminate the string

    // Parse CSV data
    token = strtok(buffer, DELIMITER);
    while (token != NULL && i < 2) {
        if (i == 0) {
            data->range = atof(token);
        } else if (i == 1) {
            data->velocity = atof(token);
        }
        token = strtok(NULL, DELIMITER);
        i++;
    }

    if (i != 2) {
        // Incomplete data packet
        return -1;
    }

    return 0;
}

// Function to log radar data
void log_radar_data(RadarData data) {
    time_t now = time(NULL);
    char *time_str = ctime(&now);
    time_str[strlen(time_str) - 1] = '\0'; // Remove trailing newline

    printf("[%s] Range: %.2f, Velocity: %.2f\n", time_str, data.range, data.velocity);
}

int main() {
    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Install signal handler
    signal(SIGINT, signal_handler);

    // Initialize UART
    if (init_uart() != 0) {
        gpioTerminate();
        return 1;
    }

    RadarData radar_data;

    // Main loop
    while (!terminate) {
        if (read_radar_data(&radar_data) == 0) {
            log_radar_data(radar_data);
        } else {
            //printf("Failed to read or parse radar data.\n");
        }

        gpioDelay(100); // 100ms delay
    }

    // Close UART
    serClose(uart_fd);

    // Terminate pigpio library
    gpioTerminate();

    printf("Program terminated successfully.\n");
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <unistd.h>
#include <pigpio.h>

// Define constants
#define SPI_CHANNEL 0
#define SPI_BAUD 1000000
#define REFERENCE_VOLTAGE 3.3
#define MCP3008_CHANNEL 0

int spi_handle;

// Signal handler for Ctrl+C
void signal_handler(int signal) {
    printf("\nCaught signal %d, cleaning up...\n", signal);
    spiClose(spi_handle);
    gpioTerminate();
    exit(0);
}

int main() {
    // Register signal handler
    signal(SIGINT, signal_handler);

    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Open SPI channel
    spi_handle = spiOpen(SPI_CHANNEL, SPI_BAUD, 0);
    if (spi_handle < 0) {
        fprintf(stderr, "SPI open failed\n");
        gpioTerminate();
        return 1;
    }

    // Main loop
    while (1) {
        // MCP3008 command to read single-ended channel
        unsigned char tx_buffer[3];
        unsigned char rx_buffer[3];

        tx_buffer[0] = 0x01; // Start bit
        tx_buffer[1] = (0x08 | MCP3008_CHANNEL) << 4; // Single-ended, channel selection
        tx_buffer[2] = 0x00; // Dummy byte

        // Transfer data
        spiXfer(spi_handle, tx_buffer, rx_buffer, 3);

        // Extract raw ADC value
        int raw_value = ((rx_buffer[1] & 0x03) << 8) + rx_buffer[2];

        // Convert to voltage
        float voltage = ((float)raw_value / 1023.0) * REFERENCE_VOLTAGE;

        // Print results
        printf("Raw ADC Value: %d, Voltage: %.2f V\n", raw_value, voltage);

        // Delay for 100 milliseconds
        usleep(100000); // 100 ms
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <signal.h>
#include <pigpio.h>
#include <stdint.h>

// STS4L I2C address
#define STS4L_ADDR 0x4A
// Command to trigger high precision measurement (no clock stretching)
#define MEASURE_CMD 0xE0

// I2C bus (typically 1 on Raspberry Pi)
#define I2C_BUS 1

int i2c_handle;

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("\nCaught signal %d, cleaning up...\n", signal);
    if (i2c_handle >= 0) {
        i2cClose(i2c_handle);
    }
    gpioTerminate();
    exit(0);
}

// Function to calculate CRC8 with polynomial 0x31
uint8_t crc8(const uint8_t *data, int len) {
    uint8_t crc = 0xFF;
    for (int i = 0; i < len; i++) {
        crc ^= data[i];
        for (int j = 0; j < 8; j++) {
            if ((crc & 0x80) != 0) {
                crc = (crc << 1) ^ 0x31;
            } else {
                crc <<= 1;
            }
        }
    }
    return crc;
}

// Function to read temperature data from the sensor
int read_temperature(double *temperature) {
    uint8_t raw_data[6];
    int bytes_read;

    // Trigger measurement
    if (i2cWriteByteData(i2c_handle, MEASURE_CMD) != 0) {
        fprintf(stderr, "Error: Failed to trigger measurement\n");
        return -1;
    }

    // Wait for measurement to complete (datasheet specifies < 10ms)
    gpioDelay(20000); // Wait 20ms to be safe

    // Read 6 bytes of data
    bytes_read = i2cReadI2CBlockData(i2c_handle, raw_data, 6);
    if (bytes_read != 6) {
        fprintf(stderr, "Error: Failed to read 6 bytes of data (read %d bytes)\n", bytes_read);
        return -1;
    }

    // CRC check for temperature data
    uint8_t temp_data[2] = {raw_data[0], raw_data[1]};
    if (crc8(temp_data, 2) != raw_data[2]) {
        fprintf(stderr, "Error: Temperature CRC check failed\n");
        return -1;
    }

    // CRC check for humidity data
    uint8_t hum_data[2] = {raw_data[3], raw_data[4]};
    if (crc8(hum_data, 2) != raw_data[5]) {
        fprintf(stderr, "Error: Humidity CRC check failed\n");
        return -1;
    }

    // Convert raw temperature data to Celsius
    int32_t temp_ticks = (raw_data[0] << 8) | raw_data[1];
    *temperature = -45.0 + (175.0 * temp_ticks) / 65535.0;

    return 0;
}

int main() {
    double temperature;

    // Register signal handler for graceful shutdown
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "Error: pigpio initialisation failed\n");
        return 1;
    }

    // Open I2C connection
    i2c_handle = i2cOpen(I2C_BUS, STS4L_ADDR, 0);
    if (i2c_handle < 0) {
        fprintf(stderr, "Error: Failed to open I2C device: %d\n", i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Main loop
    while (1) {
        // Read temperature data
        if (read_temperature(&temperature) == 0) {
            // Print temperature to console
            printf("Temperature: %.2f °C\n", temperature);
        } else {
            fprintf(stderr, "Error: Failed to read temperature\n");
        }

        // Sleep for 5 seconds
        pigpio_sleep(PI_TIME_RELATIVE, 5, 0);
    }

    // This point should not be reached due to the infinite loop
    i2cClose(i2c_handle);
    gpioTerminate();
    return 0;
}

#include <stdio.h>
#include <stdint.h>
#include <stdbool.h>
#include <wiringPi.h>
#include <wiringPiI2C.h>
#include <signal.h>
#include <unistd.h>

// LIS3MDL I2C address
#define LIS3MDL_ADDR 0x1E

// LIS3MDL Register Addresses
#define LIS3MDL_CTRL_REG1 0x20
#define LIS3MDL_CTRL_REG3 0x22
#define LIS3MDL_OUT_X_L   0x28
#define LIS3MDL_OUT_X_H   0x29
#define LIS3MDL_OUT_Y_L   0x2A
#define LIS3MDL_OUT_Y_H   0x2B
#define LIS3MDL_OUT_Z_L   0x2C
#define LIS3MDL_OUT_Z_H   0x2D

int fd;
volatile sig_atomic_t program_running = 1;

void signal_handler(int sig) {
    if (sig == SIGINT) {
        printf("Shutting down...\n");
        program_running = 0;
    }
}

int lis3mdl_init() {
    // Configure LIS3MDL for continuous mode and 10Hz data rate
    // CTRL_REG1: 0x70 = 0b01110000 (ODR = 10 Hz, Temp sensor enabled, +/- 4 gauss)
    // CTRL_REG3: 0x00 = 0b00000000 (Continuous conversion mode)
    int result;

    result = wiringPiI2CWriteReg8(fd, LIS3MDL_CTRL_REG1, 0x70);
    if (result < 0) {
        fprintf(stderr, "Error writing to CTRL_REG1: %d\n", result);
        return -1;
    }

    result = wiringPiI2CWriteReg8(fd, LIS3MDL_CTRL_REG3, 0x00); // Continuous conversion mode
    if (result < 0) {
        fprintf(stderr, "Error writing to CTRL_REG3: %d\n", result);
        return -1;
    }

    return 0;
}

int16_t read_axis(int low_reg, int high_reg) {
    int16_t value;
    int low, high;

    low = wiringPiI2CReadReg8(fd, low_reg);
    if (low < 0) {
        fprintf(stderr, "I2C read error (low byte): %d\n", low);
        return 0; // Or some error value
    }

    high = wiringPiI2CReadReg8(fd, high_reg);
    if (high < 0) {
        fprintf(stderr, "I2C read error (high byte): %d\n", high);
        return 0; // Or some error value
    }

    // Combine high and low bytes to form 16-bit signed integer
    value = (int16_t)((high << 8) | low);

    return value;
}

int main() {
    signal(SIGINT, signal_handler);

    wiringPiSetup();

    fd = wiringPiI2CSetup(LIS3MDL_ADDR);
    if (fd == -1) {
        fprintf(stderr, "I2C setup failed!\n");
        return 1;
    }

    if (lis3mdl_init() != 0) {
        fprintf(stderr, "LIS3MDL initialization failed!\n");
        return 1;
    }

    printf("LIS3MDL Magnetometer Program\n");

    while (program_running) {
        int16_t x, y, z;

        x = read_axis(LIS3MDL_OUT_X_L, LIS3MDL_OUT_X_H);
        y = read_axis(LIS3MDL_OUT_Y_L, LIS3MDL_OUT_Y_H);
        z = read_axis(LIS3MDL_OUT_Z_L, LIS3MDL_OUT_Z_H);

        printf("X: %6d, Y: %6d, Z: %6d\n", x, y, z);
        delay(250); // Read data every 250ms
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <wiringPi.h>
#include <softPwm.h>
#include <time.h>
#include <signal.h>
#include <errno.h>

// Define GPIO pins for X, Y, and Z axes (must be PWM capable)
#define X_PIN 0   // WiringPi pin 0 (physical pin 11, GPIO17)
#define Y_PIN 1   // WiringPi pin 1 (physical pin 12, GPIO18)
#define Z_PIN 2   // WiringPi pin 2 (physical pin 13, GPIO27)

// PWM range - adjust based on your setup and desired resolution
#define PWM_RANGE 1024

// Logging interval (milliseconds)
#define LOG_INTERVAL 100

// Structure to hold accelerometer data
typedef struct {
    int x;
    int y;
    int z;
} accelerometer_data_t;

// Global flag to signal program termination
volatile sig_atomic_t program_running = 1;

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    (void)signal; // Suppress unused parameter warning
    program_running = 0;
    printf("\nExiting gracefully...\n");
}

// Function to read accelerometer data
int read_accelerometer_data(accelerometer_data_t *data) {
    // Read PWM values from each axis
    data->x = softPwmRead(X_PIN);
    data->y = softPwmRead(Y_PIN);
    data->z = softPwmRead(Z_PIN);

    // Basic error check (optional: can add more sophisticated checks)
    if (data->x < 0 || data->y < 0 || data->z < 0) {
        fprintf(stderr, "Error: Invalid accelerometer data read.\n");
        return -1; // Indicate failure
    }

    return 0; // Indicate success
}

// Function to log accelerometer data to the console
void log_accelerometer_data(const accelerometer_data_t *data) {
    struct timespec ts;
    clock_gettime(CLOCK_REALTIME, &ts);
    printf("%ld.%09ld, X: %d, Y: %d, Z: %d\n", ts.tv_sec, ts.tv_nsec, data->x, data->y, data->z);
}

int main() {
    // Set up signal handling for Ctrl+C
    if (signal(SIGINT, signal_handler) == SIG_ERR) {
        perror("signal");
        return 1;
    }

    // Initialize wiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "Error initializing wiringPi: %s\n", strerror(errno));
        return 1;
    }

    // Set up PWM pins
    softPwmCreate(X_PIN, 0, PWM_RANGE);
    softPwmCreate(Y_PIN, 0, PWM_RANGE);
    softPwmCreate(Z_PIN, 0, PWM_RANGE);

    accelerometer_data_t accelerometer_data;

    printf("ADXL335 Data Logger started. Press Ctrl+C to exit.\n");

    // Main loop
    while (program_running) {
        if (read_accelerometer_data(&accelerometer_data) == 0) {
            log_accelerometer_data(&accelerometer_data);
        } else {
            fprintf(stderr, "Error reading accelerometer data.\n");
        }

        delay(LOG_INTERVAL);
    }

    // Cleanup (optional, but good practice)
    softPwmStop(X_PIN);
    softPwmStop(Y_PIN);
    softPwmStop(Z_PIN);

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <unistd.h>
#include <fcntl.h>
#include <sys/ioctl.h>
#include <linux/spi/spidev.h>
#include <time.h>
#include <string.h>
#include <signal.h>

// Define SPI parameters
#define SPI_BUS 0
#define SPI_DEVICE 0
#define SPI_MODE SPI_MODE_0
#define SPI_BITS_PER_WORD 8
#define SPI_MAX_SPEED 1000000 // 1 MHz

// Define MCP3008 channel numbers for RGB
#define RED_CHANNEL 0
#define GREEN_CHANNEL 1
#define BLUE_CHANNEL 2

// Global flag for program termination
volatile sig_atomic_t terminate = 0;

// Structure to hold sensor data
typedef struct {
    int red;
    int green;
    int blue;
} sensor_data_t;

// Signal handler for Ctrl+C
void sigint_handler(int sig) {
    terminate = 1;
    printf("\nExiting gracefully...\n");
}

// Function to initialize SPI
int spi_init(const char *device) {
    int fd = open(device, O_RDWR);
    if (fd < 0) {
        perror("Error opening SPI device");
        return -1;
    }

    // Set SPI mode
    uint8_t mode = SPI_MODE;
    if (ioctl(fd, SPI_IOC_WR_MODE, &mode) < 0) {
        perror("Error setting SPI mode");
        close(fd);
        return -1;
    }

    // Set bits per word
    uint8_t bits = SPI_BITS_PER_WORD;
    if (ioctl(fd, SPI_IOC_WR_BITS_PER_WORD, &bits) < 0) {
        perror("Error setting bits per word");
        close(fd);
        return -1;
    }

    // Set max speed
    uint32_t speed = SPI_MAX_SPEED;
    if (ioctl(fd, SPI_IOC_WR_MAX_SPEED_HZ, &speed) < 0) {
        perror("Error setting max speed");
        close(fd);
        return -1;
    }

    return fd;
}

// Function to read from MCP3008 ADC
int read_mcp3008(int fd, int channel) {
    uint8_t tx_buf[3];
    uint8_t rx_buf[3];
    struct spi_ioc_transfer tr;

    // Construct SPI message
    tx_buf[0] = 0x01;  // Start bit
    tx_buf[1] = (0x08 | channel) << 4; // Single-ended mode, channel select
    tx_buf[2] = 0x00;  // Don't care

    memset(&tr, 0, sizeof(tr));
    tr.tx_buf = (unsigned long)tx_buf;
    tr.rx_buf = (unsigned long)rx_buf;
    tr.len = 3;
    tr.speed_hz = SPI_MAX_SPEED;
    tr.bits_per_word = SPI_BITS_PER_WORD;

    if (ioctl(fd, SPI_IOC_MESSAGE(1), &tr) < 0) {
        perror("Error sending SPI message");
        return -1;
    }

    // Extract ADC value (10 bits)
    int adc_value = ((rx_buf[1] & 0x03) << 8) | rx_buf[2];
    return adc_value;
}

// Function to read sensor data
sensor_data_t read_sensor(int spi_fd) {
    sensor_data_t data;

    data.red = read_mcp3008(spi_fd, RED_CHANNEL);
    data.green = read_mcp3008(spi_fd, GREEN_CHANNEL);
    data.blue = read_mcp3008(spi_fd, BLUE_CHANNEL);

    return data;
}

// Function to log sensor data
void log_data(sensor_data_t data) {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[20];

    time(&rawtime);
    timeinfo = localtime(&rawtime);
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    printf("[%s] R: %d, G: %d, B: %d\n", timestamp, data.red, data.green, data.blue);
}

int main() {
    const char *spi_device = "/dev/spidev0.0";
    int spi_fd;
    sensor_data_t sensor_values;

    // Set up signal handler for Ctrl+C
    signal(SIGINT, sigint_handler);

    // Initialize SPI
    spi_fd = spi_init(spi_device);
    if (spi_fd < 0) {
        fprintf(stderr, "SPI initialization failed. Exiting.\n");
        return 1;
    }

    printf("RGB Color Sensor Logging (Ctrl+C to exit)\n");

    // Main loop
    while (!terminate) {
        // Read sensor data
        sensor_values = read_sensor(spi_fd);

        // Log sensor data
        log_data(sensor_values);

        // Wait 500ms
        usleep(500000); // 500ms = 500000 microseconds
    }

    // Close SPI device
    close(spi_fd);

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <unistd.h>
#include <pigpio.h>
#include <time.h>
#include <errno.h>
#include <string.h>
#include <signal.h>

// BNO055 I2C address
#define BNO055_I2C_ADDR 0x28

// BNO055 register addresses
#define BNO055_OPR_MODE 0x3D
#define BNO055_PWR_MODE 0x3E
#define BNO055_PAGE_ID 0x07
#define BNO055_SYS_TRIGGER 0x3F
#define BNO055_EULER_H_LSB 0x1E
#define BNO055_CALIB_STAT 0x35

int i2c_handle;

// Signal handler for Ctrl+C
void signal_handler(int signum) {
    printf("\nExiting...");
    i2cClose(i2c_handle);
    gpioTerminate();
    exit(signum);
}

// Function to write a single byte to a BNO055 register with retry
int bno055_write_reg(int handle, uint8_t reg, uint8_t value) {
    int retries = 3;
    int result;

    while (retries > 0) {
        result = i2cWriteByteData(handle, reg, value);
        if (result >= 0) {
            return 0; // Success
        }
        fprintf(stderr, "Error writing to register 0x%02X: %d, retries left: %d\n", reg, result, retries - 1);
        retries--;
        gpioDelay(1000); // Wait 1ms before retrying
    }

    fprintf(stderr, "Failed to write to register 0x%02X after multiple retries\n", reg);
    return -1; // Failure
}

// Function to read a single byte from a BNO055 register
int bno055_read_reg(int handle, uint8_t reg) {
    int result = i2cReadByteData(handle, reg);
    if (result < 0) {
        fprintf(stderr, "Error reading register 0x%02X: %d\n", reg, result);
        return -1; // Error
    }
    return result;
}

// Function to read multiple bytes from BNO055 registers with retry
int bno055_read_regs(int handle, uint8_t reg, char *buf, int count) {
    int retries = 3;
    int result;

    while (retries > 0) {
        result = i2cReadI2CBlockData(handle, reg, buf, count);
        if (result >= 0) {
            return 0; // Success
        }
        fprintf(stderr, "Error reading block from register 0x%02X: %d, retries left: %d\n", reg, result, retries - 1);
        retries--;
        gpioDelay(1000); // Wait 1ms before retrying
    }

    fprintf(stderr, "Failed to read block from register 0x%02X after multiple retries\n", reg);
    return -1; // Failure
}

// Function to initialize the BNO055 sensor
int bno055_init(int handle) {
    // Set to config mode
    if (bno055_write_reg(handle, BNO055_OPR_MODE, 0x00) != 0) return -1;
    gpioDelay(100000); // Wait 100ms

    // Set power mode to normal
    if (bno055_write_reg(handle, BNO055_PWR_MODE, 0x00) != 0) return -1;
    gpioDelay(10000); // Wait 10ms

    // Set page ID to 0
    if (bno055_write_reg(handle, BNO055_PAGE_ID, 0x00) != 0) return -1;

    // Use external crystal
    if (bno055_write_reg(handle, BNO055_SYS_TRIGGER, 0x80) != 0) return -1;

    // Set operating mode to NDOF
    if (bno055_write_reg(handle, BNO055_OPR_MODE, 0x0C) != 0) return -1;
    gpioDelay(10000); // Wait 10ms

    return 0;
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Open I2C device
    i2c_handle = i2cOpen(1, BNO055_I2C_ADDR, 0);
    if (i2c_handle < 0) {
        fprintf(stderr, "Failed to open I2C device: %d\n", i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Initialize BNO055 sensor
    if (bno055_init(i2c_handle) != 0) {
        fprintf(stderr, "BNO055 initialisation failed\n");
        i2cClose(i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Set up signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    char buffer[6];
    int16_t heading, roll, pitch;
    int calibration_status;

    // Main loop
    while (1) {
        // Read Euler angle data
        if (bno055_read_regs(i2c_handle, BNO055_EULER_H_LSB, buffer, 6) == 0) {
            heading = (int16_t)((buffer[1] << 8) | buffer[0]);
            roll = (int16_t)((buffer[3] << 8) | buffer[2]);
            pitch = (int16_t)((buffer[5] << 8) | buffer[4]);

            // Convert to degrees (1/16th degree resolution)
            float heading_deg = heading / 16.0;
            float roll_deg = roll / 16.0;
            float pitch_deg = pitch / 16.0;

            printf("Heading: %.2f, Roll: %.2f, Pitch: %.2f\n", heading_deg, roll_deg, pitch_deg);
        } else {
            fprintf(stderr, "Failed to read Euler angles\n");
        }

        // Check calibration status
        calibration_status = bno055_read_reg(i2c_handle, BNO055_CALIB_STAT);
        if (calibration_status >= 0) {
            if (calibration_status != 0xFF && calibration_status < 0x03) {
                fprintf(stderr, "Warning: Sensor not fully calibrated (Status: 0x%02X)\n", calibration_status);
            }
        } else {
            fprintf(stderr, "Failed to read calibration status\n");
        }

        gpioDelay(200000); // Wait 200ms
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <stdbool.h>
#include <wiringPiI2C.h>
#include <unistd.h>
#include <time.h>
#include <sys/time.h>
#include <signal.h>

// Define the I2C address of the MICS-VZ-89TE sensor
#define I2C_ADDR 0x48 // or 0x49, check your sensor's datasheet

// Define the registers for VOC and temperature data (check datasheet)
#define VOC_REG 0x01
#define TEMP_REG 0x02

// Global variable to control the main loop
volatile sig_atomic_t running = 1;

// Structure to hold sensor data
typedef struct {
    float voc;
    float temperature;
    time_t timestamp;
} sensor_data_t;

// Function prototypes
int setup_i2c(int address);
sensor_data_t read_sensor_data(int fd);
void log_data(sensor_data_t data);
void signal_handler(int signal);

int main()
{
    int i2c_fd;
    sensor_data_t sensor_data;

    // Register signal handler for graceful shutdown
    signal(SIGINT, signal_handler);

    // Initialize I2C communication
    i2c_fd = setup_i2c(I2C_ADDR);
    if (i2c_fd == -1) {
        fprintf(stderr, "Failed to initialize I2C communication. Exiting.\n");
        return 1;
    }

    printf("I2C communication initialized. Reading sensor data every 5 seconds...\n");

    // Main loop to read and log sensor data
    while (running) {
        sensor_data = read_sensor_data(i2c_fd);
        log_data(sensor_data);
        sleep(5);
    }

    printf("\nExiting gracefully.\n");
    return 0;
}

// Initialize I2C communication
int setup_i2c(int address)
{
    int fd = wiringPiI2CSetup(address);
    if (fd == -1) {
        perror("wiringPiI2CSetup failed");
        return -1;
    }
    return fd;
}

// Read VOC and temperature data from the sensor
sensor_data_t read_sensor_data(int fd)
{
    sensor_data_t data;
    int voc_raw, temp_raw;

    // Read VOC value
    voc_raw = wiringPiI2CReadReg16(fd, VOC_REG);
    if (voc_raw == -1) {
        fprintf(stderr, "Error reading VOC data\n");
        data.voc = -1.0; // Indicate error
    } else {
        data.voc = (float)voc_raw / 10.0; // Example conversion, adjust based on datasheet
    }

    // Read temperature value
    temp_raw = wiringPiI2CReadReg16(fd, TEMP_REG);
    if (temp_raw == -1) {
        fprintf(stderr, "Error reading temperature data\n");
        data.temperature = -100.0; // Indicate error
    } else {
        data.temperature = (float)temp_raw / 100.0; // Example conversion, adjust based on datasheet
    }

    // Get timestamp
    data.timestamp = time(NULL);

    return data;
}

// Log sensor data to the console
void log_data(sensor_data_t data)
{
    struct timeval tv;
    gettimeofday(&tv, NULL);
    struct tm *timeinfo = localtime(&data.timestamp);
    char timestamp[30];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    if (data.voc == -1.0 || data.temperature == -100.0) {
        fprintf(stderr, "%s.%03d - Error reading sensor data.\n", timestamp, (int)(tv.tv_usec / 1000));
    } else {
        printf("%s.%03d - VOC: %.2f ppm, Temperature: %.2f °C\n", timestamp, (int)(tv.tv_usec / 1000), data.voc, data.temperature);
    }
}

// Signal handler to catch Ctrl+C and exit gracefully
void signal_handler(int signal)
{
    running = 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <termios.h>
#include <unistd.h>
#include <fcntl.h>
#include <errno.h>
#include <time.h>
#include <signal.h>
#include <sys/select.h>
#include <pigpio.h>

// Configuration
#define UART_DEVICE "/dev/ttyAMA1"
#define BAUD_RATE B115200
#define GPIO_LED 17 // Optional GPIO pin for LED

// Global variables
volatile sig_atomic_t program_running = 1;
int uart_fd = -1;
int led_gpio = GPIO_LED;

// Structure for configuration
typedef struct {
    char uart_device[32];
    int baud_rate;
    int gpio_led;
} config_t;

config_t config = {
    .uart_device = UART_DEVICE,
    .baud_rate = BAUD_RATE,
    .gpio_led = GPIO_LED
};

// Signal handler for graceful shutdown
void signal_handler(int signum) {
    program_running = 0;
    printf("\nCaught signal %d, exiting gracefully...\n", signum);
}

// Function to initialize UART
int init_uart(const char *device, int baud_rate) {
    int fd = open(device, O_RDWR | O_NOCTTY | O_SYNC);
    if (fd == -1) {
        perror("Error opening UART");
        return -1;
    }

    struct termios tty;
    if (tcgetattr(fd, &tty) < 0) {
        perror("Error getting termios settings");
        close(fd);
        return -1;
    }

    tty.c_cflag = baud_rate | CS8 | CLOCAL | CREAD;  // 8N1, no parity, no hardware flow control
    tty.c_iflag = IGNPAR; // Ignore parity errors
    tty.c_oflag = 0;
    tty.c_lflag = 0;

    tty.c_cc[VMIN] = 0;    // Read non-blocking
    tty.c_cc[VTIME] = 5;   // Timeout of 0.5 seconds

    if (tcsetattr(fd, TCSANOW, &tty) != 0) {
        perror("Error setting termios settings");
        close(fd);
        return -1;
    }

    return fd;
}

// Function to parse data
int parse_data(char *data, float *range, float *velocity) {
    char *token;
    int i = 0;
    const char delimiter[] = ",";

    token = strtok(data, delimiter);
    while( token != NULL && i < 2 ) {
        if(i == 0) {
            *range = strtof(token, NULL);
        } else if (i == 1) {
            *velocity = strtof(token, NULL);
        }
        token = strtok(NULL, delimiter);
        i++;
    }

    if (i != 2) {
        fprintf(stderr, "Error: Incomplete data received: %s\n", data);
        return -1;
    }

    // Basic validation
    if (*range < 0 || *range > 100) { // Example range validation
        fprintf(stderr, "Error: Invalid range value: %f\n", *range);
        return -1;
    }
    if (*velocity < -10 || *velocity > 10) { // Example velocity validation
        fprintf(stderr, "Error: Invalid velocity value: %f\n", *velocity);
        return -1;
    }

    return 0;
}

// Function to get timestamp
void get_timestamp(char *timestamp) {
    time_t rawtime;
    struct tm *timeinfo;

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, 20, "%Y-%m-%d %H:%M:%S", timeinfo);
}

// Function to log data
void log_data(const char *timestamp, float range, float velocity) {
    printf("%s,%.2f,%.2f\n", timestamp, range, velocity);
}

int main() {
    // Install signal handlers
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Initialize UART
    uart_fd = init_uart(config.uart_device, config.baud_rate);
    if (uart_fd == -1) {
        return 1;
    }
    printf("UART initialized on %s at %d baud.\n", config.uart_device, config.baud_rate);

#ifdef GPIO_LED
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        // Don't exit, just continue without GPIO
        config.gpio_led = -1; // Disable GPIO
    } else {
        gpioSetMode(config.gpio_led, PI_OUTPUT);
        gpioWrite(config.gpio_led, 0); // LED off initially
        printf("GPIO %d initialized for LED.\n", config.gpio_led);
    }
#endif

    char buffer[256];
    float range, velocity;
    char timestamp[20];
    fd_set readfds;
    struct timeval timeout;

    while (program_running) {
        // Setup file descriptor set for select()
        FD_ZERO(&readfds);
        FD_SET(uart_fd, &readfds);

        // Setup timeout for select()
        timeout.tv_sec = 1;  // Timeout after 1 second
        timeout.tv_usec = 0;

        // Use select() to wait for data or timeout
        int retval = select(uart_fd + 1, &readfds, NULL, NULL, &timeout);

        if (retval == -1) {
            perror("select()");
            break;
        } else if (retval) {
            // Data is available on UART
            ssize_t bytes_read = read(uart_fd, buffer, sizeof(buffer) - 1);
            if (bytes_read > 0) {
                buffer[bytes_read] = '\0';
                //printf("Received: %s", buffer);

                if (parse_data(buffer, &range, &velocity) == 0) {
                    get_timestamp(timestamp);
                    log_data(timestamp, range, velocity);

#ifdef GPIO_LED
                    if (config.gpio_led != -1) {
                        gpioWrite(config.gpio_led, 1); // LED on
                        gpioDelay(100);                // Wait 100ms
                        gpioWrite(config.gpio_led, 0); // LED off
                        gpioDelay(100);                // Wait 100ms
                    }
#endif
                } else {
                    fprintf(stderr, "Data parsing failed for: %s\n", buffer);
                }
            } else if (bytes_read == -1) {
                perror("Error reading from UART");
            }
        } else {
            // Timeout occurred, no data received
            //printf("Timeout waiting for data.\n");
        }

        // Check for UART errors
        struct termios tty;
        if (tcgetattr(uart_fd, &tty) == 0) {
            if (tty.c_cflag & (PARENB | PARODD | CSTOPB | CRTSCTS)) {
                fprintf(stderr, "UART error detected (parity, stop bits, or flow control)\n");
            }
        } else {
            perror("tcgetattr failed");
        }

        // Small delay to prevent busy-waiting
        usleep(10000); // 10ms
    }

    // Close UART port
    if (uart_fd != -1) {
        close(uart_fd);
        printf("UART closed.\n");
    }

#ifdef GPIO_LED
    if (config.gpio_led != -1) {
        gpioWrite(config.gpio_led, 0); // Ensure LED is off
        gpioTerminate();
        printf("pigpio terminated.\n");
    }
#endif

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <time.h>
#include <signal.h>
#include <unistd.h>
#include <pthread.h>

// Define GPIO pins
#define TRIGGER_PIN 17
#define ECHO_PIN 18

// Error value for invalid distance readings
#define ERROR_DISTANCE -1.0

// Maximum pulse duration (in microseconds) - adjust as needed
#define MAX_PULSE_DURATION 30000

// Mutex to protect shared variables
pthread_mutex_t mutex;

// Variables to store echo pulse timing
static volatile uint32_t rising_edge_tick = 0;
static volatile uint32_t falling_edge_tick = 0;
static volatile int edge_count = 0;
static volatile double pulse_duration = 0.0;

// Cleanup handler for graceful shutdown
void cleanup_handler(int signum) {
    printf("\nCaught signal %d, cleaning up...\n", signum);
    gpioTerminate();
    pthread_mutex_destroy(&mutex);
    exit(0);
}

// Function to send a trigger pulse
void trigger_pulse() {
    gpioWrite(TRIGGER_PIN, 1);
    gpioDelay(10); // 10 us pulse
    gpioWrite(TRIGGER_PIN, 0);
}

// Callback function for echo pin changes
void echo_callback(int gpio, int level, uint32_t tick) {
    pthread_mutex_lock(&mutex);
    if (gpio == ECHO_PIN) {
        if (level == 1) { // Rising edge
            rising_edge_tick = tick;
            edge_count = 1;
        } else if (level == 0 && edge_count == 1) { // Falling edge
            falling_edge_tick = tick;
            pulse_duration = (double)(falling_edge_tick - rising_edge_tick);
            edge_count = 2;
        }
    }
    pthread_mutex_unlock(&mutex);
}

// Function to get the distance in centimeters
double get_distance() {
    pthread_mutex_lock(&mutex);
    rising_edge_tick = 0;
    falling_edge_tick = 0;
    edge_count = 0;
    pulse_duration = 0.0;
    pthread_mutex_unlock(&mutex);

    trigger_pulse();
    gpioDelay(10);
    // Wait for echo pulse
    int timeout_count = 0;
    while (edge_count < 2 && timeout_count < 1000) {
        gpioDelay(1); // Wait 1 us
        timeout_count++;
    }

    pthread_mutex_lock(&mutex);
    double duration = pulse_duration;
    pthread_mutex_unlock(&mutex);

    if (timeout_count >= 1000 || duration <= 0.0 || duration > MAX_PULSE_DURATION) {
        fprintf(stderr, "Error: Invalid pulse duration: %.2f us\n", duration);
        return ERROR_DISTANCE;
    }

    // Calculate distance in centimeters
    double distance = duration * 0.0343 / 2.0;

    return distance;
}

int main() {
    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Initialize mutex
    if (pthread_mutex_init(&mutex, NULL) != 0) {
        fprintf(stderr, "Mutex initialization failed\n");
        gpioTerminate();
        return 1;
    }

    // Set GPIO modes
    gpioSetMode(TRIGGER_PIN, PI_OUTPUT);
    gpioSetMode(ECHO_PIN, PI_INPUT);

    // Register signal handler for graceful shutdown
    signal(SIGINT, cleanup_handler);

    // Set alert function for echo pin
    gpioSetAlertFunc(ECHO_PIN, echo_callback);

    // Main loop
    while (1) {
        double distance = get_distance();

        if (distance != ERROR_DISTANCE) {
            // Get current timestamp
            time_t rawtime;
            struct tm *timeinfo;
            time(&rawtime);
            timeinfo = localtime(&rawtime);

            char timestamp[20];
            strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

            // Print timestamped distance reading
            printf("[%s] Distance: %.2f cm\n", timestamp, distance);
        } else {
            fprintf(stderr, "Error: Invalid distance reading\n");
        }

        gpioDelay(1000000); // Delay for 1 second
    }

    return 0;
}

#include <stdio.h>
#include <pigpio.h>
#include <unistd.h>
#include <signal.h>
#include <time.h>
#include <sys/time.h>

#define SENSOR_GPIO 17

/* Structure to hold RPM calculation data */
typedef struct {
    int pulse_count;
    unsigned long last_tick;
    double rpm;
} RpmData;

/* Global variable for RPM data */
RpmData rpm_data = {0, 0, 0.0};

/* Flag to signal program termination */
volatile sig_atomic_t terminate = 0;

/* Signal handler for graceful shutdown */
void sigint_handler(int signal) {
    terminate = 1;
    printf("\nExiting gracefully...\n");
}

/* Function to calculate RPM */
double calculate_rpm(unsigned long current_tick) {
    unsigned long tick_diff = current_tick - rpm_data.last_tick;
    rpm_data.last_tick = current_tick;

    // Convert tick difference to seconds
    double time_diff = (double)tick_diff / 1000000.0; // pigpio uses microseconds

    // Calculate frequency (pulses per second)
    double frequency = (double)rpm_data.pulse_count / time_diff;

    // Calculate RPM (revolutions per minute). Assuming one pulse per revolution.
    double rpm = frequency * 60.0;

    rpm_data.pulse_count = 0; // Reset pulse count for the next interval
    return rpm;
}

/* Callback function for GPIO interrupt */
void pulse_callback(int gpio, int level, unsigned int tick) {
    if (level == 1) { // Rising edge
        rpm_data.pulse_count++;
    }
}

/* Function to log RPM data to the console */
void log_rpm_data() {
    struct timeval tv;
    gettimeofday(&tv, NULL);
    double rpm = calculate_rpm(gpioTime());
    printf("%ld.%06ld: RPM: %.2f\n", tv.tv_sec, tv.tv_usec, rpm);
}

/* Function to initialize pigpio and sensor GPIO */
int setup() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    gpioSetMode(SENSOR_GPIO, PI_INPUT);
    gpioSetPullUpDown(SENSOR_GPIO, PI_PUD_UP); // Enable pull-up resistor

    // Set up interrupt on rising edge
    if (gpioSetAlertFunc(SENSOR_GPIO, pulse_callback) != 0) {
        fprintf(stderr, "Failed to set alert function\n");
        gpioTerminate();
        return 1;
    }

    return 0;
}

int main() {
    signal(SIGINT, sigint_handler);

    if (setup() != 0) {
        return 1;
    }

    printf("RPM monitoring started. Press Ctrl+C to exit.\n");

    while (!terminate) {
        log_rpm_data();
        gpioDelay(500000); // 0.5 seconds delay (microseconds)
    }

    gpioTerminate();
    return 0;
}

#include <stdio.h>
