#include <wiringPi.h>

// Define GPIO pins for the sensors
#define LEFT_SENSOR_PIN 4  // Example: GPIO 4
#define MIDDLE_SENSOR_PIN 5 // Example: GPIO 5
#define RIGHT_SENSOR_PIN 6 // Example: GPIO 6

// Define a structure to hold sensor data
typedef struct {
    int left;
    int middle;
    int right;
    struct timeval timestamp;
} SensorData;

// Global flag to signal program termination
volatile sig_atomic_t program_running = 1;

// Signal handler for Ctrl+C
void signal_handler(int signum) {
    program_running = 0;
    printf("\nExiting program...\n");
}

// Function to initialize the GPIO pins
bool setup() {
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "wiringPiSetup failed: %s\n", strerror(errno));
        return false;
    }

    pinMode(LEFT_SENSOR_PIN, INPUT);
    pinMode(MIDDLE_SENSOR_PIN, INPUT);
    pinMode(RIGHT_SENSOR_PIN, INPUT);

    return true;
}

// Function to read the sensor values
SensorData read_sensors() {
    SensorData data;

    data.left = digitalRead(LEFT_SENSOR_PIN);
    data.middle = digitalRead(MIDDLE_SENSOR_PIN);
    data.right = digitalRead(RIGHT_SENSOR_PIN);
    gettimeofday(&data.timestamp, NULL);

    return data;
}

// Function to log the sensor data to a file
void log_data(SensorData data) {
    FILE *fp = fopen("sensor_log.txt", "a");
    if (fp == NULL) {
        fprintf(stderr, "Error opening log file: %s\n", strerror(errno));
        return;
    }

    time_t rawtime = data.timestamp.tv_sec;
    struct tm *timeinfo = localtime(&rawtime);
    char timestamp_str[26]; // Enough to hold "YYYY-MM-DD HH:MM:SS.micros"
    strftime(timestamp_str, sizeof(timestamp_str), "%Y-%m-%d %H:%M:%S", timeinfo);
    snprintf(timestamp_str + strlen(timestamp_str), sizeof(timestamp_str) - strlen(timestamp_str), ".%06ld", data.timestamp.tv_usec);

    fprintf(fp, "%s, Left: %d, Middle: %d, Right: %d\n", timestamp_str, data.left, data.middle, data.right);
    fclose(fp);
}

// Function to check for motion and trigger surveillance (example)
void check_motion(SensorData data) {
    // Implement your motion detection logic here
    // This is a simple example: if any sensor detects something, log it.
    if (data.left == 0 || data.middle == 0 || data.right == 0) {
        printf("Motion detected!\n");
        log_data(data); // Log the data when motion is detected
        // Add your surveillance triggering logic here (e.g., take a picture, record video)
        // For example, you could use system() to execute a shell command:
        // system("raspistill -o image.jpg");
    }
}

int main() {
    // Set up signal handling for Ctrl+C
    signal(SIGINT, signal_handler);

    // Initialize the GPIO pins
    if (!setup()) {
        return 1;
    }

    printf("Motion-triggered surveillance started. Press Ctrl+C to exit.\n");

    // Main loop
    while (program_running) {
        // Read the sensor values
        SensorData data = read_sensors();

        // Check for motion and trigger surveillance
        check_motion(data);

        // Wait for a short period of time
        delay(100); // 100 milliseconds
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <wiringPiI2C.h>
#include <unistd.h>
#include <errno.h>

// Define the I2C address of the IMP23ABSU
#define IMP23ABSU_ADDR 0x68 // Replace with actual address if different

// Define the register addresses for data
#define IMP23ABSU_DATA_REG_L 0x01 // Example: Low byte of data
#define IMP23ABSU_DATA_REG_H 0x02 // Example: High byte of data

// Define the sampling interval in milliseconds
#define SAMPLING_INTERVAL 100

// Function to read a 16-bit value from the I2C device
int16_t read_sensor_data(int fd) {
    int16_t low_byte, high_byte;

    // Read the low byte
    low_byte = wiringPiI2CReadReg8(fd, IMP23ABSU_DATA_REG_L);
    if (low_byte == -1) {
        return -1; // Indicate error
    }

    // Read the high byte
    high_byte = wiringPiI2CReadReg8(fd, IMP23ABSU_DATA_REG_H);
    if (high_byte == -1) {
        return -1; // Indicate error
    }

    // Combine the bytes into a 16-bit value (assuming little-endian)
    return (int16_t)((high_byte << 8) | low_byte);
}

int main() {
    int fd; // File descriptor for I2C communication

    // Initialize the I2C interface
    if ((fd = wiringPiI2CSetup(IMP23ABSU_ADDR)) < 0) {
        fprintf(stderr, "Error initializing I2C: %s\n", strerror(errno));
        return 1;
    }

    // Main loop to continuously sample and log data
    while (1) {
        int16_t sensor_value = read_sensor_data(fd);

        if (sensor_value == -1) {
            fprintf(stderr, "Error reading sensor\n");
        } else {
            printf("%d\n", sensor_value);
        }

        // Wait for the specified sampling interval
        usleep(SAMPLING_INTERVAL * 1000); // usleep takes microseconds
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <fcntl.h>
#include <unistd.h>
#include <errno.h>
#include <signal.h>
#include <time.h>

#define GPIO_PIN 23
#define POLL_INTERVAL_MS 500

static volatile int keep_running = 1;

// Signal handler for Ctrl+C
void signal_handler(int sig) {
    if (sig == SIGINT) {
        printf("\nCtrl+C pressed, exiting...\n");
        keep_running = 0;
    }
}

// Function to export GPIO
int export_gpio(int gpio) {
    int fd;
    char buf[3];

    fd = open("/sys/class/gpio/export", O_WRONLY);
    if (fd < 0) {
        perror("Failed to open /sys/class/gpio/export");
        return -1;
    }

    int len = snprintf(buf, sizeof(buf), "%d", gpio);
    if (write(fd, buf, len) != len) {
        perror("Failed to export GPIO");
        close(fd);
        return -1;
    }

    close(fd);
    return 0;
}

// Function to unexport GPIO
int unexport_gpio(int gpio) {
    int fd;
    char buf[3];

    fd = open("/sys/class/gpio/unexport", O_WRONLY);
    if (fd < 0) {
        perror("Failed to open /sys/class/gpio/unexport");
        return -1;
    }

    int len = snprintf(buf, sizeof(buf), "%d", gpio);
    if (write(fd, buf, len) != len) {
        perror("Failed to unexport GPIO");
        close(fd);
        return -1;
    }

    close(fd);
    return 0;
}

// Function to set GPIO direction
int set_gpio_direction(int gpio, const char *direction) {
    int fd;
    char path[64];

    snprintf(path, sizeof(path), "/sys/class/gpio/gpio%d/direction", gpio);
    fd = open(path, O_WRONLY);
    if (fd < 0) {
        perror("Failed to open GPIO direction file");
        return -1;
    }

    if (write(fd, direction, strlen(direction)) != strlen(direction)) {
        perror("Failed to set GPIO direction");
        close(fd);
        return -1;
    }

    close(fd);
    return 0;
}

int main() {
    int fd;
    char path[64];
    char value[2];
    struct timespec sleep_time;
    time_t current_time;

    // Register signal handler for Ctrl+C
    if (signal(SIGINT, signal_handler) == SIG_ERR) {
        perror("Failed to register signal handler");
        return EXIT_FAILURE;
    }

    // Export GPIO
    if (export_gpio(GPIO_PIN) < 0) {
        fprintf(stderr, "GPIO %d might already be exported.  Trying to continue.\n", GPIO_PIN);
    }

    // Set GPIO direction to input
    if (set_gpio_direction(GPIO_PIN, "in") < 0) {
        unexport_gpio(GPIO_PIN);
        return EXIT_FAILURE;
    }

    // Main loop
    snprintf(path, sizeof(path), "/sys/class/gpio/gpio%d/value", GPIO_PIN);
    while (keep_running) {
        fd = open(path, O_RDONLY);
        if (fd < 0) {
            perror("Failed to open GPIO value file");
            unexport_gpio(GPIO_PIN);
            return EXIT_FAILURE;
        }

        if (read(fd, value, sizeof(value)) < 0) {
            perror("Failed to read GPIO value");
            close(fd);
            unexport_gpio(GPIO_PIN);
            return EXIT_FAILURE;
        }
        close(fd);

        time(&current_time);

        if (value[0] == '0') {
            printf("Timestamp: %ld, State: LOW\n", current_time);
        } else {
            printf("Timestamp: %ld, State: HIGH\n", current_time);
        }

        // Sleep for 500 milliseconds
        sleep_time.tv_sec = 0;
        sleep_time.tv_nsec = POLL_INTERVAL_MS * 1000000; // Convert milliseconds to nanoseconds
        nanosleep(&sleep_time, NULL);
    }

    // Unexport GPIO before exiting
    if (unexport_gpio(GPIO_PIN) < 0) {
        return EXIT_FAILURE;
    }

    return EXIT_SUCCESS;
}

