#define ADPD144RI_ADDR 0x39
#define RED_DATA_REG 0x02
#define IR_DATA_REG 0x04

int fd;
volatile sig_atomic_t running = 1;

// Signal handler for Ctrl+C
void handler(int sig)
{
    running = 0;
    printf("\nExiting gracefully...\n");
}

int main()
{
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[30];

    // Initialize WiringPi
    if (wiringPiSetup() == -1)
    {
        fprintf(stderr, "wiringPiSetup failed\n");
        return 1;
    }

    // Initialize I2C
    fd = wiringPiI2CSetup(ADPD144RI_ADDR);
    if (fd == -1)
    {
        fprintf(stderr, "wiringPiI2CSetup failed with address 0x%02x\n", ADPD144RI_ADDR);
        return 1;
    }

    printf("ADPD144RI sensor initialized successfully.\n");

    // Set up signal handling for Ctrl+C
