#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <stdbool.h>
#include <wiringPiI2C.h>
#include <unistd.h>
#include <time.h>
#include <signal.h>

// Si1145 I2C address
#define SI1145_ADDR 0x60

// Register addresses
#define REG_ALS_VIS_DATA0 0x22
#define REG_ALS_IR_DATA0  0x24

// Global variable to control the main loop
volatile sig_atomic_t keep_running = 1;

// Signal handler for graceful shutdown
void intHandler(int dummy) {
    keep_running = 0;
}

// Function to initialize the Si1145 sensor
int si1145_init(int fd) {
    // Reset the sensor
    wiringPiI2CWriteReg8(fd, 0x07, 0x00); //RST_N
    usleep(10000); // Wait 10ms
    wiringPiI2CWriteReg8(fd, 0x08, 0x00); //INT_CFG
    wiringPiI2CWriteReg8(fd, 0x09, 0x00); //IRQ_EN
    wiringPiI2CWriteReg8(fd, 0x0A, 0x03); //MEAS_RATE
    wiringPiI2CWriteReg8(fd, 0x0B, 0x00); //ALS_RATE

    wiringPiI2CWriteReg8(fd, 0x01, 0x00); //PS_LED21_SELECT
    wiringPiI2CWriteReg8(fd, 0x02, 0x01); //PS2_ADC_GAIN
    wiringPiI2CWriteReg8(fd, 0x03, 0x02); //PS1_ADC_GAIN
    wiringPiI2CWriteReg8(fd, 0x04, 0x03); //PS_ADC_COUNTER
    wiringPiI2CWriteReg8(fd, 0x05, 0x7B); //PS_MS_LED21
    wiringPiI2CWriteReg8(fd, 0x06, 0x6B); //PS_MS_LED1

    wiringPiI2CWriteReg8(fd, 0x0C, 0x0B); //ALS_VIS_ADC_GAIN
    wiringPiI2CWriteReg8(fd, 0x0D, 0x00); //ALS_IR_ADC_GAIN
    wiringPiI2CWriteReg8(fd, 0x0E, 0x00); //ALS_UV_ADC_GAIN
    wiringPiI2CWriteReg8(fd, 0x0F, 0x00); //ALS_ADC_COUNTER

    wiringPiI2CWriteReg8(fd, 0x10, 0x81); //PARAM_WR
    wiringPiI2CWriteReg8(fd, 0x11, 0x39); //COMMAND_WR

    wiringPiI2CWriteReg8(fd, 0x15, 0x29); //COMMAND_WR
    wiringPiI2CWriteReg8(fd, 0x16, 0x0F); //COMMAND_WR

    wiringPiI2CWriteReg8(fd, 0x17, 0xA0); //COMMAND_WR
    wiringPiI2CWriteReg8(fd, 0x18, 0x29); //COMMAND_WR
    wiringPiI2CWriteReg8(fd, 0x19, 0x0F); //COMMAND_WR

    wiringPiI2CWriteReg8(fd, 0x1A, 0xA0); //COMMAND_WR
    wiringPiI2CWriteReg8(fd, 0x1B, 0x29); //COMMAND_WR
    wiringPiI2CWriteReg8(fd, 0x1C, 0x0F); //COMMAND_WR

    wiringPiI2CWriteReg8(fd, 0x1E, 0xA0); //COMMAND_WR
    wiringPiI2CWriteReg8(fd, 0x21, 0x77); //COMMAND_WR

    return 0;
}

// Function to read sensor data
int read_sensor_data(int fd, int *vis, int *ir) {
    int vis_low, vis_high, ir_low, ir_high;

    vis_low = wiringPiI2CReadReg8(fd, REG_ALS_VIS_DATA0);
    vis_high = wiringPiI2CReadReg8(fd, REG_ALS_VIS_DATA0 + 1);
    ir_low = wiringPiI2CReadReg8(fd, REG_ALS_IR_DATA0);
    ir_high = wiringPiI2CReadReg8(fd, REG_ALS_IR_DATA0 + 1);

    if (vis_low == -1 || vis_high == -1 || ir_low == -1 || ir_high == -1) {
        fprintf(stderr, "I2C read error!\n");
        return -1; // Indicate error
    }

    *vis = (vis_high << 8) | vis_low;
    *ir = (ir_high << 8) | ir_low;

    return 0;
}

// Function to log sensor data
void log_data(int vis, int ir) {
    time_t rawtime;
    struct tm *timeinfo;
    time(&rawtime);
    timeinfo = localtime(&rawtime);

    printf("[%04d-%02d-%02d %02d:%02d:%02d] VIS: %d, IR: %d\n",
           timeinfo->tm_year + 1900, timeinfo->tm_mon + 1, timeinfo->tm_mday,
           timeinfo->tm_hour, timeinfo->tm_min, timeinfo->tm_sec,
           vis, ir);
}

int main() {
    int fd;
    int vis, ir;

    // Setup signal handler for Ctrl+C
    signal(SIGINT, intHandler);

    // Initialize wiringPi I2C
    fd = wiringPiI2CSetup(SI1145_ADDR);
    if (fd == -1) {
        fprintf(stderr, "wiringPiI2CSetup failed!\n");
        return 1;
    }

    // Initialize the sensor
    if (si1145_init(fd) != 0) {
        fprintf(stderr, "Si1145 initialization failed!\n");
        return 1;
    }

    // Main loop
    while (keep_running) {
        if (read_sensor_data(fd, &vis, &ir) == 0) {
            log_data(vis, ir);
        } else {
            fprintf(stderr, "Failed to read sensor data.\n");
        }
        sleep(1);
    }

    printf("Exiting cleanly.\n");
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <pigpio.h>
#include <time.h>
#include <signal.h>
#include <unistd.h>
#include <errno.h>

// I2C address of the SDP810 sensor
#define SDP810_I2C_ADDRESS 0x25
// Measurement command (trigger without averaging)
#define MEASURE_COMMAND 0x362F
// Sensitivity factor (adjust based on your sensor's calibration)
#define SENSITIVITY 60.0

// Global variables for graceful shutdown
int i2c_handle = -1;
int pigpio_initialized = 0;

// Structure to hold sensor data
typedef struct {
    int16_t differential_pressure_raw;
    int16_t temperature_raw;
    uint8_t status;
} sensor_data_t;

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("\nCaught signal %d, cleaning up...\n", signal);
    if (i2c_handle >= 0) {
        i2cClose(i2c_handle);
    }
    if (pigpio_initialized) {
        gpioTerminate();
    }
    exit(0);
}

// Function to read sensor data
int read_sensor_data(int i2c_handle, sensor_data_t *data) {
    char buf[6];
    char cmd[2] = {(MEASURE_COMMAND >> 8) & 0xFF, MEASURE_COMMAND & 0xFF};
    int result;

    // Send measurement command
    result = i2cWriteDevice(i2c_handle, cmd, 2);
    if (result != 0) {
        fprintf(stderr, "Error writing to I2C device: %s\n", strerror(errno));
        return -1;
    }

    // Wait for measurement to complete (adjust as needed)
    gpioDelay(20); // 20 ms

    // Read 6 bytes of data (pressure, temperature, status)
    result = i2cReadDevice(i2c_handle, buf, 6);
    if (result != 6) {
        fprintf(stderr, "Error reading from I2C device: %s\n", strerror(errno));
        return -1;
    }

    // Extract data from buffer
    data->differential_pressure_raw = (int16_t)((buf[0] << 8) | buf[1]);
    data->temperature_raw = (int16_t)((buf[3] << 8) | buf[4]);
    data->status = buf[5];

    return 0;
}

// Function to log sensor data with timestamp
void log_sensor_data(sensor_data_t data) {
    struct timespec ts;
    clock_gettime(CLOCK_REALTIME, &ts);

    double pressure_pa = (double)data.differential_pressure_raw / SENSITIVITY;
    double temperature_c = (double)data.temperature_raw / 200.0; // Typical scaling for SDP8xx

    printf("%ld.%09ld, Pressure: %.2f Pa, Temperature: %.2f C, Status: 0x%02X\n",
           ts.tv_sec, ts.tv_nsec, pressure_pa, temperature_c, data.status);
}

int main() {
    // Register signal handlers for graceful shutdown
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }
    pigpio_initialized = 1;

    // Open I2C connection
    i2c_handle = i2cOpen(1, SDP810_I2C_ADDRESS, 0);
    if (i2c_handle < 0) {
        fprintf(stderr, "Failed to open I2C device: %s\n", strerror(errno));
        gpioTerminate();
        return 1;
    }

    sensor_data_t sensor_data;

    // Main loop
    while (1) {
        if (read_sensor_data(i2c_handle, &sensor_data) == 0) {
            log_sensor_data(sensor_data);
        } else {
            fprintf(stderr, "Failed to read sensor data. Retrying in 1 second.\n");
            // Attempt to re-initialize I2C
            i2cClose(i2c_handle);
            i2c_handle = i2cOpen(1, SDP810_I2C_ADDRESS, 0);
            if (i2c_handle < 0) {
                fprintf(stderr, "Failed to re-open I2C device: %s\n", strerror(errno));
            }
        }

        gpioDelay(500); // 500ms delay
    }

    // Cleanup (should not reach here in normal operation due to signal handler)
    i2cClose(i2c_handle);
    gpioTerminate();
    return 0;
}

