    // Initialize I2C
    fd = wiringPiI2CSetup(SDP800_ADDR);
    if (fd < 0) {
        fprintf(stderr, "Error initializing I2C: ");
        perror(NULL); // Print the error message associated with errno
        return 1; // Exit with an error code
    }

    printf("SDP800-500Pa I2C data logger started.\n");

    // Measurement loop
    while (1) {
        // Trigger measurement
        if (wiringPiI2CWrite(fd, TRIGGER_MEASUREMENT) < 0) {
            fprintf(stderr, "Error triggering measurement: ");
            perror(NULL);
            delay(500);
            continue; // Continue to the next iteration
        }

        delay(1); // Small delay after triggering measurement, before reading

        // Read differential pressure
        raw_pressure = wiringPiI2CReadReg16(fd, 0); // Read from register 0 (pressure)
        if (raw_pressure < 0) {
            fprintf(stderr, "Error reading pressure data: ");
            perror(NULL);
            delay(500);
            continue; // Continue to the next iteration
        }

        // Convert raw pressure to Pascals
        pressure_pa = (float)raw_pressure * SCALING_FACTOR;

        // Print the pressure
        printf("Pressure: %.2f Pa\n", pressure_pa);

        delay(500); // Wait 500ms
    }

    return 0; // This line will never be reached in the infinite loop
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <unistd.h>
#include <fcntl.h>
#include <sys/ioctl.h>
#include <linux/spi/spidev.h>
#include <time.h>
#include <string.h>
#include <signal.h>

// Configuration
#define SPI_BUS 0
#define SPI_DEVICE 0
#define SPI_MODE SPI_MODE_0
#define SPI_BITS_PER_WORD 8
#define SPI_MAX_SPEED_HZ 1000000 // 1 MHz
#define MCP3008_CHANNEL 0 // ADC Channel for MLX91211

// Global Variables
int spi_fd;
volatile sig_atomic_t program_running = 1;

// Structure for SPI configuration
typedef struct {
    uint8_t mode;
    uint8_t bits;
    uint32_t speed;
} spi_config_t;

// Function Prototypes
int spi_setup(int bus, int device, spi_config_t *config);
int read_mcp3008(int channel);
float adc_to_current(int adc_value);
void signal_handler(int signal);
void cleanup(void);

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    program_running = 0;
    printf("\nCaught signal %d, exiting gracefully.\n", signal);
}

// SPI Setup Function
int spi_setup(int bus, int device, spi_config_t *config) {
    char spi_device_path[32];
    snprintf(spi_device_path, sizeof(spi_device_path), "/dev/spidev%d.%d", bus, device);

    spi_fd = open(spi_device_path, O_RDWR);
    if (spi_fd < 0) {
        perror("Error opening SPI device");
        return -1;
    }

    // Set SPI mode
    if (ioctl(spi_fd, SPI_IOC_WR_MODE, &config->mode) == -1) {
        perror("Error setting SPI mode");
        close(spi_fd);
        return -1;
    }

    // Set bits per word
    if (ioctl(spi_fd, SPI_IOC_WR_BITS_PER_WORD, &config->bits) == -1) {
        perror("Error setting bits per word");
        close(spi_fd);
        return -1;
    }

    // Set max speed
    if (ioctl(spi_fd, SPI_IOC_WR_MAX_SPEED_HZ, &config->speed) == -1) {
        perror("Error setting max speed");
        close(spi_fd);
        return -1;
    }

    return 0;
}

// Function to read from MCP3008 ADC
int read_mcp3008(int channel) {
    uint8_t tx_buf[3];
    uint8_t rx_buf[3];

    // Construct SPI message
    tx_buf[0] = 0x01; // Start bit
    tx_buf[1] = ((0x08 | channel) << 4); // Single-ended mode, channel selection
    tx_buf[2] = 0x00; // Don't care

    struct spi_ioc_transfer transfer = {
        .tx_buf = (unsigned long)tx_buf,
        .rx_buf = (unsigned long)rx_buf,
        .len = 3,
        .speed_hz = SPI_MAX_SPEED_HZ,
        .bits_per_word = SPI_BITS_PER_WORD,
    };

    if (ioctl(spi_fd, SPI_IOC_MESSAGE(1), &transfer) < 0) {
        perror("Error sending SPI message");
        return -1;
    }

    // Extract ADC value (10 bits)
    int adc_value = ((rx_buf[1] & 0x03) << 8) + rx_buf[2];
    return adc_value;
}

// Function to convert ADC value to current (example calibration)
float adc_to_current(int adc_value) {
    // Example calibration: 0 ADC = 0A, 1023 ADC = 50A
    float current = (float)adc_value / 1023.0 * 50.0;
    return current;
}

// Cleanup function
void cleanup(void) {
    if (spi_fd >= 0) {
        close(spi_fd);
    }
    printf("Cleanup complete.\n");
}

int main() {
    spi_config_t spi_config = {
        .mode = SPI_MODE,
        .bits = SPI_BITS_PER_WORD,
        .speed = SPI_MAX_SPEED_HZ
    };

    // Setup signal handler
    signal(SIGINT, signal_handler);

    // Initialize SPI
    if (spi_setup(SPI_BUS, SPI_DEVICE, &spi_config) != 0) {
        fprintf(stderr, "SPI initialization failed. Exiting.\n");
        return 1;
    }

    printf("MLX91211 Current Sensor Interface\n");

    while (program_running) {
        int adc_value = read_mcp3008(MCP3008_CHANNEL);
        if (adc_value < 0) {
            fprintf(stderr, "Error reading ADC value. Retrying in 500ms.\n");
        } else {
            float current = adc_to_current(adc_value);
            printf("Current: %.2f A\n", current);
        }
        usleep(500000); // 500ms
    }

    cleanup();
    return 0;
}

