#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <stdbool.h>
#include <unistd.h>
#include <time.h>
#include <wiringPiI2C.h>
#include <signal.h>

// VEML7700 Registers
#define VEML7700_ADDR 0x48
#define VEML7700_CONFIG 0x00
#define VEML7700_ALS_WH 0x01
#define VEML7700_ALS_WL 0x02
#define VEML7700_WHITE_WH 0x03
#define VEML7700_WHITE_WL 0x04
#define VEML7700_INTERRUPT 0x06

// Configuration settings
#define ALS_IT_800MS   0x00  // Integration time = 800ms
#define ALS_GAIN_X1    0x00  // Gain = 1
#define SD_POWER_ON    0x00  // Power on

// Global variables
int fd;
volatile sig_atomic_t keep_running = 1;

// Structure for sensor data
typedef struct {
    unsigned int ambient_light;
    unsigned int white_light;
} sensor_data_t;

// Signal handler for graceful shutdown
void intHandler(int dummy) {
    keep_running = 0;
}

// Function to initialize the VEML7700 sensor
bool init_veml7700(int fd) {
    // Configure the sensor
    uint16_t config_value = (ALS_IT_800MS << 11) | (ALS_GAIN_X1 << 9) | (SD_POWER_ON << 0);

    if (wiringPiI2CWriteReg16(fd, VEML7700_CONFIG, config_value) < 0) {
        perror("Failed to write to VEML7700 config register");
        return false;
    }
    return true;
}

// Function to read sensor data
bool read_veml7700(int fd, sensor_data_t *data) {
    int als_wh, als_wl, white_wh, white_wl;

    als_wh = wiringPiI2CReadReg8(fd, VEML7700_ALS_WH);
    als_wl = wiringPiI2CReadReg8(fd, VEML7700_ALS_WL);
    white_wh = wiringPiI2CReadReg8(fd, VEML7700_WHITE_WH);
    white_wl = wiringPiI2CReadReg8(fd, VEML7700_WHITE_WL);

    if (als_wh == -1 || als_wl == -1 || white_wh == -1 || white_wl == -1) {
        perror("Failed to read sensor data");
        return false;
    }

    data->ambient_light = (als_wh << 8) | als_wl;
    data->white_light = (white_wh << 8) | white_wl;

    return true;
}

// Function to log sensor data to the console
void log_sensor_data(const sensor_data_t *data) {
    time_t rawtime;
    struct tm * timeinfo;
    time(&rawtime);
    timeinfo = localtime(&rawtime);

    printf("[%04d-%02d-%02d %02d:%02d:%02d] Ambient Light: %u, White Light: %u\n",
           timeinfo->tm_year + 1900, timeinfo->tm_mon + 1, timeinfo->tm_mday,
           timeinfo->tm_hour, timeinfo->tm_min, timeinfo->tm_sec,
           data->ambient_light, data->white_light);
}

int main() {
    sensor_data_t sensor_data;

    // Setup signal handler for Ctrl+C
    signal(SIGINT, intHandler);

    // Initialize wiringPi I2C
    fd = wiringPiI2CSetup(VEML7700_ADDR);
    if (fd == -1) {
        perror("Failed to initialize I2C communication");
        return 1;
    }

    // Initialize the sensor
    if (!init_veml7700(fd)) {
        fprintf(stderr, "Sensor initialization failed.\n");
        return 1;
    }

    printf("VEML7700 sensor initialized successfully.\n");

    // Main loop
    while (keep_running) {
        if (read_veml7700(fd, &sensor_data)) {
            log_sensor_data(&sensor_data);
        } else {
            fprintf(stderr, "Failed to read sensor data. Retrying...");
        }

        sleep(1); // Read data every 1 second
    }

    printf("\nExiting program.\n");
    return 0;
}

