// Define the I2C address of the HMC1022 compass module
#define HMC1022_ADDR 0x1E // or 0x1D, check your module

// Define the register addresses for X, Y, and Z axis data
#define HMC1022_X_MSB 0x00
#define HMC1022_X_LSB 0x01
#define HMC1022_Z_MSB 0x02
#define HMC1022_Z_LSB 0x03
#define HMC1022_Y_MSB 0x04
#define HMC1022_Y_LSB 0x05

// Structure to hold the sensor data
typedef struct {
    int16_t x;
    int16_t y;
    int16_t z;
} sensor_data_t;

// Global variable for I2C file descriptor
int i2c_fd;

bool running = true;

void signal_handler(int signal) {
    running = false;
    printf("\nExiting gracefully...\n");
}

// Function to read a 16-bit value from a register
int16_t read_register(int fd, uint8_t msb_reg, uint8_t lsb_reg) {
    int msb = wiringPiI2CReadReg8(fd, msb_reg);
    int lsb = wiringPiI2CReadReg8(fd, lsb_reg);

    if (msb == -1 || lsb == -1) {
        fprintf(stderr, "I2C read error: %s\n", strerror(errno));
        return 0; // Or some error value
    }

    return (int16_t)((msb << 8) | lsb);
}

// Function to read sensor data
sensor_data_t read_sensor_data(int fd) {
    sensor_data_t data;
    data.x = read_register(fd, HMC1022_X_MSB, HMC1022_X_LSB);
    data.y = read_register(fd, HMC1022_Y_MSB, HMC1022_Y_LSB);
    data.z = read_register(fd, HMC1022_Z_MSB, HMC1022_Z_LSB);
    return data;
}

// Function to log sensor data to the console
void log_sensor_data(sensor_data_t data) {
    time_t rawtime;
    struct tm * timeinfo;
    char timestamp[20];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    printf("%s - X: %6d, Y: %6d, Z: %6d\n", timestamp, data.x, data.y, data.z);
}

int main() {
    // Initialize WiringPi I2C
    i2c_fd = wiringPiI2CSetup(HMC1022_ADDR);
    if (i2c_fd == -1) {
        fprintf(stderr, "I2C initialization failed: %s\n", strerror(errno));
        return 1;
    }

    signal(SIGINT, signal_handler);

    // Main loop
    while (running) {
        // Read sensor data
        sensor_data_t data = read_sensor_data(i2c_fd);

        // Log sensor data
        log_sensor_data(data);

        // Wait for a specified period (e.g., 1 second)
        sleep(1);
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
