#include <unistd.h>
#include <time.h>
#include <signal.h>

// ADT7420 I2C Address
#define ADT7420_ADDR 0x48

// ADT7420 Registers
#define ADT7420_TEMP_MSB 0x00
#define ADT7420_TEMP_LSB 0x01
#define ADT7420_CONFIG   0x03

// Global variable to control the loop
volatile sig_atomic_t keep_running = 1;

// Signal handler for Ctrl+C
void intHandler(int dummy) {
    keep_running = 0;
}

// Function to initialize the ADT7420
int setup_adt7420(int fd) {
    // Configure the ADT7420 for continuous conversion mode
    if (wiringPiI2CWriteReg8(fd, ADT7420_CONFIG, 0x00) < 0) {
        fprintf(stderr, "Error writing to config register.\n");
        return -1;
    }
    return 0;
}

// Function to read the temperature from the ADT7420
float read_temperature(int fd) {
    int16_t temp_raw;
    int msb, lsb;

    msb = wiringPiI2CReadReg8(fd, ADT7420_TEMP_MSB);
    lsb = wiringPiI2CReadReg8(fd, ADT7420_TEMP_LSB);

    if (msb < 0 || lsb < 0) {
        fprintf(stderr, "Error reading temperature data.\n");
        return -273.15; // Return absolute zero on error
    }

    temp_raw = (msb << 8) | lsb;

    // Check if it's a negative temperature
    if (temp_raw & 0x8000) {
        temp_raw |= 0xF000; // Sign extend
    }

    // Convert to Celsius
    return (float)temp_raw / 128.0;
}

// Function to log the temperature data
void log_temperature(float temperature) {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[80];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    printf("[%s] Temperature: %.2f °C\n", timestamp, temperature);
}

int main() {
    int fd;
    float temperature;

    // Setup signal handler
    signal(SIGINT, intHandler);

    // Initialize I2C
    fd = wiringPiI2CSetup(ADT7420_ADDR);
    if (fd == -1) {
        fprintf(stderr, "Error initializing I2C communication.\n");
        return 1;
    }

    // Initialize the ADT7420 sensor
    if (setup_adt7420(fd) != 0) {
        fprintf(stderr, "ADT7420 setup failed.\n");
        return 1;
    }

    printf("Temperature monitoring started. Press Ctrl+C to exit.\n");

    // Main loop
    while (keep_running) {
        temperature = read_temperature(fd);
        if (temperature != -273.15) {
            log_temperature(temperature);
        }
        sleep(2);
    }

    printf("\nTemperature monitoring stopped.\n");

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <fcntl.h>
#include <unistd.h>
#include <sys/ioctl.h>
#include <linux/spi/spidev.h>
#include <time.h>
#include <signal.h>
#include <string.h>

// Configuration
#define SPI_BUS 0
#define SPI_DEVICE 0
#define SPI_MODE SPI_MODE_0
#define SPI_BITS_PER_WORD 8
#define SPI_MAX_SPEED_HZ 1000000 //1 MHz

#define AIRFLOW_THRESHOLD 1.0 // Example threshold (adjust based on sensor and application)
#define LOG_FILE "entry_log.txt"

// Global variables
static int spi_fd;
static volatile sig_atomic_t program_running = 1;

// Structure for sensor data
typedef struct {
    float airflow;
    time_t timestamp;
} sensor_data_t;

// Function prototypes
int spi_init(int bus, int device);
uint16_t spi_read(int fd);
float convert_to_airflow(uint16_t raw_value);
void log_entry(float airflow);
void signal_handler(int signal);

// Initialize SPI
int spi_init(int bus, int device) {
    char spi_dev[20];
    sprintf(spi_dev, "/dev/spidev%d.%d", bus, device);

    spi_fd = open(spi_dev, O_RDWR);
    if (spi_fd < 0) {
        perror("Error opening SPI device");
        return -1;
    }

    // Configure SPI mode
    uint8_t mode = SPI_MODE;
    if (ioctl(spi_fd, SPI_IOC_WR_MODE, &mode) == -1) {
        perror("Error setting SPI mode");
        close(spi_fd);
        return -1;
    }

    // Configure bits per word
    uint8_t bits = SPI_BITS_PER_WORD;
    if (ioctl(spi_fd, SPI_IOC_WR_BITS_PER_WORD, &bits) == -1) {
        perror("Error setting bits per word");
        close(spi_fd);
        return -1;
    }

    // Configure max speed hz
    uint32_t speed = SPI_MAX_SPEED_HZ;
    if (ioctl(spi_fd, SPI_IOC_WR_MAX_SPEED_HZ, &speed) == -1) {
        perror("Error setting max speed hz");
        close(spi_fd);
        return -1;
    }

    return spi_fd;
}

// Read data from SPI
uint16_t spi_read(int fd) {
    uint8_t tx_buf[2] = {0x00, 0x00}; // Dummy data to clock in the response
    uint8_t rx_buf[2] = {0};
    struct spi_ioc_transfer transfer = {
        .tx_buf = (unsigned long)tx_buf,
        .rx_buf = (unsigned long)rx_buf,
        .len = 2, // Read 2 bytes
        .speed_hz = SPI_MAX_SPEED_HZ,
        .bits_per_word = SPI_BITS_PER_WORD,
    };

    if (ioctl(fd, SPI_IOC_MESSAGE(1), &transfer) < 0) {
        perror("Error sending SPI message");
        return 0; // Return 0 on error
    }

    return (rx_buf[0] << 8) | rx_buf[1]; // Combine the two bytes into a 16-bit value
}

// Convert raw value to airflow (example linear conversion)
float convert_to_airflow(uint16_t raw_value) {
    // This is a placeholder.  You MUST calibrate your sensor and replace
    // these values with the correct min/max values for your sensor.
    float min_raw = 0.0;
    float max_raw = 65535.0;
    float min_airflow = 0.0;
    float max_airflow = 5.0; // Example: 0 to 5 m/s

    return min_airflow + (raw_value - min_raw) * (max_airflow - min_airflow) / (max_raw - min_raw);
}

// Log entry event
void log_entry(float airflow) {
    FILE *fp = fopen(LOG_FILE, "a");
    if (fp == NULL) {
        perror("Error opening log file");
        return;
    }

    time_t now = time(NULL);
    struct tm *tstruct = localtime(&now);
    char buf[80];
    strftime(buf, sizeof(buf), "%Y-%m-%d.%X", tstruct);

    fprintf(fp, "Entry detected at: %s, Airflow: %.2f m/s\n", buf, airflow);
    fclose(fp);
    printf("Entry logged: %s, Airflow: %.2f m/s\n", buf, airflow);
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    program_running = 0;
    printf("Exiting program...\n");
}

int main() {
    // Initialize signal handler
    signal(SIGINT, signal_handler);

    // Initialize SPI
    if ((spi_fd = spi_init(SPI_BUS, SPI_DEVICE)) < 0) {
        fprintf(stderr, "SPI initialization failed\n");
        return 1;
    }

    printf("SPI initialized successfully\n");

    // Main loop
    while (program_running) {
        // Read raw sensor data
        uint16_t raw_value = spi_read(spi_fd);

        // Convert to airflow
        float airflow = convert_to_airflow(raw_value);

        // Check for entry event
        if (airflow > AIRFLOW_THRESHOLD) {
            log_entry(airflow);
        }

        sleep(1); // Check every 1 second
    }

    // Close SPI device
    close(spi_fd);
    printf("SPI closed\n");

    return 0;
}

#include <stdio.h>
