// Define SPI device and channel
#define SPI_DEVICE "/dev/spidev0.0"
#define SPI_CHANNEL 0
#define ADC_CHANNEL 0 // MCP3008 channel for airflow sensor

// Define constants for airflow sensor calibration (example values)
#define SENSOR_MIN_VOLTAGE 0.5  // Volts
#define SENSOR_MAX_VOLTAGE 4.5  // Volts
#define SENSOR_MIN_AIRFLOW 0.0  // m/s
#define SENSOR_MAX_AIRFLOW 10.0 // m/s

// Structure to hold SPI configuration
typedef struct {
    int fd;
    uint8_t mode;
    uint8_t bits;
    uint32_t speed;
} spi_config_t;

// Global variable for program termination
volatile sig_atomic_t program_running = 1;

// Signal handler for graceful shutdown
void signal_handler(int signum) {
    program_running = 0;
    printf("\nExiting program...\n");
}

// Function to initialize SPI
int spi_init(spi_config_t *config) {
    config->fd = open(SPI_DEVICE, O_RDWR);
    if (config->fd < 0) {
        perror("Error opening SPI device");
        return -1;
    }

    config->mode = 0;
    if (ioctl(config->fd, SPI_IOC_WR_MODE, &config->mode) == -1) {
        perror("Error setting SPI mode");
        close(config->fd);
        return -1;
    }

    config->bits = 8;
    if (ioctl(config->fd, SPI_IOC_WR_BITS_PER_WORD, &config->bits) == -1) {
        perror("Error setting SPI bits");
        close(config->fd);
        return -1;
    }

    config->speed = 1000000; // 1 MHz
    if (ioctl(config->fd, SPI_IOC_WR_MAX_SPEED_HZ, &config->speed) == -1) {
        perror("Error setting SPI speed");
        close(config->fd);
        return -1;
    }

    return 0;
}

// Function to read data from MCP3008 ADC
int read_mcp3008(int fd, int channel) {
    uint8_t tx_buf[3];
    uint8_t rx_buf[3];
    struct spi_ioc_transfer tr;

    // Construct SPI message for MCP3008
    tx_buf[0] = 0x01;                           // Start bit
    tx_buf[1] = (0x08 | channel) << 4;         // Single-ended mode, channel selection
    tx_buf[2] = 0x00;                           // Dummy byte

    memset(&tr, 0, sizeof(tr));
    tr.tx_buf = (unsigned long)tx_buf;
    tr.rx_buf = (unsigned long)rx_buf;
    tr.len = 3;
    tr.delay_usecs = 0;
    tr.speed_hz = 1000000; // 1 MHz
    tr.bits_per_word = 8;

    if (ioctl(fd, SPI_IOC_MESSAGE(1), &tr) < 1) {
        perror("Error sending SPI message");
        return -1;
    }

    // Extract ADC value from response
    int adc_value = ((rx_buf[1] & 0x03) << 8) + rx_buf[2];
    return adc_value;
}

// Function to convert ADC reading to airflow (linear interpolation)
float adc_to_airflow(int adc_value) {
    float voltage = (float)adc_value / 1023.0 * 5.0; // Assuming 5V reference
    float airflow = (voltage - SENSOR_MIN_VOLTAGE) / (SENSOR_MAX_VOLTAGE - SENSOR_MIN_VOLTAGE) * (SENSOR_MAX_AIRFLOW - SENSOR_MIN_AIRFLOW) + SENSOR_MIN_AIRFLOW;
    return airflow;
}

// Function to log timestamped airflow data to the console
void log_airflow_data(float airflow) {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[80];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);
    printf("[%s] Airflow: %.2f m/s\n", timestamp, airflow);
}

int main() {
    spi_config_t spi_config;
    int adc_value;
    float airflow;

    // Register signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Initialize SPI
    if (spi_init(&spi_config) == -1) {
        return 1;
    }

    printf("Airflow sensor data logging started. Press Ctrl+C to exit.\n");

    while (program_running) {
        // Read ADC value from MCP3008
        adc_value = read_mcp3008(spi_config.fd, ADC_CHANNEL);
        if (adc_value == -1) {
            fprintf(stderr, "Error reading ADC value. Retrying in 1 second.\n");
            sleep(1);
            continue; // Retry
        }

        // Convert ADC value to airflow
        airflow = adc_to_airflow(adc_value);

        // Log airflow data
        log_airflow_data(airflow);

        // Wait for 1 second
        sleep(1);
    }

    // Close SPI device
    close(spi_config.fd);

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <unistd.h>
#include <pigpio.h>

#define AM2303_GPIO 4

static volatile int terminate = 0;

void signal_handler(int sig)
{
    terminate = 1;
}

int read_am2303(int gpio_pin, float *temperature, float *humidity)
{
    int data[5] = {0, 0, 0, 0, 0};
    int bit_count = 0;
    int byte_index = 0;
    int checksum = 0;
    int i, j;

    /* Set GPIO as output and pull low for at least 1ms */
    gpioSetMode(gpio_pin, PI_OUTPUT);
    gpioWrite(gpio_pin, 0);
    gpioDelay(1100); // Ensure at least 1ms low

    /* Set GPIO as input */
    gpioSetMode(gpio_pin, PI_INPUT);
    gpioSetPullUpDown(gpio_pin, PI_PUD_UP);
    gpioDelay(40);

    /* Wait for AM2303 response (low then high) */
    if (gpioRead(gpio_pin) != 0) return -1; // Error: Expected low
    while (gpioRead(gpio_pin) == 0 && gpioTime() < 100000) {}; // Wait for high (max 100us)
    if (gpioRead(gpio_pin) != 1) return -2; // Error: Expected high
    while (gpioRead(gpio_pin) == 1 && gpioTime() < 100000) {}; // Wait for low (max 100us)

    /* Read 40 bits of data */
    for (i = 0; i < 40; i++)
    {
        /* Wait for the start of the data bit (low) */
        while (gpioRead(gpio_pin) == 0 && gpioTime() < 100000) {};

        /* Measure the length of the high pulse to determine if it's a 0 or a 1 */
        long start = gpioTime();
        while (gpioRead(gpio_pin) == 1 && gpioTime() < 100000) {};
        long end = gpioTime();

        if (end - start > 50) // 50us threshold
        {
            data[byte_index] |= (1 << (7 - bit_count)); // Store a 1
        }
        /*else {
            // Implicitly store a 0 (already initialized to 0)
        }*/

        bit_count++;
        if (bit_count == 8)
        {
            bit_count = 0;
            byte_index++;
        }
    }

    /* Calculate checksum */
    checksum = (data[0] + data[1] + data[2] + data[3]) & 0xFF;

    /* Validate checksum */
    if (checksum != data[4])
    {
        return -3; // Checksum error
    }

    /* Convert data to temperature and humidity */
    *humidity = ((float)data[0] * 256 + data[1]) / 10;
    *temperature = ((float)data[2] * 256 + data[3]) / 10;
    if (*temperature > 125) {
        *temperature = *temperature - 256; //handle negative temperatures
    }

    return 0;
}

int main()
{
    float temperature, humidity;
    int result;

    /* Initialize pigpio */
    if (gpioInitialise() < 0)
    {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    /* Set signal handler for Ctrl+C */
    signal(SIGINT, signal_handler);

    printf("Reading AM2303 sensor data...\n");

    while (!terminate)
    {
        result = read_am2303(AM2303_GPIO, &temperature, &humidity);

        if (result == 0)
        {
            printf("Temperature: %.1f°C, Humidity: %.1f%%\n", temperature, humidity);
        }
        else
        {
            fprintf(stderr, "Error reading sensor data: %d\n", result);
        }

        sleep(5);
    }

    printf("Exiting...\n");
    gpioTerminate();
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
