// LSM6DSL Register Map
#define LSM6DSL_ADDR 0x6A // or 0x6B
#define LSM6DSL_CTRL1_XL 0x10
#define LSM6DSL_CTRL2_G 0x11
#define LSM6DSL_OUTX_L_G 0x22
#define LSM6DSL_OUTX_H_G 0x23
#define LSM6DSL_OUTY_L_G 0x24
#define LSM6DSL_OUTY_H_G 0x25
#define LSM6DSL_OUTZ_L_G 0x26
#define LSM6DSL_OUTZ_H_G 0x27
#define LSM6DSL_OUTX_L_XL 0x28
#define LSM6DSL_OUTX_H_XL 0x29
#define LSM6DSL_OUTY_L_XL 0x2A
#define LSM6DSL_OUTY_H_XL 0x2B
#define LSM6DSL_OUTZ_L_XL 0x2C
#define LSM6DSL_OUTZ_H_XL 0x2D

// Configuration
#define ACCEL_FS 2 // +/- 2g
#define GYRO_FS 245 // +/- 245 dps

// Global variable for I2C file descriptor
int i2c_fd;
volatile sig_atomic_t keep_running = 1;

// Structure to hold sensor data
typedef struct {
    float accel_x, accel_y, accel_z;
    float gyro_x, gyro_y, gyro_z;
} imu_data_t;

// Helper function to write a byte to a register
int write_register(int fd, uint8_t reg, uint8_t value) {
    uint8_t buf[2] = {reg, value};
    if (write(fd, buf, 2) != 2) {
        perror("Failed to write to I2C device");
        return -1;
    }
    return 0;
}

// Helper function to read multiple bytes from a register
int read_registers(int fd, uint8_t reg, uint8_t *buf, int len) {
    if (write(fd, &reg, 1) != 1) {
        perror("Failed to write register address");
        return -1;
    }
    if (read(fd, buf, len) != len) {
        perror("Failed to read from I2C device");
        return -1;
    }
    return 0;
}

// Function to initialize the LSM6DSL IMU
int lsm6dsl_init(int fd) {
    // Configure accelerometer: 1.66 kHz, +/- 2g
    if (write_register(fd, LSM6DSL_CTRL1_XL, 0x80 | (ACCEL_FS << 2)) < 0) return -1;

    // Configure gyroscope: 1.66 kHz, +/- 245 dps
    if (write_register(fd, LSM6DSL_CTRL2_G, 0x80 | (GYRO_FS << 2)) < 0) return -1;

    return 0;
}

// Function to read raw sensor data
int lsm6dsl_read_raw_data(int fd, int16_t *accel_x, int16_t *accel_y, int16_t *accel_z, int16_t *gyro_x, int16_t *gyro_y, int16_t *gyro_z) {
    uint8_t buf[12];

    if (read_registers(fd, LSM6DSL_OUTX_L_G, buf, 12) < 0) return -1;

    *gyro_x = (int16_t)((buf[1] << 8) | buf[0]);
    *gyro_y = (int16_t)((buf[3] << 8) | buf[2]);
    *gyro_z = (int16_t)((buf[5] << 8) | buf[4]);
    *accel_x = (int16_t)((buf[7] << 8) | buf[6]);
    *accel_y = (int16_t)((buf[9] << 8) | buf[8]);
    *accel_z = (int16_t)((buf[11] << 8) | buf[10]);

    return 0;
}

// Function to convert raw data to physical units
imu_data_t lsm6dsl_process_data(int16_t accel_x_raw, int16_t accel_y_raw, int16_t accel_z_raw, int16_t gyro_x_raw, int16_t gyro_y_raw, int16_t gyro_z_raw) {
    imu_data_t data;

    // Accelerometer: 16 bits, +/- 2g
    data.accel_x = (float)accel_x_raw * 0.061 * ACCEL_FS / 1000.0; // mg
    data.accel_y = (float)accel_y_raw * 0.061 * ACCEL_FS / 1000.0;
    data.accel_z = (float)accel_z_raw * 0.061 * ACCEL_FS / 1000.0;

    // Gyroscope: 16 bits, +/- 245 dps
    data.gyro_x = (float)gyro_x_raw * 8.75 * GYRO_FS / 245.0 / 1000.0; // mdps
    data.gyro_y = (float)gyro_y_raw * 8.75 * GYRO_FS / 245.0 / 1000.0;
    data.gyro_z = (float)gyro_z_raw * 8.75 * GYRO_FS / 245.0 / 1000.0;

    return data;
}

// Signal handler for graceful shutdown
void signal_handler(int sig) {
    keep_running = 0;
    printf("Exiting...
");
}

int main() {
    // Set up signal handling
    signal(SIGINT, signal_handler);

    // Open I2C device
    const char *i2c_device = "/dev/i2c-1";
    i2c_fd = open(i2c_device, O_RDWR);
    if (i2c_fd < 0) {
        perror("Failed to open I2C device");
        return 1;
    }

    // Specify the address of the slave device
    if (ioctl(i2c_fd, I2C_SLAVE, LSM6DSL_ADDR) < 0) {
        perror("Failed to acquire bus access and/or talk to slave");
        close(i2c_fd);
        return 1;
    }

    // Initialize the IMU
    if (lsm6dsl_init(i2c_fd) < 0) {
        fprintf(stderr, "IMU initialization failed
");
        close(i2c_fd);
        return 1;
    }

    printf("LSM6DSL IMU initialized successfully!
");

    // Data acquisition loop
    while (keep_running) {
        int16_t accel_x_raw, accel_y_raw, accel_z_raw;
        int16_t gyro_x_raw, gyro_y_raw, gyro_z_raw;

        if (lsm6dsl_read_raw_data(i2c_fd, &accel_x_raw, &accel_y_raw, &accel_z_raw, &gyro_x_raw, &gyro_y_raw, &gyro_z_raw) == 0) {
            imu_data_t data = lsm6dsl_process_data(accel_x_raw, accel_y_raw, accel_z_raw, gyro_x_raw, gyro_y_raw, gyro_z_raw);

            printf("Accel: X=%.2f mg, Y=%.2f mg, Z=%.2f mg | Gyro: X=%.2f mdps, Y=%.2f mdps, Z=%.2f mdps
",
                   data.accel_x, data.accel_y, data.accel_z, data.gyro_x, data.gyro_y, data.gyro_z);
        } else {
            fprintf(stderr, "Failed to read sensor data
");
        }

        usleep(100000); // 100ms delay
    }

    // Close I2C device
    close(i2c_fd);

    return 0;
}

