    float range;
    float velocity;
} sensor_data_t;

// Signal handler for graceful shutdown
void sigint_handler(int sig) {
    (void)sig; // Suppress unused parameter warning
    fprintf(stderr, "\nCaught signal, exiting gracefully...\n");
    keep_running = 0;
}

// Function to initialize UART
int uart_init(const char *port, speed_t baud_rate) {
    int fd = open(port, O_RDWR | O_NOCTTY | O_SYNC);
    if (fd == -1) {
        perror("Error opening UART port");
        return -1;
    }

    struct termios tty;
    if (tcgetattr(fd, &tty) != 0) {
        perror("Error getting termios attributes");
        close(fd);
        return -1;
    }

    tty.c_cflag = baud_rate | CS8 | CLOCAL | CREAD;
    tty.c_iflag = IGNPAR; // Ignore parity errors
    tty.c_oflag = 0;
    tty.c_lflag = 0; // Non-canonical mode

    tty.c_cc[VMIN] = 0;  // Read doesn't block
    tty.c_cc[VTIME] = 5; // Timeout after 0.5 seconds

    if (tcsetattr(fd, TCSANOW, &tty) != 0) {
        perror("Error setting termios attributes");
        close(fd);
        return -1;
    }

    return fd;
}

// Function to read data from the sensor (dummy implementation)
int read_sensor_data(int fd, sensor_data_t *data) {
    char buffer[READ_BUFFER_SIZE];
    ssize_t bytes_read = read(fd, buffer, READ_BUFFER_SIZE - 1);

    if (bytes_read == -1) {
        perror("Error reading from UART");
        return -1;
    } else if (bytes_read == 0) {
        fprintf(stderr, "Timeout reading from UART\n");
        return -1;
    }

    buffer[bytes_read] = '\0'; // Null-terminate the buffer

    // Parse the data from the buffer (replace with your actual parsing logic)
    // This is a dummy example; adapt to your sensor's output format.
    if (sscanf(buffer, "Range:%f, Velocity:%f", &data->range, &data->velocity) != 2) {
        fprintf(stderr, "Error parsing sensor data: %s\n", buffer);
        return -1;
    }

    return 0;
}

// Function to log the sensor data with timestamp
void log_data(const sensor_data_t *data) {
    struct timeval tv;
    gettimeofday(&tv, NULL);
    time_t nowtime = tv.tv_sec;
    struct tm *nowtm = localtime(&nowtime);
    char tmbuf[64], buf[64];
    strftime(tmbuf, sizeof(tmbuf), "%Y-%m-%d %H:%M:%S", nowtm);
    snprintf(buf, sizeof(buf), "%s.%06ld", tmbuf, tv.tv_usec);

    printf("%s, Range: %.2f, Velocity: %.2f\n", buf, data->range, data->velocity);
}

int main() {
    // Install signal handler
    if (signal(SIGINT, sigint_handler) == SIG_ERR) {
        perror("Error installing signal handler");
        return 1;
    }

    // Initialize UART
    uart_fd = uart_init(UART_PORT, BAUD_RATE);
    if (uart_fd == -1) {
        return 1;
    }

    sensor_data_t sensor_data;

    // Main loop
    while (keep_running) {
        if (read_sensor_data(uart_fd, &sensor_data) == 0) {
            log_data(&sensor_data);
        } else {
            fprintf(stderr, "Failed to read sensor data. Retrying in %d seconds...\n", LOG_INTERVAL_SEC);
        }
        sleep(LOG_INTERVAL_SEC);
    }

    // Close UART port
    close(uart_fd);
    fprintf(stderr, "UART port closed.\n");

    return 0;
}

#include <stdio.h>
