// Configuration
#define SPI_BUS 0
#define SPI_DEVICE 0
#define ADC_CHANNEL 0 // MCP3008 Channel 0
#define SLEEP_SECONDS 5

// Global variables
int spi_fd;
volatile sig_atomic_t program_running = 1;

// Structure for MQ-2 sensor calibration data
typedef struct {
    float r0;
} mq2_calibration_t;

mq2_calibration_t mq2_data;

// Function prototypes
int spi_init(int bus, int device);
int read_adc(int channel);
float calculate_rs_r0_ratio(int adc_value);
void log_data(float ratio);
void cleanup(int signal);
float calibrate_mq2();

// Signal handler for graceful shutdown
void cleanup(int signal) {
    printf("\nCleaning up and exiting...\n");
    program_running = 0;
    close(spi_fd);
    exit(0);
}

// Initialize SPI
int spi_init(int bus, int device) {
    char spi_device_path[20];
    sprintf(spi_device_path, "/dev/spidev%d.%d", bus, device);

    spi_fd = open(spi_device_path, O_RDWR);
    if (spi_fd < 0) {
        perror("Error opening SPI device");
        return -1;
    }

    // Configure SPI mode and speed
    int mode = SPI_MODE_0;
    if (ioctl(spi_fd, SPI_IOC_WR_MODE, &mode) == -1) {
        perror("Error setting SPI mode");
        close(spi_fd);
        return -1;
    }

    int speed = 1000000; // 1 MHz
    if (ioctl(spi_fd, SPI_IOC_WR_MAX_SPEED_HZ, &speed) == -1) {
        perror("Error setting SPI speed");
        close(spi_fd);
        return -1;
    }

    return 0;
}

// Read from MCP3008 ADC
int read_adc(int channel) {
    uint8_t tx_buf[3];
    uint8_t rx_buf[3];

    // MCP3008 command: start bit, single-ended mode, channel select (0-7), MSB first
    tx_buf[0] = 0x01; // Start bit
    tx_buf[1] = (0x08 | (channel << 4)); // Single-ended, channel select
    tx_buf[2] = 0x00; // Don't care

    struct spi_ioc_transfer transfer = {
        .tx_buf = (unsigned long)tx_buf,
        .rx_buf = (unsigned long)rx_buf,
        .len = 3,
        .speed_hz = 1000000, // 1 MHz
        .delay_usecs = 0,
        .bits_per_word = 8,
    };

    if (ioctl(spi_fd, SPI_IOC_MESSAGE(1), &transfer) < 1) {
        perror("Error sending SPI message");
        return -1;
    }

    // Extract ADC value (10 bits)
    int adc_value = ((rx_buf[1] & 0x03) << 8) + rx_buf[2];
    return adc_value;
}

// Calculate Rs/R0 ratio (example formula, needs calibration)
float calculate_rs_r0_ratio(int adc_value) {
    //This is just a placeholder and requires actual sensor calibration.
    float voltage = (float)adc_value / 1023.0 * 3.3; // Assuming 3.3V reference
    float sensor_resistance = (3.3 - voltage) / voltage * 10000; // Assuming 10k load resistor
    return sensor_resistance / mq2_data.r0;
}

// Calibrate the MQ-2 sensor to find R0 in clean air
float calibrate_mq2() {
    printf("Calibrating MQ-2 sensor. Please ensure clean air...\n");
    float sum = 0.0;
    int readings = 10; // Number of calibration readings
    for (int i = 0; i < readings; i++) {
        int adc_value = read_adc(ADC_CHANNEL);
        if (adc_value < 0) {
            fprintf(stderr, "Error reading ADC during calibration\n");
            return -1.0;
        }
        float voltage = (float)adc_value / 1023.0 * 3.3; // Assuming 3.3V reference
        float sensor_resistance = (3.3 - voltage) / voltage * 10000; // Assuming 10k load resistor
        sum += sensor_resistance;
        sleep(1);
    }
    float r0 = sum / readings;
    printf("Calibration complete. R0 = %.2f ohms\n", r0);
    return r0;
}

// Log data to console
void log_data(float ratio) {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[80];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);
    printf("[%s] Rs/R0: %.4f\n", timestamp, ratio);
}

int main() {
    // Initialize SPI
    if (spi_init(SPI_BUS, SPI_DEVICE) < 0) {
        return 1;
    }

    // Register signal handler for Ctrl+C
    signal(SIGINT, cleanup);

    // Calibrate the MQ-2 sensor
    mq2_data.r0 = calibrate_mq2();
    if (mq2_data.r0 < 0) {
        fprintf(stderr, "Calibration failed. Exiting.\n");
        close(spi_fd);
        return 1;
    }

    // Main loop
    while (program_running) {
        // Read ADC value
        int adc_value = read_adc(ADC_CHANNEL);
        if (adc_value < 0) {
            fprintf(stderr, "Error reading ADC value. Retrying in %d seconds...\n", SLEEP_SECONDS);
            sleep(SLEEP_SECONDS);
            continue;
        }

        // Calculate Rs/R0 ratio
        float ratio = calculate_rs_r0_ratio(adc_value);

        // Log data
        log_data(ratio);

        // Sleep for specified interval
        sleep(SLEEP_SECONDS);
    }

    // Cleanup (should not reach here if signal handler works)
    close(spi_fd);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <unistd.h>
#include <signal.h>
#include <time.h>

// HTU21D-F I2C address
#define HTU21D_ADDR 0x40

// HTU21D-F commands
#define TRIGGER_TEMP_MEASURE_NOHOLD 0xF3
#define TRIGGER_HUMD_MEASURE_NOHOLD 0xF5
#define READ_USER_REGISTER 0xE7
#define WRITE_USER_REGISTER 0xE6
#define SOFT_RESET 0xFE

int i2c_handle;
bool running = true;

// Function prototypes
float read_temperature();
float read_humidity();
void cleanup_handler(int signal);

void cleanup_handler(int signal) {
    printf("\nCaught signal %d, cleaning up...\n", signal);
    running = false;
    if (i2c_handle >= 0) {
        i2cClose(i2c_handle);
    }
    gpioTerminate();
    exit(0);
}

float read_temperature() {
    char buf[2];
    int result;

    if (i2cWriteByte(i2c_handle, TRIGGER_TEMP_MEASURE_NOHOLD) != 0) {
        fprintf(stderr, "Error triggering temperature measurement\n");
        return -1000.0; // Indicate error
    }
    gpioDelay(50); // Wait for measurement (at least 50ms)

    if (i2cReadI2CBlockData(i2c_handle, buf, 2) != 2) {
        fprintf(stderr, "Error reading temperature data\n");
        return -1000.0;
    }

    unsigned int raw_temp = ((unsigned int)buf[0] << 8) | (unsigned int)buf[1];
    raw_temp &= 0xFFFC; // Clear status bits

    float temp_celsius = -46.85 + 175.72 * ((float)raw_temp / 65536.0);
    return temp_celsius;
}

float read_humidity() {
    char buf[2];
    int result;

    if (i2cWriteByte(i2c_handle, TRIGGER_HUMD_MEASURE_NOHOLD) != 0) {
        fprintf(stderr, "Error triggering humidity measurement\n");
        return -1000.0; // Indicate error
    }
    gpioDelay(50); // Wait for measurement (at least 50ms)

    if (i2cReadI2CBlockData(i2c_handle, buf, 2) != 2) {
        fprintf(stderr, "Error reading humidity data\n");
        return -1000.0;
    }

    unsigned int raw_humidity = ((unsigned int)buf[0] << 8) | (unsigned int)buf[1];
    raw_humidity &= 0xFFFC; // Clear status bits

    float humidity = -6.0 + 125.0 * ((float)raw_humidity / 65536.0);
    if (humidity < 0.0) humidity = 0.0;
    if (humidity > 100.0) humidity = 100.0;
    return humidity;
}

int main() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    i2c_handle = i2cOpen(1, HTU21D_ADDR, 0); // I2C bus 1, address 0x40, no flags
    if (i2c_handle < 0) {
        fprintf(stderr, "Error opening I2C device: %d\n", i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Register signal handlers for graceful shutdown
    signal(SIGINT, cleanup_handler);
    signal(SIGTERM, cleanup_handler);

    while (running) {
        float temperature = read_temperature();
        float humidity = read_humidity();

        if (temperature > -999.0 && humidity > -999.0) {
            printf("Temperature: %.2f °C, Humidity: %.2f %%\n", temperature, humidity);
        } else {
            fprintf(stderr, "Error reading sensor data\n");
        }

        sleep(5);
    }

    // Cleanup (should not reach here if signal handler works)
    i2cClose(i2c_handle);
    gpioTerminate();

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <unistd.h>
#include <fcntl.h>
#include <sys/ioctl.h>
#include <linux/spi/spidev.h>
#include <time.h>
#include <string.h>
#include <signal.h>

// Define SPI device and channel
#define SPI_DEVICE "/dev/spidev0.0"
#define SPI_CHANNEL 0

// MCP3008 resolution
#define MAX_VOLTAGE 3.3
#define ADC_RESOLUTION 1024.0

// Global flag for signal handling
volatile sig_atomic_t program_running = 1;

// Structure to hold SPI configuration
typedef struct {
    int fd;
    uint8_t mode;
    uint8_t bits;
    uint32_t speed;
} spi_config_t;

// Function prototypes
int spi_setup(spi_config_t *config);
int spi_transfer(int fd, uint8_t channel, uint16_t *adc_value);
float adc_to_voltage(uint16_t adc_value);
void log_data(float voltage);
void signal_handler(int signal);

// Signal handler to gracefully exit the program
void signal_handler(int signal) {
    program_running = 0;
    printf("\nExiting program...\n");
}

// Function to initialize SPI communication
int spi_setup(spi_config_t *config) {
    config->mode = 0;  // SPI mode 0
    config->bits = 8;   // 8 bits per word
    config->speed = 1000000; // 1 MHz

    config->fd = open(SPI_DEVICE, O_RDWR);
    if (config->fd < 0) {
        perror("Error opening SPI device");
        return -1;
    }

    // Set SPI mode
    if (ioctl(config->fd, SPI_IOC_WR_MODE, &config->mode) == -1) {
        perror("Error setting SPI mode");
        close(config->fd);
        return -1;
    }

    // Set bits per word
    if (ioctl(config->fd, SPI_IOC_WR_BITS_PER_WORD, &config->bits) == -1) {
        perror("Error setting bits per word");
        close(config->fd);
        return -1;
    }

    // Set max speed
    if (ioctl(config->fd, SPI_IOC_WR_MAX_SPEED_HZ, &config->speed) == -1) {
        perror("Error setting max speed");
        close(config->fd);
        return -1;
    }

    return 0;
}

// Function to transfer data via SPI
int spi_transfer(int fd, uint8_t channel, uint16_t *adc_value) {
    uint8_t tx_buffer[3];
    uint8_t rx_buffer[3];
    struct spi_ioc_transfer transfer[1];

    // Construct SPI message (MCP3008 single-ended read)
    tx_buffer[0] = 0x01; // Start bit
    tx_buffer[1] = (0x08 | channel) << 4; // Single-ended mode + channel selection
    tx_buffer[2] = 0x00; // Don't care

    memset(transfer, 0, sizeof(transfer));

    transfer[0].tx_buf = (unsigned long)tx_buffer;
    transfer[0].rx_buf = (unsigned long)rx_buffer;
    transfer[0].len = 3;
    transfer[0].speed_hz = 1000000; // 1 MHz
    transfer[0].bits_per_word = 8;

    if (ioctl(fd, SPI_IOC_MESSAGE(1), transfer) < 1) {
        perror("Error during SPI transfer");
        return -1;
    }

    // Extract ADC value from response
    *adc_value = ((rx_buffer[1] & 0x03) << 8) + rx_buffer[2];

    return 0;
}

// Function to convert ADC value to voltage
float adc_to_voltage(uint16_t adc_value) {
    return ((float)adc_value / ADC_RESOLUTION) * MAX_VOLTAGE;
}

// Function to log the voltage data to the console
void log_data(float voltage) {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[20];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);
    printf("[%s] Voltage: %.2f V\n", timestamp, voltage);
}

int main() {
    spi_config_t spi_config;
    uint16_t adc_value;
    float voltage;

    // Register signal handler for graceful shutdown
    signal(SIGINT, signal_handler);

    // Initialize SPI
    if (spi_setup(&spi_config) == -1) {
        return 1;
    }

    printf("Reading data from DFRobot Analog Water Level Sensor...\n");

    while (program_running) {
        // Read data from sensor
        if (spi_transfer(spi_config.fd, SPI_CHANNEL, &adc_value) == 0) {
            // Convert ADC value to voltage
            voltage = adc_to_voltage(adc_value);

            // Log the data
            log_data(voltage);
        } else {
            fprintf(stderr, "Error reading sensor data.\n");
        }

        // Wait for 500ms
        usleep(500000); // 500ms = 500000 microseconds
    }

    // Close SPI device
    close(spi_config.fd);

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <string.h>
#include <time.h>
#include <sys/time.h>
#include <unistd.h>
#include <fcntl.h>
#include <sys/ioctl.h>
#include <linux/spi/spidev.h>
#include <signal.h>
#include <errno.h>

// Configuration
#define SPI_BUS 0
#define SPI_DEVICE 0
#define SPI_MODE SPI_MODE_0
#define SPI_BITS_PER_WORD 8
#define SPI_MAX_SPEED_HZ 1000000 // 1 MHz
#define MCP3008_CHANNEL 0 // Channel connected to MLX91211
#define SLEEP_DURATION_SEC 1

// Global variables
static int spi_fd = -1;
static volatile sig_atomic_t terminate = 0;

// Structure for SPI configuration
typedef struct {
    int bus;
    int device;
    uint8_t mode;
    uint8_t bits_per_word;
    uint32_t max_speed_hz;
} spi_config_t;

// Function prototypes
int spi_setup(spi_config_t config);
int spi_transfer(int spi_fd, uint8_t *tx_buf, uint8_t *rx_buf, int len);
int read_mcp3008(int spi_fd, int channel);
void log_current(int adc_value);
void signal_handler(int sig);

/* Signal handler for graceful shutdown */
void signal_handler(int sig) {
    terminate = 1;
    fprintf(stderr, "\nSignal received, exiting gracefully...\n");
}

/* SPI setup function */
int spi_setup(spi_config_t config) {
    int fd;
    /* Open SPI device */
    if ((fd = open("/dev/spidev0.0", O_RDWR)) < 0) {
        perror("Error opening SPI device");
        return -1;
    }

    /* Set SPI mode */
    if (ioctl(fd, SPI_IOC_WR_MODE, &config.mode) < 0) {
        perror("Error setting SPI mode");
        close(fd);
        return -1;
    }

    /* Set bits per word */
    if (ioctl(fd, SPI_IOC_WR_BITS_PER_WORD, &config.bits_per_word) < 0) {
        perror("Error setting bits per word");
        close(fd);
        return -1;
    }

    /* Set max speed */
    if (ioctl(fd, SPI_IOC_WR_MAX_SPEED_HZ, &config.max_speed_hz) < 0) {
        perror("Error setting max speed");
        close(fd);
        return -1;
    }

    return fd;
}

/* SPI transfer function */
int spi_transfer(int spi_fd, uint8_t *tx_buf, uint8_t *rx_buf, int len) {
    struct spi_ioc_transfer transfer = {
        .tx_buf = (unsigned long)tx_buf,
        .rx_buf = (unsigned long)rx_buf,
        .len = len,
        .speed_hz = SPI_MAX_SPEED_HZ,
        .bits_per_word = SPI_BITS_PER_WORD,
    };

    if (ioctl(spi_fd, SPI_IOC_MESSAGE(1), &transfer) < 0) {
        perror("Error during SPI transfer");
        return -1;
    }
    return 0;
}

/* Read MCP3008 ADC value */
int read_mcp3008(int spi_fd, int channel) {
    uint8_t tx_buf[3];
    uint8_t rx_buf[3];

    /* Construct SPI message */
    tx_buf[0] = 0x01; // Start bit
    tx_buf[1] = (0x08 | channel) << 4; // Single-ended mode, channel selection
    tx_buf[2] = 0x00; // Don't care

    /* Perform SPI transfer */
    if (spi_transfer(spi_fd, tx_buf, rx_buf, 3) < 0) {
        fprintf(stderr, "SPI transfer failed.\n");
        return -1;
    }

    /* Extract ADC value */
    int adc_value = ((rx_buf[1] & 0x03) << 8) + rx_buf[2];
    return adc_value;
}

/* Log current value with timestamp */
void log_current(int adc_value) {
    struct timeval tv;
    struct tm *tm;

    gettimeofday(&tv, NULL);
    tm = localtime(&tv.tv_sec);

    char timestamp[30];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", tm);
    snprintf(timestamp + strlen(timestamp), sizeof(timestamp) - strlen(timestamp), ".%06ld", tv.tv_usec);

    printf("[%s] Current (ADC): %d\n", timestamp, adc_value);
}

int main() {
    spi_config_t spi_config = {
        .bus = SPI_BUS,
        .device = SPI_DEVICE,
        .mode = SPI_MODE,
        .bits_per_word = SPI_BITS_PER_WORD,
        .max_speed_hz = SPI_MAX_SPEED_HZ
    };

    /* Install signal handler */
    signal(SIGINT, signal_handler);

    /* Initialize SPI */
    spi_fd = spi_setup(spi_config);
    if (spi_fd < 0) {
        fprintf(stderr, "SPI initialization failed.\n");
        return EXIT_FAILURE;
    }

    fprintf(stderr, "Monitoring current... Press Ctrl+C to exit.\n");

    /* Main loop */
    while (!terminate) {
        int adc_value = read_mcp3008(spi_fd, MCP3008_CHANNEL);
        if (adc_value >= 0) {
            log_current(adc_value);
        } else {
            fprintf(stderr, "Failed to read current.\n");
        }
        sleep(SLEEP_DURATION_SEC);
    }

    /* Cleanup */
    close(spi_fd);
    fprintf(stderr, "Exited cleanly.\n");
    return EXIT_SUCCESS;
}

#include <stdio.h>
#include <stdint.h>
#include <stdbool.h>
#include <wiringPiI2C.h>
#include <unistd.h>
#include <signal.h>
#include <time.h>
#include <sys/time.h>

// SHT85 I2C address
#define SHT85_ADDR 0x44

// SHT85 commands
#define MEASURE_HIGH_PRECISION 0x2400

// Global variable to control the main loop
volatile sig_atomic_t running = 1;

// I2C file descriptor
int fd;

// Structure to hold sensor data
typedef struct {
    float temperature;
    float humidity;
    struct timeval timestamp;
} sensor_data_t;

// Signal handler for graceful shutdown
void sigint_handler(int signal)
{
    printf("\nCaught signal %d, exiting gracefully.\n", signal);
    running = 0;
}

// Function to initialize the SHT85 sensor
bool init_sht85()
{
    fd = wiringPiI2CSetup(SHT85_ADDR);
    if (fd == -1) {
        fprintf(stderr, "Failed to initialize I2C communication.\n");
        return false;
    }
    printf("I2C communication initialized successfully.\n");
    return true;
}

// Function to trigger a single measurement
bool trigger_measurement()
{
    uint8_t cmd_msb = (MEASURE_HIGH_PRECISION >> 8) & 0xFF;
    uint8_t cmd_lsb = MEASURE_HIGH_PRECISION & 0xFF;
    int result = wiringPiI2CWrite(fd, MEASURE_HIGH_PRECISION); //Sending the combined command
    if (result == -1) {
        fprintf(stderr, "Failed to trigger measurement.\n");
        return false;
    }
    return true;
}

// Function to read temperature and humidity values
bool read_temperature_humidity(float *temperature, float *humidity)
{
    uint16_t raw_temperature, raw_humidity;
    uint8_t data[6];
    int i;

    // Read 6 bytes of data (temperature MSB, temperature LSB, temperature CRC, humidity MSB, humidity LSB, humidity CRC)
    for (i = 0; i < 6; i++) {
        data[i] = wiringPiI2CReadReg8(fd, 0x00);
        if (data[i] == -1) {
            fprintf(stderr, "Failed to read data from sensor.\n");
            return false;
        }
    }

    raw_temperature = (data[0] << 8) | data[1];
    raw_humidity = (data[3] << 8) | data[4];

    *temperature = -45.0 + (175.0 * raw_temperature / 65535.0);
    *humidity = -6.0 + (125.0 * raw_humidity / 65535.0);

    return true;
}

// Function to log sensor data to the console
void log_data(const sensor_data_t *data)
{
    char timestamp[30];
    struct tm *tm_info;

    tm_info = localtime(&data->timestamp.tv_sec);
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", tm_info);

    printf("[%s.%06ld] Temperature: %.2f °C, Humidity: %.2f %%\n", timestamp, data->timestamp.tv_usec, data->temperature, data->humidity);
}

int main()
{
    // Set up signal handling for Ctrl+C
    signal(SIGINT, sigint_handler);

    // Initialize wiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "Failed to initialize WiringPi.\n");
        return 1;
    }

    // Initialize the SHT85 sensor
    if (!init_sht85()) {
        return 1;
    }

    // Main loop
    while (running) {
        float temperature, humidity;
        sensor_data_t sensor_data;
        int retries = 3;
        bool read_success = false;

        // Retry mechanism for I2C communication
        while (retries > 0 && !read_success) {
            if (trigger_measurement()) {
                // Wait for the measurement to complete (datasheet specifies typical 4-15ms, worst case 50ms)
                usleep(50000); // Wait 50ms

                if (read_temperature_humidity(&temperature, &humidity)) {
                    gettimeofday(&sensor_data.timestamp, NULL);
                    sensor_data.temperature = temperature;
                    sensor_data.humidity = humidity;
                    log_data(&sensor_data);
                    read_success = true;
                } else {
                    fprintf(stderr, "Failed to read sensor data, retrying... (%d retries left)\n", retries - 1);
                    usleep(10000); // Wait 10ms before retrying
                }
            } else {
                fprintf(stderr, "Failed to trigger measurement, retrying... (%d retries left)\n", retries - 1);
                usleep(10000); // Wait 10ms before retrying
            }
            retries--;
        }

        if (!read_success) {
            fprintf(stderr, "Failed to read sensor data after multiple retries.\n");
        }

        sleep(5); // Wait 5 seconds
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <fcntl.h>
#include <unistd.h>
#include <sys/ioctl.h>
#include <linux/i2c-dev.h>
#include <time.h>
#include <signal.h>

// Define sensor-specific constants
#define I2C_ADDR 0x49 // Example I2C address, check datasheet
#define RAW_DATA_MAX 14745 // Maximum raw sensor output
#define FLOW_RATE_MAX 200.0 // Maximum flow rate (LPM)

// Global variable for program termination
volatile sig_atomic_t terminate = 0;

// Signal handler for graceful shutdown
void sigint_handler(int sig){
    terminate = 1;
    printf("\nExiting gracefully...\n");
}

// Function to initialize the I2C bus
int i2c_setup(const char *device) {
    int fd = open(device, O_RDWR);
    if (fd < 0) {
        perror("Failed to open I2C device");
        return -1;
    }
    if (ioctl(fd, I2C_SLAVE, I2C_ADDR) < 0) {
        perror("Failed to acquire bus access and/or talk to slave.");
        close(fd);
        return -1;
    }
    return fd;
}

// Function to read raw data from the sensor
int16_t read_raw_data(int fd) {
    uint8_t buffer[2];
    if (read(fd, buffer, 2) != 2) {
        perror("Failed to read from I2C device");
        return -1;
    }
    return (int16_t)((buffer[0] << 8) | buffer[1]);
}

// Function to calculate the flow rate from the raw data (linear conversion)
float calculate_flow_rate(int16_t raw_data) {
    // Scale raw data to flow rate (linear approximation)
    return ((float)raw_data / RAW_DATA_MAX) * FLOW_RATE_MAX;
}

// Function to log data to the console
void log_data(int16_t raw_data, float flow_rate) {
    time_t now = time(NULL);
    struct tm *tstruct = localtime(&now);
    char buf[80];
    strftime(buf, sizeof(buf), "%Y-%m-%d.%X", tstruct);

    printf("%s, Raw Data: %d, Flow Rate: %.2f LPM\n", buf, raw_data, flow_rate);
}

int main() {
    int fd;
    int16_t raw_data;
    float flow_rate;

    // Install signal handler for Ctrl+C
    signal(SIGINT, sigint_handler);

    // Initialize I2C communication
    fd = i2c_setup("/dev/i2c-1");
    if (fd < 0) {
        return 1;
    }

    // Main loop
    while (!terminate) {
        // Read raw data from the sensor
        raw_data = read_raw_data(fd);
        if (raw_data < 0) {
            fprintf(stderr, "Error reading sensor data. Retrying...");
            sleep(1); // Wait before retrying
            continue;  // Skip to the next iteration
        }

        // Calculate flow rate
        flow_rate = calculate_flow_rate(raw_data);

        // Log the data
        log_data(raw_data, flow_rate);

        // Wait for 500ms
        usleep(500000);
    }

    // Close I2C device
    close(fd);

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <time.h>
#include <signal.h>

#define TRIG_PIN 17
#define ECHO_PIN 18

volatile static int pulse_start = 0;
volatile static int pulse_end = 0;
volatile static int pulse_width = 0;

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("\nShutting down gracefully...\n");
    gpioTerminate();
    exit(0);
}

// Alert function to measure pulse width
void alert(int gpio, int level, uint32_t tick) {
    if (gpio == ECHO_PIN) {
        if (level == 1) {
            pulse_start = tick;
        } else if (level == 0) {
            pulse_end = tick;
            pulse_width = pulse_end - pulse_start;
        }
    }
}

// Function to trigger the sensor and measure distance
float getDistance() {
    // Trigger the sensor
    gpioWrite(TRIG_PIN, 1);
    gpioDelay(10);
    gpioWrite(TRIG_PIN, 0);

    pulse_start = 0; // Reset pulse start time
    pulse_end = 0;   // Reset pulse end time
    pulse_width = 0;

    // Wait for echo or timeout
    int timeout_count = 0;
    while (pulse_width == 0 && timeout_count < 1000) {
        gpioDelay(1); // Delay 1 microsecond
        timeout_count++;
    }

    if (pulse_width == 0) {
        fprintf(stderr, "Error: Timeout waiting for echo.\n");
        return -1.0; // Indicate timeout error
    }

    // Calculate distance in centimeters
    float distance = pulse_width * 0.0343 / 2;
    return distance;
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO modes
    gpioSetMode(TRIG_PIN, PI_OUTPUT);
    gpioSetMode(ECHO_PIN, PI_INPUT);

    // Set alert function for ECHO pin
    gpioSetAlertFuncEx(ECHO_PIN, alert, NULL);

    // Set up signal handling
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Main loop
    while (1) {
        float distance = getDistance();

        if (distance < 0) {
            fprintf(stderr, "Error: Failed to read distance.\n");
        } else {
            // Get current timestamp
            time_t t = time(NULL);
            struct tm tm = *localtime(&t);
            printf("%d-%02d-%02d %02d:%02d:%02d Distance: %.2f cm\n", tm.tm_year + 1900, tm.tm_mon + 1, tm.tm_mday, tm.tm_hour, tm.tm_min, tm.tm_sec, distance);
        }

        time_sleep(1.0); // Delay for 1 second
    }

    return 0; // This line will never be reached due to the infinite loop, but it's good practice to include it.
}

#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <unistd.h>
#include <pigpio.h>
#include <stdint.h>

// I2C address of the IIS2DLPC accelerometer
#define I2C_ADDR 0x19

// Register addresses
#define WHO_AM_I 0x0F
#define CTRL1_REG 0x10
#define OUT_X_L 0x28
#define OUT_X_H 0x29
#define OUT_Y_L 0x2A
#define OUT_Y_H 0x2B
#define OUT_Z_L 0x2C
#define OUT_Z_H 0x2D

// Sensitivity factor for +/- 2g range (0.061 mg/LSB)
#define SENSITIVITY 0.000061f

// Global variable for the I2C handle
int i2c_handle;

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("\nCaught signal %d, cleaning up...\n", signal);
    if (i2c_handle >= 0) {
        i2cClose(i2c_handle);
    }
    gpioTerminate();
    exit(0);
}

// Function to read a register from the IIS2DLPC
int read_register(int reg_addr) {
    int result;
    result = i2cReadByteData(i2c_handle, reg_addr);
    if (result < 0) {
        fprintf(stderr, "Error reading register 0x%02X: %d\n", reg_addr, result);
        return -1; // Indicate an error
    }
    return result;
}

// Function to write a register to the IIS2DLPC
int write_register(int reg_addr, int value) {
    int result;
    result = i2cWriteByteData(i2c_handle, reg_addr, value);
    if (result < 0) {
        fprintf(stderr, "Error writing register 0x%02X with value 0x%02X: %d\n", reg_addr, value, result);
        return -1; // Indicate an error
    }
    return 0; // Indicate success
}

// Function to read acceleration data from the IIS2DLPC
int read_acceleration(float *x, float *y, float *z) {
    char buffer[6];
    int result;

    result = i2cReadI2CBlockData(i2c_handle, OUT_X_L, buffer, 6);
    if (result < 0) {
        fprintf(stderr, "Error reading acceleration data: %d\n", result);
        return -1; // Indicate an error
    }

    // Combine the low and high bytes to form signed 16-bit integers
    int16_t raw_x = (int16_t)((buffer[1] << 8) | buffer[0]);
    int16_t raw_y = (int16_t)((buffer[3] << 8) | buffer[2]);
    int16_t raw_z = (int16_t)((buffer[5] << 8) | buffer[4]);

    // Scale the raw values to g-force units
    *x = (float)raw_x * SENSITIVITY;
    *y = (float)raw_y * SENSITIVITY;
    *z = (float)raw_z * SENSITIVITY;

    return 0; // Indicate success
}

int main() {
    // Initialize the pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Open the I2C device
    i2c_handle = i2cOpen(1, I2C_ADDR, 0); // Bus 1, address 0x19, no flags
    if (i2c_handle < 0) {
        fprintf(stderr, "Error opening I2C device: %d\n", i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Verify the sensor's presence by reading the WHO_AM_I register
    int who_am_i = read_register(WHO_AM_I);
    if (who_am_i < 0 || who_am_i != 0x41) {
        fprintf(stderr, "Error: Invalid WHO_AM_I value: 0x%02X\n", who_am_i);
        i2cClose(i2c_handle);
        gpioTerminate();
        return 1;
    }
    printf("WHO_AM_I register value: 0x%02X\n", who_am_i);

    // Set the data rate to 100 Hz and enable the accelerometer
    if (write_register(CTRL1_REG, 0x64) < 0) {
        i2cClose(i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Set up signal handling for Ctrl+C
    signal(SIGINT, signal_handler);

    // Main loop
    float x, y, z;
    while (1) {
        if (read_acceleration(&x, &y, &z) == 0) {
