#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <unistd.h>
#include <fcntl.h>
#include <sys/ioctl.h>
#include <linux/spi/spidev.h>
#include <time.h>
#include <signal.h>
#include <string.h>

// Configuration
#define SPI_DEVICE "/dev/spidev0.0"
#define SPI_MODE SPI_MODE_0
#define SPI_BITS_PER_WORD 8
#define SPI_SPEED 1000000 // 1 MHz
#define MCP3008_CHANNEL 0 // Connected to channel 0
#define READ_INTERVAL_SEC 5

// Global Variables
static int spi_fd; // SPI file descriptor
static volatile sig_atomic_t keep_running = 1;

// Structure to hold configuration parameters
typedef struct {
    char spi_device[20];
    uint8_t spi_mode;
    uint8_t spi_bits_per_word;
    uint32_t spi_speed;
    uint8_t mcp3008_channel;
    int read_interval_sec;
} config_t;

// Function Prototypes
int spi_init(const char *device, uint8_t mode, uint8_t bits, uint32_t speed);
int read_mcp3008(int channel);
void log_data(int moisture_level);
void signal_handler(int signal);
void cleanup();

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    keep_running = 0;
    printf("\nCaught signal %d, exiting...\n", signal);
}

// Initialize SPI
int spi_init(const char *device, uint8_t mode, uint8_t bits, uint32_t speed) {
    int fd;

    if ((fd = open(device, O_RDWR)) < 0) {
        perror("Error opening SPI device");
        return -1;
    }

    if (ioctl(fd, SPI_IOC_WR_MODE, &mode) < 0) {
        perror("Error setting SPI mode");
        close(fd);
        return -1;
    }

    if (ioctl(fd, SPI_IOC_WR_BITS_PER_WORD, &bits) < 0) {
        perror("Error setting SPI bits per word");
        close(fd);
        return -1;
    }

    if (ioctl(fd, SPI_IOC_WR_MAX_SPEED_HZ, &speed) < 0) {
        perror("Error setting SPI speed");
        close(fd);
        return -1;
    }

    return fd;
}

// Read from MCP3008 ADC
int read_mcp3008(int channel) {
    uint8_t tx_buf[3];
    uint8_t rx_buf[3];
    struct spi_ioc_transfer transfer[1];

    // Construct SPI message (MCP3008 single-ended read)
    tx_buf[0] = 0x01; // Start bit
    tx_buf[1] = (0x08 | channel) << 4; // Single-ended, channel selection
    tx_buf[2] = 0x00; // Don't care

    memset(transfer, 0, sizeof(transfer));

    transfer[0].tx_buf = (unsigned long)tx_buf;
    transfer[0].rx_buf = (unsigned long)rx_buf;
    transfer[0].len = 3;
    transfer[0].delay_usecs = 0;
    transfer[0].speed_hz = SPI_SPEED;
    transfer[0].bits_per_word = SPI_BITS_PER_WORD;

    if (ioctl(spi_fd, SPI_IOC_MESSAGE(1), transfer) < 0) {
        perror("Error sending SPI message");
        return -1;
    }

    // Extract ADC value (10 bits)
    int adc_value = ((rx_buf[1] & 0x03) << 8) + rx_buf[2];

    return adc_value;
}

// Log data to console
void log_data(int moisture_level) {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[20];

    time(&rawtime);
    timeinfo = localtime(&rawtime);
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    printf("[%s] Moisture Level: %d\n", timestamp, moisture_level);
}

// Cleanup resources
void cleanup() {
    if (spi_fd >= 0) {
        close(spi_fd);
    }
    printf("Cleanup complete.\n");
}

int main() {
    config_t config = {
        .spi_device = SPI_DEVICE,
        .spi_mode = SPI_MODE,
        .spi_bits_per_word = SPI_BITS_PER_WORD,
        .spi_speed = SPI_SPEED,
        .mcp3008_channel = MCP3008_CHANNEL,
        .read_interval_sec = READ_INTERVAL_SEC
    };

    // Register signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Initialize SPI
    spi_fd = spi_init(config.spi_device, config.spi_mode, config.spi_bits_per_word, config.spi_speed);
    if (spi_fd < 0) {
        fprintf(stderr, "SPI initialization failed. Exiting.\n");
        return 1;
    }

    printf("Soil Moisture Sensor Data Logger\n");

    // Main loop
    while (keep_running) {
        int moisture_level = read_mcp3008(config.mcp3008_channel);
        if (moisture_level >= 0) {
            log_data(moisture_level);
        } else {
            fprintf(stderr, "Failed to read moisture level. Retrying in %d seconds.\n", config.read_interval_sec);
        }
        sleep(config.read_interval_sec);
    }

    // Cleanup and exit
    cleanup();
    return 0;
}

