#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <fcntl.h>
#include <unistd.h>
#include <errno.h>
#include <signal.h>

// Define GPIO pin number
#define GPIO_PIN 17

// Define paths for sysfs GPIO control
#define GPIO_EXPORT_PATH "/sys/class/gpio/export"
#define GPIO_UNEXPORT_PATH "/sys/class/gpio/unexport"
#define GPIO_DIRECTION_PATH "/sys/class/gpio/gpio%d/direction"
#define GPIO_VALUE_PATH "/sys/class/gpio/gpio%d/value"

// Structure to hold GPIO configuration
typedef struct {
    int gpio_pin;
    char gpio_dir_path[64];
    char gpio_value_path[64];
} gpio_config_t;

// Global variable to indicate program termination
volatile sig_atomic_t program_running = 1;

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    (void)signal; // Suppress unused parameter warning
    program_running = 0;
    printf("\nExiting gracefully...\n");
}

// Function to export the GPIO pin
int export_gpio(int pin) {
    int fd;
    char buf[64];

    fd = open(GPIO_EXPORT_PATH, O_WRONLY);
    if (fd < 0) {
        perror("Failed to open GPIO export file");
        return -1;
    }

    snprintf(buf, sizeof(buf), "%d", pin);
    if (write(fd, buf, strlen(buf)) < 0) {
        perror("Failed to write GPIO export value");
        close(fd);
        return -1;
    }

    close(fd);
    return 0;
}

// Function to unexport the GPIO pin
int unexport_gpio(int pin) {
    int fd;
    char buf[64];

    fd = open(GPIO_UNEXPORT_PATH, O_WRONLY);
    if (fd < 0) {
        perror("Failed to open GPIO unexport file");
        return -1;
    }

    snprintf(buf, sizeof(buf), "%d", pin);
    if (write(fd, buf, strlen(buf)) < 0) {
        perror("Failed to write GPIO unexport value");
        close(fd);
        return -1;
    }

    close(fd);
    return 0;
}

// Function to set the GPIO direction (in/out)
int set_gpio_direction(int pin, const char *direction) {
    int fd;
    char path[64];

    snprintf(path, sizeof(path), GPIO_DIRECTION_PATH, pin);
    fd = open(path, O_WRONLY);
    if (fd < 0) {
        perror("Failed to open GPIO direction file");
        return -1;
    }

    if (write(fd, direction, strlen(direction)) < 0) {
        perror("Failed to write GPIO direction value");
        close(fd);
        return -1;
    }

    close(fd);
    return 0;
}

// Function to read the GPIO value
int read_gpio_value(int pin) {
    int fd;
    char path[64];
    char value_str[3];

    snprintf(path, sizeof(path), GPIO_VALUE_PATH, pin);
    fd = open(path, O_RDONLY);
    if (fd < 0) {
        perror("Failed to open GPIO value file");
        return -1;
    }

    if (read(fd, value_str, 3) < 0) {
        perror("Failed to read GPIO value");
        close(fd);
        return -1;
    }

    close(fd);
    return atoi(value_str);
}

int main() {
    gpio_config_t gpio_config;
    gpio_config.gpio_pin = GPIO_PIN;
    snprintf(gpio_config.gpio_dir_path, sizeof(gpio_config.gpio_dir_path), GPIO_DIRECTION_PATH, gpio_config.gpio_pin);
    snprintf(gpio_config.gpio_value_path, sizeof(gpio_config.gpio_value_path), GPIO_VALUE_PATH, gpio_config.gpio_pin);

    // Install signal handler
    signal(SIGINT, signal_handler);

    // Export the GPIO pin
    if (export_gpio(gpio_config.gpio_pin) < 0) {
        fprintf(stderr, "Failed to export GPIO %d\n", gpio_config.gpio_pin);
        return 1;
    }

    // Set GPIO direction to input
    if (set_gpio_direction(gpio_config.gpio_pin, "in") < 0) {
        fprintf(stderr, "Failed to set GPIO %d direction to input\n", gpio_config.gpio_pin);
        unexport_gpio(gpio_config.gpio_pin);
        return 1;
    }

    // Main loop to read and log the sensor value
    printf("Reading touch sensor data (press Ctrl+C to exit)...\n");
    while (program_running) {
        int value = read_gpio_value(gpio_config.gpio_pin);
        if (value < 0) {
            fprintf(stderr, "Failed to read GPIO %d value\n", gpio_config.gpio_pin);
        } else {
            printf("Touch sensor value: %d\n", value);
        }
        usleep(100000); // 100ms
    }

    // Unexport the GPIO pin before exiting
    if (unexport_gpio(gpio_config.gpio_pin) < 0) {
        fprintf(stderr, "Failed to unexport GPIO %d\n", gpio_config.gpio_pin);
    }

    return 0;
}

