// Register addresses
#define PROM_START_ADDR 0x10
#define CMD_MEASURE 0xBE
#define PRES_MSB_REG 0x00
#define TEMP_MSB_REG 0x03

// Calibration data
struct calibration_data {
    uint16_t sens_t1_msb;
    uint16_t sens_t0_msb;
    uint32_t pres_ref_t1_lsb;
};

static volatile int running = 1;
static int i2c_handle;
struct calibration_data cal_data;

// Signal handler for graceful shutdown
void signal_handler(int signum) {
    running = 0;
    printf("\nCaught signal %d, exiting gracefully...\n", signum);
}

// Function to read calibration data from the sensor's PROM
int read_calibration_data(int i2c_handle, struct calibration_data *cal_data) {
    char buf[8];
    int result;

    // Read 8 bytes of calibration data from PROM starting at address 0x10
    result = i2cReadI2CBlockData(i2c_handle, PROM_START_ADDR, buf, 8);
    if (result < 0) {
        perror("Error reading calibration data");
        return -1;
    }

    // Extract calibration values from the buffer
    cal_data->sens_t1_msb = (buf[0] << 8) | buf[1];
    cal_data->sens_t0_msb = (buf[2] << 8) | buf[3];
    cal_data->pres_ref_t1_lsb = ((uint32_t)buf[4] << 16) | (buf[5] << 8) | buf[6];

    return 0;
}


// Function to read pressure and temperature from the sensor
int read_icp10110(int i2c_handle, float *pressure, float *temperature) {
    char buf[6];
    int result;
    uint32_t raw_pressure, raw_temperature;

    // Initiate measurement sequence (Forced Mode)
    result = i2cWriteByte(i2c_handle, CMD_MEASURE);  // Send measurement command
    if (result < 0) {
        perror("Error writing measurement command");
        return -1;
    }

    // Wait for measurement to complete (adjust delay as needed based on datasheet)
    time_sleep(0.01); // 10ms delay.  Increase if needed.

    // Read pressure and temperature data
    result = i2cReadI2CBlockData(i2c_handle, PRES_MSB_REG, buf, 6);
    if (result < 0) {
        perror("Error reading pressure and temperature data");
        return -1;
    }

    // Combine the bytes to form the raw pressure and temperature values
    raw_pressure = ((uint32_t)buf[0] << 16) | ((uint32_t)buf[1] << 8) | (uint32_t)buf[2];
    raw_temperature = ((uint32_t)buf[3] << 16) | ((uint32_t)buf[4] << 8) | (uint32_t)buf[5];
    raw_pressure >>= 8; // Shift right by 8 bits
    raw_temperature >>= 8; // Shift right by 8 bits

    // Convert raw data to physical units (replace with actual conversion formulas from the datasheet)
    *pressure = (float)raw_pressure;  // Placeholder conversion
    *temperature = (float)raw_temperature; // Placeholder conversion

    return 0;
}

int main() {
    float pressure, temperature;
    int retries = 3; // Limit re-initialization attempts

    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Register signal handler for graceful shutdown
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Open I2C connection
    i2c_handle = i2cOpen(1, ICP10110_ADDR, 0); // Bus 1, address 0x69, no flags
    if (i2c_handle < 0) {
        perror("Error opening I2C device");
        gpioTerminate();
        return 1;
    }

    // Read calibration data
    if (read_calibration_data(i2c_handle, &cal_data) != 0) {
        fprintf(stderr, "Failed to read calibration data. Exiting.\n");
        i2cClose(i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Main loop
    while (running) {
        if (read_icp10110(i2c_handle, &pressure, &temperature) == 0) {
            // Basic sanity checks
            if (pressure > 800 && pressure < 1200 && temperature > -50 && temperature < 100) {
                printf("Pressure: %.2f, Temperature: %.2f\n", pressure, temperature);
            } else {
                fprintf(stderr, "Sensor data out of range: Pressure=%.2f, Temperature=%.2f\n", pressure, temperature);
            }
        } else {
            fprintf(stderr, "Error reading sensor data. Retrying...\n");
            i2cClose(i2c_handle);
            gpioTerminate();
            if (retries > 0) {
                fprintf(stderr, "Attempting to re-initialize I2C...\n");
                gpioInitialise();
                i2c_handle = i2cOpen(1, ICP10110_ADDR, 0);
                if (i2c_handle < 0) {
                    perror("Error re-opening I2C device");
                    running = 0; // Stop the loop if re-initialization fails
                } else {
                    if (read_calibration_data(i2c_handle, &cal_data) != 0) {
                        fprintf(stderr, "Failed to read calibration data after re-init. Exiting.\n");
                        i2cClose(i2c_handle);
                        gpioTerminate();
                        return 1;
                    }

                }
                retries--;
            } else {
                fprintf(stderr, "Max retries reached. Exiting.\n");
                running = 0;
            }


        }
        time_sleep(5.0);
    }

    // Cleanup
    i2cClose(i2c_handle);
    gpioTerminate();
    printf("Program terminated.\n");

    return 0;
}

#include <stdio.h>
