// MPU-6050 I2C address
#define MPU6050_ADDR 0x68

// MPU-6050 registers
#define PWR_MGMT_1   0x6B
#define ACCEL_XOUT_H 0x3B
#define GYRO_XOUT_H  0x43

int i2c_handle;

// Signal handler for Ctrl+C
void signal_handler(int signal)
{
    printf("Ctrl+C pressed. Exiting.\n");
    if (i2c_handle >= 0) {
        i2cClose(i2c_handle);
    }
    gpioTerminate();
    exit(0);
}

int main()
{
    int status;
    char buffer[14];
    int16_t acc_x, acc_y, acc_z, gyro_x, gyro_y, gyro_z;

    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Open I2C device
    i2c_handle = i2cOpen(1, MPU6050_ADDR, 0); // Bus 1, address 0x68, flags 0
    if (i2c_handle < 0) {
        fprintf(stderr, "Error opening I2C device: %d\n", i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Wake up the MPU-6050 (set PWR_MGMT_1 to 0)
    status = i2cWriteByteData(i2c_handle, PWR_MGMT_1, 0);
    if (status < 0) {
        fprintf(stderr, "Error writing to PWR_MGMT_1: %d\n", status);
        i2cClose(i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Register signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Continuously read and print data
    while (1) {
        // Read accelerometer and gyroscope data
        status = i2cReadI2CBlockData(i2c_handle, ACCEL_XOUT_H, buffer, 14);
        if (status < 0) {
            fprintf(stderr, "Error reading data: %d\n", status);
            i2cClose(i2c_handle);
            gpioTerminate();
            return 1;
        }

        // Combine high and low bytes for accelerometer
        acc_x = (buffer[0] << 8) | buffer[1];
        acc_y = (buffer[2] << 8) | buffer[3];
        acc_z = (buffer[4] << 8) | buffer[5];

        // Combine high and low bytes for gyroscope
        gyro_x = (buffer[8] << 8) | buffer[9];
        gyro_y = (buffer[10] << 8) | buffer[11];
        gyro_z = (buffer[12] << 8) | buffer[13];

        // Print the data to the console
        printf("%d,%d,%d,%d,%d,%d\n", acc_x, acc_y, acc_z, gyro_x, gyro_y, gyro_z);

        // Wait 250 milliseconds
        usleep(250000);
    }

    return 0;
}

