// Function to initialize the pigpio library and I2C
int initialize() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return -1;
    }

    i2c_handle = i2cOpen(BUS, I2C_ADDR, 0);
    if (i2c_handle < 0) {
        fprintf(stderr, "i2cOpen failed: %s\n", pigpio_error(i2c_handle));
        gpioTerminate();
        return -1;
    }

    return 0;
}

// Function to read flow rate data from the sensor
int read_flow_rate(float *flow_rate) {
    char buffer[DATA_LENGTH];
    int bytes_read = i2cReadI2CBlockData(i2c_handle, 0x00, buffer, DATA_LENGTH);

    if (bytes_read != DATA_LENGTH) {
        fprintf(stderr, "I2C read failed: %s\n", pigpio_error(bytes_read));
        return -1;
    }

    // Combine the two bytes into a 16-bit signed integer
    int16_t raw_data = (buffer[0] << 8) | buffer[1];

    // Convert the raw data to flow rate using the scale factor and zero offset
    *flow_rate = (float)(raw_data - ZERO_OFFSET) / SCALE_FACTOR;

    return 0;
}

// Function to log the flow rate data with a timestamp
void log_data(float flow_rate) {
    time_t now = time(NULL);
    struct tm *t = localtime(&now);
    char timestamp[20];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", t);

    printf("[%s] Flow Rate: %.2f ml/min\n", timestamp, flow_rate);
}

// Function to clean up and exit
void cleanup() {
    i2cClose(i2c_handle);
    gpioTerminate();
}

int main() {
    // Register the signal handler for Ctrl+C
    signal(SIGINT, sigint_handler);

    // Initialize pigpio and I2C
    if (initialize() != 0) {
        return 1;
    }

    struct timespec sleep_time = {2, 0}; // 2 seconds
    float flow_rate;

    // Main loop to periodically read and log data
    while (!terminate) {
        if (read_flow_rate(&flow_rate) == 0) {
            log_data(flow_rate);
        } else {
            fprintf(stderr, "Failed to read flow rate\n");
        }

        nanosleep(&sleep_time, NULL);
    }

    // Clean up and exit
    cleanup();
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <stdbool.h>
#include <unistd.h>
#include <time.h>
#include <wiringPiI2C.h>
#include <errno.h>
#include <string.h>

// LSM6DSL I2C address
#define LSM6DSL_ADDR 0x6A

// LSM6DSL register addresses
#define LSM6DSL_REG_WHO_AM_I 0x0F
#define LSM6DSL_REG_CTRL1_XL 0x10
#define LSM6DSL_REG_CTRL2_G 0x11
#define LSM6DSL_REG_OUTX_L_G 0x22
#define LSM6DSL_REG_OUTX_L_XL 0x28

// Function to handle I2C errors
static inline void handle_i2c_error(int fd, const char *message) {
    fprintf(stderr, "Error: %s (errno: %d, %s)\n", message, errno, strerror(errno));
    if (fd >= 0) {
        close(fd);
    }
    exit(EXIT_FAILURE);
}

// Function to read a single byte from an I2C register
int read_register(int fd, uint8_t reg) {
    int result = wiringPiI2CReadReg8(fd, reg);
    if (result < 0) {
        fprintf(stderr, "Failed to read register 0x%02X: %s\n", reg, strerror(errno));
        return -1; // Indicate failure
    }
    return result;
}

// Function to write a single byte to an I2C register
int write_register(int fd, uint8_t reg, uint8_t value) {
    int result = wiringPiI2CWriteReg8(fd, reg, value);
    if (result < 0) {
        fprintf(stderr, "Failed to write register 0x%02X with value 0x%02X: %s\n", reg, value, strerror(errno));
        return -1; // Indicate failure
    }
    return 0;
}

// Function to read multiple bytes from I2C
int read_multi_bytes(int fd, uint8_t reg, uint8_t *data, int len) {
    for (int i = 0; i < len; i++) {
        int result = read_register(fd, reg + i);
        if (result < 0) {
            return -1; // Indicate failure
        }
        data[i] = (uint8_t)result;
    }
    return 0; // Indicate success
}

// Function to read accelerometer data
int read_accelerometer(int fd, int16_t *x, int16_t *y, int16_t *z) {
    uint8_t buffer[6];
    if (read_multi_bytes(fd, LSM6DSL_REG_OUTX_L_XL, buffer, 6) != 0) {
        return -1;
    }
    *x = (int16_t)((buffer[1] << 8) | buffer[0]);
    *y = (int16_t)((buffer[3] << 8) | buffer[2]);
    *z = (int16_t)((buffer[5] << 8) | buffer[4]);
    return 0;
}

// Function to read gyroscope data
int read_gyroscope(int fd, int16_t *x, int16_t *y, int16_t *z) {
    uint8_t buffer[6];
    if (read_multi_bytes(fd, LSM6DSL_REG_OUTX_L_G, buffer, 6) != 0) {
        return -1;
    }
    *x = (int16_t)((buffer[1] << 8) | buffer[0]);
    *y = (int16_t)((buffer[3] << 8) | buffer[2]);
    *z = (int16_t)((buffer[5] << 8) | buffer[4]);
    return 0;
}

int main() {
    int fd;
    int who_am_i;
    int16_t acc_x, acc_y, acc_z;
    int16_t gyro_x, gyro_y, gyro_z;

    // Initialize wiringPi I2C
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "wiringPiSetup failed\n");
        return EXIT_FAILURE;
    }

    // Open I2C device
    fd = wiringPiI2CSetup(LSM6DSL_ADDR);
    if (fd == -1) {
        handle_i2c_error(fd, "Failed to initialize I2C communication.");
    }

    // Verify sensor ID
    who_am_i = read_register(fd, LSM6DSL_REG_WHO_AM_I);
    if (who_am_i != 0x69) {
        fprintf(stderr, "Incorrect WHO_AM_I value: 0x%02X\n", who_am_i);
        close(fd);
        return EXIT_FAILURE;
    }
    printf("LSM6DSL detected (WHO_AM_I = 0x%02X)\n", who_am_i);

    // Configure accelerometer (e.g., 104 Hz, +-2g)
    if (write_register(fd, LSM6DSL_REG_CTRL1_XL, 0x80) != 0) {
        handle_i2c_error(fd, "Failed to configure accelerometer.");
    }

    // Configure gyroscope (e.g., 104 Hz, 250 dps)
    if (write_register(fd, LSM6DSL_REG_CTRL2_G, 0x80) != 0) {
        handle_i2c_error(fd, "Failed to configure gyroscope.");
    }

    // Main loop
    while (1) {
        // Read accelerometer data
        if (read_accelerometer(fd, &acc_x, &acc_y, &acc_z) == 0) {
            // Read gyroscope data
            if (read_gyroscope(fd, &gyro_x, &gyro_y, &gyro_z) == 0) {
                // Print the sensor data
                printf("Acc: X=%6d, Y=%6d, Z=%6d | Gyro: X=%6d, Y=%6d, Z=%6d\n",
                       acc_x, acc_y, acc_z, gyro_x, gyro_y, gyro_z);
            } else {
                fprintf(stderr, "Failed to read gyroscope data\n");
            }
        } else {
            fprintf(stderr, "Failed to read accelerometer data\n");
        }

        // Wait 100ms
        usleep(100000); // 100ms = 100000 microseconds
    }

    // Close I2C device (this will never be reached in the current loop)
    close(fd);
    return EXIT_SUCCESS;
}

