    if (i2c_handle >= 0) {
        i2cClose(i2c_handle);
    }
    gpioTerminate();
    exit(0);
}

// Function to read the raw data from the OPT4001 sensor
int read_opt4001(uint16_t *raw_data) {
    int result;

    result = i2cReadWordData(i2c_handle, RESULT_REG);
    if (result < 0) {
        fprintf(stderr, "Error reading from I2C: %d\n", result);
        return -1;
    }

    *raw_data = (uint16_t)result;
    return 0;
}

// Function to convert raw data to illuminance in lux
float calculate_illuminance(uint16_t raw_data) {
    // Refer to OPT4001 datasheet for conversion formula
    // This is a simplified example, refer to the datasheet for accurate conversion
    float lux = (float)raw_data * 0.01; // Example conversion
    return lux;
}

// Function to get the current timestamp in the format YYYY-MM-DD HH:MM:SS
void get_timestamp(char *timestamp) {
    struct timeval tv;
    time_t rawtime;
    struct tm *timeinfo;

    gettimeofday(&tv, NULL);
    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, 20, "%Y-%m-%d %H:%M:%S", timeinfo);
}

