        fprintf(stderr, "Error opening I2C: %d\n", i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Set up signal handlers for graceful shutdown
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    uint16_t raw_data;
    float illuminance;
    char timestamp[20];

    while (1) {
        if (read_opt4001(&raw_data) == 0) {
            illuminance = calculate_illuminance(raw_data);
            get_timestamp(timestamp);
