#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <pigpio.h>
#include <signal.h>
#include <unistd.h>

// Define the I2C address of the SHT31-D sensor
#define SHT31_ADDR 0x44

// Define the command for single shot measurement with high repeatability
#define SHT31_MEASURE_CMD 0x2C06

// Define the CRC-8 polynomial and initial value
#define CRC8_POLYNOMIAL 0x31
#define CRC8_INITIAL 0xFF

// Global variable to store the I2C handle
int i2c_handle;

// Function prototypes
unsigned char crc8(const unsigned char *data, int len);
void signal_handler(int signal);
int read_sht31(float *temperature, float *humidity);

// Structure for holding sensor data
typedef struct {
    float temperature;
    float humidity;
} sensor_data_t;

// Flag to control the main loop
volatile sig_atomic_t running = 1;

// Signal handler function
void signal_handler(int signal) {
    printf("Caught signal %d, exiting gracefully...\n", signal);
    running = 0;
}

// CRC-8 calculation function
unsigned char crc8(const unsigned char *data, int len) {
    unsigned char crc = CRC8_INITIAL;
    for (int i = 0; i < len; i++) {
        crc ^= data[i];
        for (int j = 0; j < 8; j++) {
            if (crc & 0x80) {
                crc = (crc << 1) ^ CRC8_POLYNOMIAL;
            } else {
                crc <<= 1;
            }
        }
    }
    return crc;
}

// Function to read temperature and humidity from the SHT31-D sensor
int read_sht31(float *temperature, float *humidity) {
    unsigned char write_data[2] = {(SHT31_MEASURE_CMD >> 8) & 0xFF, SHT31_MEASURE_CMD & 0xFF};
    unsigned char read_data[6];
    int result;

    // Send the measurement command
    result = i2cWriteDevice(i2c_handle, (char *)write_data, 2);
    if (result != 0) {
        fprintf(stderr, "Error writing to I2C device: %d\n", result);
        return -1;
    }

    // Wait for at least 10 milliseconds
    gpioDelay(10000);

    // Read the 6 bytes of data
    result = i2cReadDevice(i2c_handle, (char *)read_data, 6);
    if (result != 0) {
        fprintf(stderr, "Error reading from I2C device: %d\n", result);
        return -1;
    }

    // Validate CRC for temperature
    unsigned char temp_crc = crc8(read_data, 2);
    if (temp_crc != read_data[2]) {
        fprintf(stderr, "Temperature CRC check failed!\n");
        return -1;
    }

    // Validate CRC for humidity
    unsigned char hum_crc = crc8(read_data + 3, 2);
    if (hum_crc != read_data[5]) {
        fprintf(stderr, "Humidity CRC check failed!\n");
        return -1;
    }

    // Convert the raw data to temperature and humidity
    uint16_t raw_temperature = (read_data[0] << 8) | read_data[1];
    uint16_t raw_humidity = (read_data[3] << 8) | read_data[4];

    *temperature = -45.0 + (175.0 * raw_temperature / 65535.0);
    *humidity = 100.0 * raw_humidity / 65535.0;

    return 0;
}

int main() {
    // Initialize the pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Open the I2C device
    i2c_handle = i2cOpen(1, SHT31_ADDR, 0); // Bus 1, address 0x44, no flags
    if (i2c_handle < 0) {
        fprintf(stderr, "Error opening I2C device: %d\n", i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Set up signal handling for graceful termination
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Main loop
    sensor_data_t sensor_data;
    while (running) {
        // Read temperature and humidity
        if (read_sht31(&sensor_data.temperature, &sensor_data.humidity) == 0) {
            // Log the data to the console
            printf("Temperature: %.2f C, Humidity: %.2f %%\n", sensor_data.temperature, sensor_data.humidity);
        } else {
            fprintf(stderr, "Failed to read sensor data.\n");
        }

        // Wait for 5 seconds
        gpioDelay(5000000);
    }

    // Close the I2C device
    i2cClose(i2c_handle);

    // Terminate the pigpio library
    gpioTerminate();

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
#include <time.h>
#include <signal.h>
#include <unistd.h>

// Define GPIO pins for the 8 channels
#define CHANNEL_1 0
#define CHANNEL_2 1
#define CHANNEL_3 2
#define CHANNEL_4 3
#define CHANNEL_5 4
#define CHANNEL_6 5
#define CHANNEL_7 6
#define CHANNEL_8 7

// Structure to hold sensor data
typedef struct {
    int channel[8];
} SensorData;

// Global variable to control the main loop
volatile sig_atomic_t running = 1;

// Signal handler for graceful shutdown
void sigint_handler(int signal) {
    running = 0;
    printf("\nExiting gracefully...\n");
}

// Function to read sensor data
SensorData read_sensor() {
    SensorData data;
    data.channel[0] = digitalRead(CHANNEL_1);
    data.channel[1] = digitalRead(CHANNEL_2);
    data.channel[2] = digitalRead(CHANNEL_3);
    data.channel[3] = digitalRead(CHANNEL_4);
    data.channel[4] = digitalRead(CHANNEL_5);
    data.channel[5] = digitalRead(CHANNEL_6);
    data.channel[6] = digitalRead(CHANNEL_7);
    data.channel[7] = digitalRead(CHANNEL_8);
    return data;
}

// Function to log sensor data to the console
void log_data(SensorData data) {
    time_t rawtime;
    struct tm * timeinfo;

    time (&rawtime);
    timeinfo = localtime (&rawtime);

    printf("[%s] ", asctime(timeinfo));
    printf("Channel 1: %d, Channel 2: %d, Channel 3: %d, Channel 4: %d, ", data.channel[0], data.channel[1], data.channel[2], data.channel[3]);
    printf("Channel 5: %d, Channel 6: %d, Channel 7: %d, Channel 8: %d\n", data.channel[4], data.channel[5], data.channel[6], data.channel[7]);
}

int main(void) {
    // Setup signal handler
    signal(SIGINT, sigint_handler);

    // Initialize wiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "Failed to initialize wiringPi!\n");
        return 1;
    }

    // Set GPIO pins as input
    pinMode(CHANNEL_1, INPUT);
    pinMode(CHANNEL_2, INPUT);
    pinMode(CHANNEL_3, INPUT);
    pinMode(CHANNEL_4, INPUT);
    pinMode(CHANNEL_5, INPUT);
    pinMode(CHANNEL_6, INPUT);
    pinMode(CHANNEL_7, INPUT);
    pinMode(CHANNEL_8, INPUT);

    printf("TTP226 Sensor Logger started. Press Ctrl+C to exit.\n");

    // Main loop
    while (running) {
        SensorData data = read_sensor();
        log_data(data);
        delay(500); // Log data every 500ms
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <unistd.h>
#include <pigpio.h>

// I2C defines
#define I2C_BUS 1
#define I2C_ADDR 0x6A // Or 0x6B if SA0 is high

// ISM330DLC register defines
#define CTRL1_XL 0x10
#define CTRL2_G 0x11
#define CTRL3_C 0x12
#define OUTX_L_XL 0x28
#define OUTX_H_XL 0x29
#define OUTY_L_XL 0x2A
#define OUTY_H_XL 0x2B
#define OUTZ_L_XL 0x2C
#define OUTZ_H_XL 0x2D
#define OUTX_L_G 0x22
#define OUTX_H_G 0x23
#define OUTY_L_G 0x24
#define OUTY_H_G 0x25
#define OUTZ_L_G 0x26
#define OUTZ_H_G 0x27

int i2c_handle;

// Signal handler for Ctrl+C
void signal_handler(int signal) {
    printf("\nCtrl+C pressed. Exiting...\n");
    i2cClose(i2c_handle);
    gpioTerminate();
    exit(0);
}

// Function to handle I2C errors
int handle_i2c_error(int status, const char *message, int reg) {
    fprintf(stderr, "I2C Error: %s (reg 0x%02X, status %d)\n", message, reg, status);
    return -1; // Indicate failure
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Register signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Open I2C connection
    i2c_handle = i2cOpen(I2C_BUS, I2C_ADDR, 0);
    if (i2c_handle < 0) {
        fprintf(stderr, "Failed to open I2C device: %d\n", i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Configure ISM330DLC
    int status;

    // Set accelerometer data rate and full scale
    status = i2cWriteByteData(i2c_handle, CTRL1_XL, 0x80); // 104 Hz, ±2g
    if (status < 0) {
        if (handle_i2c_error(status, "Failed to write CTRL1_XL", CTRL1_XL) < 0) {
            i2cClose(i2c_handle);
            gpioTerminate();
            return 1;
        }
    }

    // Set gyroscope data rate and full scale
    status = i2cWriteByteData(i2c_handle, CTRL2_G, 0x80); // 104 Hz, ±250 dps
    if (status < 0) {
        if (handle_i2c_error(status, "Failed to write CTRL2_G", CTRL2_G) < 0) {
            i2cClose(i2c_handle);
            gpioTerminate();
            return 1;
        }
    }

    // Enable block data update
    status = i2cWriteByteData(i2c_handle, CTRL3_C, 0x40); // BDU enable
    if (status < 0) {
        if (handle_i2c_error(status, "Failed to write CTRL3_C", CTRL3_C) < 0) {
            i2cClose(i2c_handle);
            gpioTerminate();
            return 1;
        }
    }

    // Main loop
    while (1) {
        // Delay for 100ms
        gpioDelay(100000);

        // Read accelerometer data
        int16_t acc_x, acc_y, acc_z;
        int16_t gyro_x, gyro_y, gyro_z;
        int low, high;

        low = i2cReadByteData(i2c_handle, OUTX_L_XL);
        if (low < 0) {
             if (handle_i2c_error(low, "Failed to read OUTX_L_XL", OUTX_L_XL) < 0) {
                i2cClose(i2c_handle);
                gpioTerminate();
                return 1;
            }
        }
        high = i2cReadByteData(i2c_handle, OUTX_H_XL);
        if (high < 0) {
             if (handle_i2c_error(high, "Failed to read OUTX_H_XL", OUTX_H_XL) < 0) {
                i2cClose(i2c_handle);
                gpioTerminate();
                return 1;
            }
        }
        acc_x = (int16_t)((high << 8) | low);

        low = i2cReadByteData(i2c_handle, OUTY_L_XL);
        if (low < 0) {
             if (handle_i2c_error(low, "Failed to read OUTY_L_XL", OUTY_L_XL) < 0) {
                i2cClose(i2c_handle);
                gpioTerminate();
                return 1;
            }
        }
        high = i2cReadByteData(i2c_handle, OUTY_H_XL);
        if (high < 0) {
             if (handle_i2c_error(high, "Failed to read OUTY_H_XL", OUTY_H_XL) < 0) {
                i2cClose(i2c_handle);
                gpioTerminate();
                return 1;
            }
        }
        acc_y = (int16_t)((high << 8) | low);

        low = i2cReadByteData(i2c_handle, OUTZ_L_XL);
        if (low < 0) {
             if (handle_i2c_error(low, "Failed to read OUTZ_L_XL", OUTZ_L_XL) < 0) {
                i2cClose(i2c_handle);
                gpioTerminate();
                return 1;
            }
        }
        high = i2cReadByteData(i2c_handle, OUTZ_H_XL);
        if (high < 0) {
             if (handle_i2c_error(high, "Failed to read OUTZ_H_XL", OUTZ_H_XL) < 0) {
                i2cClose(i2c_handle);
                gpioTerminate();
                return 1;
            }
        }
        acc_z = (int16_t)((high << 8) | low);

        // Read gyroscope data
        low = i2cReadByteData(i2c_handle, OUTX_L_G);
        if (low < 0) {
             if (handle_i2c_error(low, "Failed to read OUTX_L_G", OUTX_L_G) < 0) {
                i2cClose(i2c_handle);
                gpioTerminate();
                return 1;
            }
        }
        high = i2cReadByteData(i2c_handle, OUTX_H_G);
        if (high < 0) {
             if (handle_i2c_error(high, "Failed to read OUTX_H_G", OUTX_H_G) < 0) {
                i2cClose(i2c_handle);
                gpioTerminate();
                return 1;
            }
        }
        gyro_x = (int16_t)((high << 8) | low);

        low = i2cReadByteData(i2c_handle, OUTY_L_G);
        if (low < 0) {
             if (handle_i2c_error(low, "Failed to read OUTY_L_G", OUTY_L_G) < 0) {
                i2cClose(i2c_handle);
                gpioTerminate();
                return 1;
            }
        }
        high = i2cReadByteData(i2c_handle, OUTY_H_G);
        if (high < 0) {
             if (handle_i2c_error(high, "Failed to read OUTY_H_G", OUTY_H_G) < 0) {
                i2cClose(i2c_handle);
                gpioTerminate();
                return 1;
            }
        }
        gyro_y = (int16_t)((high << 8) | low);

        low = i2cReadByteData(i2c_handle, OUTZ_L_G);
        if (low < 0) {
             if (handle_i2c_error(low, "Failed to read OUTZ_L_G", OUTZ_L_G) < 0) {
                i2cClose(i2c_handle);
                gpioTerminate();
                return 1;
            }
        }
        high = i2cReadByteData(i2c_handle, OUTZ_H_G);
        if (high < 0) {
             if (handle_i2c_error(high, "Failed to read OUTZ_H_G", OUTZ_H_G) < 0) {
                i2cClose(i2c_handle);
                gpioTerminate();
                return 1;
            }
        }
        gyro_z = (int16_t)((high << 8) | low);

        // Log the data
        printf("AccX: %d, AccY: %d, AccZ: %d, GyroX: %d, GyroY: %d, GyroZ: %d\n", acc_x, acc_y, acc_z, gyro_x, gyro_y, gyro_z);
    }

    // Close I2C connection and terminate pigpio (should not reach here normally)
    i2cClose(i2c_handle);
    gpioTerminate();
    return 0;
}

#include <stdio.h>
