// MLX90632 I2C address
#define MLX90632_ADDR 0x33

// I2C handle
int i2c_handle;

// Flag for graceful shutdown
volatile sig_atomic_t terminate = 0;

// Structure to hold sensor data
typedef struct {
    float ambient_temp;
    float object_temp;
} sensor_data_t;

// Signal handler for Ctrl+C
void signal_handler(int signal) {
    terminate = 1;
    fprintf(stderr, "\nCaught signal %d, terminating gracefully...\n", signal);
}

// Function to read raw temperature data from the sensor
int read_raw_temps(int i2c_handle, uint16_t *ambient, uint16_t *object) {
    char cmd_read_ambient[1] = {0x24}; // Command to read ambient temperature
    char cmd_read_object[1] = {0x25};  // Command to read object temperature
    char buffer[2];
    int result;

    // Read ambient temperature
    result = i2cWrite(i2c_handle, cmd_read_ambient, 1);
    if (result != 0) {
        fprintf(stderr, "Error writing ambient temperature command: %d (%s)\n", result, gpioGetError(result));
        return -1;
    }

    result = i2cReadDevice(i2c_handle, buffer, 2);
    if (result != 2) {
        fprintf(stderr, "Error reading ambient temperature: %d (%s)\n", result, gpioGetError(result));
        return -1;
    }
    *ambient = (buffer[1] << 8) | buffer[0];

    // Read object temperature
    result = i2cWrite(i2c_handle, cmd_read_object, 1);
    if (result != 0) {
        fprintf(stderr, "Error writing object temperature command: %d (%s)\n", result, gpioGetError(result));
        return -1;
    }

    result = i2cReadDevice(i2c_handle, buffer, 2);
    if (result != 2) {
        fprintf(stderr, "Error reading object temperature: %d (%s)\n", result, gpioGetError(result));
        return -1;
    }
    *object = (buffer[1] << 8) | buffer[0];

    return 0;
}

// Function to convert raw temperature data to Celsius
sensor_data_t convert_temps(uint16_t raw_ambient, uint16_t raw_object) {
    sensor_data_t data;
    data.ambient_temp = (float)raw_ambient * 0.02 - 273.15; // Simplified conversion
    data.object_temp = (float)raw_object * 0.02 - 273.15; // Simplified conversion
    return data;
}

// Function to log temperature data with timestamp
void log_temperature_data(float ambient_temp, float object_temp) {
    struct timespec ts;
    clock_gettime(CLOCK_REALTIME, &ts);
    time_t now = ts.tv_sec;
    struct tm *t = localtime(&now);
    char timestamp[100];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", t);

    printf("[%s] Ambient: %.2f °C, Object: %.2f °C\n", timestamp, ambient_temp, object_temp);
}

int main() {
    // Register signal handler for graceful shutdown
    signal(SIGINT, signal_handler);

    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Open I2C communication
    i2c_handle = i2cOpen(1, MLX90632_ADDR, 0); // Bus 1, address 0x33, no flags
    if (i2c_handle < 0) {
        fprintf(stderr, "Error opening I2C: %d (%s)\n", i2c_handle, gpioGetError(i2c_handle));
        gpioTerminate();
        return 1;
    }

    // Main loop to read and log temperature data
    while (!terminate) {
        uint16_t raw_ambient, raw_object;
        sensor_data_t temps;
        // Read raw temperature values
        if (read_raw_temps(i2c_handle, &raw_ambient, &raw_object) == 0) {
            // Convert raw values to Celsius
            temps = convert_temps(raw_ambient, raw_object);

            // Log temperature data
            log_temperature_data(temps.ambient_temp, temps.object_temp);
        } else {
            fprintf(stderr, "Error reading temperature data. Retrying in 5 seconds.\n");
        }

        // Wait for 5 seconds
        sleep(5);
    }

    // Close I2C communication
    i2cClose(i2c_handle);

    // Terminate pigpio
    gpioTerminate();

    return 0;
}

#include <stdio.h>
