#define GPIO17 17
#define GPIO27 27

static volatile int keep_running = 1;

// Function prototypes
int gpio_export(int pin);
int gpio_unexport(int pin);
int gpio_direction(int pin, char *direction);
int gpio_read(int pin);
void log_status(int pin, int value);
void signal_handler(int sig);

// Signal handler to unexport GPIO pins on Ctrl+C
void signal_handler(int sig) {
    printf("\nCaught signal %d, exiting gracefully.\n", sig);
    gpio_unexport(GPIO17);
    gpio_unexport(GPIO27);
    keep_running = 0;
    exit(0);
}

// Exports the specified GPIO pin using sysfs
int gpio_export(int pin) {
    char buffer[3];
    ssize_t bytes_written;
    int fd;

    fd = open("/sys/class/gpio/export", O_WRONLY);
    if (fd == -1) {
        if (errno == EBUSY) {
            fprintf(stderr, "GPIO %d already exported\n", pin);
            return 0; // Already exported, not an error
        }
        perror("Failed to open export file");
        return -1;
    }

    bytes_written = snprintf(buffer, sizeof(buffer), "%d", pin);
    if (write(fd, buffer, bytes_written) == -1) {
        perror("Failed to write to export file");
        close(fd);
        return -1;
    }

    close(fd);
    return 0;
}

// Unexports the specified GPIO pin using sysfs
int gpio_unexport(int pin) {
    char buffer[3];
    ssize_t bytes_written;
    int fd;

    fd = open("/sys/class/gpio/unexport", O_WRONLY);
    if (fd == -1) {
        perror("Failed to open unexport file");
        return -1;
    }

    bytes_written = snprintf(buffer, sizeof(buffer), "%d", pin);
    if (write(fd, buffer, bytes_written) == -1) {
        perror("Failed to write to unexport file");
        close(fd);
        return -1;
    }

    close(fd);
    return 0;
}

// Sets the GPIO pin direction (in or out)
int gpio_direction(int pin, char *direction) {
    char path[64];
    int fd;

    snprintf(path, sizeof(path), "/sys/class/gpio/gpio%d/direction", pin);
    fd = open(path, O_WRONLY);
    if (fd == -1) {
        perror("Failed to open direction file");
        return -1;
    }

    if (write(fd, direction, strlen(direction)) == -1) {
        perror("Failed to write to direction file");
        close(fd);
        return -1;
    }

    close(fd);
    return 0;
}

// Reads the value of the GPIO pin (0 or 1)
int gpio_read(int pin) {
    char path[64];
    char value_str[3];
    int fd;

    snprintf(path, sizeof(path), "/sys/class/gpio/gpio%d/value", pin);
    fd = open(path, O_RDONLY);
    if (fd == -1) {
        perror("Failed to open value file");
        return -1;
    }

    if (read(fd, value_str, 3) == -1) {
        perror("Failed to read value file");
        close(fd);
        return -1;
    }

    close(fd);
    return atoi(value_str);
}

// Logs the tilt status to the console
void log_status(int pin, int value) {
    if (pin == GPIO17) {
        printf("Sensor A: %s\n", value ? "Tilted" : "Not Tilted");
    } else if (pin == GPIO27) {
        printf("Sensor B: %s\n", value ? "Tilted" : "Not Tilted");
    } else {
        fprintf(stderr, "Error: Invalid pin number: %d\n", pin);
    }
}

int main() {
    // Register signal handler for Ctrl+C
    if (signal(SIGINT, signal_handler) == SIG_ERR) {
        perror("Failed to register signal handler");
        return 1;
    }

    // Export GPIO pins
    if (gpio_export(GPIO17) == -1) {
        return 1;
    }
    if (gpio_export(GPIO27) == -1) {
        gpio_unexport(GPIO17); // Clean up previously exported pin
        return 1;
    }

    // Set GPIO direction to input
    if (gpio_direction(GPIO17, "in") == -1) {
        gpio_unexport(GPIO17);
        gpio_unexport(GPIO27);
        return 1;
    }
    if (gpio_direction(GPIO27, "in") == -1) {
        gpio_unexport(GPIO17);
        gpio_unexport(GPIO27);
        return 1;
    }

    // Main loop
    while (keep_running) {
        int value17 = gpio_read(GPIO17);
        int value27 = gpio_read(GPIO27);

        if (value17 == -1 || value27 == -1) {
            fprintf(stderr, "Error reading GPIO value. Retrying...\n");
        } else {
            log_status(GPIO17, value17);
            log_status(GPIO27, value27);
        }

        sleep(1);
    }

    // Unexport GPIO pins before exiting
    gpio_unexport(GPIO17);
    gpio_unexport(GPIO27);

    return 0;
}

