// Function to read from MCP3008 ADC
int read_mcp3008(int channel) {
    if (channel < 0 || channel > 7) {
        fprintf(stderr, "Invalid ADC channel: %d\n", channel);
        return -1;
    }

    // Construct SPI message (MCP3008 datasheet)
    char tx_buffer[3];
    char rx_buffer[3];

    tx_buffer[0] = 0x01; // Start bit
    tx_buffer[1] = (0x08 | channel) << 4; // Single-ended mode, channel select
    tx_buffer[2] = 0x00; // Don't care

    // Perform SPI transaction
    gpioSpiXfer(spi_handle, tx_buffer, rx_buffer, 3);

    // Extract ADC value from response
    int adc_value = ((rx_buffer[1] & 0x03) << 8) + rx_buffer[2];

    return adc_value;
}

// Function to convert ADC value to CO concentration (ppm)
float adc_to_co_ppm(int adc_value) {
    // Placeholder calibration values (replace with actual sensor calibration data)
    float zero_ppm_adc = 0.0;   // ADC value at 0 ppm CO
    float full_scale_adc = 1023.0; // ADC value at full scale CO (e.g., 100 ppm)
    float full_scale_ppm = 100.0; // Full scale CO concentration in ppm

    // Linear conversion (simple, but may not be accurate for all sensors)
    float co_ppm = (adc_value - zero_ppm_adc) * (full_scale_ppm / (full_scale_adc - zero_ppm_adc));

    /*
    NOTE: This is a simplified linear conversion.  A real-world application
    would require proper calibration and a more sophisticated conversion formula
    to account for the sensor's non-linearity and environmental factors like
    temperature and humidity.
    */

    return co_ppm;
}

