    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Open SPI channel
    spi_handle = spiOpen(SPI_CHANNEL, SPI_BAUD, 0); // Channel 0, 1MHz, mode 0
    if (spi_handle < 0) {
        fprintf(stderr, "SPI open failed: %d\n", spi_handle);
        gpioTerminate();
        return 1;
    }

    // Set up signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    printf("CO sensor reading program started. Press Ctrl+C to exit.\n");

    // Main loop
    while (1) {
        // Read ADC value from CO sensor (channel 0)
        int adc_value = read_mcp3008(0);
        if (adc_value < 0) {
            fprintf(stderr, "Error reading ADC value\n");
