#include <stdlib.h>

// Define the I2C address of the SDP810-500Pa sensor
#define SDP810_ADDR 0x25

// Define scaling factors
#define PRES_SCALE 60.0f
#define TEMP_SCALE 200.0f

// Global variable to control the main loop
volatile sig_atomic_t keep_running = 1;

// Structure to hold sensor data
typedef struct {
    float pressure;
    float temperature;
} sensor_data_t;

// Signal handler for graceful shutdown
void intHandler(int dummy) {
    keep_running = 0;
}

// Function to initialize the I2C connection
int setup_i2c() {
    int fd = wiringPiI2CSetup(SDP810_ADDR);
    if (fd == -1) {
        perror("wiringPiI2CSetup failed");
    }
    return fd;
}

// Function to read raw data from the sensor
bool read_raw_data(int fd, int16_t *dp_raw, int16_t *temp_raw) {
    uint8_t buffer[9];

    // Trigger measurement (command 0x362F for continuous average)
    if (wiringPiI2CWrite(fd, 0x36) == -1 || wiringPiI2CWrite(fd, 0x2F) == -1) {
        fprintf(stderr, "I2C write failed when triggering measurement.\n");
        return false;
    }

    // Wait for data ready (at least 20ms)
    usleep(25000); 

    // Read 9 bytes from the sensor
    if (read(fd, buffer, 9) != 9) {
        fprintf(stderr, "I2C read failed.\n");
        return false;
    }

    // Extract data from buffer
    *dp_raw = (buffer[0] << 8) | buffer[1];
    *temp_raw = (buffer[3] << 8) | buffer[4];

    // Check CRC (not implemented here for brevity)

    return true;
}

// Function to convert raw data to physical values
sensor_data_t convert_data(int16_t dp_raw, int16_t temp_raw) {
    sensor_data_t data;
    data.pressure = (float)dp_raw / PRES_SCALE;
    data.temperature = (float)temp_raw / TEMP_SCALE;
    return data;
}

// Function to log sensor data to the console
void log_data(sensor_data_t data) {
    time_t rawtime;
    struct tm * timeinfo;
    char timestamp[80];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    printf("[%s] Pressure: %.2f Pa, Temperature: %.2f °C\n", timestamp, data.pressure, data.temperature);
}

int main() {
    int fd;
    int16_t dp_raw, temp_raw;
    sensor_data_t data;

    // Setup signal handler for Ctrl+C
    signal(SIGINT, intHandler);

    // Initialize I2C
    fd = setup_i2c();
    if (fd == -1) {
        return 1;
    }

    // Main loop
    while (keep_running) {
        // Read raw data from the sensor
        if (read_raw_data(fd, &dp_raw, &temp_raw)) {
            // Convert raw data to physical values
            data = convert_data(dp_raw, temp_raw);

            // Log the data
            log_data(data);
        } else {
            fprintf(stderr, "Failed to read sensor data. Retrying...\n");
        }

        // Wait 500ms
        usleep(500000);
    }

    printf("Exiting...\n");
    close(fd);
    return 0;
}

#include <pigpio.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>
#include <unistd.h>
#include <signal.h>

#define UART_DEVICE "/dev/ttyAMA0"
#define BAUD_RATE 115200
#define BUFFER_SIZE 256
#define LOG_INTERVAL_MS 100

int uart_fd = -1; // Global file descriptor for the UART

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("Caught signal %d, cleaning up...\n", signal);
    if (uart_fd != -1) {
        serialClose(uart_fd);
        printf("UART closed.\n");
    }
    gpioTerminate();
    printf("pigpio terminated.\n");
    exit(0);
}

// Initializes the UART interface
int initialize_uart(const char* device, int baud_rate) {
    int fd = serialOpen(device, baud_rate);
    if (fd < 0) {
        fprintf(stderr, "Error opening serial port: %s\n", device);
        return -1;
    }
    printf("UART initialized on %s at %d baud.\n", device, baud_rate);
    return fd;
}

// Reads range data from the UART
int read_range_data(int fd, char* buffer, int buffer_size) {
    int i = 0;
    while (serialDataAvailable(fd)) {
        char c = serialRead(fd);
        if (c < 0) {
            fprintf(stderr, "Error reading from UART\n");
            return -1;
        }
        buffer[i++] = c;
        if (i >= buffer_size - 1) {
            fprintf(stderr, "Buffer full, discarding data\n");
            buffer[0] = '\0'; // Clear the buffer
            return -1;
        }
        if (c == '\n' || c == '\r') {
            buffer[i] = '\0';
            return 0; // Success, complete line received
        }
    }
    return 1; // No complete line received yet
}

// Parses comma-separated range data
int parse_range_data(const char* data, float* ranges, int max_ranges) {
    char* token;
    char* rest = (char*)data; // Cast away const to use strtok_r
    int i = 0;

    while ((token = strtok_r(rest, ",", &rest)) != NULL && i < max_ranges) {
        char* endptr;
        float range = strtof(token, &endptr);
        if (*endptr != '\0' && *endptr != '\n' && *endptr != '\r') {
            fprintf(stderr, "Error converting '%s' to float\n", token);
            return -1;
        }
        ranges[i++] = range;
    }
    return i; // Return the number of parsed ranges
}

// Logs range data to the console with a timestamp
void log_range_data(const float* ranges, int num_ranges) {
    struct timespec ts;
    clock_gettime(CLOCK_MONOTONIC, &ts);
    long timestamp_ms = (ts.tv_sec * 1000) + (ts.tv_nsec / 1000000);

    printf("%ld", timestamp_ms);
    for (int i = 0; i < num_ranges; ++i) {
        printf(",%.2f", ranges[i]);
    }
    printf("\n");
}

int main() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return EXIT_FAILURE;
    }

    uart_fd = initialize_uart(UART_DEVICE, BAUD_RATE);
    if (uart_fd < 0) {
        gpioTerminate();
        return EXIT_FAILURE;
    }

    // Register signal handler
    signal(SIGINT, signal_handler);

    char buffer[BUFFER_SIZE];
    float ranges[32]; // Assuming a maximum of 32 range values
    struct timespec sleep_time;
    sleep_time.tv_sec = 0;
    sleep_time.tv_nsec = LOG_INTERVAL_MS * 1000000; // 100ms

    while (1) {
        int read_result = read_range_data(uart_fd, buffer, BUFFER_SIZE);
        if (read_result == 0) {
            // Complete line received, parse and log
            int num_ranges = parse_range_data(buffer, ranges, sizeof(ranges) / sizeof(ranges[0]));
            if (num_ranges > 0) {
                log_range_data(ranges, num_ranges);
            }
        } else if (read_result < 0) {
            fprintf(stderr, "Error reading or parsing data, exiting...\n");
            break; // Exit the loop on read/parse error
        }
        nanosleep(&sleep_time, NULL);
    }

    // Cleanup (only reached if an error occurs)
    serialClose(uart_fd);
    gpioTerminate();
    return EXIT_FAILURE;
}

