    printf("\nExiting gracefully...\n");
}

// Function to initialize the I2C device
int i2c_init(i2c_device_t *dev, int bus, int address) {
    char filename[20];
    snprintf(filename, 19, "/dev/i2c-%d", bus);
    dev->fd = open(filename, O_RDWR);
    if (dev->fd < 0) {
        perror("Failed to open I2C bus");
        return -1;
    }
    dev->address = address;
    if (ioctl(dev->fd, I2C_SLAVE, address) < 0) {
        perror("Failed to acquire bus access and/or talk to slave");
        close(dev->fd);
        return -1;
    }
    return 0;
}

// Function to read data from I2C register
int i2c_read_reg(i2c_device_t *dev, uint8_t reg, uint16_t *value) {
    uint8_t buf[2];
    buf[0] = reg;
    if (write(dev->fd, buf, 1) != 1) {
        perror("Failed to write to I2C device");
        return -1;
    }
    if (read(dev->fd, buf, 2) != 2) {
        perror("Failed to read from I2C device");
        return -1;
    }
    *value = (buf[0] << 8) | buf[1];
    return 0;
}

// Function to convert raw temperature data to Celsius
float convert_temp(uint16_t raw_temp) {
    return (float)raw_temp * 0.0078125;
}

// Function to log data with timestamp
void log_data(float temperature) {
    time_t now = time(NULL);
    struct tm *tstruct = localtime(&now);
    char buf[80];
    strftime(buf, sizeof(buf), "%Y-%m-%d.%X", tstruct);
    printf("%s Temperature: %.2f °C\n", buf, temperature);
}

int main() {
    i2c_device_t tmp112;
    uint16_t raw_temp;
    float temperature;

    // Install signal handler
    signal(SIGINT, sigint_handler);

    // Initialize I2C
    if (i2c_init(&tmp112, I2C_BUS, TMP112_ADDR) < 0) {
        fprintf(stderr, "Failed to initialize I2C. Exiting.\n");
        return 1;
    }

    // Main loop
    while (keep_running) {
        if (i2c_read_reg(&tmp112, TEMP_REG, &raw_temp) == 0) {
            temperature = convert_temp(raw_temp);
            log_data(temperature);
        } else {
            fprintf(stderr, "Error reading temperature.\n");
        }
        sleep(5);
    }

    // Close I2C device
    close(tmp112.fd);

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <stdbool.h>
#include <unistd.h>
#include <wiringPiI2C.h>
#include <time.h>
#include <sys/time.h>
#include <signal.h>

// OPT3001 I2C address
#define OPT3001_ADDR 0x44

// OPT3001 registers
#define RESULT_REG 0x00
#define CONFIG_REG 0x01
#define LOW_LIMIT_REG 0x02
#define HIGH_LIMIT_REG 0x03
#define MANUFACTURER_ID_REG 0x7E
#define DEVICE_ID_REG 0x7F

// Configuration settings
#define CONTINUOUS_MODE 0xCC10  // Continuous conversion mode, 100 ms conversion time

// Global variables
int fd;
volatile sig_atomic_t program_running = 1;

// Structure to hold sensor data and configuration
typedef struct {
    int i2c_address;
    int file_descriptor;
    uint16_t config;
} sensor_config_t;

// Function prototypes
int setup_sensor(sensor_config_t *config);
float read_lux(int fd);
void log_data(float lux);
void signal_handler(int signal);

void signal_handler(int signal) {
    program_running = 0;
    printf("\nExiting gracefully...\n");
}

int setup_sensor(sensor_config_t *config) {
    // Initialize I2C
    config->file_descriptor = wiringPiI2CSetup(config->i2c_address);
    if (config->file_descriptor == -1) {
        fprintf(stderr, "Failed to initialize I2C communication.\n");
        return -1;
    }

    // Configure the sensor
    if (wiringPiI2CWriteReg16(config->file_descriptor, CONFIG_REG, config->config) != 0) {
        fprintf(stderr, "Failed to write configuration to the sensor.\n");
        return -1;
    }

    return config->file_descriptor;
}

float read_lux(int fd) {
    int result;
    float lux = -1.0f;

    // Read the result register
    result = wiringPiI2CReadReg16(fd, RESULT_REG);
    if (result != -1) {
        // Extract exponent and result values
        int exponent = (result >> 12) & 0x0F;
        int raw_result = result & 0x0FFF;

        // Calculate lux value
        lux = 0.01f * raw_result * (1 << exponent);
    } else {
        fprintf(stderr, "Failed to read sensor data.\n");
    }

    return lux;
}

void log_data(float lux) {
    struct timeval tv;
    gettimeofday(&tv, NULL);
    time_t nowtime = tv.tv_sec;
    struct tm *nowtm = localtime(&nowtime);
    char tmbuf[64], buf[64];
    strftime(tmbuf, sizeof(tmbuf), "%Y-%m-%d %H:%M:%S", nowtm);
    snprintf(buf, sizeof(buf), "%s.%06ld", tmbuf, tv.tv_usec);

    printf("[%s] Lux: %.2f\n", buf, lux);
}

int main() {
    sensor_config_t sensor_config = {
        .i2c_address = OPT3001_ADDR,
        .file_descriptor = -1,
        .config = CONTINUOUS_MODE
    };

    // Setup signal handling
    signal(SIGINT, signal_handler);

    // Initialize the sensor
    if ((fd = setup_sensor(&sensor_config)) == -1) {
        return 1;
    }

    // Main loop
    while (program_running) {
        float lux = read_lux(fd);
        if (lux >= 0.0f) {
            log_data(lux);
        } else {
            fprintf(stderr, "Error reading lux value.\n");
        }
        sleep(5);
    }

    return 0;
}

