// I2C address of the SDP800-500Pa sensor
#define I2C_ADDR 0x25

// I2C bus number (usually 1 on Raspberry Pi)
#define I2C_BUS 1

// Trigger measurement command
#define TRIGGER_MEASUREMENT_COMMAND 0x2400

int i2c_handle;

// Signal handler for graceful shutdown
void signal_handler(int signal)
{
    printf("\nCaught signal %d, cleaning up...\n", signal);
    i2cClose(i2c_handle);
    gpioTerminate();
    exit(0);
}

int main()
{
    // Initialize the pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Open I2C handle
    i2c_handle = i2cOpen(I2C_BUS, I2C_ADDR, 0);
    if (i2c_handle < 0) {
        fprintf(stderr, "Failed to open I2C device: %d\n", i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Set up signal handler for Ctrl+C
    if (signal(SIGINT, signal_handler) == SIG_ERR) {
        fprintf(stderr, "Failed to set signal handler\n");
        i2cClose(i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Main loop
    while (1) {
        // Send trigger measurement command
        char trigger_cmd[2] = {0x24, 0x00};
        int write_result = i2cWriteI2C(i2c_handle, trigger_cmd, 2);
        if (write_result != 2) {
            fprintf(stderr, "I2C write error: %d\n", write_result);
            usleep(500000); // Wait 500ms before retrying
            continue;
        }

        // Wait for measurement to be ready (at least 8ms)
        gpioDelay(10000); // 10ms

        // Read 6 bytes from the sensor
        char buffer[6];
        int read_result = i2cReadI2C(i2c_handle, buffer, 6);
        if (read_result != 6) {
            fprintf(stderr, "I2C read error: %d\n", read_result);
            usleep(500000); // Wait 500ms before retrying
            continue;
        }

        // Convert bytes to integers
        int16_t pressure = (buffer[0] << 8) | buffer[1];
        int16_t temperature = (buffer[2] << 8) | buffer[3];

        // Get current time for timestamp
        time_t now = time(NULL);
        struct tm *tstruct = localtime(&now);
        char buf[80];
        strftime(buf, sizeof(buf), "%Y-%m-%d.%X", tstruct);

        // Log the data to the console
        printf("%s Pressure: %d Pa, Temperature: %d\n", buf, pressure, temperature);

        // Wait 500ms before the next measurement
        usleep(500000);
    }

    return 0;
}

#include <stdio.h>
