// Define sensor-specific constants
#define I2C_BUS 1
#define I2C_ADDRESS 0x25
#define TRIGGER_MEASUREMENT_COMMAND_1 0x36
#define TRIGGER_MEASUREMENT_COMMAND_2 0x15

// Scaling factors (from datasheet)
#define PRESSURE_SCALE_FACTOR 60.0
#define TEMPERATURE_OFFSET 200.0
#define TEMPERATURE_SCALE_FACTOR 200.0

// Global variables
int i2c_device_fd;
volatile sig_atomic_t program_running = 1;

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("\nCaught signal %d, exiting gracefully...\n", signal);
    program_running = 0;
}

// Function to read pressure and temperature from the sensor
int read_sensor(float *pressure, float *temperature) {
    unsigned char buffer[3];
    unsigned char command[2] = {TRIGGER_MEASUREMENT_COMMAND_1, TRIGGER_MEASUREMENT_COMMAND_2};
    int bytes_written, bytes_read;
    int raw_pressure, raw_temperature;

    // Send trigger measurement command
    bytes_written = i2cWriteDevice(i2c_device_fd, command, 2);
    if (bytes_written != 2) {
        fprintf(stderr, "Error: Failed to write trigger command. Wrote %d bytes\n", bytes_written);
        return -1;
    }

    // Delay for measurement (500 us)
    usleep(500);

    // Read 3 bytes of data
    bytes_read = i2cReadDevice(i2c_device_fd, buffer, 3);
    if (bytes_read < 3) {
        fprintf(stderr, "Error: Failed to read sensor data. Read %d bytes\n", bytes_read);
        return -1;
    }

    // Convert raw data to physical units
    raw_pressure = (buffer[0] << 8) | buffer[1];
    raw_temperature = buffer[2];

    // Basic data validity checks
    if (raw_pressure < -32768 || raw_pressure > 32767) {
        fprintf(stderr, "Error: Invalid raw pressure value: %d\n", raw_pressure);
        return -1;
    }
    if (raw_temperature < 0 || raw_temperature > 255) {
        fprintf(stderr, "Error: Invalid raw temperature value: %d\n", raw_temperature);
        return -1;
    }

    *pressure = (float)raw_pressure / PRESSURE_SCALE_FACTOR;
    *temperature = TEMPERATURE_OFFSET + (float)raw_temperature / TEMPERATURE_SCALE_FACTOR;

    return 0;
}

int main() {
    float pressure, temperature;
    int result;

    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "Error: pigpio initialisation failed\n");
        return 1;
    }

    // Open I2C bus
    i2c_device_fd = i2cOpen(I2C_BUS, I2C_ADDRESS, 0);
    if (i2c_device_fd < 0) {
        fprintf(stderr, "Error: Could not open I2C device: %d\n", i2c_device_fd);
        gpioTerminate();
        return 1;
    }

    // Register signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    printf("Reading SDP810-500Pa sensor data...\n");

    // Main loop
    while (program_running) {
        result = read_sensor(&pressure, &temperature);
        if (result == 0) {
            printf("Pressure: %.2f Pa, Temperature: %.2f °C\n", pressure, temperature);
        } else {
            fprintf(stderr, "Error reading sensor data\n");
        }

        time_sleep(0.5);
    }

    // Cleanup
    i2cClose(i2c_device_fd);
    gpioTerminate();

    printf("Program terminated gracefully.\n");
    return 0;
}

