// Constants
#define I2C_BUS 1
#define SI7202_ADDR 0x40
#define DATA_REG 0x01
#define READ_SIZE 2
#define DELAY_MS 500

// Global variables
int i2c_handle;
volatile sig_atomic_t terminate = 0;

// Signal handler for graceful shutdown
void handler(int signal_number) {
    printf("Caught signal %d, terminating gracefully...\n", signal_number);
    terminate = 1;
}

// Function to read magnetic field strength from the sensor
int read_magnetic_field(int handle, int *raw_value) {
    char data[READ_SIZE];
    int bytes_read = i2cReadI2CBlockData(handle, DATA_REG, data, READ_SIZE);

    if (bytes_read < 0) {
        fprintf(stderr, "Error reading from I2C: %d\n", bytes_read);
        return -1; // Indicate failure
    } else if (bytes_read != READ_SIZE) {
        fprintf(stderr, "Warning: Read %d bytes, expected %d\n", bytes_read, READ_SIZE);
        return -1;
    }

    *raw_value = (data[0] << 8) | data[1];
    return 0; // Indicate success
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Open I2C device
    i2c_handle = i2cOpen(I2C_BUS, SI7202_ADDR, 0);
    if (i2c_handle < 0) {
        fprintf(stderr, "Error opening I2C device: %d\n", i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Set up signal handler
    signal(SIGINT, handler);

    printf("Starting data logging...\n");

    // Main loop
    while (!terminate) {
        int raw_magnetic_field;
        if (read_magnetic_field(i2c_handle, &raw_magnetic_field) == 0) {
            printf("Raw magnetic field: %d\n", raw_magnetic_field);
        } else {
            fprintf(stderr, "Failed to read magnetic field, retrying...\n");
        }

        gpioDelay(DELAY_MS * 1000); // Delay in microseconds
    }

    // Close I2C device and terminate pigpio
    i2cClose(i2c_handle);
    gpioTerminate();

    printf("Program terminated.\n");
    return 0;
}

