// APDS9960 I2C address
#define APDS9960_I2C_ADDR 0x39

// APDS9960 register addresses
#define APDS9960_ENABLE      0x80
#define APDS9960_ATIME       0x81
#define APDS9960_PTIME       0x82
#define APDS9960_WTIME       0x83
#define APDS9960_PPULSE      0x8E
#define APDS9960_CONTROL     0x8F
#define APDS9960_CONFIG1     0x90
#define APDS9960_CONFIG2     0x91
#define APDS9960_ID          0x92
#define APDS9960_STATUS      0x93
#define APDS9960_CDATAL      0x94
#define APDS9960_CDATAH      0x95
#define APDS9960_RDATAL      0x96
#define APDS9960_RDATAH      0x97
#define APDS9960_GDATAL      0x98
#define APDS9960_GDATAH      0x99
#define APDS9960_BDATAL      0x9A
#define APDS9960_BDATAH      0x9B
#define APDS9960_PDATAL      0x9C
#define APDS9960_PDATAH      0x9D
#define APDS9960_POFFSET_UR  0x9E
#define APDS9960_POFFSET_DL  0x9F
#define APDS9960_GPENTH      0xA0
#define APDS9960_GPEXL       0xA1
#define APDS9960_GCONF1      0xA2
#define APDS9960_GCONF2      0xA3
#define APDS9960_GCONF3      0xAA
#define APDS9960_GCONF4      0xAB


// Enable bits
#define APDS9960_PON   (1 << 0)
#define APDS9960_AEN   (1 << 1)
#define APDS9960_PEN   (1 << 2)
#define APDS9960_GEN   (1 << 6)

// Gesture defines
#define APDS9960_GESTURE_THRESHOLD_OUT   10
#define APDS9960_GESTURE_THRESHOLD_IN    5

#define APDS9960_GESTURE_WAIT_TIME         17

//Direction defines
#define DIR_NONE  0
#define DIR_UP    1
#define DIR_DOWN  2
#define DIR_LEFT  3
#define DIR_RIGHT 4

int i2c_handle;
volatile sig_atomic_t program_running = 1;

void signal_handler(int sig) {
    program_running = 0;
    printf("\nCaught signal %d, exiting gracefully...\n", sig);
}

int apds9960_init() {
    // Enable power, ALS, and proximity
    if (i2cWriteByteData(i2c_handle, APDS9960_ENABLE, APDS9960_PON | APDS9960_AEN | APDS9960_PEN) < 0) {
        perror("Failed to enable power, ALS, and proximity");
        return -1;
    }

    // Set ALS integration time
    if (i2cWriteByteData(i2c_handle, APDS9960_ATIME, 0xDB) < 0) { //default value
        perror("Failed to set ALS integration time");
        return -1;
    }

    // Set proximity integration time
    if (i2cWriteByteData(i2c_handle, APDS9960_PTIME, 0xFF) < 0) {
        perror("Failed to set proximity integration time");
        return -1;
    }

    // Set LED drive strength and proximity pulse length
    if (i2cWriteByteData(i2c_handle, APDS9960_PPULSE, 0x87) < 0) {
        perror("Failed to set LED drive strength and pulse length");
        return -1;
    }

    // Set proximity gain
    if (i2cWriteByteData(i2c_handle, APDS9960_CONTROL, 0x03) < 0) {
        perror("Failed to set proximity gain");
        return -1;
    }

    return 0;
}

int read_apds9960_data(int *proximity, int *ambient, int *red, int *green, int *blue) {
    unsigned char block[8];

    if (i2cReadI2CBlockData(i2c_handle, APDS9960_CDATAL, (char *)block, 8) != 8) {
        perror("Failed to read data block");
        return -1;
    }

    *ambient = ((uint16_t)block[1] << 8) | block[0];
    *red     = ((uint16_t)block[3] << 8) | block[2];
    *green   = ((uint16_t)block[5] << 8) | block[4];
    *blue    = ((uint16_t)block[7] << 8) | block[6];

    unsigned char prox_block[2];
    if (i2cReadI2CBlockData(i2c_handle, APDS9960_PDATAL, (char *)prox_block, 2) != 2) {
        perror("Failed to read proximity data");
        return -1;
    }
    *proximity = ((uint16_t)prox_block[1] << 8) | prox_block[0];

    return 0;
}

int main() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    i2c_handle = i2cOpen(1, APDS9960_I2C_ADDR, 0);
    if (i2c_handle < 0) {
        fprintf(stderr, "Failed to open I2C device: %d\n", i2c_handle);
        gpioTerminate();
        return 1;
    }

    if (apds9960_init() < 0) {
        fprintf(stderr, "APDS9960 initialisation failed\n");
        i2cClose(i2c_handle);
        gpioTerminate();
        return 1;
    }

    signal(SIGINT, signal_handler);

    int proximity, ambient, red, green, blue;

    while (program_running) {
        if (read_apds9960_data(&proximity, &ambient, &red, &green, &blue) == 0) {
            printf("Proximity: %d, Ambient: %d, Red: %d, Green: %d, Blue: %d\n",
                   proximity, ambient, red, green, blue);
        } else {
            fprintf(stderr, "Failed to read sensor data\n");
        }

        gpioDelay(250); // 250ms delay
    }

    i2cClose(i2c_handle);
    gpioTerminate();

    return 0;
}

