// Define UART port
#define UART_PORT "/dev/ttyS0" //Or /dev/ttyAMA0

// Define baud rate
#define BAUD_RATE B115200

// Define data structure for mmWave sensor data
typedef struct {
    float range;
    float velocity;
} mmWaveData_t;

// Global variable for UART file descriptor
int uart_fd = -1;

// Signal handler for graceful shutdown
void signal_handler(int signo) {
    if (signo == SIGINT) {
        printf("Received SIGINT, closing UART port...\n");
        if (uart_fd != -1) {
            close(uart_fd);
        }
        exit(0);
    }
}

// Function to initialize UART
int init_uart(const char *port, speed_t baud_rate) {
    int fd = open(port, O_RDWR | O_NOCTTY | O_NDELAY);
    if (fd == -1) {
        perror("Error opening UART port");
        return -1;
    }

    struct termios tty;
    memset(&tty, 0, sizeof(tty));

    if (tcgetattr(fd, &tty) != 0) {
        perror("Error getting termios attributes");
        close(fd);
        return -1;
    }

    cfsetospeed(&tty, baud_rate);
    cfsetispeed(&tty, baud_rate);

    tty.c_cflag |= (CLOCAL | CREAD);//Enable receiver and set local mode
    tty.c_cflag &= ~CSIZE;/* Mask the character size bits */
    tty.c_cflag |= CS8;    /* 8-bit data */
    tty.c_cflag &= ~(PARENB | PARODD); /* No parity */
    tty.c_cflag &= ~CSTOPB;/* 1 stop bit */
    tty.c_cflag &= ~CRTSCTS;// Disable hardware flow control

    tty.c_iflag &= ~(IGNBRK | BRKINT | PARMRK | ISTRIP | INLCR | IGNCR | ICRNL | IXON);
    tty.c_lflag &= ~(ECHO | ECHONL | ICANON | ISIG | IEXTEN);
    tty.c_oflag &= ~OPOST;

    // Set VMIN and VTIME
    tty.c_cc[VMIN] = 0;    // Read non-blocking
    tty.c_cc[VTIME] = 5;   // Timeout of 0.5 seconds

    if (tcsetattr(fd, TCSANOW, &tty) != 0) {
        perror("Error setting termios attributes");
        close(fd);
        return -1;
    }

    return fd;
}

// Function to read mmWave sensor data
int read_mmwave_data(int fd, mmWaveData_t *data) {
    // Implement your data parsing logic here based on the sensor's output format.
    // This is a placeholder.  Replace with actual UART read and data parsing.
    // Example (assuming comma-separated range and velocity):
    char buffer[256];
    ssize_t bytes_read = read(fd, buffer, sizeof(buffer) - 1);

    if (bytes_read > 0) {
        buffer[bytes_read] = '\0';
        //printf("Received: %s", buffer);
        float range, velocity;
        if (sscanf(buffer, "%f,%f", &range, &velocity) == 2) {
            data->range = range;
            data->velocity = velocity;
            return 0; // Success
        } else {
            fprintf(stderr, "Error parsing data: %s\n", buffer);
            return -1; // Error parsing
        }
    } else if (bytes_read == 0) {
        fprintf(stderr, "Timeout reading from UART\n");
        return -1; // Timeout
    } else {
        perror("Error reading from UART");
        return -1; // Error reading
    }
}

// Function to log mmWave sensor data
void log_data(const mmWaveData_t *data) {
    time_t rawtime;
    struct tm * timeinfo;

    time (&rawtime);
    timeinfo = localtime (&rawtime);

    printf("[%s] Range: %.2f, Velocity: %.2f\n", asctime(timeinfo), data->range, data->velocity);
