// Function to initialize the UART port
int init_uart() {
    struct termios tty;

    // Open the UART port
    uart_fd = open(UART_PORT, O_RDWR | O_NOCTTY | O_SYNC);
    if (uart_fd < 0) {
        perror("Error opening UART port");
        return -1;
    }

    // Get the current attributes of the UART port
    if (tcgetattr(uart_fd, &tty) != 0) {
        perror("Error getting UART attributes");
        close(uart_fd);
        uart_fd = -1;
        return -1;
    }

    // Configure the UART port
    tty.c_cflag = BAUD_RATE | CS8 | CLOCAL | CREAD;  // 8N1, no parity, enable receiver
    tty.c_iflag = IGNPAR;                          // Ignore parity errors
    tty.c_oflag = 0;
    tty.c_lflag = 0;                               // Non-canonical mode
    tty.c_cc[VMIN] = 1;                              // Read at least 1 character
    tty.c_cc[VTIME] = 5;                             // Timeout of 0.5 seconds

    // Set the new attributes of the UART port
    if (tcsetattr(uart_fd, TCSANOW, &tty) != 0) {
        perror("Error setting UART attributes");
        close(uart_fd);
        uart_fd = -1;
        return -1;
    }

    return 0;
}

