        // Example: Assuming the data is two floats
        if (bytes_read == 8) {
            memcpy(&(data->range), buffer, 4);
            memcpy(&(data->doppler), buffer + 4, 4);
            return 0;
        } else {
            fprintf(stderr, "Unexpected number of bytes received: %zd\n", bytes_read);
            return -1;
        }
    }
}

// Function to log the range-Doppler data with a timestamp
void log_range_doppler_data(RangeDopplerData data) {
