// Define the I2C bus and sensor address
#define I2C_BUS "/dev/i2c-1"
#define MLX90615_ADDR 0x5A

// MLX90615 register addresses
#define TA_REG 0x26 // Ambient temperature
#define TO_REG 0x27 // Object temperature

// Global variable to control the main loop
volatile sig_atomic_t keep_running = 1;

// Signal handler to catch SIGINT (Ctrl+C)
void sigint_handler(int signal)
{
    keep_running = 0;
    printf("\nExiting gracefully...\n");
}

// Function to read a 16-bit value from the I2C device
int16_t read_i2c_word(int fd, uint8_t reg)
{
    uint8_t buf[2];
    int16_t val;

    // Write the register address to read from
    if (write(fd, &reg, 1) != 1) {
        perror("Failed to write register address");
        return -1;
    }

    // Read the 2 bytes of data
    if (read(fd, buf, 2) != 2) {
        perror("Failed to read data");
        return -1;
    }

    // Combine the bytes into a 16-bit value
    val = (buf[1] << 8) | buf[0];
    return val;
}

// Function to convert raw temperature data to Celsius
double convert_temperature(int16_t raw_temp)
{
    double temp = (double)raw_temp * 0.02 - 273.15;
    return temp;
}

// Function to log the temperature data to the console
void log_temperature_data(double ambient_temp, double object_temp)
{
    time_t now = time(NULL);
    struct tm *t = localtime(&now);
    char timestamp[30];
    strftime(timestamp, sizeof(timestamp)-1, "%Y-%m-%d %H:%M:%S", t);

    printf("[%s] Ambient Temp: %.2f °C, Object Temp: %.2f °C\n", timestamp, ambient_temp, object_temp);
}

int main()
{
    int fd; // I2C file descriptor
    int retries = 3; // Number of retries for I2C communication

    // Register the signal handler for SIGINT
    signal(SIGINT, sigint_handler);

    // Open the I2C bus
    fd = open(I2C_BUS, O_RDWR);
    if (fd < 0) {
        perror("Failed to open I2C bus");
        return 1;
    }

    // Set the I2C slave address
    if (ioctl(fd, I2C_SLAVE, MLX90615_ADDR) < 0) {
        perror("Failed to set I2C slave address");
        close(fd);
        return 1;
    }

    // Main loop to read and log temperature data
    while (keep_running) {
        int16_t raw_ambient_temp, raw_object_temp;
        double ambient_temp, object_temp;

        // Read ambient temperature
        for (int i = 0; i < retries; i++) {
            raw_ambient_temp = read_i2c_word(fd, TA_REG);
            if (raw_ambient_temp != -1) break; // Exit retry loop if successful
            usleep(10000); // Wait before retrying
        }
        if (raw_ambient_temp == -1) {
            fprintf(stderr, "Failed to read ambient temperature after multiple retries.\n");
            continue; // Skip to the next iteration
        }

        // Read object temperature
        for (int i = 0; i < retries; i++) {
            raw_object_temp = read_i2c_word(fd, TO_REG);
            if (raw_object_temp != -1) break; // Exit retry loop if successful
            usleep(10000); // Wait before retrying
        }
        if (raw_object_temp == -1) {
            fprintf(stderr, "Failed to read object temperature after multiple retries.\n");
            continue; // Skip to the next iteration
        }

        // Convert raw temperatures to Celsius
        ambient_temp = convert_temperature(raw_ambient_temp);
        object_temp = convert_temperature(raw_object_temp);

        // Log the temperature data
        log_temperature_data(ambient_temp, object_temp);

        // Wait for a specified period (e.g., 1 second)
        sleep(1);
    }

    // Close the I2C bus
    close(fd);

    return 0;
}

