#define PDM_DATA_PIN 21
#define PDM_CLK_PIN 20
#define SAMPLE_RATE 2048000  // 2.048 MHz
#define DECIMATION_FACTOR 128 // 2048000 / 16000 = 128
#define PCM_SAMPLE_RATE 16000
#define BUFFER_SIZE 1024

static volatile int running = 1;

// Data structure for managing buffers
typedef struct {
    int16_t buffer[BUFFER_SIZE];
    int filled;
} AudioBuffer;

AudioBuffer buffer1, buffer2; // Double buffers
AudioBuffer *currentBuffer = &buffer1;
AudioBuffer *processingBuffer = &buffer2;

// Signal handler for graceful shutdown
void signal_handler(int sig) {
    fprintf(stderr, "Signal received, cleaning up...\n");
    running = 0;
}

// PDM to PCM Decimation Filter (Simple Moving Average)
void decimate_pdm_to_pcm(uint8_t *pdm_data, int16_t *pcm_data, int num_pdm_samples) {
    int i, j;
    for (i = 0; i < BUFFER_SIZE; i++) {
        int32_t sum = 0;
        for (j = 0; j < DECIMATION_FACTOR; j++) {
            sum += (pdm_data[i * DECIMATION_FACTOR + j] > 0) ? 1 : -1; // Convert 1/0 to 1/-1
        }
        pcm_data[i] = (int16_t)(sum * (32767.0 / DECIMATION_FACTOR)); // Scale to 16-bit range
    }
}


int main() {
    int i, res;
    gpioCfgClock(5, 1);

    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Configure GPIO pins
    if (gpioSetMode(PDM_DATA_PIN, PI_INPUT) != 0) {
        fprintf(stderr, "Failed to set GPIO%d to input\n", PDM_DATA_PIN);
        gpioTerminate();
        return 1;
    }
    gpioSetPullUpDown(PDM_DATA_PIN, PI_PUD_DOWN);

    if (gpioSetMode(PDM_CLK_PIN, PI_OUTPUT) != 0) {
        fprintf(stderr, "Failed to set GPIO%d to output\n", PDM_CLK_PIN);
        gpioTerminate();
        return 1;
    }

    // Set signal handlers
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Generate clock wave
    gpioWaveClear();
    gpioPulse_t pulse[2];
    pulse[0].gpioOn = (1 << PDM_CLK_PIN);
    pulse[0].gpioOff = 0;
    pulse[0].usDelay = 244; // Half period for 2.048 MHz (1/2.048MHz / 2 * 1000000) ~ 244
    pulse[1].gpioOn = 0;
    pulse[1].gpioOff = (1 << PDM_CLK_PIN);
    pulse[1].usDelay = 244;

    gpioWaveAddGeneric(2, pulse);
    uint32_t wave_id = gpioWaveCreate();

    if (wave_id == PI_BAD_WAVE_ID) {
        fprintf(stderr, "Failed to create wave\n");
        gpioTerminate();
        return 1;
    }

    // Start the clock wave
    gpioWaveChain((char*)&wave_id, 4); //Loop the wave continuously

    uint8_t pdm_data[BUFFER_SIZE * DECIMATION_FACTOR];

    while (running) {
        // Read PDM data
        for (i = 0; i < BUFFER_SIZE * DECIMATION_FACTOR; i++) {
            // Simple polling for data (replace with DMA or interrupts for efficiency)
            pdm_data[i] = gpioRead(PDM_DATA_PIN);
        }

        // Decimate PDM to PCM
        decimate_pdm_to_pcm(pdm_data, currentBuffer->buffer, BUFFER_SIZE * DECIMATION_FACTOR);
        currentBuffer->filled = 1;

        // Swap buffers
        AudioBuffer *temp = currentBuffer;
        currentBuffer = processingBuffer;
        processingBuffer = temp;

        // Process the filled buffer
        if (processingBuffer->filled) {
            for (i = 0; i < BUFFER_SIZE; i++) {
                printf("%d\n", processingBuffer->buffer[i]); // Log raw PCM data to console
            }
            processingBuffer->filled = 0;
        }

        // Small delay to avoid busy-waiting
        usleep(64000); // 64ms delay (BUFFER_SIZE / PCM_SAMPLE_RATE)
    }

    // Clean up
    gpioWaveDelete(wave_id);
    gpioTerminate();

    return 0;
}

