// Function to initialize the GPIO pins
int setup_gpio() {
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "Error initializing wiringPi: %s\n", strerror(errno));
        return 1;
    }

    pinMode(SENSOR_1_PIN, INPUT);
    pinMode(SENSOR_2_PIN, INPUT);

    // Enable pull-up resistors (optional, depending on sensor configuration)
    pullUpDnControl(SENSOR_1_PIN, PUD_UP);
    pullUpDnControl(SENSOR_2_PIN, PUD_UP);

    return 0;
}

// Function to read the sensor data
SensorData read_sensors() {
    SensorData data;
    data.sensor1_state = digitalRead(SENSOR_1_PIN);
    data.sensor2_state = digitalRead(SENSOR_2_PIN);
    return data;
}

// Function to log the sensor data
void log_data(SensorData data) {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[20];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    printf("[%s] Sensor 1: %s, Sensor 2: %s\n", timestamp,
           data.sensor1_state == HIGH ? "HIGH" : "LOW",
           data.sensor2_state == HIGH ? "HIGH" : "LOW");
}

