    signal(SIGINT, signal_handler);

    // Initialize GPIO
    if (setup_gpio() != 0) {
        return 1;
    }

    printf("Tilt sensor monitoring started. Press Ctrl+C to exit.\n");

    // Main loop
    while (program_running) {
        SensorData data = read_sensors();
        log_data(data);
        delay(LOGGING_INTERVAL);
    }

    return 0;
}

