    float temperature, humidity;
    int raw_temperature, raw_humidity;

    // Initialize WiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "WiringPi initialization failed.\n");
        return 1;
    }

    // Initialize I2C communication
    fd = wiringPiI2CSetup(SI7021_ADDR);
    if (fd == -1) {
        fprintf(stderr, "I2C initialization failed. Error code: %d\n", errno);
        perror("wiringPiI2CSetup");
        return 1;
    }

    // Register signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Main loop
    while (1) {
        // Start Temperature Measurement (No Hold Master Mode)
        if (wiringPiI2CWrite(fd, SI7021_TEMP_NOHOLD) < 0) {
            perror("Error writing temperature command");
            continue; // Retry
        }

        // Wait for conversion (at least 11ms)
        delay(11);

        // Read Temperature Data
        raw_temperature = wiringPiI2CReadReg16(fd, 0);
        if (raw_temperature < 0) {
            perror("Error reading temperature data");
            continue; // Retry
        }

        raw_temperature = byte_swap(raw_temperature);

        // Calculate Temperature
        temperature = (175.72 * raw_temperature / 65536.0) - 46.85;

        // Start Humidity Measurement (No Hold Master Mode)
        if (wiringPiI2CWrite(fd, SI7021_HUMID_NOHOLD) < 0) {
            perror("Error writing humidity command");
            continue; // Retry
        }

        // Wait for conversion (at least 11ms)
        delay(11);

        // Read Humidity Data
        raw_humidity = wiringPiI2CReadReg16(fd, 0);
        if (raw_humidity < 0) {
            perror("Error reading humidity data");
            continue; // Retry
        }

        raw_humidity = byte_swap(raw_humidity);

        // Calculate Humidity
        humidity = (125.0 * raw_humidity / 65536.0) - 6.0;

        // Log Data to Console
        printf("Temperature: %.2f °C, Humidity: %.2f %%\n", temperature, humidity);

        // Wait 5 seconds
        delay(5000);
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <pigpio.h>
#include <time.h>
#include <unistd.h>

// Configuration
#define GPIO_PIN 4
#define PULSES_PER_REVOLUTION 1
#define TIMESTAMP_BUFFER_SIZE 10

// Global Variables
volatile unsigned int timestamp_buffer[TIMESTAMP_BUFFER_SIZE];
volatile int buffer_index = 0;
volatile int interrupt_count = 0;
int running = 1;

// Function Prototypes
void signal_handler(int signal);
void interrupt_handler(int gpio, int level, unsigned int tick);
double calculate_frequency();
double calculate_rpm(double frequency);

// Structure to hold the last timestamps.
typedef struct {
    unsigned int timestamps[TIMESTAMP_BUFFER_SIZE];
    int head;
    int count;
} timestamp_circular_buffer;

timestamp_circular_buffer ts_buffer = {{0}, 0, 0};

void add_timestamp(unsigned int timestamp) {
    ts_buffer.timestamps[ts_buffer.head] = timestamp;
    ts_buffer.head = (ts_buffer.head + 1) % TIMESTAMP_BUFFER_SIZE;
    if (ts_buffer.count < TIMESTAMP_BUFFER_SIZE) {
        ts_buffer.count++;
    }
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("\nCaught signal %d, cleaning up...\n", signal);
    running = 0;
    gpioSetISRFuncEx(GPIO_PIN, RISING_EDGE, 0, NULL); // Disable interrupt handler
    gpioTerminate(); // Terminate pigpio
    exit(0);
}

// Interrupt handler
void interrupt_handler(int gpio, int level, unsigned int tick) {
    // Add the timestamp to the circular buffer
    add_timestamp(tick);
    interrupt_count++;
}

// Calculate pulse frequency
double calculate_frequency() {
    if (ts_buffer.count < 2) {
        return 0.0; // Not enough data
    }

    double total_difference = 0.0;
    int num_differences = ts_buffer.count - 1;

    // Calculate the sum of the differences between consecutive timestamps.
    for (int i = 0; i < num_differences; i++) {
        int index1 = (ts_buffer.head - 1 - i + TIMESTAMP_BUFFER_SIZE) % TIMESTAMP_BUFFER_SIZE;
        int index2 = (ts_buffer.head - 2 - i + TIMESTAMP_BUFFER_SIZE) % TIMESTAMP_BUFFER_SIZE;
        unsigned int timestamp1 = ts_buffer.timestamps[index1];
        unsigned int timestamp2 = ts_buffer.timestamps[index2];
        double difference = (double)(timestamp1 - timestamp2);
        total_difference += difference;
    }

    //Calculate average time difference
    double average_difference = total_difference / num_differences;

    if (average_difference <= 0) {
        return 0.0; // Avoid division by zero or negative values
    }

    //Frequency is inverse of time period
    return 1000000.0 / average_difference; // Convert microseconds to seconds
}

// Calculate RPM from frequency
double calculate_rpm(double frequency) {
    return (frequency * 60.0) / PULSES_PER_REVOLUTION;
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO pin as input
    gpioSetMode(GPIO_PIN, PI_INPUT);

    // Register signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Set interrupt handler for rising edge
    if (gpioSetISRFuncEx(GPIO_PIN, RISING_EDGE, 0, interrupt_handler) != 0) {
        fprintf(stderr, "Failed to set interrupt handler\n");
        gpioTerminate();
        return 1;
    }

    printf("MLX90254 RPM Measurement Program\n");
    printf("GPIO Pin: %d, PPR: %d\n", GPIO_PIN, PULSES_PER_REVOLUTION);

    // Main loop
    while (running) {
        // Calculate frequency and RPM
        double frequency = calculate_frequency();
        double rpm = calculate_rpm(frequency);

        // Get current timestamp
        time_t now = time(NULL);
        struct tm *tstruct = localtime(&now);
        char buf[80];
        strftime(buf, sizeof(buf), "%Y-%m-%d.%X", tstruct);

        // Log RPM to console
        printf("%s - Frequency: %.2f Hz, RPM: %.2f\n", buf, frequency, rpm);

        sleep(1);
    }

    // Cleanup (should not reach here if signal handler works)
    gpioSetISRFuncEx(GPIO_PIN, RISING_EDGE, 0, NULL); // Disable interrupt handler
    gpioTerminate(); // Terminate pigpio

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <fcntl.h>
