#include <errno.h>
#include <string.h>

// Configuration
#define I2C_BUS "/dev/i2c-1" // I2C bus on Raspberry Pi 5
#define SDP31_ADDR 0x21       // SDP31 I2C address
#define MEASURE_COMMAND 0x362F // Command to start measurement (trigger + data ready)
#define SLEEP_DURATION_MS 500  // Sleep duration in milliseconds

// Function to handle I2C errors
void i2c_error(const char *message) {
    fprintf(stderr, "I2C Error: %s: %s\n", message, strerror(errno));
}

// Function to initialize the I2C bus
int i2c_setup(const char *bus) {
    int fd = open(bus, O_RDWR);
    if (fd < 0) {
        i2c_error("Failed to open I2C bus");
        return -1;
    }
    if (ioctl(fd, I2C_SLAVE, SDP31_ADDR) < 0) {
        i2c_error("Failed to acquire bus access and/or talk to slave");
        close(fd);
        return -1;
    }
    return fd;
}

// Function to read differential pressure from the SDP31 sensor
int16_t read_differential_pressure(int fd) {
    uint8_t write_buffer[2] = {(MEASURE_COMMAND >> 8) & 0xFF, MEASURE_COMMAND & 0xFF};
    uint8_t read_buffer[3];

    // Write the measurement command
    if (write(fd, write_buffer, 2) != 2) {
        i2c_error("Failed to write measurement command");
        return -1;
    }

    usleep(10000); // Wait 10ms for conversion (Datasheet says 6.5ms max)

    // Read the pressure data
    if (read(fd, read_buffer, 3) != 3) {
        i2c_error("Failed to read pressure data");
        return -1;
    }

    // Combine the bytes to form the 16-bit pressure value
    int16_t pressure = (int16_t)((read_buffer[0] << 8) | read_buffer[1]);
    return pressure;
}

// Function to log the pressure data to the console
void log_pressure(int16_t pressure) {
    // Scale factor from datasheet
    float pressure_pa = (float)pressure / 60.0; //Pa
    printf("Pressure: %.2f Pa\n", pressure_pa);
}

int main() {
    int fd;
    struct timespec sleep_time = {0, SLEEP_DURATION_MS * 1000000L}; // 500ms

    // Initialize I2C communication
    fd = i2c_setup(I2C_BUS);
    if (fd < 0) {
        fprintf(stderr, "Failed to initialize I2C. Exiting.\n");
        return 1;
    }

    // Main loop: Read and log pressure data periodically
    while (1) {
        int16_t pressure = read_differential_pressure(fd);
        if (pressure != -1) {
            log_pressure(pressure);
        } else {
            fprintf(stderr, "Failed to read pressure. Retrying.\n");
        }

        // Sleep for the specified duration
        nanosleep(&sleep_time, NULL);
    }

    close(fd);
    return 0;
}

