    terminate = 1;
    fprintf(stderr, "\nCaught SIGINT, exiting gracefully...\n");
}

int main() {
    int gpio_status;
    int sensor_value;
    time_t current_time;
    struct tm *time_info;
    char timestamp[20]; // Buffer to hold the formatted timestamp

    // Register the signal handler for SIGINT
