#include <stdio.h>
#include <stdint.h>
#include <stdbool.h>
#include <wiringPiI2C.h>
#include <time.h>
#include <sys/time.h>
#include <unistd.h>
#include <signal.h>

// MPU-6050 Register Map
#define MPU6050_ADDR 0x68
#define PWR_MGMT_1 0x6B
#define ACCEL_XOUT_H 0x3B
#define GYRO_XOUT_H 0x43

// Global flag for graceful shutdown
volatile bool running = true;

// Signal handler for Ctrl+C
void signal_handler(int sig) {
    running = false;
    printf("\nExiting gracefully...\n");
}

// Function to initialize the MPU-6050
int mpu6050_init(int fd) {
    // Wake up the MPU-6050 (clear sleep mode bit)
    if (wiringPiI2CWriteReg8(fd, PWR_MGMT_1, 0) < 0) {
        fprintf(stderr, "Error: Could not wake up MPU-6050\n");
        return -1;
    }
    return 0;
}

// Function to read raw accelerometer and gyroscope data
int read_mpu6050_data(int fd, int16_t *accel_x, int16_t *accel_y, int16_t *accel_z, int16_t *gyro_x, int16_t *gyro_y, int16_t *gyro_z) {
    *accel_x = (int16_t)(wiringPiI2CReadReg8(fd, ACCEL_XOUT_H) << 8 | wiringPiI2CReadReg8(fd, ACCEL_XOUT_H + 1));
    *accel_y = (int16_t)(wiringPiI2CReadReg8(fd, ACCEL_XOUT_H + 2) << 8 | wiringPiI2CReadReg8(fd, ACCEL_XOUT_H + 3));
    *accel_z = (int16_t)(wiringPiI2CReadReg8(fd, ACCEL_XOUT_H + 4) << 8 | wiringPiI2CReadReg8(fd, ACCEL_XOUT_H + 5));
    *gyro_x = (int16_t)(wiringPiI2CReadReg8(fd, GYRO_XOUT_H) << 8 | wiringPiI2CReadReg8(fd, GYRO_XOUT_H + 1));
    *gyro_y = (int16_t)(wiringPiI2CReadReg8(fd, GYRO_XOUT_H + 2) << 8 | wiringPiI2CReadReg8(fd, GYRO_XOUT_H + 3));
    *gyro_z = (int16_t)(wiringPiI2CReadReg8(fd, GYRO_XOUT_H + 4) << 8 | wiringPiI2CReadReg8(fd, GYRO_XOUT_H + 5));

    return 0;
}

// Function to log the sensor data with timestamp
void log_data(int16_t accel_x, int16_t accel_y, int16_t accel_z, int16_t gyro_x, int16_t gyro_y, int16_t gyro_z) {
    struct timeval tv;
    gettimeofday(&tv, NULL);
    time_t nowtime = tv.tv_sec;
    struct tm *nowtm = localtime(&nowtime);
    char tmbuf[64], buf[64];
    strftime(tmbuf, sizeof(tmbuf), "%Y-%m-%d %H:%M:%S", nowtm);
    snprintf(buf, sizeof(buf), "%s.%06ld", tmbuf, tv.tv_usec);

    printf("%s, Accel: %6d %6d %6d, Gyro: %6d %6d %6d\n", buf, accel_x, accel_y, accel_z, gyro_x, gyro_y, gyro_z);
}

int main() {
    int fd;
    int16_t accel_x, accel_y, accel_z, gyro_x, gyro_y, gyro_z;

    // Register signal handler for graceful shutdown
    signal(SIGINT, signal_handler);

    // Initialize wiringPi I2C
    if ((fd = wiringPiI2CSetup(MPU6050_ADDR)) < 0) {
        fprintf(stderr, "Error: Could not initialize I2C device\n");
        return 1;
    }

    // Initialize MPU-6050
    if (mpu6050_init(fd) < 0) {
        return 1;
    }

    printf("MPU-6050 data logging started. Press Ctrl+C to exit.\n");

    // Main loop
    while (running) {
        // Read sensor data
        if (read_mpu6050_data(fd, &accel_x, &accel_y, &accel_z, &gyro_x, &gyro_y, &gyro_z) == 0) {
            // Log the data
            log_data(accel_x, accel_y, accel_z, gyro_x, gyro_y, gyro_z);
        } else {
            fprintf(stderr, "Error: Could not read MPU-6050 data\n");
        }

        // Sleep for 100ms
        usleep(100000);
    }

    return 0;
}

#include <stdio.h>
