#include <unistd.h>

// Define sensor address and register addresses
#define FXOS8700_ADDR 0x1D
#define CTRL_REG1 0x2A
#define M_CTRL_REG1 0x14
#define M_CTRL_REG2 0x15
#define OUT_X_MSB_A 0x01
#define OUT_X_LSB_A 0x02
#define OUT_Y_MSB_A 0x03
#define OUT_Y_LSB_A 0x04
#define OUT_Z_MSB_A 0x05
#define OUT_Z_LSB_A 0x06
#define OUT_X_MSB_M 0x33
#define OUT_X_LSB_M 0x34
#define OUT_Y_MSB_M 0x35
#define OUT_Y_LSB_M 0x36
#define OUT_Z_MSB_M 0x37
#define OUT_Z_LSB_M 0x38

// Global variable for I2C file descriptor
int fd;

// Global flag to control the main loop
volatile sig_atomic_t running = 1;

// Signal handler for Ctrl+C
void signalHandler(int signum)
{
    running = 0;
    printf("\nExiting gracefully...\n");
}

// Function to configure the FXOS8700 sensor
int configureSensor(int fd)
{
    int result;

    // Put the sensor in standby mode
    result = wiringPiI2CWriteReg8(fd, CTRL_REG1, 0x00);
    if (result < 0) {
        fprintf(stderr, "Error: Failed to write to CTRL_REG1 (standby mode). Error code: %d\n", result);
        return 1;
    }

    // Set the sensor to active mode, 100 Hz ODR, and hybrid mode
    result = wiringPiI2CWriteReg8(fd, CTRL_REG1, 0x0D);
    if (result < 0) {
        fprintf(stderr, "Error: Failed to write to CTRL_REG1 (active mode). Error code: %d\n", result);
        return 1;
    }

    // Enable magnetometer hybrid mode with oversampling ratio of 1
    result = wiringPiI2CWriteReg8(fd, M_CTRL_REG1, 0x01);
    if (result < 0) {
        fprintf(stderr, "Error: Failed to write to M_CTRL_REG1. Error code: %d\n", result);
        return 1;
    }

    // Set magnetometer hybrid auto increment
    result = wiringPiI2CWriteReg8(fd, M_CTRL_REG2, 0x20);
    if (result < 0) {
        fprintf(stderr, "Error: Failed to write to M_CTRL_REG2. Error code: %d\n", result);
        return 1;
    }

    return 0;
}

int main(void)
{
    int16_t accel_x, accel_y, accel_z, mag_x, mag_y, mag_z;
    int result;

    // Register the signal handler for Ctrl+C
    signal(SIGINT, signalHandler);

    // Initialize wiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "Error: Failed to initialize wiringPi.\n");
        return 1;
    }

    // Initialize I2C communication
    fd = wiringPiI2CSetup(FXOS8700_ADDR);
    if (fd < 0) {
        fprintf(stderr, "Error: Failed to initialize I2C communication. Error code: %d\n", fd);
        return 1;
    }

    // Configure the sensor
    if (configureSensor(fd) != 0) {
        fprintf(stderr, "Error: Failed to configure the sensor.\n");
        close(fd);
        return 1;
    }

    // Main loop to read and print sensor data
    while (running) {
        // Read accelerometer data
        int8_t raw_accel_x_msb = wiringPiI2CReadReg8(fd, OUT_X_MSB_A);
        int8_t raw_accel_x_lsb = wiringPiI2CReadReg8(fd, OUT_X_LSB_A);
        int8_t raw_accel_y_msb = wiringPiI2CReadReg8(fd, OUT_Y_MSB_A);
        int8_t raw_accel_y_lsb = wiringPiI2CReadReg8(fd, OUT_Y_LSB_A);
        int8_t raw_accel_z_msb = wiringPiI2CReadReg8(fd, OUT_Z_MSB_A);
        int8_t raw_accel_z_lsb = wiringPiI2CReadReg8(fd, OUT_Z_LSB_A);

        // Read magnetometer data
        int8_t raw_mag_x_msb = wiringPiI2CReadReg8(fd, OUT_X_MSB_M);
        int8_t raw_mag_x_lsb = wiringPiI2CReadReg8(fd, OUT_X_LSB_M);
        int8_t raw_mag_y_msb = wiringPiI2CReadReg8(fd, OUT_Y_MSB_M);
        int8_t raw_mag_y_lsb = wiringPiI2CReadReg8(fd, OUT_Y_LSB_M);
        int8_t raw_mag_z_msb = wiringPiI2CReadReg8(fd, OUT_Z_MSB_M);
        int8_t raw_mag_z_lsb = wiringPiI2CReadReg8(fd, OUT_Z_LSB_M);

        // Combine MSB and LSB for accelerometer data and right-shift by 2
        accel_x = (int16_t)((raw_accel_x_msb << 8) | raw_accel_x_lsb) >> 2;
        accel_y = (int16_t)((raw_accel_y_msb << 8) | raw_accel_y_lsb) >> 2;
        accel_z = (int16_t)((raw_accel_z_msb << 8) | raw_accel_z_lsb) >> 2;

        // Combine MSB and LSB for magnetometer data
        mag_x = (int16_t)((raw_mag_x_msb << 8) | raw_mag_x_lsb);
        mag_y = (int16_t)((raw_mag_y_msb << 8) | raw_mag_y_lsb);
        mag_z = (int16_t)((raw_mag_z_msb << 8) | raw_mag_z_lsb);

        // Print the sensor data
        printf("Accel X: %d, Accel Y: %d, Accel Z: %d, Mag X: %d, Mag Y: %d, Mag Z: %d\n",
               accel_x, accel_y, accel_z, mag_x, mag_y, mag_z);

        // Delay before the next reading
        delay(100);
    }

    // Put the sensor in standby mode before exiting
    result = wiringPiI2CWriteReg8(fd, CTRL_REG1, 0x00);
    if (result < 0) {
        fprintf(stderr, "Error: Failed to write to CTRL_REG1 (standby mode) during exit. Error code: %d\n", result);
    }

    // Close the I2C file descriptor
    close(fd);

    return 0;
}

