}

// Function to initialize I2C
int init_i2c(int bus, int addr) {
    int handle = i2cOpen(bus, addr, 0);
    if (handle < 0) {
        fprintf(stderr, "Error opening I2C device: %s\n", pigpio_error(handle));
        return -1;
    }
    return handle;
}

// Function to read sensor data
int read_sensor_data(int handle, unsigned int *ambient, unsigned int *red, unsigned int *green) {
    char buffer[6];

    // Start measurement (replace with actual register and value from datasheet)
    if (i2cWriteByteData(handle, ADPD105_CONTROL_REG, 0x01) < 0) {
        fprintf(stderr, "Error writing to control register: %s\n", pigpio_error(gpioGetError()));
        return -1;
    }

    // Short delay to allow data acquisition
    usleep(10000); // 10ms

    // Read sensor data (replace with actual register from datasheet)
    if (i2cReadI2CBlockData(handle, ADPD105_DATA_REG, buffer, 6) < 0) {
        fprintf(stderr, "Error reading sensor data: %s\n", pigpio_error(gpioGetError()));
        return -1;
    }

    // Extract data from buffer
    *ambient = (buffer[0] << 8) | buffer[1];
    *red = (buffer[2] << 8) | buffer[3];
    *green = (buffer[4] << 8) | buffer[5];

