#define ICU20201_ADDR 0x6A

// Register addresses (Example - Refer to the datasheet for correct addresses)
#define DISTANCE_MSB_REG 0x58 // Example: Distance MSB register
#define DISTANCE_LSB_REG 0x59 // Example: Distance LSB register

// Function to read distance data from the ICU-20201 sensor
int read_distance(int i2c_handle) {
    char buf[2];
    int result;

    // Read two bytes (MSB and LSB) from the distance registers
    result = i2cReadI2C(i2c_handle, buf, 2);
    if (result != 2) {
        fprintf(stderr, "Error reading distance data: i2cReadI2C returned %d\n", result);
        perror("i2cReadI2C");
        return -1; // Indicate an error
    }

    // Combine the MSB and LSB to form the distance value
    int distance = (buf[0] << 8) | buf[1];

    return distance;
}

