// LPS22HH I2C address
#define LPS22HH_ADDR 0x5C

// LPS22HH register addresses
#define CTRL_REG1 0x10
#define PRESS_OUT_XL 0x28
#define PRESS_OUT_L 0x29
#define PRESS_OUT_H 0x2A
#define WHO_AM_I 0x0F

// Global variable to control the main loop
volatile sig_atomic_t running = 1;

// Function to handle Ctrl+C signal
void sigint_handler(int sig) {
    running = 0;
    printf("\nExiting gracefully...\n");
}

// Structure to hold sensor data
typedef struct {
    float pressure;
    long timestamp;
} sensor_data_t;

// Function to initialize the LPS22HH sensor
bool init_lps22hh(int fd) {
    // Check WHO_AM_I register
    int who_am_i = wiringPiI2CReadReg8(fd, WHO_AM_I);
    if (who_am_i != 0xB1) {
        fprintf(stderr, "Error: WHO_AM_I returned 0x%X, expected 0xB1\n", who_am_i);
        return false;
    }

    // Enable the sensor (ODR = 10 Hz)
    if (wiringPiI2CWriteReg8(fd, CTRL_REG1, 0x10) < 0) {
        fprintf(stderr, "Error writing to CTRL_REG1\n");
        return false;
    }

    return true;
}

// Function to read pressure data from the LPS22HH sensor
bool read_pressure(int fd, float *pressure) {
    int press_xl, press_l, press_h;
    int32_t press_raw;

    // Read pressure data
    press_xl = wiringPiI2CReadReg8(fd, PRESS_OUT_XL);
    press_l = wiringPiI2CReadReg8(fd, PRESS_OUT_L);
    press_h = wiringPiI2CReadReg8(fd, PRESS_OUT_H);

    if (press_xl == -1 || press_l == -1 || press_h == -1) {
        fprintf(stderr, "Error reading pressure data\n");
        return false;
    }

    // Combine the pressure data
    press_raw = (int32_t)(press_xl | (press_l << 8) | (press_h << 16));

    // Convert to hPa (hectopascals)
    *pressure = (float)press_raw / 4096.0;

    return true;
}

// Function to get current timestamp in milliseconds
long get_timestamp() {
    struct timeval tv;
    gettimeofday(&tv, NULL);
    return (tv.tv_sec) * 1000 + (tv.tv_usec) / 1000;
}

// Function to log sensor data to the console
void log_data(const sensor_data_t *data) {
    printf("Timestamp: %ld ms, Pressure: %.2f hPa\n", data->timestamp, data->pressure);
}

int main() {
    int fd;
    float pressure;
    sensor_data_t sensor_data;

    // Register signal handler for Ctrl+C
    signal(SIGINT, sigint_handler);

    // Initialize wiringPi I2C
    if ((fd = wiringPiI2CSetup(LPS22HH_ADDR)) < 0) {
        fprintf(stderr, "Error: Unable to initialize I2C\n");
        return 1;
    }

    // Initialize the LPS22HH sensor
    if (!init_lps22hh(fd)) {
        fprintf(stderr, "Error initializing LPS22HH sensor\n");
        return 1;
    }

    printf("LPS22HH sensor initialized successfully!\n");

    // Main loop to read and log data
    while (running) {
        // Read pressure data
        if (read_pressure(fd, &pressure)) {
            // Get timestamp
            sensor_data.timestamp = get_timestamp();
            sensor_data.pressure = pressure;

            // Log the data
            log_data(&sensor_data);
        } else {
            fprintf(stderr, "Error reading sensor data. Retrying...");
        }

        // Wait for 100 ms (adjust as needed)
        usleep(100000); // 100 ms
    }

    return 0;
}

#include <stdio.h>
