#define SDP32_ADDR 0x21

/* Function to initialize the I2C connection */
int setup_i2c(int *fd) {
    *fd = wiringPiI2CSetup(SDP32_ADDR);
    if (*fd == -1) {
        fprintf(stderr, "Error initializing I2C: %s\n", strerror(errno));
        return -1;
    }
    return 0;
}

/* Function to read the SDP32 sensor data */
int read_sdp32(int fd, float *pressure, float *temperature) {
    uint8_t cmd[1] = {0x00}; // Trigger measurement command
    int bytes_written = write(fd, cmd, 1);
    if (bytes_written != 1) {
        fprintf(stderr, "Error writing to I2C: %s\n", strerror(errno));
        return -1;
    }

    usleep(10000); // Wait for conversion (10ms)

    uint8_t data[6];
    int bytes_read = read(fd, data, 6);
    if (bytes_read != 6) {
        fprintf(stderr, "Error reading from I2C: %s\n", strerror(errno));
        return -1;
    }

    int16_t raw_pressure = (data[0] << 8) | data[1];
    int16_t raw_temperature = (data[3] << 8) | data[4];

    *pressure = (float)raw_pressure / 30.0; // Scale factor for SDP32
    *temperature = (float)raw_temperature / 200.0; //Scale factor for SDP32

    return 0;
}

/* Function to log the sensor data */
void log_data(float pressure, float temperature) {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[80];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    printf("%s - Pressure: %.2f Pa, Temperature: %.2f °C\n", timestamp, pressure, temperature);
}

bool running = true;

void sigint_handler(int sig) {
    running = false;
    printf("\nExiting...\n");
}

int main() {
    int fd;
    float pressure, temperature;

    if (wiringPiSetup() == -1) {
        fprintf(stderr, "Error initializing WiringPi: %s\n", strerror(errno));
        return 1;
    }

    if (setup_i2c(&fd) == -1) {
        return 1;
    }

    signal(SIGINT, sigint_handler);

    while (running) {
        if (read_sdp32(fd, &pressure, &temperature) == 0) {
            log_data(pressure, temperature);
        } else {
            fprintf(stderr, "Failed to read sensor data. Retrying...\n");
        }

        sleep(1); // Read every second
    }

    close(fd);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <unistd.h>
#include <fcntl.h>
#include <sys/mman.h>
#include <signal.h>
#include <time.h>

// Define GPIO pins
#define GPIO_CLOCK 2
#define GPIO_DATA 3

// Memory map physical address (adjust for your Raspberry Pi version if needed)
#define GPIO_BASE 0xFE200000
#define GPIO_SIZE 4096

// GPIO register offsets
#define GPFSEL0 0  // GPIO Function Select 0
#define GPSET0  7  // GPIO Pin Output Set 0
#define GPCLR0  10 // GPIO Pin Output Clear 0
#define GPLEV0  13 // GPIO Pin Level 0

// PDM parameters
#define OVERSAMPLE 64 // Oversampling rate

// Global variables
volatile unsigned int *gpio_map;
volatile int running = 1;

// Structure to hold GPIO configuration and state
typedef struct {
    int mem_fd;
    void *gpio_map_base;
} gpio_context_t;

// Function prototypes
int setup_gpio(gpio_context_t *ctx);
void cleanup_gpio(gpio_context_t *ctx);
int read_pdm_sample();
void signal_handler(int signal);

// Helper function to access GPIO registers
static inline void gpio_write(volatile unsigned int *addr, unsigned int value) {
    *addr = value;
}

static inline unsigned int gpio_read(volatile unsigned int *addr) {
    return *addr;
}

// Function to set GPIO pin mode (IN or OUT)
void set_gpio_mode(int pin, int mode) {
    int fsel_reg = pin / 10;
    int shift = (pin % 10) * 3;
    unsigned int fsel = gpio_read(gpio_map + fsel_reg);
    fsel &= ~(7 << shift);
    fsel |= (mode << shift);
    gpio_write(gpio_map + fsel_reg, fsel);
}

// Function to set GPIO pin output
void set_gpio_output(int pin, int value) {
    if (value) {
        gpio_write(gpio_map + GPSET0, 1 << pin);
    } else {
        gpio_write(gpio_map + GPCLR0, 1 << pin);
    }
}

// Function to read GPIO pin input
int read_gpio_input(int pin) {
    return (gpio_read(gpio_map + GPLEV0) >> pin) & 1;
}

// Setup GPIO
int setup_gpio(gpio_context_t *ctx) {
    /* Open /dev/mem */
    ctx->mem_fd = open("/dev/mem", O_RDWR | O_SYNC);
    if (ctx->mem_fd < 0) {
        perror("Can't open /dev/mem");
        return -1;
    }

    /* mmap GPIO */
    ctx->gpio_map_base = mmap(NULL, GPIO_SIZE, PROT_READ | PROT_WRITE, MAP_SHARED, ctx->mem_fd, GPIO_BASE);
    if (ctx->gpio_map_base == MAP_FAILED) {
        perror("mmap error");
        close(ctx->mem_fd);
        return -1;
    }

    gpio_map = (volatile unsigned int *)ctx->gpio_map_base;

    // Set GPIO pins to input or output
    set_gpio_mode(GPIO_CLOCK, 1); // Output
    set_gpio_mode(GPIO_DATA, 0);  // Input

    return 0;
}

// Cleanup GPIO
void cleanup_gpio(gpio_context_t *ctx) {
    munmap(ctx->gpio_map_base, GPIO_SIZE);
    close(ctx->mem_fd);
}

// Read a single 16-bit PCM sample from the PDM microphone
int read_pdm_sample() {
    int16_t sample = 0;
    //int32_t sum = 0;
    for (int i = 0; i < OVERSAMPLE; i++) {
        // Generate clock signal
        set_gpio_output(GPIO_CLOCK, 1);
        //usleep(1); // Small delay
        // Read data bit
        if (read_gpio_input(GPIO_DATA)) {
            sample++;
        } else {
            sample--;
        }
        set_gpio_output(GPIO_CLOCK, 0);
        //usleep(1); // Small delay
    }
    return sample; // Return the signed sample
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("Caught signal %d, exiting...\n", signal);
    running = 0;
}

int main() {
    gpio_context_t gpio_ctx;

    // Register signal handler
    signal(SIGINT, signal_handler);

    // Setup GPIO
    if (setup_gpio(&gpio_ctx) != 0) {
        fprintf(stderr, "GPIO setup failed!\n");
        return 1;
    }

    printf("SPH0645LM4H PDM MEMS Microphone Data Logging\n");

    // Main loop
    struct timespec sleep_time;
    sleep_time.tv_sec = 0;
    sleep_time.tv_nsec = 10000000; // 10ms

    while (running) {
        // Read PDM sample
        int16_t sample = read_pdm_sample();

        // Log the raw sample to the console
        printf("%d\n", sample);

        // Sleep for 10ms
        nanosleep(&sleep_time, NULL);
    }

    // Cleanup GPIO
    cleanup_gpio(&gpio_ctx);

    printf("Exiting.\n");
    return 0;
}

