// LIS3DH I2C address
#define LIS3DH_ADDR 0x18

// LIS3DH register addresses
#define LIS3DH_REG_WHO_AM_I 0x0F
#define LIS3DH_REG_CTRL1 0x20
#define LIS3DH_REG_OUT_X_L 0x28
#define LIS3DH_REG_OUT_X_H 0x29
#define LIS3DH_REG_OUT_Y_L 0x2A
#define LIS3DH_REG_OUT_Y_H 0x2B
#define LIS3DH_REG_OUT_Z_L 0x2C
#define LIS3DH_REG_OUT_Z_H 0x2D

// Configuration structure
typedef struct {
    int i2c_fd;
    bool running;
} app_config_t;

// Global configuration
app_config_t config;

// Function to initialize the LIS3DH accelerometer
bool lis3dh_init(int fd) {
    // Check WHO_AM_I register
    int who_am_i = wiringPiI2CReadReg8(fd, LIS3DH_REG_WHO_AM_I);
    if (who_am_i != 0x33) {
        fprintf(stderr, "Error: WHO_AM_I returned 0x%02x, expected 0x33\n", who_am_i);
        return false;
    }

    // Enable accelerometer (100Hz, all axes)
    if (wiringPiI2CWriteReg8(fd, LIS3DH_REG_CTRL1, 0x27) < 0) {
        perror("Error writing to CTRL1 register");
        return false;
    }

    return true;
}

// Function to read accelerometer data
bool lis3dh_read_data(int fd, int16_t *x, int16_t *y, int16_t *z) {
    // Read X, Y, and Z axis data (low and high bytes)
    int x_l = wiringPiI2CReadReg8(fd, LIS3DH_REG_OUT_X_L);
    int x_h = wiringPiI2CReadReg8(fd, LIS3DH_REG_OUT_X_H);
    int y_l = wiringPiI2CReadReg8(fd, LIS3DH_REG_OUT_Y_L);
    int y_h = wiringPiI2CReadReg8(fd, LIS3DH_REG_OUT_Y_H);
    int z_l = wiringPiI2CReadReg8(fd, LIS3DH_REG_OUT_Z_L);
    int z_h = wiringPiI2CReadReg8(fd, LIS3DH_REG_OUT_Z_H);

    if (x_l == -1 || x_h == -1 || y_l == -1 || y_h == -1 || z_l == -1 || z_h == -1) {
        perror("Error reading accelerometer data");
        return false;
    }

    // Combine low and high bytes to form 16-bit values
    *x = (int16_t)((x_h << 8) | x_l);
    *y = (int16_t)((y_h << 8) | y_l);
    *z = (int16_t)((z_h << 8) | z_l);

    return true;
}

// Function to log accelerometer data
void log_data(int16_t x, int16_t y, int16_t z) {
    time_t now = time(NULL);
    struct tm *t = localtime(&now);
    char timestamp[32];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", t);

    printf("%s - X: %6d, Y: %6d, Z: %6d\n", timestamp, x, y, z);
}

// Signal handler for graceful shutdown
void signal_handler(int signum) {
    if (signum == SIGINT) {
        printf("Received SIGINT, exiting...\n");
        config.running = false;
    }
}

int main() {
    // Initialize wiringPi I2C
    int fd = wiringPiI2CSetup(LIS3DH_ADDR);
    if (fd == -1) {
        perror("Error initializing I2C");
        return 1;
    }

    config.i2c_fd = fd;
    config.running = true;

    // Initialize LIS3DH accelerometer
    if (!lis3dh_init(fd)) {
        fprintf(stderr, "LIS3DH initialization failed\n");
        return 1;
    }

    // Set up signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Main loop
    while (config.running) {
        int16_t x, y, z;

        if (lis3dh_read_data(fd, &x, &y, &z)) {
            log_data(x, y, z);
        } else {
            fprintf(stderr, "Failed to read accelerometer data\n");
        }

        sleep(1); // Read data every 1 second
    }

    return 0;
}

#include <stdio.h>
