// I2C address of the Si7060 temperature sensor
#define SI7060_ADDR 0x40

// I2C bus number on Raspberry Pi (default is 1)
#define I2C_BUS 1

// Command to measure temperature, hold master
#define MEASURE_TEMP_HOLD 0xE3

int i2c_handle;

// Signal handler for Ctrl+C
void signal_handler(int signal) {
    printf("\nCaught signal %d, cleaning up...\n", signal);
    i2cClose(i2c_handle);
    gpioTerminate();
    exit(0);
}

// Function to read temperature from the Si7060 sensor
float read_temperature() {
    int raw_temperature;
    float temperature_C;

    // Send the measure temperature command
    if (i2cWriteByteData(i2c_handle, 0, MEASURE_TEMP_HOLD) != 0) {
        fprintf(stderr, "Error writing to I2C device.\n");
        return -1000.0; // Indicate an error
    }

    // Wait for the measurement to complete (at least 25ms)
    time_sleep(0.025);

    // Read the raw temperature value
    raw_temperature = i2cReadWordData(i2c_handle, 0);
    if (raw_temperature < 0) {
        fprintf(stderr, "Error reading from I2C device.\n");
        return -1000.0; // Indicate an error
    }

    // Convert the raw value to degrees Celsius
    temperature_C = ((175.72 * raw_temperature) / 65536.0) - 46.85;

    return temperature_C;
}

int main() {
    // Register the signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Initialize the pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Open the I2C device
    i2c_handle = i2cOpen(I2C_BUS, SI7060_ADDR, 0);
    if (i2c_handle < 0) {
        fprintf(stderr, "Error opening I2C device: %d\n", i2c_handle);
        gpioTerminate();
        return 1;
    }

    printf("Si7060 temperature sensor monitoring...\n");

    // Main loop to read and log temperature
    while (1) {
        float temperature = read_temperature();

        if (temperature > -1000.0) {
            printf("Temperature: %.2f °C\n", temperature);
        } else {
            fprintf(stderr, "Failed to read temperature, retrying...\n");
        }

        // Wait for 5 seconds
        sleep(5);
    }

    // The following lines will never be reached due to the infinite loop,
    // but are included for completeness.
    i2cClose(i2c_handle);
    gpioTerminate();
    return 0;
}

#include <stdio.h>
