// Omron B5L-T0023D I2C address
#define SENSOR_ADDR 0x50

// Register addresses (example, adjust based on datasheet)
#define REG_X 0x02
#define REG_Y 0x04
#define REG_Z 0x06
#define REG_DISTANCE 0x08

// Global variable for the I2C file descriptor
int fd;

// Structure to hold sensor data
typedef struct {
    int16_t x;
    int16_t y;
    int16_t z;
    uint16_t distance;
} sensor_data_t;

// Function to handle Ctrl+C (SIGINT) signal
void signal_handler(int signal) {
    printf("\nExiting program cleanly.\n");
    exit(0);
}

// Function to read a 16-bit register with retry
int16_t read_register_with_retry(int fd, uint8_t reg) {
    int retries = 3;
    int16_t value = -1; // Default to error value

    while (retries > 0) {
        value = wiringPiI2CReadReg16(fd, reg);
        if (value != -1) { // Check for I2C error
            return value;
        }
        fprintf(stderr, "I2C read error, retrying...\n");
        delay(10); // Wait before retrying
        retries--;
    }

    fprintf(stderr, "I2C read failed after multiple retries.\n");
    return -1; // Return error value after all retries fail
}

// Function to read sensor data
int read_sensor_data(int fd, sensor_data_t *data) {
    data->x = read_register_with_retry(fd, REG_X);
    if (data->x == -1) return -1;

    data->y = read_register_with_retry(fd, REG_Y);
    if (data->y == -1) return -1;

    data->z = read_register_with_retry(fd, REG_Z);
    if (data->z == -1) return -1;

    data->distance = read_register_with_retry(fd, REG_DISTANCE);
    if (data->distance == -1) return -1;

    return 0; // Success
}

// Function to log sensor data with timestamp
void log_sensor_data(sensor_data_t data) {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[20];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    // Basic sanity check for the data
    if (data.x > -2000 && data.x < 2000 &&
        data.y > -2000 && data.y < 2000 &&
        data.z > -2000 && data.z < 2000 &&
        data.distance < 4000) {
        printf("%s.%03ld XYZ: %d, %d, %d, Distance: %d\n", timestamp, (long) (rawtime % 1000), data.x, data.y, data.z, data.distance);
    } else {
        fprintf(stderr, "Data out of range, not logging.\n");
    }
}

int main() {
    // Setup signal handler for graceful shutdown
    signal(SIGINT, signal_handler);

    // Initialize wiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "wiringPiSetup failed.\n");
        return 1;
    }

    // Initialize I2C
    fd = wiringPiI2CSetup(SENSOR_ADDR);
    if (fd == -1) {
        fprintf(stderr, "wiringPiI2CSetup failed.\n");
        return 1;
    }

    sensor_data_t sensor_data;

    // Main loop
    while (1) {
        if (read_sensor_data(fd, &sensor_data) == 0) {
            log_sensor_data(sensor_data);
        } else {
            fprintf(stderr, "Failed to read sensor data.\n");
        }

        delay(100); // Read every 100 milliseconds
    }

    return 0;
}

