#define M_OUT_Y_MSB_REG         0x35
#define M_OUT_Y_LSB_REG         0x36
#define M_OUT_Z_MSB_REG         0x37
#define M_OUT_Z_LSB_REG         0x38
#define CTRL_REG1               0x2A
#define M_CTRL_REG1             0x2B

// Scaling factors
#define ACCEL_SENSITIVITY   0.000244f // 0.244 mg/LSB = 0.000244 g/LSB
#define MAG_SENSITIVITY     0.1f      // 0.1 µT/LSB

// Function to read raw accelerometer and magnetometer data
int read_sensor_data(int fd, int16_t *accel_x, int16_t *accel_y, int16_t *accel_z, int16_t *mag_x, int16_t *mag_y, int16_t *mag_z) {
    int status;
    int retries = 3; // Number of retries

    while (retries > 0) {
        status = wiringPiI2CReadReg8(fd, STATUS);
        if (status < 0) {
            fprintf(stderr, "Error reading STATUS register: %s\n", strerror(errno));
            retries--;
            delay(10); // Wait before retrying
            continue;
        }

        if (status & 0x08) { // Check if new data is ready
            // Read accelerometer data
            int16_t raw_accel_x_msb = wiringPiI2CReadReg8(fd, OUT_X_MSB_REG);
            int16_t raw_accel_x_lsb = wiringPiI2CReadReg8(fd, OUT_X_LSB_REG);
            int16_t raw_accel_y_msb = wiringPiI2CReadReg8(fd, OUT_Y_MSB_REG);
            int16_t raw_accel_y_lsb = wiringPiI2CReadReg8(fd, OUT_Y_LSB_REG);
            int16_t raw_accel_z_msb = wiringPiI2CReadReg8(fd, OUT_Z_MSB_REG);
            int16_t raw_accel_z_lsb = wiringPiI2CReadReg8(fd, OUT_Z_LSB_REG);

            // Read magnetometer data
            int16_t raw_mag_x_msb = wiringPiI2CReadReg8(fd, M_OUT_X_MSB_REG);
            int16_t raw_mag_x_lsb = wiringPiI2CReadReg8(fd, M_OUT_X_LSB_REG);
            int16_t raw_mag_y_msb = wiringPiI2CReadReg8(fd, M_OUT_Y_MSB_REG);
            int16_t raw_mag_y_lsb = wiringPiI2CReadReg8(fd, M_OUT_Y_LSB_REG);
            int16_t raw_mag_z_msb = wiringPiI2CReadReg8(fd, M_OUT_Z_MSB_REG);
            int16_t raw_mag_z_lsb = wiringPiI2CReadReg8(fd, M_OUT_Z_LSB_REG);

            if (raw_accel_x_msb < 0 || raw_accel_x_lsb < 0 || raw_accel_y_msb < 0 || raw_accel_y_lsb < 0 || raw_accel_z_msb < 0 || raw_accel_z_lsb < 0 ||
                raw_mag_x_msb < 0 || raw_mag_x_lsb < 0 || raw_mag_y_msb < 0 || raw_mag_y_lsb < 0 || raw_mag_z_msb < 0 || raw_mag_z_lsb < 0) {
                fprintf(stderr, "Error reading sensor data: %s\n", strerror(errno));
                retries--;
                delay(10); // Wait before retrying
                continue;
            }

            *accel_x = (raw_accel_x_msb << 8) | raw_accel_x_lsb;
            *accel_y = (raw_accel_y_msb << 8) | raw_accel_y_lsb;
            *accel_z = (raw_accel_z_msb << 8) | raw_accel_z_lsb;
            *mag_x = (raw_mag_x_msb << 8) | raw_mag_x_lsb;
            *mag_y = (raw_mag_y_msb << 8) | raw_mag_y_lsb;
            *mag_z = (raw_mag_z_msb << 8) | raw_mag_z_lsb;

            return 0; // Success
        } else {
            delay(1); // Wait briefly if no new data
        }
    }

    fprintf(stderr, "Failed to read sensor data after multiple retries.\n");
    return -1; // Failure
}

// Function to convert raw data to g and µT
void convert_data(int16_t accel_x, int16_t accel_y, int16_t accel_z, int16_t mag_x, int16_t mag_y, int16_t mag_z,
                  float *accel_x_g, float *accel_y_g, float *accel_z_g, float *mag_x_uT, float *mag_y_uT, float *mag_z_uT) {
    *accel_x_g = accel_x * ACCEL_SENSITIVITY;
    *accel_y_g = accel_y * ACCEL_SENSITIVITY;
    *accel_z_g = accel_z * ACCEL_SENSITIVITY;
    *mag_x_uT = mag_x * MAG_SENSITIVITY;
    *mag_y_uT = mag_y * MAG_SENSITIVITY;
    *mag_z_uT = mag_z * MAG_SENSITIVITY;
}

int main() {
    int fd; // I2C file descriptor

    // Initialize wiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "wiringPiSetup failed: %s\n", strerror(errno));
        return 1;
    }

    // Initialize I2C
    fd = wiringPiI2CSetup(FXOS8700_ADDRESS);
    if (fd == -1) {
        fprintf(stderr, "wiringPiI2CSetup failed: %s\n", strerror(errno));
        return 1;
    }

    // Initialize the FXOS8700 sensor
    if (wiringPiI2CWriteReg8(fd, CTRL_REG1, 0x00) < 0) { // Standby mode
        fprintf(stderr, "Error writing to CTRL_REG1 (standby): %s\n", strerror(errno));
        return 1;
    }
    if (wiringPiI2CWriteReg8(fd, M_CTRL_REG1, 0x1F) < 0) { // Hybrid mode
        fprintf(stderr, "Error writing to M_CTRL_REG1 (hybrid): %s\n", strerror(errno));
        return 1;
    }
    if (wiringPiI2CWriteReg8(fd, CTRL_REG1, 0x19) < 0) { // Active mode, 100Hz
        fprintf(stderr, "Error writing to CTRL_REG1 (active): %s\n", strerror(errno));
        return 1;
    }

    struct timespec sleep_time;
    sleep_time.tv_sec = 0;
    sleep_time.tv_nsec = 200000000; // 200ms

    while (1) {
        int16_t accel_x, accel_y, accel_z, mag_x, mag_y, mag_z;
        float accel_x_g, accel_y_g, accel_z_g, mag_x_uT, mag_y_uT, mag_z_uT;
        struct timeval tv;
        struct tm *tm_info;
        char timestamp[26];

        // Read sensor data
        if (read_sensor_data(fd, &accel_x, &accel_y, &accel_z, &mag_x, &mag_y, &mag_z) == 0) {
            // Convert raw data to g and µT
            convert_data(accel_x, accel_y, accel_z, mag_x, mag_y, mag_z,
                         &accel_x_g, &accel_y_g, &accel_z_g, &mag_x_uT, &mag_y_uT, &mag_z_uT);

            // Get timestamp
            gettimeofday(&tv, NULL);
            tm_info = localtime(&tv.tv_sec);
            strftime(timestamp, 26, "%Y-%m-%d %H:%M:%S", tm_info);
            sprintf(timestamp + 19, ".%06ld", tv.tv_usec);

            // Print the readings
            printf("%s Accel(g): X=%.2f, Y=%.2f, Z=%.2f  Mag(uT): X=%.2f, Y=%.2f, Z=%.2f\n",
                   timestamp, accel_x_g, accel_y_g, accel_z_g, mag_x_uT, mag_y_uT, mag_z_uT);
        } else {
            fprintf(stderr, "Failed to read sensor data.\n");
        }

        nanosleep(&sleep_time, NULL);
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <unistd.h>
#include <time.h>
#include <math.h>
#include <wiringPi.h>
#include <signal.h>

// Define MCP3008 pins (SPI interface)
#define SPI_CE 0 // Chip Enable pin (CE0 or CE1)
#define SPI_SPEED 1000000 // SPI clock speed (1 MHz)

// Define ADC channel for LMT70 (0-7)
#define LMT70_CHANNEL 0

// Struct to hold program state
typedef struct {
    int running;
} ProgramState;

ProgramState state = {1}; // Initialize running to 1

// Function prototypes
int initialize_spi();
int read_adc_channel(int channel);
float convert_to_temperature(int adc_value);
void log_temperature(float temperature);
void cleanup();
void signal_handler(int signal);

// Function to initialize SPI
int initialize_spi() {
    if (wiringPiSPISetup(SPI_CE, SPI_SPEED) < 0) {
        perror("wiringPiSPISetup failed");
        return -1;
    }
    return 0;
}

// Function to read from MCP3008 ADC channel
int read_adc_channel(int channel) {
    uint8_t buffer[3];
    buffer[0] = 0x01; // Start bit
    buffer[1] = (0x08 | channel) << 4; // Single-ended mode, channel selection
    buffer[2] = 0x00;

    wiringPiSPIDataRW(SPI_CE, buffer, 3);

    int adc_value = ((buffer[1] & 0x03) << 8) + buffer[2];
    return adc_value;
}

// Function to convert ADC value to temperature (LMT70)
float convert_to_temperature(int adc_value) {
    // Example conversion (adjust based on LMT70 datasheet and VREF)
    float voltage = (adc_value / 1023.0) * 3.3; // Assuming VREF = 3.3V
    float temperature = (voltage - 0.5) / 0.01; // Simplified LMT70 conversion
    return temperature;
}

// Function to log temperature to console
void log_temperature(float temperature) {
    time_t rawtime;
    struct tm * timeinfo;
    char timestamp[80];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    printf("[%s] Temperature: %.2f °C\n", timestamp, temperature);
}

// Cleanup function
void cleanup() {
    printf("Cleaning up...\n");
    // No specific cleanup needed for this example
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    state.running = 0;
    printf("Caught signal %d, exiting gracefully...\n", signal);
}

int main() {
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "wiringPiSetup failed\n");
        return 1;
    }

    if (initialize_spi() == -1) {
        fprintf(stderr, "SPI initialization failed\n");
        return 1;
    }

    signal(SIGINT, signal_handler); // Register signal handler
    signal(SIGTERM, signal_handler);

    printf("Temperature monitoring started. Press Ctrl+C to exit.\n");

    while (state.running) {
        int adc_value = read_adc_channel(LMT70_CHANNEL);
        if (adc_value >= 0) {
            float temperature = convert_to_temperature(adc_value);
            log_temperature(temperature);
        } else {
            fprintf(stderr, "Failed to read ADC value\n");
        }
        sleep(5);
    }

    cleanup();
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <unistd.h>
#include <time.h>
#include <signal.h>

// Configuration
#define SPI_CHANNEL 0
#define SPI_BAUD 1000000  // 1 MHz
#define REFERENCE_VOLTAGE 3.3 // Reference voltage for ADC

// MQ135 Calibration parameters (CO2 - Example values, adjust based on datasheet)
#define PPM_SLOPE 500.0
#define PPM_INTERCEPT 200.0

int spi_handle;
volatile sig_atomic_t terminate = 0;

// Structure to hold sensor data and configuration
typedef struct {
    int channel;
    double slope;
    double intercept;
} SensorConfig;

// Signal handler for Ctrl+C
void signal_handler(int signal) {
    printf("Ctrl+C pressed. Exiting...\n");
    terminate = 1;
}

// Function to read from MCP3008 ADC
int read_mcp3008(int channel) {
    if (channel < 0 || channel > 7) {
        fprintf(stderr, "Error: Invalid ADC channel %d\n", channel);
        return -1;
    }

    // Construct SPI message (MCP3008 datasheet)
    char tx_buffer[3];
    char rx_buffer[3];

    tx_buffer[0] = 0x01; // Start bit
    tx_buffer[1] = (0x08 | channel) << 4; // Single-ended mode, channel select
    tx_buffer[2] = 0x00; // Don't care

    spiXfer(spi_handle, tx_buffer, rx_buffer, 3); // Perform SPI transaction

    // Extract ADC value from response
    int adc_value = ((rx_buffer[1] & 0x03) << 8) + rx_buffer[2];

    return adc_value;
}

// Function to calculate PPM using a linear approximation
double calculate_ppm(double voltage) {
    return PPM_SLOPE * voltage + PPM_INTERCEPT;
}

int main(int argc, char *argv[]) {
    // Set default sampling period
    int sampling_period = 5; // seconds

    // Override sampling period if provided as a command-line argument
    if (argc > 1) {
        sampling_period = atoi(argv[1]);
        if (sampling_period <= 0) {
            fprintf(stderr, "Error: Invalid sampling period. Using default (5 seconds).\n");
            sampling_period = 5;
        }
    }

    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "Error: pigpio initialisation failed\n");
        return 1;
    }

    // Open SPI channel
    spi_handle = spiOpen(SPI_CHANNEL, SPI_BAUD, 0); // Channel 0, 1MHz, Mode 0
    if (spi_handle < 0) {
        fprintf(stderr, "Error: SPI initialisation failed\n");
        gpioTerminate();
        return 1;
    }

    // Register signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    printf("Sampling MQ135 sensor every %d seconds. Press Ctrl+C to exit.\n", sampling_period);

    // Main loop
    while (!terminate) {
        // Read ADC value from MCP3008 (Channel 0)
        int raw_adc = read_mcp3008(0);

        if (raw_adc >= 0) {
            // Validate ADC reading
            if (raw_adc > 1023) {
                fprintf(stderr, "Error: Invalid ADC reading: %d\n", raw_adc);
            } else {
                // Calculate voltage
                double voltage = (double)raw_adc / 1023.0 * REFERENCE_VOLTAGE;

                // Calculate PPM
                double ppm = calculate_ppm(voltage);

                // Get current time
                time_t now = time(NULL);
                struct tm *t = localtime(&now);
                char timestamp[26];
                strftime(timestamp, sizeof(timestamp)-1, "%Y-%m-%d %H:%M:%S", t);

                // Log data to console
                printf("%s - Raw ADC: %d, Voltage: %.3fV, PPM: %.2f\n", timestamp, raw_adc, voltage, ppm);
            }
        } else {
            fprintf(stderr, "Error reading ADC value.\n");
        }

        sleep(sampling_period);
    }

    // Cleanup
    spiClose(spi_handle);
    gpioTerminate();

    return 0;
}

#include <stdio.h>
#include <pigpio.h>
#include <unistd.h>
#include <signal.h>
#include <time.h>

// LSM303DLHC I2C addresses
#define LSM303_ACCEL 0x19
#define LSM303_MAG 0x1E

// LSM303DLHC Registers
#define CTRL_REG1_A 0x20
#define MR_REG_M 0x02

#define OUT_X_L_A 0x28
#define OUT_X_H_A 0x29
#define OUT_Y_L_A 0x2A
#define OUT_Y_H_A 0x2B
#define OUT_Z_L_A 0x2C
#define OUT_Z_H_A 0x2D

#define OUT_X_L_M 0x08
#define OUT_X_H_M 0x09
#define OUT_Y_L_M 0x0A
#define OUT_Y_H_M 0x0B
#define OUT_Z_L_M 0x0C
#define OUT_Z_H_M 0x0D

int accel_handle, mag_handle;
bool running = true;

// Structure to hold sensor data
typedef struct {
    int16_t x, y, z;
} sensor_data_t;

void signal_handler(int signal) {
    printf("Ctrl+C pressed. Exiting...\n");
    running = false;
}

int initialize_i2c(int *accel_handle, int *mag_handle) {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return -1;
    }

    *accel_handle = i2cOpen(1, LSM303_ACCEL, 0);
    if (*accel_handle < 0) {
        fprintf(stderr, "Failed to open accelerometer I2C device: %d\n", *accel_handle);
        gpioTerminate();
        return -1;
    }

    *mag_handle = i2cOpen(1, LSM303_MAG, 0);
    if (*mag_handle < 0) {
        fprintf(stderr, "Failed to open magnetometer I2C device: %d\n", *mag_handle);
        i2cClose(*accel_handle);
        gpioTerminate();
        return -1;
    }

    // Configure accelerometer: ±2G range, 50Hz data rate
    if (i2cWriteByteData(*accel_handle, CTRL_REG1_A, 0x57) < 0) {
        fprintf(stderr, "Failed to write to accelerometer CTRL_REG1_A\n");
        i2cClose(*accel_handle);
        i2cClose(*mag_handle);
        gpioTerminate();
        return -1;
    }

    // Configure magnetometer: continuous conversion mode
    if (i2cWriteByteData(*mag_handle, MR_REG_M, 0x00) < 0) {
        fprintf(stderr, "Failed to write to magnetometer MR_REG_M\n");
        i2cClose(*accel_handle);
        i2cClose(*mag_handle);
        gpioTerminate();
        return -1;
    }

    return 0;
}

int read_accelerometer(int handle, sensor_data_t *data) {
    char buffer[6];
    if (i2cReadI2CBlockData(handle, OUT_X_L_A, buffer, 6) < 0) {
        fprintf(stderr, "Failed to read accelerometer data\n");
        return -1;
    }

    data->x = (int16_t)((buffer[1] << 8) | buffer[0]);
    data->y = (int16_t)((buffer[3] << 8) | buffer[2]);
    data->z = (int16_t)((buffer[5] << 8) | buffer[4]);

    return 0;
}

int read_magnetometer(int handle, sensor_data_t *data) {
    char buffer[6];
    if (i2cReadI2CBlockData(handle, OUT_X_L_M, buffer, 6) < 0) {
        fprintf(stderr, "Failed to read magnetometer data\n");
        return -1;
    }

    data->x = (int16_t)((buffer[1] << 8) | buffer[0]);
    data->y = (int16_t)((buffer[3] << 8) | buffer[2]);
    data->z = (int16_t)((buffer[5] << 8) | buffer[4]);

    return 0;
}

int main() {
    signal(SIGINT, signal_handler);

    if (initialize_i2c(&accel_handle, &mag_handle) != 0) {
        return 1;
    }

    sensor_data_t accel_data, mag_data;

    while (running) {
        if (read_accelerometer(accel_handle, &accel_data) == 0 &&
            read_magnetometer(mag_handle, &mag_data) == 0) {

            printf("Accelerometer: X=%6d, Y=%6d, Z=%6d | Magnetometer: X=%6d, Y=%6d, Z=%6d\n",
                   accel_data.x, accel_data.y, accel_data.z,
                   mag_data.x, mag_data.y, mag_data.z);
        } else {
            fprintf(stderr, "Error reading sensor data. Re-initializing...\n");
            i2cClose(accel_handle);
            i2cClose(mag_handle);
            gpioTerminate();
            if (initialize_i2c(&accel_handle, &mag_handle) != 0) {
                fprintf(stderr, "Failed to re-initialize I2C. Exiting.\n");
                break;
            }
        }

        gpioDelay(500000); // 500ms
    }

    i2cClose(accel_handle);
    i2cClose(mag_handle);
    gpioTerminate();

    return 0;
}
